/**
 * Chill「遇见」单文件包（内联页面+样式+逻辑）；部署：主壳 index.html 引入本文件即可。
 * 主壳与 html 同目录：<script src="chill-meet-bundle.js"></script>
 * 依赖：与主壳同域（共用 IndexedDB）；需可访问 unpkg（Phosphor）与 Google Fonts。
 */
(function () {
  function noopClose() {}
  try {
    var IFRAME_ID = 'chill-meet-iframe';
    var MEET_SRCDOC = "<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no, viewport-fit=cover\">\n<title>Chill · 遇见</title>\n<script src=\"https://unpkg.com/@phosphor-icons/web\"></script>\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n<link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n<link href=\"https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;700&family=Noto+Sans+SC:wght@300;400;500;700&family=Playfair+Display:ital,wght@0,400;0,600;1,400&family=Space+Mono:ital,wght@0,400;0,700&family=Cormorant+Garamond:ital,wght@0,400;0,600;1,400&family=Inter:wght@400;500;600&display=swap\" rel=\"stylesheet\">\n<style>\n:root {\n  --bg-body:rgba(220,242,255,0.5); --bg-device:rgba(235,248,255,0.7); --bg-card:#fff;\n  --glass-bg:rgba(255,255,255,0.72); --glass-border:rgba(255,255,255,0.85); --glass-blur:blur(22px);\n  --text-main:#1a3a50; --text-sub:#666; --border-line:#e8e8e8;\n  --shadow-card:0 4px 24px rgba(0,0,0,.04);\n  --shadow-float:0 8px 32px rgba(0,0,0,.06);\n  --pass:#8B3A33; --like:#2d5a3d;\n  --font-mono:'Space Mono',monospace;\n  /* 卡片高度由发现页 .ma-deck 在父级剩余空间内撑满，避免底栏遮挡胶囊按钮 */\n  --app-pad-bottom:max(100px,calc(env(safe-area-inset-bottom,0px) + 92px));\n}\n[data-theme=\"dark\"] {\n  --bg-body:#111; --bg-device:#1a3a50; --bg-card:#222;\n  --glass-bg:rgba(38,38,38,0.82); --glass-border:rgba(255,255,255,0.1);\n  --text-main:rgba(220,242,255,0.5); --text-sub:#888; --border-line:#2e2e2e;\n  --shadow-card:0 4px 28px rgba(0,0,0,.45);\n  --shadow-float:0 12px 40px rgba(0,0,0,.35);\n  --pass:#d4796e; --like:#7cb890;\n}\n*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent;}\nhtml{font-size:16px;}\nbody{\n  font-family:'DM Sans','Noto Sans SC',sans-serif;\n  background:var(--bg-body);\n  min-height:100vh;\n  display:flex;\n  justify-content:center;\n  align-items:center;\n  color:var(--text-main);\n  transition:background .3s,color .3s;\n}\n.device{\n  width:390px; height:844px; max-height:100vh;\n  background:var(--bg-device);\n  border-radius:44px;\n  position:relative;\n  overflow:hidden;\n  box-shadow:0 0 0 10px #222,0 24px 60px rgba(0,0,0,.18);\n}\n@media (max-width:640px){\n  body{align-items:stretch;justify-content:flex-start;min-height:100dvh;}\n  .device{width:100%;min-height:100dvh;height:100vh;height:100dvh;max-height:none;border-radius:0;box-shadow:none;}\n}\n/* 与主界面一致的底纹 + 水印 */\n.ma-ambience{position:absolute;inset:0;pointer-events:none;z-index:0;overflow:hidden;}\n.ma-wallpaper{\n  position:absolute;inset:0;\n  background:\n    radial-gradient(ellipse 120% 80% at 20% 0%, rgba(180,170,160,.14), transparent 50%),\n    radial-gradient(ellipse 90% 70% at 100% 30%, rgba(160,175,185,.1), transparent 45%),\n    var(--bg-device);\n}\n[data-theme=\"dark\"] .ma-wallpaper{\n  background:\n    radial-gradient(ellipse 120% 80% at 15% 10%, rgba(80,70,90,.2), transparent 50%),\n    radial-gradient(ellipse 90% 60% at 100% 40%, rgba(50,60,70,.25), transparent 45%),\n    var(--bg-device);\n}\n.ma-watermark{\n  position:absolute;bottom:100px;right:-8px;font-family:'Playfair Display',serif;font-size:7rem;font-weight:300;font-style:italic;\n  color:var(--text-main);opacity:.035;line-height:1;user-select:none;\n}\n[data-theme=\"dark\"] .ma-watermark{opacity:.06;}\n.app{\n  position:absolute;inset:0;z-index:1;\n  display:flex;flex-direction:column;\n  padding:calc(env(safe-area-inset-top,0px) + 18px) 18px var(--app-pad-bottom);\n}\n/* —— 顶栏（对齐首页 header + theme-switch） —— */\n.ma-header{\n  display:flex;justify-content:space-between;align-items:flex-end;\n  margin-bottom:18px;padding:0 2px;flex-shrink:0;gap:10px;\n}\n/* 与主壳 index.html .sub-back-btn 一致；顶栏右侧叠在 REFRESH 上方 */\n.sub-back-btn{\n  background:transparent;border:none;color:var(--text-main);cursor:pointer;\n  transition:opacity .3s;\n  font-family:'DM Sans',sans-serif;font-size:0.8rem;font-weight:500;\n  text-transform:uppercase;letter-spacing:2px;\n  text-decoration:underline;text-underline-offset:4px;padding:2px 0 0;\n  -webkit-appearance:none;appearance:none;\n}\n.sub-back-btn:active{opacity:.4;}\n.ma-header-back{align-self:flex-end;line-height:1.2;}\n.ma-date-box{min-width:0;flex:1;}\n.ma-date-box h1{\n  font-family:'Playfair Display',serif;font-size:2rem;font-weight:400;font-style:italic;line-height:1;color:var(--text-main);\n}\n.ma-dateline{\n  display:flex;align-items:center;gap:8px;margin-top:8px;\n  color:var(--text-sub);font-size:0.72rem;letter-spacing:1.5px;text-transform:uppercase;\n}\n.ma-theme-switch{\n  font-family:var(--font-mono);font-size:0.58rem;font-weight:600;letter-spacing:2px;text-transform:uppercase;\n  color:var(--text-main);cursor:pointer;padding:8px 0;display:flex;align-items:center;gap:8px;border:none;background:transparent;\n  transition:opacity .2s;\n}\n.ma-theme-switch::before{\n  content:'';width:5px;height:5px;background:var(--text-main);border-radius:50%;\n  transition:transform .3s cubic-bezier(0.16,1,0.3,1);\n}\n.ma-theme-switch:active{opacity:.55;}\n.ma-theme-switch:active::before{transform:scale(.45);}\n.ma-refresh-action::before{display:none;}\n.ma-refresh-action:active::before{display:none;}\n.ma-refresh-ico{\n  display:flex;align-items:center;justify-content:center;color:var(--text-sub);\n}\n.ma-refresh-ico i{font-size:0.95rem;line-height:1;}\n.ma-refresh-action.is-busy .ma-refresh-ico i{animation:ma-refresh-spin .55s ease-out;}\n.ma-refresh-action:disabled{opacity:.42;cursor:not-allowed;}\n@keyframes ma-refresh-spin{\n  from{transform:rotate(0deg);}\n  to{transform:rotate(360deg);}\n}\n.ma-header-trail{\n  display:flex;flex-direction:column;align-items:flex-end;justify-content:flex-end;\n  gap:2px;flex-shrink:0;\n}\n.ma-header-trail .ma-theme-switch{padding-top:2px;}\n/* —— 视图切换 —— */\n.ma-views{\n  position:relative;flex:1;min-height:0;overflow:hidden;\n}\n.ma-view{\n  position:absolute;inset:0;\n  display:flex;flex-direction:column;min-height:0;\n  opacity:0;pointer-events:none;\n  transform:translate3d(0,10px,0) scale(.995);\n}\n.ma-view.active{\n  opacity:1;pointer-events:auto;transform:translate3d(0,0,0) scale(1);\n}\n.ma-view.is-enter-from-right{animation:ma-view-enter-r .26s cubic-bezier(0.22,1,0.36,1) both;}\n.ma-view.is-enter-from-left{animation:ma-view-enter-l .26s cubic-bezier(0.22,1,0.36,1) both;}\n.ma-view.is-exit-to-left{animation:ma-view-exit-l .22s cubic-bezier(0.22,1,0.36,1) both;pointer-events:none;}\n.ma-view.is-exit-to-right{animation:ma-view-exit-r .22s cubic-bezier(0.22,1,0.36,1) both;pointer-events:none;}\n@keyframes ma-view-enter-r{\n  from{opacity:0;transform:translate3d(16px,6px,0) scale(.996);}\n  to{opacity:1;transform:translate3d(0,0,0) scale(1);}\n}\n@keyframes ma-view-enter-l{\n  from{opacity:0;transform:translate3d(-16px,6px,0) scale(.996);}\n  to{opacity:1;transform:translate3d(0,0,0) scale(1);}\n}\n@keyframes ma-view-exit-l{\n  from{opacity:1;transform:translate3d(0,0,0) scale(1);}\n  to{opacity:0;transform:translate3d(-14px,4px,0) scale(.995);}\n}\n@keyframes ma-view-exit-r{\n  from{opacity:1;transform:translate3d(0,0,0) scale(1);}\n  to{opacity:0;transform:translate3d(14px,4px,0) scale(.995);}\n}\n/* —— 卡片堆（叠放幽灵卡 + 主卡） —— */\n.ma-deck-wrap{\n  flex:1;position:relative;min-height:0;\n  perspective:1400px;\n}\n.ma-deck-wrap.ma-deck-empty{min-height:min(360px,45vh);}\n.ma-deck-ghost{\n  position:absolute;left:50%;top:8px;bottom:0;\n  width:min(358px,calc(100% - 32px));height:auto;\n  transform:translateX(-50%);\n  background:var(--bg-card);\n  border:1px solid var(--border-line);\n  border-radius:24px;\n  box-shadow:var(--shadow-card);\n  pointer-events:none;\n}\n.ma-deck-ghost.ma-dg2{transform:translateX(-50%) scale(.88) translateY(24px);opacity:.36;z-index:0;}\n.ma-deck-ghost.ma-dg1{transform:translateX(-50%) scale(.94) translateY(12px);opacity:.55;z-index:1;}\n.ma-deck-wrap.ma-deck-empty .ma-deck-ghost{visibility:hidden;opacity:0;}\n.ma-deck{\n  position:absolute;left:50%;top:8px;bottom:0;z-index:2;\n  width:min(358px,calc(100% - 32px));height:auto;\n  transform:translateX(-50%);\n}\n.ma-deck .ma-empty{min-height:100%;justify-content:center;}\n.ma-card{\n  position:absolute;left:0;right:0;top:0;bottom:0;margin:auto;\n  width:100%;max-width:none;height:100%;\n  background:transparent;\n  border-radius:24px;\n  border:none;\n  box-shadow:var(--shadow-float);\n  overflow:visible;\n  touch-action:none;\n  user-select:none;\n  -webkit-user-drag:none;\n  will-change:transform;\n  transition:transform 0.38s cubic-bezier(0.19,1,0.22,1), filter .2s;\n  cursor:grab;\n  filter:drop-shadow(0 2px 8px rgba(0,0,0,.04));\n}\n.ma-card.ma-card-appear{animation:ma-card-in .26s cubic-bezier(0.22,1,0.36,1);}\n@keyframes ma-card-in{\n  from{opacity:0;transform:translateY(8px) scale(.988);}\n  to{opacity:1;transform:translateY(0) scale(1);}\n}\n[data-theme=\"dark\"] .ma-card{filter:drop-shadow(0 4px 20px rgba(0,0,0,.3));}\n[data-theme=\"dark\"] .ma-card.ma-card-appear{animation:ma-card-in .26s cubic-bezier(0.22,1,0.36,1);}\n.ma-card.dragging{\n  transition:none;\n  cursor:grabbing;\n  filter:drop-shadow(0 12px 36px rgba(0,0,0,.1));\n}\n@media (prefers-reduced-motion: reduce){\n  .ma-view,.ma-view.active{animation:none!important;transform:none;}\n  .ma-view.is-enter-from-right,.ma-view.is-enter-from-left,.ma-view.is-exit-to-left,.ma-view.is-exit-to-right{animation:none!important;}\n  .ma-card.ma-card-appear{animation:none;}\n}\n.ma-card-inner{\n  border-radius:24px;\n  overflow:hidden;\n  height:100%;\n  min-height:0;\n  display:flex;\n  flex-direction:column;\n  background:var(--bg-card);\n  position:relative;\n  border:1px solid var(--border-line);\n  box-shadow:inset 0 1px 0 rgba(255,255,255,.65);\n}\n[data-theme=\"dark\"] .ma-card-inner{box-shadow:inset 0 1px 0 rgba(255,255,255,.06);}\n.ma-card-stamps{\n  position:absolute;inset:0;pointer-events:none;z-index:4;\n  display:flex;align-items:center;justify-content:space-between;padding:0 10% 8%;\n}\n/* 滑动提示：空心衬线 + 极细副标，避免粗边框盒子 */\n.ma-card-stamp{\n  display:flex;flex-direction:column;align-items:center;gap:8px;\n  opacity:0;transition:opacity .1s ease;\n  border:none;padding:0;background:none;\n}\n.ma-card-stamp.nope{transform:rotate(-11deg);}\n.ma-card-stamp.like{transform:rotate(11deg);}\n.ma-stamp-word{\n  font-family:'Playfair Display',serif;font-style:italic;font-weight:400;\n  font-size:clamp(1.75rem,7vw,2.35rem);line-height:1;letter-spacing:0.02em;\n  color:transparent;\n  -webkit-text-stroke:1px rgba(255,255,255,.92);\n  filter:drop-shadow(0 6px 20px rgba(0,0,0,.25));\n}\n.ma-card-stamp.nope .ma-stamp-word{\n  -webkit-text-stroke-color:rgba(255,200,190,.95);\n}\n.ma-card-stamp.like .ma-stamp-word{\n  -webkit-text-stroke-color:rgba(190,230,205,.95);\n}\n.ma-stamp-sub{\n  font-family:var(--font-mono);font-size:0.45rem;font-weight:600;letter-spacing:0.35em;\n  text-transform:uppercase;color:rgba(255,255,255,.5);\n}\n.ma-card-photo{\n  flex:0 0 38%;\n  max-height:220px;\n  min-height:88px;\n  background:linear-gradient(155deg,#ece8e2 0%,#d8d2c8 42%,#c5bdb2 100%);\n  position:relative;\n}\n[data-theme=\"dark\"] .ma-card-photo{\n  background:linear-gradient(155deg,#2c2a28 0%,#22201e 50%,#181614 100%);\n}\n.ma-card-photo::after{\n  content:'';position:absolute;inset:0;z-index:1;\n  background:linear-gradient(to top,rgba(0,0,0,.52) 0%,transparent 50%);\n  pointer-events:none;\n}\n.ma-card-rail{\n  position:absolute;top:0;bottom:0;left:0;width:34px;border-right:1px dashed rgba(255,255,255,.4);\n  display:flex;align-items:center;justify-content:flex-start;padding-top:14px;z-index:3;pointer-events:none;\n}\n.ma-card-rail span{\n  writing-mode:vertical-rl;transform:rotate(180deg);\n  font-family:var(--font-mono);font-size:0.48rem;letter-spacing:3px;text-transform:uppercase;\n  color:rgba(255,255,255,.75);\n}\n.ma-card-photo span{\n  position:absolute;bottom:16px;left:16px;right:18px;z-index:4;\n  text-align:right;\n  font-family:'Playfair Display',serif;font-style:italic;font-size:1.4rem;font-weight:400;color:#fff;\n  text-shadow:0 2px 16px rgba(0,0,0,.4);line-height:1.2;\n}\n.ma-card-body{\n  flex:1 1 auto;\n  min-height:0;\n  overflow-y:auto;\n  overflow-x:hidden;\n  -webkit-overflow-scrolling:touch;\n  overscroll-behavior-y:contain;\n  touch-action:pan-y;\n  padding:14px 16px 18px 16px;\n}\n.ma-card-body::-webkit-scrollbar{width:4px;}\n.ma-card-body::-webkit-scrollbar-thumb{\n  background:var(--border-line);border-radius:4px;\n}\n.ma-card-rule{\n  height:1px;background:linear-gradient(90deg,transparent,var(--border-line) 15%,var(--border-line) 85%,transparent);\n  margin:0 4px 14px;\n  opacity:.85;\n}\n.ma-card-meta{\n  display:flex;justify-content:space-between;align-items:flex-start;gap:10px;margin-bottom:4px;\n}\n.ma-card-name{\n  font-family:'Cormorant Garamond',serif;font-size:1.45rem;font-weight:600;font-style:italic;line-height:1.1;\n}\n.ma-card-age{\n  color:var(--text-sub);font-size:0.72rem;margin-top:6px;font-family:var(--font-mono);letter-spacing:.5px;text-transform:uppercase;\n}\n.ma-badges{display:flex;flex-wrap:wrap;gap:6px;justify-content:flex-end;}\n.ma-badge{\n  font-family:var(--font-mono);font-size:0.5rem;font-weight:700;letter-spacing:1px;text-transform:uppercase;\n  padding:5px 8px;border-radius:100px;border:1px solid var(--border-line);color:var(--text-sub);\n}\n.ma-stats{\n  display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:4px;\n}\n.ma-stat{\n  background:var(--bg-body);border-radius:18px;padding:14px 14px 12px;border:1px solid var(--border-line);\n}\n[data-theme=\"dark\"] .ma-stat{background:#1a3a50;}\n.ma-stat-k{\n  font-family:var(--font-mono);font-size:0.48rem;letter-spacing:2px;text-transform:uppercase;color:var(--text-sub);margin-bottom:6px;\n}\n.ma-stat-v{font-family:'Cormorant Garamond',serif;font-size:1.55rem;font-weight:600;font-style:italic;}\n.ma-stat-v small{font-size:0.7rem;font-weight:500;font-family:'Inter',sans-serif;font-style:normal;color:var(--text-sub);margin-left:2px;}\n/* 发现卡 · 星盘/匹配双环 */\n.ma-astro-dual{\n  display:flex;justify-content:space-around;align-items:center;gap:10px;margin-top:6px;padding:12px 6px 10px;\n  background:linear-gradient(165deg,rgba(0,0,0,.02) 0%,transparent 55%);\n  border-radius:20px;border:1px solid var(--border-line);\n  flex-shrink:0;\n}\n[data-theme=\"dark\"] .ma-astro-dual{\n  background:linear-gradient(165deg,rgba(255,255,255,.04) 0%,transparent 55%);\n}\n.ma-orbit{\n  position:relative;width:min(82px,23vw);height:min(82px,23vw);flex-shrink:0;\n  display:grid;place-items:center;\n}\n.ma-orbit::before{\n  content:'';position:absolute;inset:0;border-radius:50%;\n  background:conic-gradient(var(--orbit-accent, #1a3a50) calc(var(--p,0) * 1%), var(--border-line) 0);\n  opacity:.9;\n}\n[data-theme=\"dark\"] .ma-orbit::before{\n  background:conic-gradient(var(--orbit-accent, #e8e8e8) calc(var(--p,0) * 1%), var(--border-line) 0);\n}\n.ma-orbit::after{\n  content:'';position:absolute;inset:5px;border-radius:50%;background:var(--bg-card);\n  border:1px solid rgba(0,0,0,.04);\n  box-shadow:inset 0 1px 0 rgba(255,255,255,.5);\n}\n[data-theme=\"dark\"] .ma-orbit::after{border-color:rgba(255,255,255,.06);box-shadow:inset 0 1px 0 rgba(255,255,255,.04);}\n.ma-orbit-core{\n  position:relative;z-index:1;text-align:center;line-height:1.05;\n}\n.ma-orbit-core strong{\n  font-family:'Cormorant Garamond',serif;font-size:clamp(1.05rem,4.2vw,1.3rem);font-style:italic;font-weight:600;display:block;\n}\n.ma-orbit-core span{\n  font-family:var(--font-mono);font-size:0.42rem;letter-spacing:2px;text-transform:uppercase;color:var(--text-sub);margin-top:4px;display:block;\n}\n.ma-orbit.ma-orbit-match{--orbit-accent:#5c6b5a;}\n.ma-orbit.ma-orbit-astro{--orbit-accent:#6b5c7a;}\n[data-theme=\"dark\"] .ma-orbit.ma-orbit-match{--orbit-accent:#8faa8c;}\n[data-theme=\"dark\"] .ma-orbit.ma-orbit-astro{--orbit-accent:#a896c4;}\n.ma-orbit-dots{\n  position:absolute;inset:-4px;border-radius:50%;pointer-events:none;\n  background:radial-gradient(circle at 30% 20%,rgba(255,255,255,.15) 0 1px,transparent 2px),\n    radial-gradient(circle at 70% 25%,rgba(255,255,255,.12) 0 1px,transparent 2px),\n    radial-gradient(circle at 50% 8%,rgba(255,255,255,.1) 0 1px,transparent 2px);\n}\n/* 发现卡 · 迷你合盘（与运势 / 本命渐变气质统一） */\n.ma-syn-mini{\n  margin-top:12px;border-radius:20px;border:1px solid var(--border-line);padding:14px 13px 12px;flex-shrink:0;\n  background:\n    linear-gradient(158deg,rgba(107,92,122,.08) 0%,transparent 48%),\n    linear-gradient(322deg,rgba(92,107,90,.06) 0%,transparent 42%),\n    var(--glass-bg);\n  backdrop-filter:blur(14px);-webkit-backdrop-filter:blur(14px);\n  box-shadow:0 2px 14px rgba(0,0,0,.04),inset 0 1px 0 rgba(255,255,255,.5);\n}\n[data-theme=\"dark\"] .ma-syn-mini{\n  background:\n    linear-gradient(158deg,rgba(168,150,196,.1) 0%,transparent 48%),\n    linear-gradient(322deg,rgba(120,140,118,.08) 0%,transparent 42%),\n    var(--glass-bg);\n  box-shadow:0 4px 18px rgba(0,0,0,.22),inset 0 1px 0 rgba(255,255,255,.05);\n}\n.ma-syn-mini--empty{\n  background:var(--bg-card);\n  backdrop-filter:none;-webkit-backdrop-filter:none;\n  border-style:dashed;opacity:.96;\n}\n[data-theme=\"dark\"] .ma-syn-mini--empty{background:var(--bg-card);}\n.ma-syn-mini-head{\n  display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:12px;\n}\n.ma-syn-mini-k{\n  font-family:var(--font-mono);font-size:0.48rem;letter-spacing:2px;text-transform:uppercase;color:var(--text-sub);\n}\n.ma-syn-mini-tag{\n  font-family:var(--font-mono);font-size:0.4rem;letter-spacing:1px;text-transform:uppercase;\n  padding:3px 8px;border-radius:100px;border:1px solid var(--border-line);color:var(--text-sub);opacity:.85;\n}\n.ma-syn-mini-lead{\n  font-size:0.78rem;line-height:1.55;color:var(--text-sub);font-family:'Noto Sans SC',sans-serif;margin:0;\n}\n.ma-syn-mini-orbs{\n  display:flex;align-items:stretch;justify-content:space-between;gap:8px;\n}\n.ma-syn-orb{\n  flex:1;min-width:0;text-align:center;padding:11px 8px 10px;border-radius:16px;border:1px solid var(--border-line);\n  background:var(--bg-card);display:flex;flex-direction:column;align-items:center;gap:5px;\n  box-shadow:inset 0 1px 0 rgba(255,255,255,.55);\n}\n[data-theme=\"dark\"] .ma-syn-orb{box-shadow:inset 0 1px 0 rgba(255,255,255,.06);}\n.ma-syn-orb--me{border-color:rgba(107,92,122,.22);}\n.ma-syn-orb--peer{border-color:rgba(92,107,90,.2);}\n[data-theme=\"dark\"] .ma-syn-orb--me{border-color:rgba(168,150,196,.28);}\n[data-theme=\"dark\"] .ma-syn-orb--peer{border-color:rgba(120,140,118,.25);}\n.ma-syn-orb-lbl{\n  font-family:var(--font-mono);font-size:0.4rem;letter-spacing:1.4px;text-transform:uppercase;color:var(--text-sub);\n}\n.ma-syn-orb-z{\n  font-family:'Cormorant Garamond',serif;font-size:1.25rem;font-style:italic;font-weight:600;color:var(--text-main);line-height:1;\n}\n.ma-syn-orb-note{\n  font-family:var(--font-mono);font-size:0.35rem;letter-spacing:0.8px;text-transform:uppercase;color:var(--text-sub);opacity:.75;\n}\n.ma-syn-axis{\n  display:flex;flex-direction:column;align-items:center;justify-content:center;gap:0;flex-shrink:0;width:22px;align-self:center;\n  padding:18px 0 6px;\n}\n.ma-syn-axis-line{\n  width:1px;height:14px;background:linear-gradient(180deg,transparent,var(--border-line) 20%,var(--border-line) 80%,transparent);\n  opacity:.9;\n}\n.ma-syn-axis-dot{\n  width:6px;height:6px;border-radius:50%;background:linear-gradient(145deg,rgba(107,92,122,.45),rgba(92,107,90,.4));\n  box-shadow:0 0 0 3px rgba(107,92,122,.08);\n}\n[data-theme=\"dark\"] .ma-syn-axis-dot{\n  background:linear-gradient(145deg,rgba(168,150,196,.55),rgba(120,140,118,.45));\n  box-shadow:0 0 0 3px rgba(0,0,0,.2);\n}\n.ma-syn-mini-foot{\n  margin-top:12px;padding-top:12px;border-top:1px solid var(--border-line);\n}\n.ma-syn-score-row{display:flex;flex-direction:column;gap:8px;}\n.ma-syn-score{\n  display:flex;align-items:baseline;gap:6px;font-family:'Cormorant Garamond',serif;font-style:italic;font-weight:600;color:var(--text-main);line-height:1;\n}\n.ma-syn-score strong{font-size:1.65rem;font-weight:600;}\n.ma-syn-score small{\n  font-family:var(--font-mono);font-size:0.5rem;font-style:normal;letter-spacing:2px;text-transform:uppercase;opacity:.6;\n}\n.ma-syn-meter{\n  height:3px;border-radius:100px;background:var(--border-line);overflow:hidden;\n}\n.ma-syn-meter-fill{\n  height:100%;border-radius:100px;\n  background:linear-gradient(90deg,rgba(92,107,90,.55),rgba(107,92,122,.65));\n  transition:width .45s cubic-bezier(0.19,1,0.22,1);\n}\n[data-theme=\"dark\"] .ma-syn-meter-fill{\n  background:linear-gradient(90deg,rgba(120,140,118,.65),rgba(168,150,196,.7));\n}\n.ma-syn-line{\n  margin:10px 0 0;font-size:0.76rem;line-height:1.5;color:var(--text-main);font-family:'Noto Sans SC',sans-serif;opacity:.92;\n}\n.ma-card-bio{\n  margin-top:12px;font-size:0.82rem;color:var(--text-sub);line-height:1.5;font-family:'Noto Sans SC',sans-serif;\n  flex-shrink:0;\n}\n.ma-stack-hint{\n  text-align:center;font-family:var(--font-mono);font-size:0.5rem;letter-spacing:2.5px;color:var(--text-sub);\n  text-transform:uppercase;margin-top:12px;opacity:.8;padding:0 12px;line-height:1.5;\n}\n/* —— 发现页 · 拉取推荐（加载 / 失败） —— */\n.ma-deck-wrap.ma-deck-loading .ma-deck-ghost{opacity:0;visibility:hidden;}\n.ma-deck-loading-inner,.ma-deck-fetch-err{\n  position:absolute;left:50%;top:50%;transform:translate(-50%,-50%);width:min(320px,88%);\n  text-align:center;padding:28px 20px;border-radius:22px;border:1px solid var(--border-line);\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  box-shadow:var(--shadow-card);\n}\n.ma-deck-loading-inner i{font-size:2rem;color:var(--text-sub);display:block;margin-bottom:14px;}\n.ma-deck-loading-inner p,.ma-deck-fetch-err p{\n  font-family:'Noto Sans SC',sans-serif;font-size:0.82rem;color:var(--text-sub);line-height:1.5;margin:0;\n}\n.ma-deck-fetch-err strong{display:block;font-family:'Cormorant Garamond',serif;font-style:italic;font-size:1.05rem;color:var(--text-main);margin-bottom:8px;}\n.ma-deck-fetch-err .ma-dfe-sub{font-size:0.72rem;opacity:.85;margin-top:6px;}\n@keyframes ma-spin{to{transform:rotate(360deg);}}\n.ma-spin{display:inline-block;animation:ma-spin .75s linear infinite;}\n/* —— 操作：玻璃胶囊 + 线框圆钮（与底栏气质一致） —— */\n.ma-actions{\n  display:flex;justify-content:center;padding:12px 0 8px;flex-shrink:0;\n}\n.ma-actions-capsule{\n  display:flex;align-items:center;gap:44px;padding:12px 44px;border-radius:100px;\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  border:1px solid var(--glass-border);\n  box-shadow:0 4px 24px rgba(0,0,0,.05);\n}\n[data-theme=\"dark\"] .ma-actions-capsule{\n  box-shadow:0 8px 32px rgba(0,0,0,.25);\n}\n.ma-btn{\n  width:50px;height:50px;border-radius:50%;\n  border:1.5px solid var(--border-line);\n  background:var(--bg-card);\n  display:flex;align-items:center;justify-content:center;\n  cursor:pointer;transition:transform .15s,border-color .2s,background .2s,color .2s;\n  color:var(--text-sub);\n}\n.ma-btn:hover,.ma-btn:focus-visible{\n  border-color:var(--text-main);color:var(--text-main);\n}\n.ma-btn:active{transform:scale(.88);}\n.ma-btn:disabled{opacity:.38;pointer-events:none;cursor:default;}\n.ma-btn.pass:hover,.ma-btn.pass:focus-visible{border-color:var(--pass);color:var(--pass);background:rgba(139,58,51,.06);}\n.ma-btn.like:hover,.ma-btn.like:focus-visible{border-color:var(--like);color:var(--like);background:rgba(45,90,61,.07);}\n[data-theme=\"dark\"] .ma-btn{background:rgba(30,30,30,.6);}\n[data-theme=\"dark\"] .ma-btn.pass:hover{background:rgba(212,121,110,.1);}\n[data-theme=\"dark\"] .ma-btn.like:hover{background:rgba(124,184,144,.1);}\n.ma-btn i{font-size:1.38rem;}\n/* —— 空状态 —— */\n.ma-empty{\n  flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:32px;\n  color:var(--text-sub);\n}\n.ma-empty i{font-size:2.5rem;opacity:.35;margin-bottom:16px;}\n.ma-empty p{font-family:'Playfair Display',serif;font-style:italic;font-size:1.1rem;color:var(--text-main);}\n.ma-empty span{font-family:var(--font-mono);font-size:0.55rem;letter-spacing:2px;margin-top:12px;text-transform:uppercase;}\n/* —— 列表（消息 / 陌生人） —— */\n.ma-list{flex:1;overflow-y:auto;padding-bottom:8px;}\n.ma-list::-webkit-scrollbar{display:none;}\n.ma-inbox-scroll .ma-list{flex:none;overflow:visible;}\n.ma-row-swipe{\n  position:relative;margin-bottom:10px;border-radius:20px;overflow:hidden;\n}\n.ma-row-del{\n  position:absolute;inset:0 0 0 auto;width:92px;border:none;cursor:pointer;\n  display:flex;align-items:center;justify-content:center;\n  background:linear-gradient(145deg,#cf5e5e,#b94f4f);color:#fff;\n  font-family:var(--font-mono);font-size:.5rem;letter-spacing:1.6px;text-transform:uppercase;\n  opacity:0;transform:translateX(10px);pointer-events:none;\n  transition:opacity .16s ease,transform .16s ease;\n}\n.ma-row-swipe.is-open .ma-row-del{opacity:1;transform:translateX(0);pointer-events:auto;}\n.ma-row{\n  display:flex;align-items:center;gap:14px;padding:14px 16px;border-radius:20px;\n  border:1px solid var(--border-line);\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  margin-bottom:0;cursor:pointer;transition:transform .2s cubic-bezier(0.16,1,0.3,1);\n  box-shadow:0 2px 12px rgba(0,0,0,.03);\n}\n.ma-row:active{transform:scale(.98);}\n.ma-row-main{touch-action:pan-y;will-change:transform;}\n.ma-row-av{width:48px;height:48px;border-radius:14px;background:var(--bg-card);flex-shrink:0;display:flex;align-items:center;justify-content:center;overflow:visible;position:relative;border:1px solid var(--border-line);}\n.ma-row-unread-dot{position:absolute;top:2px;right:2px;width:9px;height:9px;border-radius:50%;background:var(--pass);box-shadow:0 0 0 2px var(--bg-device);}\n[data-theme=\"dark\"] .ma-row-unread-dot{box-shadow:0 0 0 2px var(--bg-device);background:#e07a6e;}\n.ma-row-av i{font-size:1.4rem;color:var(--text-sub);}\n.ma-row-mid{flex:1;min-width:0;}\n.ma-row-t{font-weight:600;font-size:0.95rem;}\n.ma-row-s{font-size:0.75rem;color:var(--text-sub);margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}\n.ma-row-tag{font-family:var(--font-mono);font-size:0.45rem;letter-spacing:1px;background:var(--text-main);color:var(--bg-device);padding:3px 6px;border-radius:6px;}\n/* —— 我的 —— */\n.ma-me-head{\n  background:var(--bg-card);border:1px solid var(--border-line);border-radius:24px;padding:22px 20px;display:flex;gap:16px;align-items:center;margin-bottom:12px;\n  box-shadow:var(--shadow-card);\n}\n.ma-me-head .ma-row-av{width:64px;height:64px;border-radius:50%;outline:1px solid var(--text-main);border-width:2px;}\n.ma-me-avatar-wrap{\n  position:relative;width:64px;height:64px;flex-shrink:0;border-radius:50%;overflow:hidden;\n  border:2px solid var(--bg-device);outline:1px solid var(--text-main);cursor:pointer;\n  -webkit-tap-highlight-color:transparent;background:var(--bg-card);\n}\n.ma-me-avatar-wrap:focus-visible{outline:2px solid var(--text-main);outline-offset:2px;}\n.ma-me-avatar-img{\n  position:absolute;inset:0;width:100%;height:100%;object-fit:cover;display:none;\n}\n.ma-me-avatar-wrap.has-photo .ma-me-avatar-img{display:block;}\n.ma-me-avatar-ph{\n  position:absolute;inset:0;display:flex;align-items:center;justify-content:center;\n  background:var(--bg-card);\n}\n.ma-me-avatar-wrap.has-photo .ma-me-avatar-ph{display:none;}\n.ma-me-avatar-ph i{font-size:1.5rem;color:var(--text-sub);}\n.ma-me-avatar-hint{\n  position:absolute;inset:0;display:flex;align-items:center;justify-content:center;\n  background:rgba(0,0,0,.42);opacity:0;transition:opacity .2s;pointer-events:none;\n}\n.ma-me-avatar-hint i{color:#fff;font-size:1.15rem;}\n.ma-me-avatar-wrap:hover .ma-me-avatar-hint,.ma-me-avatar-wrap:active .ma-me-avatar-hint{opacity:1;}\n.ma-me-head .ma-card-name{font-family:'Cormorant Garamond',serif;font-style:italic;}\n.ma-me-scroll{flex:1;overflow-y:auto;min-height:0;-webkit-overflow-scrolling:touch;padding-bottom:12px;}\n.ma-me-scroll::-webkit-scrollbar{display:none;}\n/* —— 本命星盘（生日驱动）· 与全站玻璃 / 衬线气质统一 —— */\n.ma-natal-card{\n  position:relative;border:1px solid var(--border-line);border-radius:26px;overflow:hidden;margin-bottom:12px;\n  background:\n    linear-gradient(155deg,rgba(107,92,122,.06) 0%,transparent 46%),\n    linear-gradient(315deg,rgba(92,107,90,.05) 0%,transparent 40%),\n    var(--bg-card);\n  box-shadow:var(--shadow-card),inset 0 1px 0 rgba(255,255,255,.55);\n  padding:20px 17px 17px;\n}\n[data-theme=\"dark\"] .ma-natal-card{\n  background:\n    linear-gradient(155deg,rgba(168,150,196,.08) 0%,transparent 48%),\n    linear-gradient(315deg,rgba(120,140,118,.06) 0%,transparent 42%),\n    var(--bg-card);\n  box-shadow:var(--shadow-card),inset 0 1px 0 rgba(255,255,255,.04);\n}\n.ma-natal-card .ma-section-title{\n  margin-top:0;margin-bottom:14px;padding-bottom:12px;border-bottom:1px solid var(--border-line);\n  align-items:center;gap:10px;\n}\n.ma-natal-card .ma-section-title::before{\n  content:'';width:3px;height:1.1rem;border-radius:2px;flex-shrink:0;\n  background:linear-gradient(180deg,rgba(107,92,122,.55),rgba(92,107,90,.4));\n}\n.ma-natal-empty{\n  text-align:center;padding:6px 10px 18px;color:var(--text-sub);font-size:0.82rem;line-height:1.55;\n}\n.ma-natal-empty > i{\n  font-size:2rem;display:block;margin-bottom:12px;\n  color:rgba(107,92,122,.45);\n  opacity:.85;\n}\n[data-theme=\"dark\"] .ma-natal-empty > i{color:rgba(168,150,196,.5);}\n.ma-natal-empty strong{\n  color:var(--text-main);font-family:'Playfair Display',serif;font-style:italic;font-weight:500;font-size:1.02rem;\n}\n.ma-natal-body{display:none;}\n.ma-natal-body.is-on{display:block;}\n#natal-zodiac-labels{position:absolute;inset:0;z-index:2;pointer-events:none;}\n.ma-natal-wheel-wrap{\n  position:relative;width:100%;max-width:278px;margin:2px auto 22px;aspect-ratio:1;\n  --rim:min(98px, 29vw);\n  filter:drop-shadow(0 14px 28px rgba(107,92,122,.07));\n}\n[data-theme=\"dark\"] .ma-natal-wheel-wrap{filter:drop-shadow(0 18px 36px rgba(0,0,0,.4));}\n.ma-natal-wheel-wrap::before{\n  content:'';position:absolute;inset:-7%;border-radius:50%;pointer-events:none;\n  border:1px dashed rgba(107,92,122,.22);\n  opacity:.9;\n}\n[data-theme=\"dark\"] .ma-natal-wheel-wrap::before{border-color:rgba(168,150,196,.28);}\n.ma-natal-wheel-wrap::after{\n  content:'';position:absolute;inset:-2%;border-radius:50%;pointer-events:none;\n  background:radial-gradient(circle,transparent 58%,rgba(107,92,122,.05) 59%,transparent 72%);\n}\n.ma-natal-wheel-ring{\n  position:absolute;inset:3%;border-radius:50%;z-index:0;\n  background:\n    radial-gradient(ellipse 85% 75% at 38% 32%,rgba(255,255,255,.5) 0%,transparent 52%),\n    radial-gradient(circle at 50% 50%,transparent 48%,rgba(0,0,0,.03) 100%),\n    conic-gradient(\n      from -90deg at 50% 50%,\n      rgba(92,107,90,.16) 0deg 30deg,\n      rgba(107,92,122,.13) 30deg 60deg,\n      rgba(125,132,155,.15) 60deg 90deg,\n      rgba(95,118,138,.14) 90deg 120deg,\n      rgba(92,107,90,.16) 120deg 150deg,\n      rgba(107,92,122,.13) 150deg 180deg,\n      rgba(125,132,155,.15) 180deg 210deg,\n      rgba(95,118,138,.14) 210deg 240deg,\n      rgba(92,107,90,.16) 240deg 270deg,\n      rgba(107,92,122,.13) 270deg 300deg,\n      rgba(125,132,155,.15) 300deg 330deg,\n      rgba(95,118,138,.14) 330deg 360deg\n    );\n  box-shadow:\n    inset 0 0 0 1px rgba(255,255,255,.65),\n    inset 0 10px 28px rgba(255,255,255,.4),\n    0 2px 12px rgba(0,0,0,.04);\n}\n[data-theme=\"dark\"] .ma-natal-wheel-ring{\n  background:\n    radial-gradient(ellipse 80% 70% at 35% 28%,rgba(255,255,255,.06) 0%,transparent 45%),\n    radial-gradient(circle at 50% 50%,transparent 45%,rgba(0,0,0,.25) 100%),\n    conic-gradient(\n      from -90deg at 50% 50%,\n      rgba(120,140,118,.2) 0deg 30deg,\n      rgba(140,128,168,.18) 30deg 60deg,\n      rgba(110,125,150,.2) 60deg 90deg,\n      rgba(95,125,145,.19) 90deg 120deg,\n      rgba(120,140,118,.2) 120deg 150deg,\n      rgba(140,128,168,.18) 150deg 180deg,\n      rgba(110,125,150,.2) 180deg 210deg,\n      rgba(95,125,145,.19) 210deg 240deg,\n      rgba(120,140,118,.2) 240deg 270deg,\n      rgba(140,128,168,.18) 270deg 300deg,\n      rgba(110,125,150,.2) 300deg 330deg,\n      rgba(95,125,145,.19) 330deg 360deg\n    );\n  box-shadow:\n    inset 0 0 0 1px rgba(255,255,255,.1),\n    inset 0 12px 32px rgba(0,0,0,.2);\n}\n.ma-natal-wheel-inner{\n  position:absolute;inset:23.5%;border-radius:50%;z-index:3;\n  display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:12px 10px;\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  border:1px solid var(--glass-border);\n  box-shadow:\n    inset 0 1px 0 rgba(255,255,255,.75),\n    0 10px 28px rgba(0,0,0,.05);\n}\n[data-theme=\"dark\"] .ma-natal-wheel-inner{\n  box-shadow:\n    inset 0 1px 0 rgba(255,255,255,.08),\n    0 12px 32px rgba(0,0,0,.25);\n}\n.ma-natal-hub-k{\n  font-family:var(--font-mono);font-size:0.42rem;letter-spacing:2.8px;text-transform:uppercase;color:var(--text-sub);margin-bottom:5px;opacity:.9;\n}\n.ma-natal-hub-main{\n  font-family:'Playfair Display',serif;font-size:1.42rem;font-style:italic;font-weight:500;line-height:1.12;color:var(--text-main);\n}\n.ma-natal-hub-sub{\n  font-size:0.66rem;color:var(--text-sub);margin-top:7px;line-height:1.4;max-width:11.5rem;padding:0 4px;\n  font-family:'Noto Sans SC',sans-serif;font-weight:400;\n}\n.ma-natal-zlbl{\n  position:absolute;left:50%;top:50%;z-index:1;\n  font-family:'Cormorant Garamond',serif;font-style:italic;font-size:0.52rem;font-weight:500;\n  letter-spacing:.02em;color:var(--text-main);opacity:.36;max-width:40px;margin-left:-20px;margin-top:-6px;\n  text-align:center;line-height:1.05;pointer-events:none;\n  transform:rotate(var(--z-rot,0deg)) translateY(calc(-1 * var(--rim))) rotate(calc(-1 * var(--z-rot,0deg)));\n}\n[data-theme=\"dark\"] .ma-natal-zlbl{opacity:.5;}\n.ma-natal-markers{position:absolute;inset:0;z-index:4;pointer-events:none;}\n.ma-natal-marker{\n  position:absolute;left:50%;top:50%;width:12px;height:12px;border-radius:50%;margin:-6px;\n  transform:rotate(var(--deg)) translateY(calc(-1 * var(--rim))) rotate(calc(-1 * var(--deg)));\n  box-shadow:\n    0 0 0 2px var(--bg-card),\n    0 0 0 3px rgba(107,92,122,.12),\n    0 4px 14px rgba(0,0,0,.1);\n}\n.ma-natal-marker.sun{\n  background:linear-gradient(150deg,#efe2c4,#c9b06a);\n  box-shadow:\n    0 0 0 2px var(--bg-card),\n    0 0 0 3px rgba(201,176,106,.25),\n    0 0 18px rgba(201,176,106,.28),\n    0 4px 12px rgba(0,0,0,.08);\n}\n.ma-natal-marker.moon{\n  background:linear-gradient(150deg,#dcd4ec,#9e8fb8);\n  box-shadow:\n    0 0 0 2px var(--bg-card),\n    0 0 0 3px rgba(158,143,184,.22),\n    0 0 18px rgba(158,143,184,.22),\n    0 4px 12px rgba(0,0,0,.08);\n}\n.ma-natal-marker.asc{\n  background:linear-gradient(150deg,#b8d4c4,#5a8a6e);\n  box-shadow:\n    0 0 0 2px var(--bg-card),\n    0 0 0 3px rgba(90,138,110,.22),\n    0 0 18px rgba(90,138,110,.2),\n    0 4px 12px rgba(0,0,0,.08);\n}\n.ma-natal-legend{\n  display:flex;justify-content:center;gap:8px;flex-wrap:wrap;margin-bottom:16px;\n}\n.ma-natal-legend span{\n  display:inline-flex;align-items:center;gap:7px;\n  padding:8px 13px;border-radius:100px;\n  background:var(--glass-bg);backdrop-filter:blur(14px);-webkit-backdrop-filter:blur(14px);\n  border:1px solid var(--glass-border);\n  font-family:var(--font-mono);font-size:0.44rem;letter-spacing:1.2px;text-transform:uppercase;color:var(--text-sub);\n  box-shadow:0 2px 10px rgba(0,0,0,.03);\n}\n[data-theme=\"dark\"] .ma-natal-legend span{box-shadow:0 4px 16px rgba(0,0,0,.2);}\n.ma-natal-legend i{width:8px;height:8px;border-radius:50%;flex-shrink:0;box-shadow:0 0 0 1px rgba(0,0,0,.06);}\n.ma-natal-legend .lg-sun{background:linear-gradient(145deg,#efe2c4,#c9b06a);}\n.ma-natal-legend .lg-moon{background:linear-gradient(145deg,#dcd4ec,#9e8fb8);}\n.ma-natal-legend .lg-asc{background:linear-gradient(145deg,#b8d4c4,#5a8a6e);}\n.ma-natal-trio{\n  display:grid;grid-template-columns:repeat(3,1fr);gap:9px;margin-bottom:6px;\n}\n.ma-natal-chip{\n  text-align:center;padding:14px 7px 12px;border-radius:20px;\n  border:1px solid var(--glass-border);\n  background:linear-gradient(168deg,rgba(107,92,122,.07) 0%,transparent 55%),var(--glass-bg);\n  backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  box-shadow:inset 0 1px 0 rgba(255,255,255,.5),0 2px 12px rgba(0,0,0,.03);\n}\n[data-theme=\"dark\"] .ma-natal-chip{\n  box-shadow:inset 0 1px 0 rgba(255,255,255,.06),0 4px 16px rgba(0,0,0,.15);\n  background:linear-gradient(168deg,rgba(168,150,196,.1) 0%,transparent 55%),var(--glass-bg);\n}\n.ma-natal-chip .k{\n  font-family:var(--font-mono);font-size:0.4rem;letter-spacing:1.8px;color:var(--text-sub);text-transform:uppercase;margin-bottom:5px;opacity:.88;\n}\n.ma-natal-chip .v{font-family:'Playfair Display',serif;font-size:1.08rem;font-style:italic;font-weight:500;}\n.ma-natal-chip .hint{font-size:0.6rem;color:var(--text-sub);margin-top:5px;line-height:1.35;}\n.ma-natal-dims{\n  margin-top:10px;padding:11px 12px;border-radius:16px;border:1px solid var(--glass-border);\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  display:grid;gap:8px;\n}\n.ma-natal-dim-row{display:grid;grid-template-columns:76px 1fr 32px;align-items:center;gap:8px;}\n.ma-natal-dim-k{\n  font-size:0.58rem;color:var(--text-sub);font-family:var(--font-mono);\n  letter-spacing:1.1px;text-transform:uppercase;\n}\n.ma-natal-dim-bar{\n  height:6px;border-radius:999px;background:rgba(120,126,140,.2);\n  overflow:hidden;position:relative;\n}\n[data-theme=\"dark\"] .ma-natal-dim-bar{background:rgba(206,206,220,.15);}\n.ma-natal-dim-fill{\n  height:100%;border-radius:999px;\n  background:linear-gradient(90deg,rgba(168,150,196,.95),rgba(186,168,214,.72));\n}\n.ma-natal-dim-v{font-size:0.66rem;color:var(--text-main);text-align:right;font-weight:600;opacity:.88;}\n.ma-natal-breakdown{\n  margin-top:8px;display:grid;grid-template-columns:repeat(2,1fr);gap:8px;\n}\n.ma-natal-break-item{\n  border-radius:14px;border:1px solid var(--glass-border);padding:8px 10px;\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n}\n.ma-natal-break-k{\n  display:block;font-size:.48rem;color:var(--text-sub);font-family:var(--font-mono);\n  letter-spacing:1.4px;text-transform:uppercase;margin-bottom:4px;\n}\n.ma-natal-break-v{\n  font-size:.73rem;color:var(--text-main);line-height:1.4;font-weight:600;\n}\n.ma-natal-meta{\n  font-size:0.68rem;color:var(--text-sub);text-align:center;margin-top:12px;line-height:1.5;\n  font-family:'Noto Sans SC',sans-serif;opacity:.92;padding:0 6px;\n}\n.ma-natal-form{margin-top:4px;padding-top:14px;border-top:1px dashed var(--border-line);}\n.ma-natal-form.is-collapsed .ma-natal-fields{display:none;}\n.ma-natal-fields{display:grid;gap:12px;}\n.ma-natal-field label{\n  display:block;font-size:0.55rem;font-family:var(--font-mono);letter-spacing:1.5px;color:var(--text-sub);\n  text-transform:uppercase;margin-bottom:6px;\n}\n.ma-natal-field input[type=\"date\"],.ma-natal-field input[type=\"time\"]{\n  width:100%;padding:11px 14px;border-radius:14px;border:1px solid var(--border-line);\n  background:var(--bg-device);color:var(--text-main);font-size:0.88rem;font-family:inherit;\n}\n.ma-natal-field-hint{font-size:0.65rem;color:var(--text-sub);margin-top:4px;line-height:1.35;}\n.ma-natal-form-actions{display:flex;gap:10px;margin-top:4px;flex-wrap:wrap;}\n.ma-natal-btn-save{\n  flex:1;min-width:140px;padding:12px 16px;border-radius:100px;border:none;cursor:pointer;\n  background:var(--text-main);color:var(--bg-device);\n  font-family:var(--font-mono);font-size:0.52rem;font-weight:600;letter-spacing:2px;text-transform:uppercase;\n}\n.ma-natal-btn-save:active{transform:scale(.98);opacity:.92;}\n.ma-natal-btn-ghost{\n  padding:12px 16px;border-radius:100px;border:1px solid var(--border-line);background:transparent;\n  color:var(--text-sub);font-family:var(--font-mono);font-size:0.5rem;letter-spacing:1.5px;text-transform:uppercase;cursor:pointer;\n}\n.ma-natal-form-toggle{\n  width:100%;display:flex;align-items:center;justify-content:space-between;gap:8px;\n  padding:10px 4px 2px;border:none;background:transparent;cursor:pointer;\n  font-family:var(--font-mono);font-size:0.5rem;letter-spacing:2px;text-transform:uppercase;color:var(--text-sub);\n}\n.ma-natal-form-toggle::after{\n  content:'';width:6px;height:6px;border-right:1.5px solid var(--text-sub);border-bottom:1.5px solid var(--text-sub);\n  transform:rotate(45deg);transition:transform .2s;opacity:.7;\n}\n.ma-natal-form.is-collapsed .ma-natal-form-toggle::after{transform:rotate(-135deg);}\n.ma-section-title{\n  font-family:var(--font-mono);font-size:0.55rem;letter-spacing:2px;text-transform:uppercase;color:var(--text-sub);margin:20px 0 10px 4px;\n  display:flex;align-items:center;justify-content:space-between;gap:8px;\n}\n.ma-section-title .ma-sec-badge{\n  font-size:0.5rem;padding:4px 8px;border-radius:100px;background:var(--text-main);color:var(--bg-device);letter-spacing:1px;\n}\n/* 消息页 · 陌生招呼堆叠 */\n.ma-str-empty-hint{\n  display:flex;align-items:flex-start;gap:12px;margin:8px 4px 16px;padding:14px 16px;border-radius:18px;\n  border:1px dashed var(--glass-border);background:rgba(107,92,122,.04);color:var(--text-sub);font-size:0.78rem;line-height:1.55;\n}\n.ma-str-empty-hint .ph{font-size:1.35rem;opacity:.65;flex-shrink:0;margin-top:2px;}\n.ma-str-empty-hint strong{color:var(--text-main);font-weight:600;}\n[data-theme=\"dark\"] .ma-str-empty-hint{background:rgba(168,150,196,.08);}\n.ma-inbox-scroll{flex:1;overflow-y:auto;min-height:0;padding-bottom:8px;}\n.ma-inbox-scroll::-webkit-scrollbar{display:none;}\n.ma-str-stack-wrap{margin-bottom:8px;}\n.ma-str-stack{\n  position:relative;height:132px;margin:8px 4px 20px;cursor:pointer;\n  -webkit-tap-highlight-color:transparent;\n}\n.ma-str-stack:active .ma-str-layer:first-child{transform:translateY(0) scale(.99);}\n.ma-str-layer{\n  position:absolute;left:0;right:0;margin:0 auto;max-width:100%;\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  border:1px solid var(--glass-border);border-radius:18px;padding:14px 16px 12px;\n  box-shadow:0 4px 20px rgba(0,0,0,.06);\n  display:flex;align-items:center;gap:12px;transition:transform .15s;\n  transform-origin:center bottom;\n}\n[data-theme=\"dark\"] .ma-str-layer{box-shadow:0 6px 24px rgba(0,0,0,.3);}\n.ma-str-layer .ma-row-av{width:44px;height:44px;border-radius:12px;}\n.ma-str-layer .ma-row-mid{flex:1;min-width:0;}\n.ma-str-layer .ma-row-t{font-size:0.92rem;}\n.ma-str-layer .ma-row-s{font-size:0.72rem;}\n.ma-str-meta{\n  font-family:var(--font-mono);font-size:0.45rem;letter-spacing:1px;color:var(--text-sub);text-transform:uppercase;\n  flex-shrink:0;text-align:right;line-height:1.3;\n}\n.ma-str-count{font-size:0.65rem;font-weight:700;color:var(--text-main);letter-spacing:0;}\n.ma-str-head{flex-wrap:wrap;align-items:flex-start !important;}\n.ma-str-head > div:first-child{flex:1;min-width:0;}\n.ma-str-subhint{\n  display:block;font-family:var(--font-mono);font-size:0.45rem;letter-spacing:1px;text-transform:uppercase;\n  color:var(--text-sub);margin-top:6px;opacity:.88;\n}\n.ma-str-collapse{\n  flex-shrink:0;margin-top:2px;padding:7px 14px;border-radius:100px;border:1px solid var(--border-line);\n  background:var(--bg-card);font-family:var(--font-mono);font-size:0.45rem;letter-spacing:1.2px;\n  text-transform:uppercase;color:var(--text-main);cursor:pointer;\n}\n.ma-str-collapse:active{opacity:.88;transform:scale(.98);}\n.ma-str-block.is-expanded .ma-str-stack-wrap{display:none;}\n.ma-str-list{display:none;margin:4px 0 10px;}\n.ma-str-block.is-expanded .ma-str-list{display:block;}\n.ma-str-block--solo .ma-str-list{display:block;}\n.ma-str-head-actions{\n  display:flex;align-items:center;gap:8px;flex-shrink:0;margin-top:2px;flex-wrap:wrap;justify-content:flex-end;\n}\n.ma-str-clear-all{\n  padding:7px 12px;border-radius:100px;border:1px solid var(--border-line);\n  background:transparent;font-family:var(--font-mono);font-size:0.42rem;letter-spacing:1.2px;\n  text-transform:uppercase;color:var(--text-sub);cursor:pointer;\n  -webkit-tap-highlight-color:transparent;\n}\n.ma-str-clear-all:hover,.ma-str-clear-all:focus-visible{color:var(--text-main);outline:none;}\n.ma-str-clear-all:active{opacity:.85;}\n.ma-str-list .ma-str-swipe{margin-bottom:8px;}\n.ma-str-list .ma-str-swipe:last-child{margin-bottom:0;}\n.ma-str-swipe-main{touch-action:pan-y;}\n.ma-str-swipe .ma-str-li-go{font-family:var(--font-mono);font-size:0.42rem;letter-spacing:1px;color:var(--text-sub);flex-shrink:0;}\n/* 今日运势 */\n.ma-daily-scroll{flex:1;overflow-y:auto;min-height:0;padding-bottom:12px;}\n.ma-daily-scroll::-webkit-scrollbar{display:none;}\n.ma-astro-hero{\n  position:relative;text-align:center;padding:28px 16px 24px;margin-bottom:8px;border-radius:28px;\n  border:1px solid var(--border-line);\n  background:linear-gradient(160deg,rgba(107,92,122,.08) 0%,rgba(92,107,90,.05) 40%,transparent 100%),var(--bg-card);\n  overflow:hidden;\n}\n[data-theme=\"dark\"] .ma-astro-hero{\n  background:linear-gradient(160deg,rgba(168,150,196,.12) 0%,rgba(120,140,118,.08) 45%,transparent 100%),var(--bg-card);\n}\n.ma-astro-hero::before{\n  content:'';position:absolute;width:200px;height:200px;left:50%;top:40%;transform:translate(-50%,-50%);\n  border:1px dashed rgba(107,92,122,.2);border-radius:50%;pointer-events:none;\n}\n.ma-astro-hero::after{\n  content:'';position:absolute;width:140px;height:140px;left:50%;top:40%;transform:translate(-50%,-50%);\n  border:1px solid rgba(107,92,122,.12);border-radius:50%;pointer-events:none;\n}\n.ma-astro-zodiac{\n  font-family:var(--font-mono);font-size:0.5rem;letter-spacing:3px;text-transform:uppercase;color:var(--text-sub);margin-bottom:10px;position:relative;z-index:1;\n}\n.ma-astro-score{\n  font-family:'Cormorant Garamond',serif;font-size:3.2rem;font-style:italic;font-weight:500;line-height:1;color:var(--text-main);position:relative;z-index:1;\n}\n.ma-astro-score small{\n  font-family:var(--font-mono);font-size:0.55rem;font-style:normal;letter-spacing:2px;vertical-align:super;opacity:.65;margin-left:4px;\n}\n.ma-astro-mood{\n  font-family:'Playfair Display',serif;font-style:italic;font-size:0.95rem;color:var(--text-sub);margin-top:10px;position:relative;z-index:1;\n}\n.ma-daily-orbits{\n  display:flex;justify-content:center;align-items:flex-end;gap:22px;margin-top:18px;position:relative;z-index:1;\n}\n.ma-orbit.ma-orbit-sm{width:58px;height:58px;}\n.ma-orbit.ma-orbit-sm::after{inset:4px;}\n.ma-orbit.ma-orbit-sm .ma-orbit-dots{inset:-3px;}\n.ma-orbit.ma-orbit-sm .ma-orbit-core strong{font-size:1rem;}\n.ma-orbit.ma-orbit-sm .ma-orbit-core span{font-size:0.38rem;margin-top:2px;}\n.ma-daily-grid{\n  display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px;\n}\n.ma-daily-pill{\n  border-radius:20px;padding:16px 14px;border:1px solid var(--border-line);background:var(--bg-card);text-align:left;\n}\n.ma-daily-pill h4{\n  font-family:var(--font-mono);font-size:0.48rem;letter-spacing:2px;text-transform:uppercase;margin-bottom:8px;color:var(--text-sub);\n}\n.ma-daily-pill.yi h4{color:#5c6b5a;}\n.ma-daily-pill.ji h4{color:#8B3A33;}\n[data-theme=\"dark\"] .ma-daily-pill.yi h4{color:#8faa8c;}\n[data-theme=\"dark\"] .ma-daily-pill.ji h4{color:#d4796e;}\n.ma-daily-pill p{font-size:0.8rem;line-height:1.45;color:var(--text-main);}\n.ma-daily-chatbox{\n  border-radius:22px;padding:18px 18px 16px;border:1px solid var(--border-line);\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  margin-bottom:12px;\n}\n.ma-daily-chatbox .ma-dcb-k{\n  font-family:var(--font-mono);font-size:0.48rem;letter-spacing:2.5px;text-transform:uppercase;color:var(--text-sub);margin-bottom:10px;\n}\n.ma-daily-chatbox p{font-size:0.82rem;line-height:1.5;color:var(--text-main);}\n.ma-daily-chatbox ul{margin-top:10px;padding-left:1.1rem;font-size:0.78rem;color:var(--text-sub);line-height:1.55;}\n.ma-daily-recommend{\n  border-radius:22px;padding:16px 16px 14px;border:1px solid var(--border-line);\n  background:linear-gradient(165deg,rgba(92,107,90,.07) 0%,transparent 55%),var(--glass-bg);\n  backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  margin-bottom:12px;\n  box-shadow:0 2px 14px rgba(0,0,0,.04);\n}\n[data-theme=\"dark\"] .ma-daily-recommend{\n  background:linear-gradient(165deg,rgba(120,140,118,.1) 0%,transparent 55%),var(--glass-bg);\n  box-shadow:0 4px 20px rgba(0,0,0,.2);\n}\n.ma-drec-k{\n  font-family:var(--font-mono);font-size:0.48rem;letter-spacing:2.5px;text-transform:uppercase;color:var(--text-sub);margin-bottom:12px;\n}\n.ma-drec-row{\n  display:flex;align-items:flex-start;gap:12px;padding:12px 12px 10px;border-radius:18px;\n  border:1px solid var(--border-line);background:var(--bg-card);margin-bottom:10px;\n}\n.ma-drec-av{\n  width:48px;height:48px;border-radius:14px;background:var(--bg-device);border:1px solid var(--border-line);\n  display:flex;align-items:center;justify-content:center;flex-shrink:0;\n}\n.ma-drec-av i{font-size:1.35rem;color:var(--text-sub);opacity:.75;}\n.ma-drec-mid{flex:1;min-width:0;}\n.ma-drec-name{font-family:'Cormorant Garamond',serif;font-size:1.12rem;font-style:italic;font-weight:600;}\n.ma-drec-meta{font-size:0.68rem;color:var(--text-sub);margin-top:3px;font-family:var(--font-mono);letter-spacing:.5px;}\n.ma-drec-reason{font-size:0.78rem;color:var(--text-main);line-height:1.45;margin-top:8px;}\n.ma-drec-badges{display:flex;flex-direction:column;gap:4px;align-items:flex-end;flex-shrink:0;}\n.ma-drec-badges span{\n  font-family:var(--font-mono);font-size:0.42rem;letter-spacing:1px;padding:4px 7px;border-radius:8px;\n  background:var(--bg-body);border:1px solid var(--border-line);color:var(--text-sub);\n}\n.ma-drec-empty{\n  font-size:0.8rem;line-height:1.55;color:var(--text-main);font-family:'Noto Sans SC',sans-serif;margin:0 0 14px;\n}\n.ma-drec-empty strong{font-weight:600;}\n.ma-drec-foot{font-size:0.68rem;color:var(--text-sub);line-height:1.45;margin-bottom:10px;}\n.ma-drec-btn{\n  width:100%;padding:12px 16px;border-radius:100px;border:1px solid var(--text-main);background:var(--text-main);\n  color:var(--bg-device);font-family:var(--font-mono);font-size:0.5rem;font-weight:600;letter-spacing:2px;text-transform:uppercase;cursor:pointer;\n}\n.ma-drec-btn:active{transform:scale(.99);opacity:.94;}\n.ma-drec-btn.ma-drec-secondary{\n  background:transparent;color:var(--text-main);border-color:var(--border-line);\n}\n.ma-aspects{\n  border-radius:20px;border:1px dashed var(--border-line);padding:14px 16px;background:rgba(0,0,0,.015);\n}\n[data-theme=\"dark\"] .ma-aspects{background:rgba(255,255,255,.03);}\n.ma-aspects h4{\n  font-family:var(--font-mono);font-size:0.48rem;letter-spacing:2px;margin-bottom:12px;color:var(--text-sub);text-transform:uppercase;\n}\n.ma-aspect-row{\n  display:flex;justify-content:space-between;align-items:center;padding:8px 0;border-bottom:1px solid var(--border-line);font-size:0.78rem;\n}\n.ma-aspect-row:last-child{border-bottom:none;}\n.ma-aspect-row span:first-child{color:var(--text-sub);font-family:var(--font-mono);font-size:0.55rem;letter-spacing:1px;}\n.ma-aspect-row span:last-child{font-family:'Cormorant Garamond',serif;font-style:italic;color:var(--text-main);}\n.ma-setting{\n  display:flex;align-items:center;justify-content:space-between;padding:16px 18px;border-radius:18px;border:1px solid var(--border-line);\n  background:var(--bg-card);margin-bottom:8px;cursor:pointer;\n}\n.ma-setting:active{opacity:.92;}\n.ma-setting-info span{display:block;}\n.ma-setting-info span:first-child{font-weight:500;}\n.ma-setting-info span:last-child{font-size:0.72rem;color:var(--text-sub);margin-top:4px;}\n.ma-toggle{width:44px;height:26px;border-radius:100px;background:var(--border-line);position:relative;flex-shrink:0;transition:background .2s;}\n.ma-toggle.on{background:var(--text-main);}\n.ma-toggle::after{\n  content:'';position:absolute;width:22px;height:22px;border-radius:50%;background:var(--bg-card);top:2px;left:2px;\n  transition:transform .2s cubic-bezier(.19,1,.22,1);\n  box-shadow:0 1px 4px rgba(0,0,0,.12);\n}\n.ma-toggle.on::after{transform:translateX(18px);}\n/* —— 私聊权限（单选） —— */\n.ma-privacy-card{\n  border:1px solid var(--border-line);border-radius:22px;background:var(--bg-card);\n  padding:18px 16px 16px;margin-bottom:12px;box-shadow:var(--shadow-card);\n}\n.ma-privacy-lead{\n  font-size:0.76rem;color:var(--text-sub);line-height:1.5;margin:6px 0 14px;\n  font-family:'Noto Sans SC',sans-serif;\n}\n.ma-radio-list{display:flex;flex-direction:column;gap:10px;}\n.ma-radio-pill{\n  display:flex;align-items:flex-start;gap:12px;\n  padding:14px 14px 14px 12px;border-radius:18px;border:1px solid var(--border-line);\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  cursor:pointer;transition:border-color .2s,box-shadow .2s,background .2s;\n}\n.ma-radio-pill:hover{border-color:rgba(0,0,0,.12);}\n[data-theme=\"dark\"] .ma-radio-pill:hover{border-color:rgba(255,255,255,.14);}\n.ma-radio-pill.is-selected{\n  border-color:var(--text-main);\n  box-shadow:0 0 0 1px var(--text-main),inset 0 1px 0 rgba(255,255,255,.4);\n  background:linear-gradient(165deg,rgba(107,92,122,.06),transparent 55%),var(--glass-bg);\n}\n[data-theme=\"dark\"] .ma-radio-pill.is-selected{\n  box-shadow:0 0 0 1px var(--text-main),inset 0 1px 0 rgba(255,255,255,.06);\n  background:linear-gradient(165deg,rgba(168,150,196,.1),transparent 55%),var(--glass-bg);\n}\n.ma-radio-pill input[type=\"radio\"]{\n  width:17px;height:17px;accent-color:var(--text-main);margin-top:3px;flex-shrink:0;cursor:pointer;\n}\n.ma-rp-body{flex:1;min-width:0;}\n.ma-rp-title{font-weight:600;font-size:0.9rem;color:var(--text-main);margin-bottom:5px;}\n.ma-rp-desc{font-size:0.7rem;color:var(--text-sub);line-height:1.45;}\n.ma-str-off-hint{\n  display:flex;align-items:flex-start;gap:10px;padding:14px 16px;border-radius:18px;margin-bottom:8px;\n  border:1px dashed var(--border-line);background:rgba(0,0,0,.02);color:var(--text-sub);font-size:0.78rem;line-height:1.45;\n}\n[data-theme=\"dark\"] .ma-str-off-hint{background:rgba(255,255,255,.04);}\n.ma-str-off-hint i{font-size:1.2rem;opacity:.45;margin-top:1px;flex-shrink:0;}\n.ma-str-off-hint strong{color:var(--text-main);font-weight:600;}\n/* —— 全屏聊天（与 wallpaper / 玻璃条统一） —— */\n.ma-chat{\n  position:absolute;inset:0;z-index:40;\n  display:none;flex-direction:column;\n  background:\n    radial-gradient(ellipse 120% 80% at 20% 0%, rgba(180,170,160,.12), transparent 50%),\n    radial-gradient(ellipse 90% 70% at 100% 25%, rgba(160,175,185,.08), transparent 45%),\n    var(--bg-device);\n  padding:0;\n}\n[data-theme=\"dark\"] .ma-chat{\n  background:\n    radial-gradient(ellipse 120% 80% at 15% 8%, rgba(80,70,90,.16), transparent 50%),\n    radial-gradient(ellipse 90% 60% at 100% 35%, rgba(50,60,70,.2), transparent 45%),\n    var(--bg-device);\n}\n.ma-chat.open{display:flex;}\n.ma-chat-bar{\n  flex-shrink:0;\n  display:flex;align-items:flex-start;gap:12px;\n  padding:calc(env(safe-area-inset-top,0px) + 12px) 16px 14px;\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  border-bottom:1px solid var(--glass-border);\n  box-shadow:0 6px 24px rgba(0,0,0,.04);\n}\n[data-theme=\"dark\"] .ma-chat-bar{box-shadow:0 10px 32px rgba(0,0,0,.22);}\n.ma-chat-back{\n  width:42px;height:42px;border-radius:50%;border:1px solid var(--border-line);background:var(--bg-card);\n  display:flex;align-items:center;justify-content:center;cursor:pointer;color:var(--text-main);flex-shrink:0;\n  box-shadow:var(--shadow-card);transition:transform .15s,border-color .15s;\n}\n.ma-chat-back:active{transform:scale(.96);}\n.ma-chat-bar-main{flex:1;min-width:0;padding-top:1px;}\n.ma-chat-bar-head{\n  display:flex;align-items:flex-start;justify-content:space-between;gap:10px;\n}\n.ma-chat-bar-links{\n  display:flex;align-items:flex-start;gap:12px;flex-shrink:0;margin-top:6px;\n}\n.ma-chat-bar-titles{flex:1;min-width:0;}\n.ma-chat-peer-name{\n  display:block;font-family:'Cormorant Garamond',serif;font-style:italic;font-weight:600;font-size:1.22rem;color:var(--text-main);line-height:1.15;letter-spacing:.01em;\n}\n.ma-chat-peer-sub{\n  display:block;font-family:var(--font-mono);font-size:0.48rem;letter-spacing:1.8px;text-transform:uppercase;color:var(--text-sub);margin-top:7px;opacity:.88;\n}\n.ma-chat-mood-link{\n  flex-shrink:0;align-self:flex-start;margin-top:6px;padding:4px 2px 4px 8px;\n  border:none;background:transparent;cursor:pointer;\n  font-family:'Cormorant Garamond',serif;font-style:italic;font-weight:600;font-size:0.95rem;\n  color:var(--text-sub);letter-spacing:.02em;line-height:1.2;\n  -webkit-tap-highlight-color:transparent;transition:color .15s,opacity .15s;\n}\n.ma-chat-mood-link:hover,.ma-chat-mood-link:focus-visible{color:var(--text-main);outline:none;}\n.ma-chat-mood-link:active{opacity:.75;}\n.ma-modal.ma-modal-compat-wrap .ma-compat{margin-top:0;}\n.ma-compat-modal-head{\n  display:flex;align-items:center;justify-content:space-between;gap:10px;\n  margin-bottom:12px;padding:0 2px 0 4px;\n}\n.ma-compat-modal-title{\n  font-family:var(--font-mono);font-size:0.52rem;letter-spacing:2px;text-transform:uppercase;color:var(--text-sub);\n}\n.ma-compat-refresh{\n  flex-shrink:0;width:36px;height:36px;border-radius:50%;border:1px solid var(--border-line);\n  background:var(--bg-body);color:var(--text-main);cursor:pointer;\n  display:flex;align-items:center;justify-content:center;padding:0;\n  transition:opacity .15s,transform .12s;\n}\n.ma-compat-refresh:active:not(:disabled){transform:scale(.94);}\n.ma-compat-refresh:disabled{opacity:.42;cursor:default;}\n.ma-compat-refresh.is-busy i{display:inline-block;animation:ma-spin .7s linear infinite;}\n.ma-modal.ma-modal-compat-wrap .ma-modal-actions{margin-top:12px;}\n.ma-modal.ma-modal-mood h3{\n  margin-bottom:10px;font-size:1.05rem;font-style:italic;font-weight:600;letter-spacing:.04em;text-transform:none;\n}\n.ma-modal.ma-modal-mood .ma-mood-k{\n  font-family:'Cormorant Garamond',serif;font-style:italic;font-size:0.82rem;font-weight:600;\n  letter-spacing:.04em;text-transform:none;color:var(--text-sub);margin:0 0 8px;\n}\n.ma-mood-lead{\n  font-size:0.86rem;line-height:1.55;color:var(--text-main);margin:0 0 14px;font-family:'Noto Sans SC',sans-serif;\n}\n.ma-mood-divider{\n  height:1px;background:linear-gradient(90deg,transparent,var(--border-line) 12%,var(--border-line) 88%,transparent);margin:0 0 12px;opacity:.9;\n}\n.ma-mood-k{\n  font-family:var(--font-mono);font-size:0.46rem;font-weight:600;letter-spacing:2px;text-transform:uppercase;color:var(--text-sub);margin:0 0 8px;\n}\n.ma-mood-body{\n  font-size:0.8rem;line-height:1.6;color:var(--text-main);margin:0 0 14px;font-family:'Noto Sans SC',sans-serif;font-style:italic;opacity:.95;\n}\n.ma-chat-impress-panel{\n  margin-top:12px;display:flex;align-items:stretch;gap:0;\n  border-radius:20px;border:1px solid var(--border-line);\n  background:\n    linear-gradient(145deg,rgba(107,92,122,.05) 0%,transparent 42%),\n    linear-gradient(315deg,rgba(92,107,90,.04) 0%,transparent 40%),\n    var(--bg-card);\n  box-shadow:var(--shadow-card),inset 0 1px 0 rgba(255,255,255,.55);\n  overflow:hidden;\n}\n[data-theme=\"dark\"] .ma-chat-impress-panel{\n  background:\n    linear-gradient(145deg,rgba(168,150,196,.07) 0%,transparent 45%),\n    linear-gradient(315deg,rgba(120,140,118,.06) 0%,transparent 38%),\n    var(--bg-card);\n  box-shadow:var(--shadow-card),inset 0 1px 0 rgba(255,255,255,.05);\n}\n.ma-chat-impress-col{\n  flex:1;min-width:0;display:flex;flex-direction:column;align-items:flex-start;gap:6px;\n  padding:11px 12px 12px 14px;\n}\n.ma-chat-impress-col--peer{\n  align-items:flex-end;padding-left:10px;padding-right:14px;\n}\n.ma-chat-impress-label{\n  font-family:var(--font-mono);font-size:0.44rem;font-weight:600;letter-spacing:1.5px;text-transform:uppercase;color:var(--text-sub);opacity:.92;\n}\n.ma-chat-impress-stars{display:flex;gap:3px;align-items:center;}\n.ma-chat-impress-stars i{\n  font-size:0.82rem;line-height:1;\n  color:#a8944a;\n  filter:drop-shadow(0 1px 2px rgba(0,0,0,.06));\n}\n[data-theme=\"dark\"] .ma-chat-impress-stars i{color:#d4c47a;}\n.ma-chat-impress-stars i.ph:not(.ph-fill){opacity:0.22;color:var(--text-sub);filter:none;}\n.ma-chat-impress-div{\n  width:1px;align-self:stretch;margin:10px 0;\n  background:linear-gradient(180deg,transparent,var(--border-line) 20%,var(--border-line) 80%,transparent);\n  opacity:.9;\n}\n.ma-chat-impress-note{\n  margin:10px 0 0;font-size:0.72rem;color:var(--text-sub);line-height:1.5;font-family:'Noto Sans SC',sans-serif;\n  padding:10px 12px;border-radius:16px;border:1px dashed var(--border-line);\n  background:rgba(0,0,0,.015);\n}\n[data-theme=\"dark\"] .ma-chat-impress-note{background:rgba(255,255,255,.03);}\n.ma-chat-stranger-cta{\n  margin-top:10px;display:flex;align-items:center;justify-content:space-between;gap:10px;flex-wrap:wrap;\n}\n#chat-stranger-cta[hidden]{display:none!important;}\n.ma-chat-stranger-cta .ma-chat-impress-note{margin:0;flex:1;min-width:0;}\n.ma-str-mutual-btn{\n  flex-shrink:0;padding:8px 16px;border-radius:999px;border:1px solid var(--border-line);\n  background:var(--bg-card);cursor:pointer;font-family:'Noto Sans SC',sans-serif;font-size:0.74rem;font-weight:600;\n  color:var(--text-main);box-shadow:var(--shadow-card);transition:transform .12s,opacity .15s,border-color .15s;\n  -webkit-tap-highlight-color:transparent;\n}\n.ma-str-mutual-btn:hover,.ma-str-mutual-btn:focus-visible{background:var(--bg-body);outline:none;}\n.ma-str-mutual-btn:active{transform:scale(.96);opacity:.92;}\n[data-theme=\"dark\"] .ma-str-mutual-btn{box-shadow:var(--shadow-card),inset 0 1px 0 rgba(255,255,255,.05);}\n.ma-chat-body{\n  flex:1;min-height:0;display:flex;flex-direction:column;\n}\n.ma-chat-thread{\n  flex:1;min-height:0;overflow-y:auto;-webkit-overflow-scrolling:touch;\n  padding:18px 16px 16px;display:flex;flex-direction:column;gap:14px;\n  -webkit-user-select:none;user-select:none;-webkit-touch-callout:none;\n}\n.ma-chat-thread::-webkit-scrollbar{width:3px;}\n.ma-chat-thread::-webkit-scrollbar-thumb{background:var(--border-line);border-radius:4px;}\n/* 聊天 · 破冰句（玻璃 + 衬线引文） */\n.ma-icebreaker{\n  flex-shrink:0;padding:4px 14px 10px;\n}\n.ma-icebreaker-head{\n  display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:8px;\n}\n.ma-icebreaker-k{\n  font-family:var(--font-mono);font-size:0.48rem;letter-spacing:2px;text-transform:uppercase;color:var(--text-sub);\n}\n.ma-icebreaker-shuffle{\n  font-family:var(--font-mono);font-size:0.45rem;font-weight:600;letter-spacing:1.5px;text-transform:uppercase;\n  padding:6px 12px;border-radius:100px;border:1px solid var(--border-line);background:var(--bg-card);color:var(--text-main);\n  cursor:pointer;transition:transform .12s,opacity .15s,background .15s;\n  box-shadow:0 1px 8px rgba(0,0,0,.04);\n}\n[data-theme=\"dark\"] .ma-icebreaker-shuffle{box-shadow:0 2px 12px rgba(0,0,0,.2);}\n.ma-icebreaker-shuffle:active{transform:scale(.96);opacity:.88;}\n.ma-icebreaker-quote{\n  width:100%;display:block;text-align:left;padding:13px 15px 14px;border-radius:18px;border:1px solid var(--border-line);\n  cursor:pointer;font:inherit;color:var(--text-main);\n  background:\n    linear-gradient(165deg,rgba(107,92,122,.06) 0%,transparent 55%),\n    linear-gradient(320deg,rgba(92,107,90,.05) 0%,transparent 45%),\n    var(--glass-bg);\n  backdrop-filter:blur(16px);-webkit-backdrop-filter:blur(16px);\n  box-shadow:0 2px 14px rgba(0,0,0,.04),inset 0 1px 0 rgba(255,255,255,.45);\n  transition:transform .12s,border-color .2s;\n  -webkit-appearance:none;appearance:none;\n}\n[data-theme=\"dark\"] .ma-icebreaker-quote{\n  background:\n    linear-gradient(165deg,rgba(168,150,196,.09) 0%,transparent 55%),\n    linear-gradient(320deg,rgba(120,140,118,.07) 0%,transparent 45%),\n    var(--glass-bg);\n  box-shadow:0 4px 18px rgba(0,0,0,.2),inset 0 1px 0 rgba(255,255,255,.05);\n}\n.ma-icebreaker-quote:active{transform:scale(.99);border-color:rgba(107,92,122,.28);}\n.ma-icebreaker-text{\n  display:block;font-size:0.84rem;line-height:1.55;font-weight:400;font-family:'Noto Sans SC',sans-serif;\n}\n.ma-icebreaker-hint{\n  margin:8px 4px 0;text-align:center;font-family:var(--font-mono);font-size:0.4rem;letter-spacing:1.2px;\n  text-transform:uppercase;color:var(--text-sub);opacity:.65;line-height:1.4;\n}\n.ma-compat{\n  margin-top:10px;padding:0;\n}\n.ma-compat-head{\n  display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:8px;\n}\n.ma-compat-k{\n  font-family:var(--font-mono);font-size:0.48rem;letter-spacing:2px;text-transform:uppercase;color:var(--text-sub);\n}\n.ma-compat-next{\n  font-family:var(--font-mono);font-size:0.45rem;font-weight:600;letter-spacing:1.5px;text-transform:uppercase;\n  padding:6px 12px;border-radius:100px;border:1px solid var(--border-line);background:var(--bg-card);color:var(--text-main);\n  cursor:pointer;transition:transform .12s,opacity .15s;\n}\n.ma-compat-next:active{transform:scale(.96);opacity:.88;}\n.ma-compat-q{\n  margin:0 0 8px;padding:10px 12px;border-radius:14px;border:1px solid var(--border-line);\n  background:var(--glass-bg);line-height:1.5;font-size:.82rem;color:var(--text-main);\n}\n.ma-compat-opts{\n  display:grid;grid-template-columns:1fr 1fr;gap:8px;\n}\n.ma-compat-opt{\n  padding:11px 10px;border-radius:14px;border:1px solid var(--border-line);\n  background:var(--bg-card);color:var(--text-main);cursor:pointer;text-align:left;\n  font-size:.78rem;line-height:1.45;transition:transform .12s,border-color .18s,background .18s;\n}\n.ma-compat-opt:active{transform:scale(.985);}\n.ma-compat-opt.on{\n  border-color:rgba(107,92,122,.5);\n  background:linear-gradient(165deg,rgba(107,92,122,.12) 0%,transparent 70%),var(--bg-card);\n}\n.ma-compat-hint{\n  margin:8px 2px 0;font-family:var(--font-mono);font-size:.42rem;letter-spacing:1.1px;\n  text-transform:uppercase;color:var(--text-sub);opacity:.72;line-height:1.45;\n}\n.ma-compat.is-locked .ma-compat-opt,\n.ma-compat.is-locked .ma-compat-next{\n  opacity:.55;pointer-events:none;\n}\n.ma-chat-msg{display:flex;flex-direction:column;max-width:min(86%,300px);gap:5px;}\n.ma-chat-msg{position:relative;}\n.ma-chat-msg.peer{align-self:flex-start;align-items:flex-start;}\n.ma-chat-msg.me{align-self:flex-end;align-items:flex-end;}\n.ma-chat-msg.is-selectable{cursor:pointer;}\n.ma-chat-msg.is-selected .ma-chat-bub{\n  outline:2px solid rgba(107,92,122,.36);\n  outline-offset:1px;\n}\n.ma-chat-msg.is-selected::after{\n  content:'✓';position:absolute;top:-6px;right:-6px;\n  width:18px;height:18px;border-radius:50%;\n  display:flex;align-items:center;justify-content:center;\n  font-size:.58rem;font-weight:700;color:#fff;background:#6b5c7a;\n  box-shadow:0 2px 8px rgba(0,0,0,.18);\n}\n.ma-chat-msg.peer.is-selected::after{right:auto;left:-6px;}\n.ma-chat-bub{\n  padding:12px 15px;font-size:0.85rem;line-height:1.5;font-family:'Noto Sans SC',sans-serif;font-weight:400;\n  white-space:pre-line;word-break:break-word;\n  -webkit-user-select:none;user-select:none;-webkit-touch-callout:none;\n}\n.ma-chat-quote-inline{\n  margin-bottom:7px;padding:6px 8px;border-radius:10px;background:rgba(0,0,0,.06);\n  display:flex;align-items:center;gap:6px;max-width:100%;\n}\n[data-theme=\"dark\"] .ma-chat-quote-inline{background:rgba(255,255,255,.12);}\n.ma-chat-quote-inline .k{\n  font-family:var(--font-mono);font-size:.4rem;letter-spacing:.08em;text-transform:uppercase;opacity:.75;flex-shrink:0;\n}\n.ma-chat-quote-inline .t{\n  min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-size:.72rem;opacity:.9;\n}\n.ma-chat-recalled{\n  font-size:.78rem;opacity:.72;font-style:italic;\n}\n.ma-chat-msg.peer .ma-chat-bub{\n  background:var(--glass-bg);backdrop-filter:blur(16px);-webkit-backdrop-filter:blur(16px);\n  color:var(--text-main);border:1px solid var(--glass-border);\n  border-radius:20px;border-bottom-left-radius:6px;\n  box-shadow:0 2px 14px rgba(0,0,0,.04);\n}\n[data-theme=\"dark\"] .ma-chat-msg.peer .ma-chat-bub{box-shadow:0 4px 18px rgba(0,0,0,.25);}\n.ma-chat-msg.me .ma-chat-bub{\n  background:linear-gradient(155deg,#2a5070 0%,#1a3a50 100%);\n  color:#f5f5f5;border-radius:20px;border-bottom-right-radius:6px;\n  box-shadow:0 4px 18px rgba(0,0,0,.12);\n  border:1px solid rgba(255,255,255,.06);\n}\n[data-theme=\"dark\"] .ma-chat-msg.me .ma-chat-bub{\n  background:linear-gradient(155deg,#ececec 0%,#d8d8d8 100%);\n  color:#1a3a50;border-color:rgba(0,0,0,.06);\n  box-shadow:0 4px 20px rgba(0,0,0,.35);\n}\n.ma-chat-msg time{\n  font-family:var(--font-mono);font-size:0.4rem;letter-spacing:0.12em;text-transform:uppercase;color:var(--text-sub);opacity:.65;padding:0 6px;\n}\n.ma-chat-composer-wrap{\n  flex-shrink:0;padding:0 14px calc(12px + env(safe-area-inset-bottom,0px));\n}\n.ma-chat-composer-wrap.is-busy .ma-chat-composer{opacity:.72;pointer-events:none;}\n.ma-chat-typing{margin:0 0 12px 0;display:flex;justify-content:flex-start;}\n.ma-chat-typing .ma-chat-typing-dots{\n  display:flex;align-items:center;gap:5px;\n  padding:11px 15px;border-radius:18px;\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  border:1px solid var(--border-line);\n  box-shadow:0 2px 12px rgba(0,0,0,.06);\n}\n.ma-chat-typing span{\n  width:6px;height:6px;border-radius:50%;\n  background:var(--text-main);\n  animation:ma-peer-typing-dot 1.05s ease-in-out infinite;\n}\n.ma-chat-typing span:nth-child(2){animation-delay:.15s;}\n.ma-chat-typing span:nth-child(3){animation-delay:.3s;}\n@keyframes ma-peer-typing-dot{\n  0%,80%,100%{transform:scale(.7);opacity:.28;}\n  40%{transform:scale(1.02);opacity:.92;}\n}\n@media (prefers-reduced-motion:reduce){\n  .ma-chat-typing span{animation:none;opacity:.55;}\n}\n.ma-chat-composer{\n  display:flex;align-items:center;gap:8px;\n  padding:6px 6px 6px 16px;border-radius:100px;\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  border:1px solid var(--glass-border);\n  box-shadow:0 4px 24px rgba(0,0,0,.06);\n}\n[data-theme=\"dark\"] .ma-chat-composer{box-shadow:0 8px 28px rgba(0,0,0,.3);}\n.ma-chat-composer input{\n  flex:1;min-width:0;border:none;border-radius:0;background:transparent;\n  padding:10px 4px;font-size:0.88rem;font-family:inherit;color:var(--text-main);\n}\n.ma-chat-composer input:focus{outline:none;}\n.ma-chat-composer input::placeholder{color:var(--text-sub);opacity:.55;}\n.ma-chat-send{\n  width:40px;height:40px;border-radius:50%;border:none;background:transparent;color:var(--text-main);\n  display:flex;align-items:center;justify-content:center;cursor:pointer;flex-shrink:0;\n  transition:transform .15s,opacity .15s;\n  box-shadow:none;\n}\n.ma-chat-reply{\n  width:40px;height:40px;border-radius:50%;border:none;background:var(--text-main);color:var(--bg-device);\n  display:flex;align-items:center;justify-content:center;cursor:pointer;flex-shrink:0;\n  transition:transform .15s,opacity .15s;box-shadow:0 3px 14px rgba(0,0,0,.15);\n}\n.ma-chat-reply:active{transform:scale(.9);}\n.ma-chat-reply:disabled{opacity:.45;cursor:not-allowed;transform:none;}\n.ma-chat-send:active{opacity:.5;transform:none;}\n.ma-chat-send:disabled{opacity:.45;cursor:not-allowed;transform:none;}\n.ma-chat-send i,.ma-chat-reply i{font-size:1.12rem;}\n/* —— 个人资料入口 + 编辑页 —— */\n.ma-profile-cta-card{\n  border:1px solid var(--border-line);border-radius:22px;background:var(--bg-card);\n  box-shadow:var(--shadow-card);margin-bottom:12px;overflow:hidden;\n}\n.ma-profile-cta{\n  width:100%;display:flex;align-items:center;justify-content:space-between;gap:12px;\n  padding:16px 18px;border:none;background:transparent;cursor:pointer;text-align:left;\n  transition:background .15s;\n}\n.ma-profile-cta:active{background:rgba(0,0,0,.03);}\n[data-theme=\"dark\"] .ma-profile-cta:active{background:rgba(255,255,255,.05);}\n.ma-profile-cta-main{display:flex;flex-direction:column;gap:6px;min-width:0;}\n.ma-profile-cta-k{\n  font-family:var(--font-mono);font-size:0.5rem;letter-spacing:2px;text-transform:uppercase;color:var(--text-sub);\n}\n.ma-profile-cta-t{\n  font-family:'Cormorant Garamond',serif;font-size:1.15rem;font-style:italic;font-weight:600;color:var(--text-main);line-height:1.2;\n}\n.ma-profile-cta > .ph{font-size:1.15rem;color:var(--text-sub);opacity:.65;flex-shrink:0;}\n.ma-profile-sheet{\n  position:absolute;inset:0;z-index:42;\n  display:none;flex-direction:column;\n  /* 与 .ma-wallpaper 同系底纹，保持「同一台设备里」的气质 */\n  background:\n    radial-gradient(ellipse 120% 80% at 20% 0%, rgba(180,170,160,.14), transparent 50%),\n    radial-gradient(ellipse 90% 70% at 100% 30%, rgba(160,175,185,.1), transparent 45%),\n    var(--bg-device);\n  padding:0 0 env(safe-area-inset-bottom,0px);\n}\n[data-theme=\"dark\"] .ma-profile-sheet{\n  background:\n    radial-gradient(ellipse 120% 80% at 15% 10%, rgba(80,70,90,.2), transparent 50%),\n    radial-gradient(ellipse 90% 60% at 100% 40%, rgba(50,60,70,.25), transparent 45%),\n    var(--bg-device);\n}\n.ma-profile-sheet.open{display:flex;}\n.ma-profile-bar{\n  flex-shrink:0;\n  padding:calc(env(safe-area-inset-top,0px) + 12px) 14px 14px;\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  border-bottom:1px solid var(--glass-border);\n  box-shadow:0 4px 20px rgba(0,0,0,.04);\n}\n[data-theme=\"dark\"] .ma-profile-bar{box-shadow:0 8px 28px rgba(0,0,0,.25);}\n.ma-profile-bar-row{\n  display:flex;align-items:center;gap:10px;\n}\n.ma-profile-bar-txt{flex:1;text-align:center;min-width:0;}\n.ma-profile-bar-txt strong{\n  display:block;font-family:'Playfair Display',serif;font-style:italic;font-size:1.28rem;font-weight:500;color:var(--text-main);line-height:1.15;\n}\n.ma-profile-bar-txt span{\n  display:block;font-family:var(--font-mono);font-size:0.48rem;letter-spacing:2.5px;text-transform:uppercase;color:var(--text-sub);margin-top:6px;opacity:.9;\n}\n.ma-profile-bar .ma-spacer{width:40px;flex-shrink:0;}\n.ma-profile-scroll{\n  flex:1;min-height:0;overflow-y:auto;padding:12px 18px 24px;-webkit-overflow-scrolling:touch;\n}\n.ma-profile-scroll::-webkit-scrollbar{display:none;}\n.ma-profile-intro{\n  font-size:0.78rem;color:var(--text-sub);line-height:1.55;margin:0 2px 6px;\n  font-family:'Noto Sans SC',sans-serif;\n}\n.ma-prof-section{margin-bottom:6px;}\n.ma-prof-section:last-child{margin-bottom:0;}\n/* 分区标题：对齐本命盘卡片里的 ma-section-title（竖条 + 底分割线） */\n.ma-profile-scroll .ma-prof-sec-title{\n  margin-top:22px;margin-bottom:14px;padding-bottom:12px;\n  border-bottom:1px solid var(--border-line);\n  justify-content:flex-start;gap:10px;\n}\n.ma-profile-scroll .ma-prof-sec-title::before{\n  content:'';width:3px;height:1.1rem;border-radius:2px;flex-shrink:0;\n  background:linear-gradient(180deg,rgba(107,92,122,.55),rgba(92,107,90,.4));\n}\n[data-theme=\"dark\"] .ma-profile-scroll .ma-prof-sec-title::before{\n  background:linear-gradient(180deg,rgba(168,150,196,.55),rgba(120,140,118,.45));\n}\n.ma-profile-scroll .ma-profile-intro + .ma-prof-section .ma-prof-sec-title{margin-top:10px;}\n.ma-prof-field{margin-bottom:18px;}\n.ma-prof-field:last-child{margin-bottom:0;}\n.ma-prof-field > label,.ma-prof-legend{\n  display:block;font-family:var(--font-mono);font-size:0.5rem;letter-spacing:2px;text-transform:uppercase;\n  color:var(--text-sub);margin-bottom:8px;\n}\n.ma-prof-field input[type=\"text\"],.ma-prof-field textarea{\n  width:100%;padding:12px 14px;border-radius:18px;border:1px solid var(--border-line);\n  background:var(--bg-card);color:var(--text-main);font-size:0.88rem;font-family:inherit;line-height:1.45;\n  box-shadow:inset 0 1px 0 rgba(255,255,255,.65);\n  transition:border-color .15s,box-shadow .15s;\n}\n[data-theme=\"dark\"] .ma-prof-field input[type=\"text\"],\n[data-theme=\"dark\"] .ma-prof-field textarea{box-shadow:inset 0 1px 0 rgba(255,255,255,.06);}\n.ma-prof-field input[type=\"text\"]:focus,.ma-prof-field textarea:focus{\n  outline:none;border-color:rgba(107,92,122,.38);box-shadow:inset 0 1px 0 rgba(255,255,255,.65),0 0 0 3px rgba(107,92,122,.1);\n}\n[data-theme=\"dark\"] .ma-prof-field input[type=\"text\"]:focus,\n[data-theme=\"dark\"] .ma-prof-field textarea:focus{box-shadow:inset 0 1px 0 rgba(255,255,255,.06),0 0 0 3px rgba(168,150,196,.12);}\n.ma-prof-field textarea{min-height:88px;resize:vertical;}\n.ma-prof-hint{font-size:0.64rem;color:var(--text-sub);margin-top:8px;line-height:1.45;}\n.ma-gender-opt{display:flex;gap:8px;}\n.ma-gender-opt label{\n  flex:1;text-align:center;padding:12px 6px;border-radius:18px;border:1px solid var(--border-line);\n  background:var(--bg-card);cursor:pointer;font-size:0.84rem;\n  box-shadow:inset 0 1px 0 rgba(255,255,255,.55);\n  transition:border-color .15s,background .15s,color .15s,transform .1s;\n}\n[data-theme=\"dark\"] .ma-gender-opt label{box-shadow:inset 0 1px 0 rgba(255,255,255,.05);}\n.ma-gender-opt label:active{transform:scale(.98);}\n.ma-gender-opt input{\n  position:absolute;opacity:0;width:0;height:0;pointer-events:none;\n}\n.ma-gender-opt label:has(input:checked){\n  border-color:var(--text-main);background:var(--text-main);color:var(--bg-device);font-weight:600;\n  box-shadow:none;\n}\n.ma-mbti-grid{\n  display:grid;grid-template-columns:repeat(4,1fr);gap:7px;\n}\n.ma-mbti-cell{\n  position:relative;display:flex;align-items:center;justify-content:center;\n  min-height:40px;padding:6px 4px;border-radius:14px;border:1px solid var(--border-line);\n  background:var(--bg-card);cursor:pointer;\n  box-shadow:inset 0 1px 0 rgba(255,255,255,.55);\n  font-family:var(--font-mono);font-size:0.58rem;font-weight:600;letter-spacing:.02em;\n  color:var(--text-main);transition:border-color .15s,background .15s,color .15s;\n}\n[data-theme=\"dark\"] .ma-mbti-cell{box-shadow:inset 0 1px 0 rgba(255,255,255,.05);}\n.ma-mbti-cell input{\n  position:absolute;opacity:0;width:0;height:0;pointer-events:none;\n}\n.ma-mbti-cell span{pointer-events:none;}\n.ma-mbti-cell:has(input:checked){\n  border-color:var(--text-main);background:var(--text-main);color:var(--bg-device);\n  box-shadow:none;\n}\n.ma-mbti-none-wrap{margin-top:12px;}\n.ma-mbti-none{\n  position:relative;display:flex;align-items:center;justify-content:center;width:100%;\n  padding:11px;border-radius:18px;border:1px dashed var(--border-line);\n  background:var(--bg-card);cursor:pointer;font-size:0.78rem;color:var(--text-sub);\n  box-shadow:inset 0 1px 0 rgba(255,255,255,.45);\n  transition:border-color .15s,background .15s,color .15s;\n}\n[data-theme=\"dark\"] .ma-mbti-none{box-shadow:inset 0 1px 0 rgba(255,255,255,.04);}\n.ma-mbti-none:has(input:checked){\n  border-style:solid;border-color:var(--text-main);color:var(--text-main);\n  background:linear-gradient(165deg,rgba(107,92,122,.08) 0%,transparent 55%);\n}\n[data-theme=\"dark\"] .ma-mbti-none:has(input:checked){\n  background:linear-gradient(165deg,rgba(168,150,196,.12) 0%,transparent 55%);\n}\n.ma-mbti-none input{position:absolute;opacity:0;width:0;height:0;}\n.ma-profile-footer{\n  flex-shrink:0;padding:12px 18px calc(12px + env(safe-area-inset-bottom,0px));\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  border-top:1px solid var(--glass-border);\n  box-shadow:0 -8px 32px rgba(0,0,0,.05);\n}\n[data-theme=\"dark\"] .ma-profile-footer{box-shadow:0 -8px 32px rgba(0,0,0,.3);}\n.ma-prof-save{\n  width:100%;padding:15px 16px;border-radius:100px;border:none;cursor:pointer;\n  background:var(--text-main);color:var(--bg-device);\n  font-family:var(--font-mono);font-size:0.52rem;font-weight:600;letter-spacing:2.2px;text-transform:uppercase;\n  box-shadow:0 4px 20px rgba(0,0,0,.12);\n}\n[data-theme=\"dark\"] .ma-prof-save{box-shadow:0 6px 24px rgba(0,0,0,.4);}\n.ma-prof-save:active{transform:scale(.99);opacity:.94;}\n.ma-chip-grid{\n  display:flex;flex-wrap:wrap;gap:8px;margin-bottom:10px;\n}\n.ma-chip-tog{\n  padding:8px 14px;border-radius:100px;border:1px solid var(--border-line);\n  background:var(--bg-card);color:var(--text-main);\n  font-size:0.72rem;font-family:var(--font-mono);font-weight:600;letter-spacing:.04em;text-transform:uppercase;\n  cursor:pointer;transition:border-color .15s,background .15s,color .15s,box-shadow .15s;\n  box-shadow:inset 0 1px 0 rgba(255,255,255,.5);\n}\n[data-theme=\"dark\"] .ma-chip-tog{box-shadow:inset 0 1px 0 rgba(255,255,255,.05);}\n.ma-chip-tog:hover{border-color:rgba(107,92,122,.28);}\n.ma-chip-tog.is-on{\n  border-color:var(--text-main);background:var(--text-main);color:var(--bg-device);\n  box-shadow:var(--shadow-card);\n  font-weight:700;\n}\n[data-theme=\"dark\"] .ma-chip-tog.is-on{box-shadow:0 4px 16px rgba(0,0,0,.35);}\n.ma-prof-sublabel{\n  display:block;font-size:0.55rem;font-family:var(--font-mono);letter-spacing:1.4px;text-transform:uppercase;\n  color:var(--text-sub);margin:14px 0 7px;\n}\n/* —— 底部导航：悬浮式玻璃胶囊（近 dock 气质） —— */\n.ma-nav-wrap{\n  position:absolute;bottom:0;left:0;right:0;z-index:5;\n  padding:0 20px calc(env(safe-area-inset-bottom,0px) + 14px);\n  pointer-events:none;\n}\n.ma-nav{\n  pointer-events:auto;\n  display:flex;justify-content:space-around;align-items:center;\n  padding:10px 8px;border-radius:100px;\n  background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);\n  border:1px solid var(--glass-border);\n  box-shadow:0 4px 24px rgba(0,0,0,.06);\n}\n[data-theme=\"dark\"] .ma-nav{box-shadow:0 8px 32px rgba(0,0,0,.35);}\n.ma-nav button{\n  flex:1;display:flex;flex-direction:column;align-items:center;gap:5px;border:none;background:transparent;\n  color:var(--text-sub);cursor:pointer;padding:6px 4px;font-family:var(--font-mono);font-size:0.48rem;letter-spacing:1.2px;text-transform:uppercase;\n  transition:color .2s;\n}\n.ma-nav button.active{color:var(--text-main);}\n.ma-nav button i{font-size:1.4rem;opacity:.92;}\n.ma-nav button.active i{opacity:1;}\n/* —— 弹窗：退出聊天好感 —— */\n.ma-modal-overlay{\n  position:absolute;inset:0;z-index:60;background:rgba(0,0,0,.35);backdrop-filter:blur(6px);\n  display:none;align-items:center;justify-content:center;padding:24px;\n}\n.ma-modal-overlay.open{display:flex;}\n.ma-modal{\n  position:relative;width:100%;max-width:318px;background:var(--bg-card);border-radius:32px;padding:28px 24px 22px;\n  border:1px solid var(--border-line);box-shadow:0 28px 64px rgba(0,0,0,.14);overflow:hidden;\n}\n.ma-modal::before{\n  content:'?';position:absolute;top:-12px;right:8px;font-family:'Playfair Display',serif;font-size:5.5rem;font-style:italic;font-weight:300;\n  color:var(--text-main);opacity:.04;line-height:1;pointer-events:none;\n}\n.ma-modal h3{font-family:'Cormorant Garamond',serif;font-size:1.65rem;font-style:italic;font-weight:600;margin-bottom:8px;position:relative;}\n.ma-modal>p{font-size:0.8rem;color:var(--text-sub);line-height:1.45;margin-bottom:18px;}\n.ma-modal>p strong{font-weight:600;color:var(--text-main);}\n.ma-rate-row{display:flex;flex-wrap:wrap;justify-content:center;gap:6px;margin-bottom:8px;}\n.ma-rate-row button{\n  width:40px;height:40px;border-radius:50%;border:1px solid var(--border-line);background:var(--bg-body);cursor:pointer;\n  color:var(--text-sub);font-size:1.1rem;transition:all .15s;\n}\n.ma-rate-row button.on{background:var(--text-main);color:var(--bg-device);border-color:var(--text-main);}\n.ma-rate-row button:active{transform:scale(.9);}\n.ma-modal-hint{font-family:var(--font-mono);font-size:0.5rem;color:var(--text-sub);text-align:center;letter-spacing:1px;margin-bottom:16px;text-transform:uppercase;}\n.ma-modal-actions{display:flex;gap:10px;}\n.ma-modal-actions button{\n  flex:1;padding:14px;border-radius:100px;border:1px solid var(--border-line);background:transparent;font-weight:600;font-size:0.85rem;cursor:pointer;color:var(--text-main);\n}\n.ma-modal-actions button.primary{background:var(--text-main);color:var(--bg-device);border-color:var(--text-main);}\n.ma-modal-input{\n  width:100%;\n  margin:2px 0 12px;\n  padding:12px 14px;\n  border-radius:14px;\n  border:1px solid var(--border-line);\n  background:var(--bg-card);\n  color:var(--text-main);\n  font-size:0.84rem;\n  outline:none;\n}\n.ma-modal-input:focus{\n  border-color:rgba(107,92,122,.55);\n  box-shadow:0 0 0 3px rgba(107,92,122,.14);\n}\n#name-unlock-error{\n  color:#b34747;\n  text-align:left;\n  letter-spacing:.6px;\n}\n.ma-modal-actionsheet h3{margin-bottom:14px;}\n.ma-modal-actions--stack{flex-direction:column;}\n.ma-modal-actions--stack button{width:100%;}\n.ma-modal.ma-modal-milestone{max-width:300px;padding:24px 22px 20px;}\n.ma-modal.ma-modal-milestone h3{font-size:1.45rem;}\n.ma-modal.ma-modal-milestone>p{margin-bottom:16px;}\n/* 与主文件 Toast 同系：深色胶囊条 */\n.ma-toast{\n  position:absolute;left:50%;bottom:calc(var(--app-pad-bottom) + 10px);transform:translateX(-50%) translateY(14px);\n  max-width:min(320px,calc(100% - 40px));padding:11px 20px;border-radius:100px;\n  background:var(--text-main);color:var(--bg-device);font-size:0.84rem;font-weight:500;line-height:1.35;\n  text-align:center;box-shadow:0 10px 28px rgba(0,0,0,.14);\n  opacity:0;pointer-events:none;transition:transform .28s ease,opacity .28s ease;z-index:85;\n}\n.ma-toast.show{opacity:1;transform:translateX(-50%) translateY(0);}\n[data-theme=\"dark\"] .ma-toast{box-shadow:0 12px 32px rgba(0,0,0,.4);}\n.ma-modal.ma-modal-heart-letter{max-width:328px;padding:22px 20px 18px;max-height:min(78vh,620px);display:flex;flex-direction:column;}\n.ma-modal.ma-modal-heart-letter h3{font-size:1.42rem;margin-bottom:4px;}\n.ma-modal.ma-modal-heart-letter .ma-modal-hint{margin-bottom:10px;}\n.ma-heart-loading{font-size:0.82rem;color:var(--text-sub);padding:12px 0;text-align:center;letter-spacing:1px;}\n.ma-heart-panel{overflow-y:auto;flex:1;min-height:0;margin-bottom:8px;}\n.ma-heart-char-text{\n  font-size:0.84rem;line-height:1.55;color:var(--text-main);white-space:pre-wrap;margin-bottom:14px;padding:12px 14px;\n  background:var(--bg-body);border-radius:16px;border:1px solid var(--border-line);\n}\n.ma-heart-reply-block{margin-top:4px;}\n.ma-heart-label{display:block;font-size:0.68rem;color:var(--text-sub);letter-spacing:.5px;margin-bottom:6px;text-transform:uppercase;}\n.ma-heart-textarea{resize:vertical;min-height:88px;margin-bottom:8px;font-family:inherit;}\n.ma-heart-user-sent{font-size:0.8rem;color:var(--text-sub);line-height:1.45;padding:10px 12px;border-radius:14px;border:1px dashed var(--border-line);margin-top:8px;}\n.ma-heart-error{color:#b34747;text-align:left;margin:0 0 10px;min-height:0;}\n.ma-heart-error:empty{display:none;}\n\n</style>\n</head>\n<body>\n<div class=\"device\" id=\"device\">\n  <div class=\"ma-ambience\" aria-hidden=\"true\">\n    <div class=\"ma-wallpaper\"></div>\n    <div class=\"ma-watermark\">C.</div>\n  </div>\n  <div class=\"app\">\n    <header class=\"ma-header\">\n      <div class=\"ma-date-box\">\n        <h1>遇见.</h1>\n        <div class=\"ma-dateline\"><span>Discover</span><span>•</span><span>Swipe</span></div>\n      </div>\n      <div class=\"ma-header-trail\">\n        <button type=\"button\" class=\"sub-back-btn ma-header-back\" id=\"btn-os-home\" aria-label=\"返回 Chill 桌面\">Back</button>\n        <button type=\"button\" class=\"ma-theme-switch ma-refresh-action\" id=\"btn-refresh-discover\" aria-label=\"Refresh deck\">\n          <span class=\"ma-refresh-ico\" aria-hidden=\"true\"><i class=\"ph ph-arrow-clockwise\"></i></span>\n          REFRESH\n        </button>\n      </div>\n    </header>\n\n    <div class=\"ma-views\" id=\"ma-views\">\n    <!-- 发现 -->\n    <div class=\"ma-view active\" id=\"view-discover\">\n      <div class=\"ma-deck-wrap\">\n        <div class=\"ma-deck-ghost ma-dg2\" aria-hidden=\"true\"></div>\n        <div class=\"ma-deck-ghost ma-dg1\" aria-hidden=\"true\"></div>\n        <div class=\"ma-deck\" id=\"deck\"></div>\n      </div>\n\n      <p class=\"ma-stack-hint\">左滑跳过 · 右滑喜欢 · 卡片内资料区可上下滑 · 亦可点下方胶囊 · 右上角 REFRESH：发现页拉卡片 · 运势页刷新今日运势</p>\n      <div class=\"ma-actions\">\n        <div class=\"ma-actions-capsule\">\n          <button type=\"button\" class=\"ma-btn pass\" id=\"btn-pass\" aria-label=\"不感兴趣\"><i class=\"ph ph-x\"></i></button>\n          <button type=\"button\" class=\"ma-btn like\" id=\"btn-like\" aria-label=\"喜欢\"><i class=\"ph-fill ph-heart\"></i></button>\n        </div>\n      </div>\n    </div>\n\n    <!-- 消息：陌生招呼堆叠 + 对话列表 -->\n    <div class=\"ma-view\" id=\"view-inbox\">\n      <div class=\"ma-inbox-scroll\" id=\"inbox-scroll\">\n        <div id=\"stranger-stack-host\"></div>\n        <div class=\"ma-section-title\" style=\"margin-top:4px;\">对话</div>\n        <div class=\"ma-list\" id=\"list-inbox\" style=\"padding-bottom:0;\"></div>\n      </div>\n    </div>\n\n    <!-- 今日运势 -->\n    <div class=\"ma-view\" id=\"view-daily\">\n      <div class=\"ma-daily-scroll\">\n        <div class=\"ma-astro-hero\">\n          <p class=\"ma-astro-zodiac\" id=\"daily-date-line\">—</p>\n          <div class=\"ma-astro-score\"><span id=\"daily-index\">82</span><small>INDEX</small></div>\n          <p class=\"ma-astro-mood\" id=\"daily-mood\">月亮进入温柔相位 · 适合慢聊与倾听</p>\n          <div class=\"ma-daily-orbits\" aria-hidden=\"true\">\n            <div class=\"ma-orbit ma-orbit-match ma-orbit-sm\" id=\"daily-orbit-day\" style=\"--p:78\">\n              <div class=\"ma-orbit-dots\"></div>\n              <div class=\"ma-orbit-core\"><strong id=\"daily-orbit-day-pct\">78<small>%</small></strong><span>日合</span></div>\n            </div>\n            <div class=\"ma-orbit ma-orbit-astro ma-orbit-sm\" id=\"daily-orbit-chat\" style=\"--p:64\">\n              <div class=\"ma-orbit-dots\"></div>\n              <div class=\"ma-orbit-core\"><strong id=\"daily-orbit-chat-pct\">64<small>%</small></strong><span>聊感</span></div>\n            </div>\n          </div>\n        </div>\n        <div class=\"ma-daily-grid\">\n          <div class=\"ma-daily-pill yi\">\n            <h4>宜</h4>\n            <p id=\"daily-yi\">简短开场、分享歌单、傍晚后上线、接话不过度解读</p>\n          </div>\n          <div class=\"ma-daily-pill ji\">\n            <h4>忌</h4>\n            <p id=\"daily-ji\">连珠炮追问、刚匹配就长语音、否定对方兴趣</p>\n          </div>\n        </div>\n        <div class=\"ma-daily-recommend\" id=\"daily-recommend-wrap\">\n          <div class=\"ma-drec-k\">今日推荐 · Today's pick</div>\n          <div id=\"daily-recommend-body\"></div>\n        </div>\n        <div class=\"ma-daily-chatbox\">\n          <div class=\"ma-dcb-k\">适宜和谁聊 · Chat bias</div>\n          <p id=\"daily-chat-bias\">今日与水象、土象标签的人更容易聊开；若对方简介带「夜猫子」「爵士」等关键词，破冰成功率更高。</p>\n          <ul id=\"daily-chat-tips\">\n            <li>优先回复：带月亮/海王星意象的慢热型</li>\n            <li>时段建议：19:00–23:00 消息打开率偏高（示意）</li>\n          </ul>\n        </div>\n        <div class=\"ma-aspects\">\n          <h4>星盘快照 · Aspects</h4>\n          <div id=\"daily-aspects-rows\">\n            <div class=\"ma-aspect-row\"><span>金星 ↔ 水星</span><span>利于轻松话题</span></div>\n            <div class=\"ma-aspect-row\"><span>月亮 三分 木星</span><span>情绪包容度 +</span></div>\n            <div class=\"ma-aspect-row\"><span>火星</span><span>避免硬碰硬辩论</span></div>\n          </div>\n        </div>\n      </div>\n    </div>\n\n    <!-- 我的 -->\n    <div class=\"ma-view\" id=\"view-me\">\n      <div class=\"ma-me-scroll\">\n      <div class=\"ma-me-head\">\n        <input type=\"file\" id=\"meet-avatar-input\" accept=\"image/*\" hidden>\n        <div class=\"ma-me-avatar-wrap\" id=\"meet-avatar-wrap\" role=\"button\" tabindex=\"0\" aria-label=\"上传或更换头像\">\n          <img id=\"meet-avatar-img\" class=\"ma-me-avatar-img\" alt=\"\">\n          <div class=\"ma-me-avatar-ph\" id=\"meet-avatar-ph\"><i class=\"ph ph-user\" aria-hidden=\"true\"></i></div>\n          <div class=\"ma-me-avatar-hint\" aria-hidden=\"true\"><i class=\"ph ph-camera\"></i></div>\n        </div>\n        <div>\n          <div class=\"ma-card-name\" id=\"me-display-name\">我</div>\n          <div class=\"ma-card-age\" id=\"me-tagline\" style=\"margin-top:4px;\">填写生日，生成你的星座与星盘</div>\n        </div>\n      </div>\n\n      <div class=\"ma-profile-cta-card\">\n        <button type=\"button\" class=\"ma-profile-cta\" id=\"btn-open-profile\" aria-label=\"编辑个人资料\">\n          <div class=\"ma-profile-cta-main\">\n            <span class=\"ma-profile-cta-k\">个人资料</span>\n            <span class=\"ma-profile-cta-t\" id=\"profile-cta-line\">点我填写 · 让匹配更懂你</span>\n          </div>\n          <i class=\"ph ph-caret-right\" aria-hidden=\"true\"></i>\n        </button>\n      </div>\n\n      <div class=\"ma-natal-card\" id=\"natal-card\">\n        <div class=\"ma-section-title\">本命星盘</div>\n        <div class=\"ma-natal-empty\" id=\"natal-empty\">\n          <i class=\"ph ph-sparkle\" aria-hidden=\"true\"></i>\n          <strong>还没有出生信息</strong><br>\n          保存后展示太阳星座、生肖、月亮与上升（上升需填写出生时间更准确）。\n        </div>\n        <div class=\"ma-natal-body\" id=\"natal-body\">\n          <div class=\"ma-natal-wheel-wrap\" id=\"natal-wheel\" aria-hidden=\"true\">\n            <div class=\"ma-natal-wheel-ring\"></div>\n            <div id=\"natal-zodiac-labels\"></div>\n            <div class=\"ma-natal-wheel-inner\">\n              <span class=\"ma-natal-hub-k\">核心印象</span>\n              <span class=\"ma-natal-hub-main\" id=\"natal-hub-title\">—</span>\n              <span class=\"ma-natal-hub-sub\" id=\"natal-hub-sub\">—</span>\n            </div>\n            <div class=\"ma-natal-markers\" id=\"natal-markers\"></div>\n          </div>\n          <div class=\"ma-natal-legend\">\n            <span><i class=\"lg-sun\"></i>太阳</span>\n            <span><i class=\"lg-moon\"></i>月亮</span>\n            <span><i class=\"lg-asc\"></i>上升</span>\n          </div>\n          <div class=\"ma-natal-trio\" id=\"natal-trio\"></div>\n          <div class=\"ma-natal-dims\" id=\"natal-dims\" aria-label=\"星盘维度\"></div>\n          <div class=\"ma-natal-breakdown\" id=\"natal-breakdown\" aria-label=\"星盘结构\"></div>\n          <p class=\"ma-natal-meta\" id=\"natal-meta\"></p>\n        </div>\n        <div class=\"ma-natal-form\" id=\"natal-form\">\n          <button type=\"button\" class=\"ma-natal-form-toggle\" id=\"natal-form-toggle\" aria-expanded=\"true\">编辑出生信息</button>\n          <div class=\"ma-natal-fields\">\n            <div class=\"ma-natal-field\">\n              <label for=\"birth-date\">出生日期</label>\n              <input type=\"text\" id=\"birth-date\" name=\"birth-date\" inputmode=\"numeric\" placeholder=\"YYYY-MM-DD\" autocomplete=\"bday\">\n            </div>\n            <div class=\"ma-natal-field\">\n              <label for=\"birth-time\">出生时间</label>\n              <input type=\"text\" id=\"birth-time\" name=\"birth-time\" inputmode=\"numeric\" placeholder=\"HH:mm\" autocomplete=\"off\">\n              <p class=\"ma-natal-field-hint\">日期格式：YYYY-MM-DD；时间格式：HH:mm（24 小时制，选填）。</p>\n            </div>\n            <div class=\"ma-natal-form-actions\">\n              <button type=\"button\" class=\"ma-natal-btn-save\" id=\"birth-save\">保存并更新星盘</button>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"ma-profile-cta-card\">\n        <button type=\"button\" class=\"ma-profile-cta\" id=\"btn-open-wb\" aria-label=\"世界书设定\">\n          <div class=\"ma-profile-cta-main\">\n            <span class=\"ma-profile-cta-k\">世界书设定</span>\n            <span class=\"ma-profile-cta-t\" id=\"wb-cta-line\">未绑定 · 点我从主文件世界书绑定</span>\n          </div>\n          <i class=\"ph ph-caret-right\" aria-hidden=\"true\"></i>\n        </button>\n      </div>\n\n      <div class=\"ma-section-title\">聊天与隐私</div>\n      <div class=\"ma-privacy-card\" id=\"privacy-dm-card\">\n        <div class=\"ma-section-title\" style=\"margin-top:0;margin-bottom:0;\">谁能私信我</div>\n        <p class=\"ma-privacy-lead\">单选。选择「允许陌生人」后，未匹配用户的招呼会出现在消息页顶部的<strong>陌生招呼</strong>堆叠里。</p>\n        <div class=\"ma-radio-list\" id=\"dm-policy-list\" role=\"radiogroup\" aria-label=\"私聊权限\">\n          <label class=\"ma-radio-pill\" id=\"dm-pill-match\">\n            <input type=\"radio\" name=\"dm-policy\" value=\"match_only\" id=\"dm-radio-match\">\n            <div class=\"ma-rp-body\">\n              <div class=\"ma-rp-title\">仅互相喜欢后可私聊</div>\n              <div class=\"ma-rp-desc\">右滑互相匹配后才会进对话列表。不接收陌生私信，消息页也不会出现陌生招呼。</div>\n            </div>\n          </label>\n          <label class=\"ma-radio-pill\" id=\"dm-pill-strangers\">\n            <input type=\"radio\" name=\"dm-policy\" value=\"strangers_ok\" id=\"dm-radio-strangers\">\n            <div class=\"ma-rp-body\">\n              <div class=\"ma-rp-title\">允许陌生人私信</div>\n              <div class=\"ma-rp-desc\">未匹配也可以向你发招呼；统一收纳在「陌生招呼」，可展开逐条查看与回复。</div>\n            </div>\n          </label>\n        </div>\n      </div>\n      </div>\n    </div>\n    </div>\n\n    <div class=\"ma-nav-wrap\">\n      <nav class=\"ma-nav\" aria-label=\"主导航\">\n        <button type=\"button\" class=\"active\" data-tab=\"discover\"><i class=\"ph-fill ph-cards\"></i>发现</button>\n        <button type=\"button\" data-tab=\"inbox\"><i class=\"ph ph-chat-circle\"></i>消息</button>\n        <button type=\"button\" data-tab=\"daily\"><i class=\"ph ph-sparkle\"></i>运势</button>\n        <button type=\"button\" data-tab=\"me\"><i class=\"ph ph-user-circle\"></i>我的</button>\n      </nav>\n    </div>\n  </div>\n\n  <!-- 全屏聊天 -->\n  <div class=\"ma-chat\" id=\"chat-screen\" aria-hidden=\"true\">\n    <div class=\"ma-chat-bar\">\n      <button type=\"button\" class=\"ma-chat-back\" id=\"chat-back\" aria-label=\"返回\"><i class=\"ph ph-arrow-left\"></i></button>\n      <div class=\"ma-chat-bar-main\">\n        <div class=\"ma-chat-bar-head\">\n          <div class=\"ma-chat-bar-titles\">\n            <strong class=\"ma-chat-peer-name\" id=\"chat-peer\">昵称</strong>\n            <span class=\"ma-chat-peer-sub\" id=\"chat-peer-sub\">印象星级 · 双方可见</span>\n          </div>\n          <div class=\"ma-chat-bar-links\">\n            <button type=\"button\" class=\"ma-chat-mood-link\" id=\"chat-mood-trigger\" aria-label=\"Mood\">mood</button>\n            <button type=\"button\" class=\"ma-chat-mood-link\" id=\"chat-compat-trigger\" aria-label=\"默契问答\" hidden>quiz</button>\n          </div>\n        </div>\n        <div class=\"ma-chat-impress-panel\" id=\"chat-impress-matched\" hidden>\n          <div class=\"ma-chat-impress-col\">\n            <span class=\"ma-chat-impress-label\">我对 Ta</span>\n            <div class=\"ma-chat-impress-stars\" id=\"chat-stars-me\" role=\"img\" aria-label=\"我对对方的印象星级\"></div>\n          </div>\n          <div class=\"ma-chat-impress-div\" aria-hidden=\"true\"></div>\n          <div class=\"ma-chat-impress-col ma-chat-impress-col--peer\">\n            <span class=\"ma-chat-impress-label\">Ta 对我</span>\n            <div class=\"ma-chat-impress-stars\" id=\"chat-stars-peer\" role=\"img\" aria-label=\"对方对我的印象星级\"></div>\n          </div>\n        </div>\n        <div class=\"ma-chat-stranger-cta\" id=\"chat-stranger-cta\" hidden>\n          <p class=\"ma-chat-impress-note\" id=\"chat-impress-stranger\">互选后可见星级、mood 等。</p>\n          <button type=\"button\" class=\"ma-str-mutual-btn\" id=\"chat-stranger-mutual\">互选</button>\n        </div>\n      </div>\n    </div>\n    <div class=\"ma-chat-body\">\n      <div class=\"ma-chat-thread\" id=\"chat-thread\" aria-live=\"polite\"></div>\n      <div class=\"ma-icebreaker\" id=\"chat-icebreaker\" aria-label=\"破冰句\">\n        <div class=\"ma-icebreaker-head\">\n          <span class=\"ma-icebreaker-k\">破冰 · Icebreaker</span>\n          <button type=\"button\" class=\"ma-icebreaker-shuffle\" id=\"btn-icebreaker-shuffle\" aria-label=\"换一句\">换一句</button>\n        </div>\n        <button type=\"button\" class=\"ma-icebreaker-quote\" id=\"chat-icebreaker-quote\" aria-label=\"将本句填入输入框\">\n          <span class=\"ma-icebreaker-text\" id=\"chat-icebreaker-text\">—</span>\n        </button>\n        <p class=\"ma-icebreaker-hint\">轻触句子填入输入框 · 可改后再发</p>\n      </div>\n      <div class=\"ma-chat-composer-wrap\">\n        <div class=\"ma-chat-composer\">\n          <input type=\"text\" id=\"chat-input\" maxlength=\"500\" placeholder=\"写一句…\" enterkeyhint=\"send\" autocomplete=\"off\">\n          <button type=\"button\" class=\"ma-chat-send\" id=\"chat-send\" aria-label=\"上屏不触发AI\" title=\"上屏不触发AI\"><i class=\"ph ph-arrow-up\"></i></button>\n          <button type=\"button\" class=\"ma-chat-reply\" id=\"chat-reply\" aria-label=\"触发AI回复\" title=\"触发AI回复\"><i class=\"ph-fill ph-sparkle\"></i></button>\n        </div>\n      </div>\n    </div>\n  </div>\n  <div class=\"ma-toast\" id=\"ma-toast\" role=\"status\" aria-live=\"polite\"></div>\n\n  <!-- 世界书设置 -->\n  <div class=\"ma-profile-sheet ma-wb-sheet\" id=\"wb-sheet\" aria-hidden=\"true\">\n    <header class=\"ma-profile-bar\">\n      <div class=\"ma-profile-bar-row\">\n        <button type=\"button\" class=\"ma-chat-back\" id=\"wb-back\" aria-label=\"返回\"><i class=\"ph ph-arrow-left\"></i></button>\n        <div class=\"ma-profile-bar-txt\">\n          <strong>世界书设定</strong>\n          <span>Worldbook Binding</span>\n        </div>\n        <span class=\"ma-spacer\" aria-hidden=\"true\"></span>\n      </div>\n    </header>\n    <div class=\"ma-profile-scroll\">\n      <p class=\"ma-profile-intro\">选择主文件世界书词条，绑定到当前聊天对象。仅绑定启用中的聊天词条。</p>\n\n      <div class=\"ma-prof-section\">\n        <div class=\"ma-section-title ma-prof-sec-title\">词条绑定</div>\n        <div class=\"ma-prof-field\">\n          <label>已选词条</label>\n          <p class=\"ma-prof-hint\"><span id=\"wb-bind-count\">0</span> 条</p>\n          <div class=\"ma-chip-grid\" id=\"wb-entry-list\" role=\"group\" aria-label=\"世界书词条列表\"></div>\n          <p class=\"ma-prof-hint\" id=\"wb-empty\" hidden>暂无可绑定词条，请先在主文件世界书创建并启用聊天词条。</p>\n        </div>\n      </div>\n    </div>\n    <footer class=\"ma-profile-footer\">\n      <button type=\"button\" class=\"ma-prof-save\" id=\"wb-save\">完成</button>\n    </footer>\n  </div>\n\n  <!-- 编辑个人资料 -->\n  <div class=\"ma-profile-sheet\" id=\"profile-sheet\" aria-hidden=\"true\">\n    <header class=\"ma-profile-bar\">\n      <div class=\"ma-profile-bar-row\">\n        <button type=\"button\" class=\"ma-chat-back\" id=\"profile-back\" aria-label=\"返回\"><i class=\"ph ph-arrow-left\"></i></button>\n        <div class=\"ma-profile-bar-txt\">\n          <strong>编辑资料</strong>\n          <span>Edit profile</span>\n        </div>\n        <span class=\"ma-spacer\" aria-hidden=\"true\"></span>\n      </div>\n    </header>\n    <div class=\"ma-profile-scroll\">\n      <p class=\"ma-profile-intro\">完善资料有助于更合拍的人找到你，可随时修改。</p>\n\n      <div class=\"ma-prof-section\">\n        <div class=\"ma-section-title ma-prof-sec-title\">基础信息</div>\n        <div class=\"ma-prof-field\">\n          <label for=\"prof-nick\">昵称 / 代号</label>\n          <input type=\"text\" id=\"prof-nick\" maxlength=\"16\" placeholder=\"例如：小 C · 仅展示代号\" autocomplete=\"nickname\">\n        </div>\n        <div class=\"ma-prof-field\">\n          <div class=\"ma-prof-legend\" id=\"prof-gender-label\">性别</div>\n          <div class=\"ma-gender-opt\" role=\"group\" aria-labelledby=\"prof-gender-label\">\n            <label><input type=\"radio\" name=\"prof-gender\" value=\"男\">男</label>\n            <label><input type=\"radio\" name=\"prof-gender\" value=\"女\">女</label>\n            <label><input type=\"radio\" name=\"prof-gender\" value=\"none\">不展示</label>\n          </div>\n          <p class=\"ma-prof-hint\">选「不展示」则对外资料里不出现性别。</p>\n        </div>\n        <div class=\"ma-prof-field\">\n          <label for=\"prof-city\">常居城市</label>\n          <input type=\"text\" id=\"prof-city\" maxlength=\"20\" placeholder=\"例如：上海\" autocomplete=\"address-level2\">\n        </div>\n      </div>\n\n      <div class=\"ma-prof-section\">\n        <div class=\"ma-section-title ma-prof-sec-title\">关于你</div>\n        <div class=\"ma-prof-field\">\n          <label for=\"prof-bio\">自我介绍</label>\n          <textarea id=\"prof-bio\" maxlength=\"200\" placeholder=\"作息、爱好、最近在听什么…\"></textarea>\n          <p class=\"ma-prof-hint\">最多 200 字</p>\n        </div>\n      </div>\n\n      <div class=\"ma-prof-section\">\n        <div class=\"ma-section-title ma-prof-sec-title\">想认识谁 & 兴趣</div>\n        <div class=\"ma-prof-field\">\n          <label id=\"prof-seeking-label\">想找什么样的朋友（可多选）</label>\n          <div class=\"ma-chip-grid\" id=\"prof-seeking-chips\" role=\"group\" aria-labelledby=\"prof-seeking-label\">\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"seeking\" data-value=\"饭搭子\" aria-pressed=\"false\">饭搭子</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"seeking\" data-value=\"散步聊天\" aria-pressed=\"false\">散步聊天</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"seeking\" data-value=\"看展拍照\" aria-pressed=\"false\">看展拍照</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"seeking\" data-value=\"学习搭子\" aria-pressed=\"false\">学习搭子</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"seeking\" data-value=\"运动健身\" aria-pressed=\"false\">运动健身</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"seeking\" data-value=\"听演出\" aria-pressed=\"false\">听演出</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"seeking\" data-value=\"慢聊不深交\" aria-pressed=\"false\">慢聊不深交</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"seeking\" data-value=\"随缘认识\" aria-pressed=\"false\">随缘认识</button>\n          </div>\n          <span class=\"ma-prof-sublabel\" id=\"prof-seeking-other-l\">其他想补充的</span>\n          <input type=\"text\" id=\"prof-seeking-other\" maxlength=\"80\" placeholder=\"没有合适选项时写在这里\" aria-labelledby=\"prof-seeking-other-l\">\n        </div>\n        <div class=\"ma-prof-field\">\n          <label id=\"prof-tags-label\">兴趣标签（可多选）</label>\n          <div class=\"ma-chip-grid\" id=\"prof-tags-chips\" role=\"group\" aria-labelledby=\"prof-tags-label\">\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"tags\" data-value=\"咖啡\" aria-pressed=\"false\">咖啡</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"tags\" data-value=\"阅读\" aria-pressed=\"false\">阅读</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"tags\" data-value=\"电影\" aria-pressed=\"false\">电影</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"tags\" data-value=\"音乐\" aria-pressed=\"false\">音乐</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"tags\" data-value=\"徒步\" aria-pressed=\"false\">徒步</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"tags\" data-value=\"摄影\" aria-pressed=\"false\">摄影</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"tags\" data-value=\"游戏\" aria-pressed=\"false\">游戏</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"tags\" data-value=\"播客\" aria-pressed=\"false\">播客</button>\n            <button type=\"button\" class=\"ma-chip-tog\" data-chip=\"tags\" data-value=\"料理\" aria-pressed=\"false\">料理</button>\n          </div>\n          <span class=\"ma-prof-sublabel\" id=\"prof-tags-other-l\">其他兴趣</span>\n          <input type=\"text\" id=\"prof-tags-other\" maxlength=\"60\" placeholder=\"如：爵士、黑胶、独立游戏…\" aria-labelledby=\"prof-tags-other-l\">\n        </div>\n      </div>\n\n      <div class=\"ma-prof-section\">\n        <div class=\"ma-section-title ma-prof-sec-title\">MBTI（选填）</div>\n        <div class=\"ma-prof-field\">\n          <div class=\"ma-prof-legend\" id=\"prof-mbti-label\">选择你的类型</div>\n          <div class=\"ma-mbti-grid\" role=\"radiogroup\" aria-labelledby=\"prof-mbti-label\">\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"INTJ\"><span>INTJ</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"INTP\"><span>INTP</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"ENTJ\"><span>ENTJ</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"ENTP\"><span>ENTP</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"INFJ\"><span>INFJ</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"INFP\"><span>INFP</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"ENFJ\"><span>ENFJ</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"ENFP\"><span>ENFP</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"ISTJ\"><span>ISTJ</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"ISFJ\"><span>ISFJ</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"ESTJ\"><span>ESTJ</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"ESFJ\"><span>ESFJ</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"ISTP\"><span>ISTP</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"ISFP\"><span>ISFP</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"ESTP\"><span>ESTP</span></label>\n            <label class=\"ma-mbti-cell\"><input type=\"radio\" name=\"prof-mbti\" value=\"ESFP\"><span>ESFP</span></label>\n          </div>\n          <div class=\"ma-mbti-none-wrap\">\n            <label class=\"ma-mbti-none\"><input type=\"radio\" name=\"prof-mbti\" value=\"none\" checked><span>先不选 / 不展示</span></label>\n          </div>\n          <p class=\"ma-prof-hint\">16 型为常见命名，仅供展示；不确定可留空。</p>\n        </div>\n      </div>\n    </div>\n    <footer class=\"ma-profile-footer\">\n      <button type=\"button\" class=\"ma-prof-save\" id=\"prof-save\">保存资料</button>\n    </footer>\n  </div>\n\n  <!-- 退出聊天弹窗 -->\n  <div class=\"ma-modal-overlay\" id=\"modal-rate\">\n    <div class=\"ma-modal\">\n      <h3>聊得怎么样？</h3>\n      <p>为 Ta 结算<strong>好感</strong>，双方仍互可见。</p>\n      <div class=\"ma-rate-row\" id=\"rate-stars\"></div>\n      <p class=\"ma-modal-hint\" id=\"rate-current-hint\"></p>\n      <p class=\"ma-modal-hint\" style=\"margin-top:4px;\">结算档位：-1→-8、0→0、½→2、1★→3、2★→6、3★→9、4★→12、5★→15 · 默认 0 ·「完成」结算 ·「跳过」不加分</p>\n      <div class=\"ma-modal-actions\">\n        <button type=\"button\" id=\"rate-skip\">跳过</button>\n        <button type=\"button\" class=\"primary\" id=\"rate-ok\">完成</button>\n      </div>\n    </div>\n  </div>\n  <div class=\"ma-modal-overlay\" id=\"modal-unmatch\">\n    <div class=\"ma-modal\">\n      <h3>还没互选</h3>\n      <p id=\"unmatch-msg\">Ta 还没有选择你。当前设置为<strong>仅互相喜欢后可私聊</strong>，暂时无法开始对话。</p>\n      <div class=\"ma-modal-actions\">\n        <button type=\"button\" class=\"primary\" id=\"unmatch-ok\">知道了</button>\n      </div>\n    </div>\n  </div>\n  <div class=\"ma-modal-overlay\" id=\"modal-name-unlock\">\n    <div class=\"ma-modal\">\n      <h3>一星解锁姓名</h3>\n      <p>你们达到 <strong>1 星</strong> 了。输入你的名字，并确认 Ta 的真实姓名（当前代号：<strong id=\"name-unlock-peer-alias\">Ta</strong>）。</p>\n      <input type=\"text\" id=\"name-unlock-self-input\" class=\"ma-modal-input\" maxlength=\"24\" placeholder=\"输入你的名字\">\n      <input type=\"text\" id=\"name-unlock-peer-input\" class=\"ma-modal-input\" maxlength=\"24\" placeholder=\"可编辑 Ta 的名字\">\n      <p class=\"ma-modal-hint\" id=\"name-unlock-error\" style=\"min-height:16px;margin-top:2px;\"></p>\n      <p class=\"ma-modal-hint\">角色名不能和主文件已有角色重复</p>\n      <div class=\"ma-modal-actions\">\n        <button type=\"button\" id=\"name-unlock-cancel\">稍后</button>\n        <button type=\"button\" class=\"primary\" id=\"name-unlock-ok\">解锁</button>\n      </div>\n    </div>\n  </div>\n  <div class=\"ma-modal-overlay\" id=\"modal-peer-mood\">\n    <div class=\"ma-modal ma-modal-mood\">\n      <h3>status</h3>\n      <p class=\"ma-mood-lead\" id=\"peer-mood-status\">—</p>\n      <div class=\"ma-mood-divider\" aria-hidden=\"true\"></div>\n      <p class=\"ma-mood-k\">mood</p>\n      <p class=\"ma-mood-body\" id=\"peer-mood-voice\">—</p>\n      <div class=\"ma-modal-actions\">\n        <button type=\"button\" class=\"primary\" id=\"peer-mood-close\">知道了</button>\n      </div>\n    </div>\n  </div>\n  <div class=\"ma-modal-overlay\" id=\"modal-compat-quiz\">\n    <div class=\"ma-modal ma-modal-compat-wrap\">\n      <div class=\"ma-compat-modal-head\">\n        <span class=\"ma-compat-modal-title\">默契问答</span>\n        <button type=\"button\" class=\"ma-compat-refresh\" id=\"compat-quiz-refresh\" aria-label=\"换一批题目\" title=\"按聊天与人设重新生成 5 题\">\n          <i class=\"ph ph-arrow-clockwise\" aria-hidden=\"true\"></i>\n        </button>\n      </div>\n      <div class=\"ma-compat\" id=\"chat-compat\" hidden>\n        <div class=\"ma-compat-head\">\n          <span class=\"ma-compat-k\">pick one</span>\n          <button type=\"button\" class=\"ma-compat-next\" id=\"chat-compat-next\" aria-label=\"换一题\">换一题</button>\n        </div>\n        <p class=\"ma-compat-q\" id=\"chat-compat-q\">—</p>\n        <div class=\"ma-compat-opts\">\n          <button type=\"button\" class=\"ma-compat-opt\" id=\"chat-compat-a\" data-opt=\"0\">A</button>\n          <button type=\"button\" class=\"ma-compat-opt\" id=\"chat-compat-b\" data-opt=\"1\">B</button>\n        </div>\n        <p class=\"ma-compat-hint\" id=\"chat-compat-hint\"></p>\n      </div>\n      <div class=\"ma-modal-actions\">\n        <button type=\"button\" class=\"primary\" id=\"compat-quiz-close\">关闭</button>\n      </div>\n    </div>\n  </div>\n  <div class=\"ma-modal-overlay\" id=\"modal-mutual-milestone\">\n    <div class=\"ma-modal ma-modal-milestone\">\n      <h3 id=\"mutual-milestone-title\">—</h3>\n      <p id=\"mutual-milestone-body\">—</p>\n      <div class=\"ma-modal-actions\">\n        <button type=\"button\" class=\"primary\" id=\"mutual-milestone-ok\">好的</button>\n      </div>\n    </div>\n  </div>\n  <div class=\"ma-modal-overlay\" id=\"modal-peer-heart-letter\">\n    <div class=\"ma-modal ma-modal-heart-letter\">\n      <h3 id=\"peer-heart-title\">互相 4★</h3>\n      <p class=\"ma-modal-hint\" id=\"peer-heart-lead\">Ta 根据聊天与人设，认真写了下面这段话给你。</p>\n      <p class=\"ma-heart-loading\" id=\"peer-heart-loading\">正在写…</p>\n      <p class=\"ma-modal-hint ma-heart-error\" id=\"peer-heart-error\"></p>\n      <div class=\"ma-heart-panel\" id=\"peer-heart-panel\" hidden>\n        <p class=\"ma-heart-char-text\" id=\"peer-heart-char-text\"></p>\n        <div class=\"ma-heart-reply-block\" id=\"peer-heart-reply-block\">\n          <label class=\"ma-heart-label\" for=\"peer-heart-user-input\">你也可以回写一句给 Ta（可选）</label>\n          <textarea id=\"peer-heart-user-input\" class=\"ma-modal-input ma-heart-textarea\" rows=\"4\" maxlength=\"400\" placeholder=\"写你想对 Ta 说的…\"></textarea>\n        </div>\n        <p class=\"ma-heart-user-sent\" id=\"peer-heart-user-sent\" hidden></p>\n      </div>\n      <div class=\"ma-modal-actions\" id=\"peer-heart-actions-pending\" hidden>\n        <button type=\"button\" id=\"peer-heart-skip\">暂不回应</button>\n        <button type=\"button\" class=\"primary\" id=\"peer-heart-send\">发送回应</button>\n      </div>\n      <div class=\"ma-modal-actions\" id=\"peer-heart-actions-done\" hidden>\n        <button type=\"button\" class=\"primary\" id=\"peer-heart-done\">知道了</button>\n      </div>\n      <div class=\"ma-modal-actions\" id=\"peer-heart-actions-error\" hidden>\n        <button type=\"button\" class=\"primary\" id=\"peer-heart-retry\">重试</button>\n      </div>\n    </div>\n  </div>\n  <div class=\"ma-modal-overlay\" id=\"modal-bubble-action\">\n    <div class=\"ma-modal ma-modal-actionsheet\">\n      <h3>消息操作</h3>\n      <div class=\"ma-modal-actions ma-modal-actions--stack\">\n        <button type=\"button\" id=\"bubble-act-copy\">复制</button>\n        <button type=\"button\" id=\"bubble-act-multi\">多选</button>\n        <button type=\"button\" id=\"bubble-act-reroll\">重roll</button>\n        <button type=\"button\" id=\"bubble-act-reroll-round\">整轮重roll</button>\n        <button type=\"button\" id=\"bubble-act-quote\">引用</button>\n        <button type=\"button\" id=\"bubble-act-edit\">编辑</button>\n        <button type=\"button\" id=\"bubble-act-recall\">撤回</button>\n        <button type=\"button\" id=\"bubble-act-cancel\">取消</button>\n      </div>\n    </div>\n  </div>\n</div>\n<script>\n/**\n * Chill「遇见」——独立页为 chill-match.html；主壳通过 js/chill-meet-embed.js 以 iframe 内嵌同页。\n * 与主应用共用 IndexedDB `chillOS`：\n * `api_profiles`（当前 API）、`meet`（遇见专用表，与主壳 `messages`/`settings` 同级，IndexedDB 持久化）。\n * OpenAI 兼容 /v1/chat/completions：刷新卡片、聊天对方回复、破冰句（失败则本地兜底）；\n * 允许陌生人私信时，间隔约 4～7 小时批量生成 1～5 条陌生招呼（与喜欢列表/发现卡组/已有招呼去重）。\n * 运势 tab 下右上角 REFRESH 调用主应用 API 刷新当日运势（`meet` 表缓存 `meet_dailyFortuneV1`）。\n * 可选 window.CHILL_DISCOVER_API 强制走自定义 HTTP 拉卡片（POST JSON）。\n * 我的页头像 → IndexedDB `assets` key `meet_profile_avatar`，压缩逻辑与主壳 Assets.save(…,400,0.85) 一致。\n */\n(function(){\n  let deck = [];\n  let liked = [];\n  const IDB_KEY_MEET_LIKED = 'meet_likedV1';\n  const IDB_KEY_MEET_CONV = 'meet_matchConvV1';\n  const IDB_KEY_MEET_PROFILE = 'meet_userProfile';\n  const IDB_KEY_MEET_BIRTH = 'meet_natalBirth';\n  const IDB_KEY_MEET_DM = 'meet_dmPolicy';\n  const IDB_KEY_MEET_STRANGERS = 'meet_strangersInboxV1';\n  const IDB_KEY_MEET_STRANGER_DUE = 'meet_strangerNextDueV1';\n  const IDB_KEY_MEET_DAILY = 'meet_dailyFortuneV1';\n  const IDB_KEY_MEET_CHAT_PERSONA = 'meet_chatPersonaMapV1';\n  const IDB_KEY_MEET_WB_BIND = 'meet_worldbookBindMapV1';\n  const IDB_KEY_MEET_WB_FREETEXT = 'meet_worldviewFreetextV1';\n  const IDB_KEY_MEET_SELF_NAME = 'meet_userInputNameV1';\n  const IDB_KEY_MEET_MUTUAL_MILESTONE_TOAST = 'meet_mutualMilestoneToastsV1';\n  const IDB_KEY_MEET_PEER_HEART_LETTER = 'meet_peerHeartLetterV1';\n  const IDB_KEY_MEET_INBOX_READ = 'meet_inboxLastReadV1';\n  const ASSET_KEY_MEET_AVATAR = 'meet_profile_avatar';\n\n  let _meetConvMap = {};\n  let _meetUserProfile = null;\n  let _meetBirth = null;\n  let _meetStrangerNextDue = 0;\n  let _meetChatPersonaMap = {};\n  let _meetChatPersonaBusy = {};\n  let _meetWbBindMap = {};\n  let _meetWorldviewFreetext = '';\n  let _wbMainEntriesCache = [];\n  let _meetSelfName = '';\n  let _meetAvatarObjectUrl = null;\n  let _mutualMilestoneToastMap = {};\n  const _mutualMilestoneToastQueue = [];\n  let _mutualMilestoneToastOpen = false;\n  let _peerHeartLetterMap = {};\n  let _peerHeartLetterFlowPeerId = '';\n  let _meetInboxLastReadTs = {};\n\n  /**\n   * 升星按「分段累计」：先积满 30 分得 1★，再积满 30 分得 2★，再积 50 得 3★，再积 60 得 4★，再积 100 得 5★。\n   * 存库的是总好感；下表为总分门槛：30 / 60 / 110 / 170 / 270。\n   */\n  const IMPRESSION_FAVOR_STAR_SEGMENTS = [30, 30, 50, 60, 100];\n  const IMPRESSION_FAVOR_STAR_THRESHOLDS = (() => {\n    const out = [];\n    let sum = 0;\n    for(let i = 0; i < IMPRESSION_FAVOR_STAR_SEGMENTS.length; i++){\n      sum += IMPRESSION_FAVOR_STAR_SEGMENTS[i];\n      out.push(sum);\n    }\n    return out;\n  })();\n  const IMPRESSION_FAVOR_CAP = IMPRESSION_FAVOR_STAR_THRESHOLDS[IMPRESSION_FAVOR_STAR_THRESHOLDS.length - 1];\n  const RATE_STEPS = [-1, 0, 0.5, 1, 2, 3, 4, 5];\n  const MEET_CONV_MAX_TURNS = 120;\n  const MEET_CHAT_LLM_MAX_TURNS = 64;\n  /** 气泡内引用预览最大字符数（超出加省略号，与存储的 140 字脱钩） */\n  const MEET_QUOTE_DISPLAY_MAX = 52;\n\n  function meetInboxReadMapClone(){\n    const src = _meetInboxLastReadTs && typeof _meetInboxLastReadTs === 'object' ? _meetInboxLastReadTs : {};\n    return Object.assign({}, src);\n  }\n\n  async function migrateInboxReadBaselineIfNeeded(){\n    const m = meetInboxReadMapClone();\n    const conv = convMapGet();\n    let changed = false;\n    for(const pid of Object.keys(conv || {})){\n      if(Object.prototype.hasOwnProperty.call(m, pid)) continue;\n      const hist = getConvHistory(pid);\n      if(!hist.length) continue;\n      let maxTs = 0;\n      for(const t of hist){\n        maxTs = Math.max(maxTs, Number(t.ts) || 0);\n      }\n      if(maxTs > 0){\n        m[pid] = maxTs;\n        changed = true;\n      }\n    }\n    if(changed){\n      _meetInboxLastReadTs = m;\n      await meetStoreSet(IDB_KEY_MEET_INBOX_READ, m);\n    }\n  }\n\n  function peerHasUnreadFromAssistant(peerId){\n    const id = String(peerId || '');\n    if(!id) return false;\n    const hist = getConvHistory(id);\n    if(!hist.length) return false;\n    const last = hist[hist.length - 1];\n    if(!last || last.role !== 'assistant' || last.recalled) return false;\n    const lastTs = Number(last.ts) || 0;\n    const readTs = Number(meetInboxReadMapClone()[id]) || 0;\n    return lastTs > readTs;\n  }\n\n  function markInboxThreadReadNow(peerId){\n    const id = String(peerId || '');\n    if(!id) return;\n    const hist = getConvHistory(id);\n    let markTs = Date.now();\n    if(hist.length){\n      let maxTs = 0;\n      for(const t of hist){\n        maxTs = Math.max(maxTs, Number(t.ts) || 0);\n      }\n      if(maxTs > 0) markTs = Math.max(maxTs, markTs);\n    }\n    const next = Object.assign({}, meetInboxReadMapClone(), { [id]: markTs });\n    _meetInboxLastReadTs = next;\n    void meetStoreSet(IDB_KEY_MEET_INBOX_READ, next);\n    renderInbox();\n    renderStrangerStack();\n  }\n\n  function halfStepsFromChosenRate(step){\n    const k = step === '0.5' || step === 0.5 ? 0.5 : Number(step);\n    const map = { 0: 0, 0.5: 1, 1: 2, 2: 4, 3: 6, 4: 8, 5: 10 };\n    return map[k] !== undefined ? map[k] : 0;\n  }\n\n  /** 本次结算增加的好感：按「每半颗星」约 1～2 点取平均 1.5，再四舍五入（0→0，½→2，1★→3，…5★→15） */\n  function getFavorDeltaFromRateStep(step){\n    const k = step === '0.5' || step === 0.5 ? 0.5 : Number(step);\n    if(k === -1) return -8;\n    const h = halfStepsFromChosenRate(step);\n    return Math.round(h * 1.5);\n  }\n  function normalizeRateStepInput(v){\n    const k = v === '0.5' || v === 0.5 ? 0.5 : Number(v);\n    if(!Number.isFinite(k)) return null;\n    for(let i = 0; i < RATE_STEPS.length; i++){\n      if(RATE_STEPS[i] === k) return k;\n    }\n    return null;\n  }\n  function nearestRateStepByDelta(delta){\n    const n = Number(delta);\n    if(!Number.isFinite(n)) return null;\n    let bestStep = RATE_STEPS[0];\n    let bestDist = Infinity;\n    for(let i = 0; i < RATE_STEPS.length; i++){\n      const step = RATE_STEPS[i];\n      const d = Math.abs(getFavorDeltaFromRateStep(step) - n);\n      if(d < bestDist){\n        bestDist = d;\n        bestStep = step;\n      }\n    }\n    return bestStep;\n  }\n\n  function starCountFromFavor(favor){\n    const f = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, Math.round(Number(favor) || 0)));\n    let n = 0;\n    for(let i = 0; i < IMPRESSION_FAVOR_STAR_THRESHOLDS.length; i++){\n      if(f >= IMPRESSION_FAVOR_STAR_THRESHOLDS[i]) n = i + 1;\n    }\n    return n;\n  }\n  /** 仅有旧版「星数」无好感数值时，用该星级的最低分回填，避免迁移后掉星 */\n  function minFavorForStoredStars(starCount){\n    const s = Math.min(5, Math.max(0, Math.round(Number(starCount) || 0)));\n    if(s <= 0) return 0;\n    return IMPRESSION_FAVOR_STAR_THRESHOLDS[s - 1];\n  }\n  function syncStarsFromFavor(o){\n    const fm = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, Math.round(Number(o.favorMe) || 0)));\n    const fp = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, Math.round(Number(o.favorPeer) || 0)));\n    o.favorMe = fm;\n    o.favorPeer = fp;\n    o.stars = starCountFromFavor(fm);\n    o.starsFromPeer = starCountFromFavor(fp);\n  }\n\n  function normalizeLikedEntry(o){\n    if(!o || typeof o !== 'object') return null;\n    const out = Object.assign({}, o);\n    const economy = Number(out.favorEconomy) || 0;\n    let favorMe = Number(out.favorMe);\n    if(!Number.isFinite(favorMe)){\n      const leg = Math.min(5, Math.max(0, Number(out.stars) || 0));\n      favorMe = Math.min(IMPRESSION_FAVOR_CAP, minFavorForStoredStars(leg));\n    }else if(economy === 2){\n      favorMe = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, Math.round(favorMe * 10)));\n    }else if(economy === 3){\n      favorMe = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, Math.round(favorMe)));\n    }else{\n      const legacy = Math.round(favorMe);\n      const adapted = legacy <= 50 ? legacy * 10 : legacy;\n      favorMe = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, adapted));\n    }\n    let favorPeer = Number(out.favorPeer);\n    if(!Number.isFinite(favorPeer)){\n      const legp = Math.min(5, Math.max(0, Number(out.starsFromPeer) || 0));\n      favorPeer = Math.min(IMPRESSION_FAVOR_CAP, minFavorForStoredStars(legp));\n    }else if(economy === 2){\n      favorPeer = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, Math.round(favorPeer * 10)));\n    }else if(economy === 3){\n      favorPeer = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, Math.round(favorPeer)));\n    }else{\n      const legacy = Math.round(favorPeer);\n      const adapted = legacy <= 50 ? legacy * 10 : legacy;\n      favorPeer = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, adapted));\n    }\n    out.favorEconomy = 3;\n    out.favorMe = favorMe;\n    out.favorPeer = favorPeer;\n    out.realNameUnlocked = !!out.realNameUnlocked;\n    out.realName = String(out.realName || '').trim().slice(0, 24);\n    syncStarsFromFavor(out);\n    return out;\n  }\n  function normalizePeerNameInput(v){\n    return String(v == null ? '' : v)\n      .replace(/\\s+/g, '')\n      .replace(/[^\\u4e00-\\u9fa5A-Za-z0-9·]/g, '')\n      .trim()\n      .slice(0, 24);\n  }\n  function isLikelyAliasName(v){\n    const s = String(v || '').trim();\n    if(!s) return true;\n    if(s.length <= 2 && /[A-Za-z]/.test(s)) return true;\n    if(/[._\\-]/.test(s)) return true;\n    return false;\n  }\n  function generatePeerRealNameCandidates(u){\n    const SURNAMES = ['王','李','张','刘','陈','杨','黄','赵','周','吴','徐','孙','胡','朱','高','林','何','郭','马','罗'];\n    const GIVEN_F = ['若宁','可欣','书瑶','雨桐','嘉宁','清妍','以晴','知夏','安然','语汐','星语','沐妍'];\n    const GIVEN_M = ['子谦','景行','亦辰','承泽','嘉屿','知远','时予','闻舟','泽言','奕辰','明川','予安'];\n    const GIVEN_N = ['知遥','安屿','星野','言初','清和','若白','时安','朝暮','木夏','予澄','云舒','念舟'];\n    const seed = String((u && u.id) || '') + '|' + String((u && u.name) || '') + '|' + String((u && u.city) || '') + '|' + String((u && u.tag) || '');\n    const h = hash32(seed);\n    const g = String((u && u.gender) || '').trim();\n    const pool = g === '女' ? GIVEN_F : (g === '男' ? GIVEN_M : GIVEN_N);\n    const out = [];\n    const rawAlias = String((u && u.name) || '').trim();\n    if(rawAlias && !isLikelyAliasName(rawAlias)){\n      out.push(normalizePeerNameInput(rawAlias));\n    }\n    for(let i = 0; i < 8; i++){\n      const sur = SURNAMES[(h + i * 7) % SURNAMES.length];\n      const given = pool[((h >>> 4) + i * 5) % pool.length];\n      out.push(normalizePeerNameInput(sur + given));\n    }\n    return out.filter(Boolean);\n  }\n  function nameKey(v){\n    return normalizePeerNameInput(v).toLowerCase();\n  }\n  async function collectReservedCharNameKeys(excludePeerId){\n    const sid = String(excludePeerId || '');\n    const set = new Set();\n    liked.forEach(x => {\n      if(!x || String(x.id || '') === sid) return;\n      const rk = nameKey(x.realName || '');\n      if(rk) set.add(rk);\n    });\n    try{\n      const db = await openChillIdb();\n      const rows = await new Promise((resolve, reject) => {\n        try{\n          const req = db.transaction('characters', 'readonly').objectStore('characters').getAll();\n          req.onsuccess = () => resolve(Array.isArray(req.result) ? req.result : []);\n          req.onerror = () => reject(req.error);\n        }catch(e){ reject(e); }\n      });\n      rows.forEach(r => {\n        const rk = nameKey(r && r.name);\n        if(rk) set.add(rk);\n      });\n    }catch(_){}\n    return set;\n  }\n  async function pickAvailablePeerRealName(u, preferredName, excludePeerId){\n    const reserve = await collectReservedCharNameKeys(excludePeerId || (u && u.id));\n    const candidates = [];\n    if(preferredName) candidates.push(normalizePeerNameInput(preferredName));\n    candidates.push(...generatePeerRealNameCandidates(u));\n    const uniq = [];\n    const seen = new Set();\n    candidates.forEach(n => {\n      const nn = normalizePeerNameInput(n);\n      const k = nameKey(nn);\n      if(!nn || !k || seen.has(k)) return;\n      seen.add(k);\n      uniq.push(nn);\n    });\n    for(let i = 0; i < uniq.length; i++){\n      const k = nameKey(uniq[i]);\n      if(!reserve.has(k)) return uniq[i];\n    }\n    const base = uniq[0] || '匿名用户';\n    const stem = normalizePeerNameInput(base).slice(0, 20) || '匿名用户';\n    for(let i = 2; i <= 99; i++){\n      const trial = normalizePeerNameInput(stem + i);\n      const k = nameKey(trial);\n      if(k && !reserve.has(k)) return trial;\n    }\n    return stem || '匿名用户';\n  }\n  function ensurePeerRealName(u){\n    if(!u || typeof u !== 'object') return '';\n    const name = String(u.realName || '').trim();\n    if(name) return name.slice(0, 24);\n    const gen = generatePeerRealNameCandidates(u)[0] || '匿名用户';\n    u.realName = gen;\n    return gen;\n  }\n  function getPeerDisplayName(u){\n    if(!u || typeof u !== 'object') return 'Ta';\n    if(u.realNameUnlocked){\n      const real = ensurePeerRealName(u);\n      if(real) return real;\n    }\n    const alias = String(u.name || '').trim();\n    return alias || 'Ta';\n  }\n  function saveLiked(){\n    void meetStoreSet(IDB_KEY_MEET_LIKED, liked);\n  }\n  function peerStarsSeed(id){\n    let h = 2166136261;\n    const s = String(id);\n    for(let i = 0; i < s.length; i++){\n      h ^= s.charCodeAt(i);\n      h = Math.imul(h, 16777619);\n    }\n    return (Math.abs(h) >>> 0) % 4;\n  }\n  function peerFavorSeed(id){\n    return Math.min(IMPRESSION_FAVOR_CAP, peerStarsSeed(id) * 15);\n  }\n  let strangers = [];\n  let strangerExpanded = false;\n\n  const DM_MATCH_ONLY = 'match_only';\n  const DM_STRANGERS_OK = 'strangers_ok';\n  let _meetDmPolicy = DM_STRANGERS_OK;\n\n  const STRANGER_MIN_GAP_MS = 4 * 60 * 60 * 1000;\n  const STRANGER_MAX_GAP_MS = 7 * 60 * 60 * 1000;\n  const STRANGER_MAX_INBOX = 24;\n\n  const STRANGER_BATCH_SYSTEM_PROMPT =\n    'You output ONLY valid JSON (no markdown, no code fences, no commentary). ' +\n    'Return an object {\"items\":[...]} with 1 to 5 items (vary the count). Each item: ' +\n    'id (string, unique random alphanumeric slug), name (short alias like \"M.\"), ' +\n    'preview (Chinese, one short first DM line, warm slow-dating tone, single line, no line breaks). ' +\n    'All id, name, and preview must be unique within items. ' +\n    'Do not reuse or closely copy any id, name, or preview from blockedIds, blockedNames, or blockedPreviews in the user message.';\n\n  function getDmPolicy(){\n    const v = _meetDmPolicy;\n      if(v === DM_MATCH_ONLY || v === DM_STRANGERS_OK) return v;\n    return DM_STRANGERS_OK;\n  }\n\n  function setDmPolicy(v){\n    _meetDmPolicy = v === DM_MATCH_ONLY ? DM_MATCH_ONLY : DM_STRANGERS_OK;\n    void meetStoreSet(IDB_KEY_MEET_DM, _meetDmPolicy);\n  }\n\n  function syncDmPolicyUi(){\n    const pol = getDmPolicy();\n    const list = document.getElementById('dm-policy-list');\n    if(!list) return;\n    list.querySelectorAll('input[name=\"dm-policy\"]').forEach(inp => {\n      inp.checked = inp.value === pol;\n    });\n    list.querySelectorAll('.ma-radio-pill').forEach(lab => {\n      const inp = lab.querySelector('input[name=\"dm-policy\"]');\n      lab.classList.toggle('is-selected', !!(inp && inp.checked));\n    });\n  }\n\n  function bindDmPolicyRadios(){\n    const list = document.getElementById('dm-policy-list');\n    if(!list) return;\n    list.addEventListener('change', (e) => {\n      const t = e.target;\n      if(t.name !== 'dm-policy' || t.type !== 'radio' || !t.checked) return;\n      setDmPolicy(t.value);\n      syncDmPolicyUi();\n      strangerExpanded = false;\n      renderInbox();\n      if(t.value === DM_STRANGERS_OK) void maybeAppendStrangerBatch();\n    });\n    syncDmPolicyUi();\n  }\n\n  const $deck = document.getElementById('deck');\n  const $listInbox = document.getElementById('list-inbox');\n  const $modal = document.getElementById('modal-rate');\n  const $modalUnmatch = document.getElementById('modal-unmatch');\n  const $modalBubbleAction = document.getElementById('modal-bubble-action');\n  const $modalNameUnlock = document.getElementById('modal-name-unlock');\n  const $modalPeerMood = document.getElementById('modal-peer-mood');\n  const $modalCompatQuiz = document.getElementById('modal-compat-quiz');\n  const $modalMutualMilestone = document.getElementById('modal-mutual-milestone');\n  const $modalPeerHeartLetter = document.getElementById('modal-peer-heart-letter');\n  let currentChat = null;\n  let selectedRateStep = null;\n  let discoverBusy = false;\n  let dailyRefreshBusy = false;\n  let strangerInboxBusy = false;\n  let currentQuoteRef = null;\n  let currentEditTurnId = null;\n  let bubbleActionCtx = null;\n  let multiSelectMode = false;\n  let multiSelectTurnIds = new Set();\n  let currentCompatQuiz = null;\n  let compatQuizOffset = 0;\n  const _compatLlmDeck = {};\n  let _compatQuizRefreshBusy = false;\n  let pendingNameUnlockPeerId = '';\n\n  function esc(s){ const d=document.createElement('div'); d.textContent=s; return d.innerHTML; }\n\n  let _meetToastTimer = 0;\n  function meetToastShow(msg, durationMs){\n    const ms = durationMs == null ? 2400 : Math.max(800, Number(durationMs) || 2400);\n    const el = document.getElementById('ma-toast');\n    if(el){\n      el.textContent = msg;\n      el.classList.add('show');\n      clearTimeout(_meetToastTimer);\n      _meetToastTimer = setTimeout(() => { el.classList.remove('show'); }, ms);\n      return;\n    }\n    try{\n      if(typeof Toast !== 'undefined' && Toast && typeof Toast.show === 'function') Toast.show(msg, ms);\n    }catch(_){}\n  }\n\n  function resolveChatForStarGates(){\n    if(!currentChat) return null;\n    if(currentChat.isStranger) return currentChat;\n    const row = liked.find(x => String(x.id) === String(currentChat.id));\n    return row || currentChat;\n  }\n\n  function isMutualStarsAtLeast(chatObj, n){\n    if(!chatObj || chatObj.isStranger) return false;\n    const sm = Number(chatObj.stars) || 0;\n    const sp = Number(chatObj.starsFromPeer) || 0;\n    return sm >= n && sp >= n;\n  }\n\n  function canViewPeerMood(chatObj){\n    return isMutualStarsAtLeast(chatObj, 2);\n  }\n\n  const CHILL_OS_DB_NAME = 'chillOS';\n  const CHILL_OS_DB_VERSION = (window.parent && window.parent.DB && window.parent.DB.VERSION) || 9;\n\n  const CHAT_URL_SUFFIXES = [\n    '/v1/chat/completions','/v1/completions','/v1/embeddings','/v1/models',\n    '/chat/completions','/completions','/embeddings','/models','/v1',\n  ];\n  function chillApiRootUrl(input){\n    let url = String(input || '').trim().replace(/\\/+$/, '');\n    for(const suf of CHAT_URL_SUFFIXES){\n      if(url.endsWith(suf)){\n        url = url.slice(0, -suf.length);\n        break;\n      }\n    }\n    return url;\n  }\n  function chillChatCompletionsUrl(input){\n    var url = String(input || '').trim().replace(/\\/+$/, '');\n    if(/\\/chat\\/completions$/.test(url)) return url;\n    if(/\\/v1$/.test(url)) return url + '/chat/completions';\n    return chillApiRootUrl(input) + '/chat/completions';\n  }\n\n  let _chillIdb = null;\n  function openChillIdb(){\n    return new Promise((resolve, reject) => {\n      if(_chillIdb) return resolve(_chillIdb);\n      const req = indexedDB.open(CHILL_OS_DB_NAME, CHILL_OS_DB_VERSION);\n      req.onerror = () => reject(req.error || new Error('IndexedDB open failed'));\n      req.onupgradeneeded = (e) => {\n        const db = e.target.result;\n        const old = e.oldVersion;\n        if(old < 1){\n          db.createObjectStore('settings', { keyPath: 'key' });\n          db.createObjectStore('assets', { keyPath: 'key' });\n          const ap = db.createObjectStore('api_profiles', { keyPath: 'id', autoIncrement: true });\n          ap.createIndex('isActive', 'isActive', { unique: false });\n        }\n        if(old < 2){\n          if(!db.objectStoreNames.contains('characters'))\n            db.createObjectStore('characters', { keyPath: 'id', autoIncrement: true });\n        }\n        if(old < 3){\n          if(!db.objectStoreNames.contains('groups'))\n            db.createObjectStore('groups', { keyPath: 'id' });\n        }\n        if(old < 4){\n          if(!db.objectStoreNames.contains('chat_bindings'))\n            db.createObjectStore('chat_bindings', { keyPath: 'charId' });\n        }\n        if(old < 5){\n          if(!db.objectStoreNames.contains('messages')){\n            const ms = db.createObjectStore('messages', { keyPath: 'id', autoIncrement: true });\n            ms.createIndex('charId', 'charId', { unique: false });\n          }\n        }\n        if(old < 7){\n          // 与主文件 DB 升级一致：必须含 world_info，否则若 iframe 抢先完成首次 open，会永久缺表导致遇见世界书为空\n          if(!db.objectStoreNames.contains('world_info'))\n            db.createObjectStore('world_info', { keyPath: 'id', autoIncrement: true });\n          if(!db.objectStoreNames.contains('settings'))\n            db.createObjectStore('settings', { keyPath: 'key' });\n          if(!db.objectStoreNames.contains('assets'))\n            db.createObjectStore('assets', { keyPath: 'key' });\n          if(!db.objectStoreNames.contains('api_profiles')){\n            const ap = db.createObjectStore('api_profiles', { keyPath: 'id', autoIncrement: true });\n            ap.createIndex('isActive', 'isActive', { unique: false });\n          }\n          if(!db.objectStoreNames.contains('characters'))\n            db.createObjectStore('characters', { keyPath: 'id', autoIncrement: true });\n          if(!db.objectStoreNames.contains('groups'))\n            db.createObjectStore('groups', { keyPath: 'id' });\n          if(!db.objectStoreNames.contains('chat_bindings'))\n            db.createObjectStore('chat_bindings', { keyPath: 'charId' });\n          if(!db.objectStoreNames.contains('messages')){\n            const ms = db.createObjectStore('messages', { keyPath: 'id', autoIncrement: true });\n            ms.createIndex('charId', 'charId', { unique: false });\n          }\n        }\n        if(old < 8){\n          if(!db.objectStoreNames.contains('meet'))\n            db.createObjectStore('meet', { keyPath: 'key' });\n          const tx = e.target.transaction;\n          if(db.objectStoreNames.contains('settings') && db.objectStoreNames.contains('meet')){\n            const st = tx.objectStore('settings');\n            const mt = tx.objectStore('meet');\n            st.openCursor().onsuccess = (ev) => {\n              const cursor = ev.target.result;\n              if(!cursor) return;\n              const row = cursor.value;\n              const k = row && row.key;\n              if(typeof k === 'string' && k.indexOf('meet_') === 0){\n                mt.put({ key: k, value: row.value });\n                cursor.delete();\n              }\n              cursor.continue();\n            };\n          }\n        }\n      };\n      req.onsuccess = () => {\n        _chillIdb = req.result;\n        resolve(_chillIdb);\n      };\n    });\n  }\n\n  async function getActiveApiProfileFromMain(){\n    const db = await openChillIdb();\n    return new Promise((resolve, reject) => {\n      let req;\n      try{\n        req = db.transaction('api_profiles', 'readonly').objectStore('api_profiles').getAll();\n      }catch(e){\n        reject(e);\n        return;\n      }\n      req.onsuccess = () => {\n        const all = req.result || [];\n        resolve(all.find(p => p && p.isActive) || null);\n      };\n      req.onerror = () => reject(req.error);\n    });\n  }\n\n  async function meetStoreGet(key){\n    const db = await openChillIdb();\n    return new Promise((resolve, reject) => {\n      try{\n        const req = db.transaction('meet', 'readonly').objectStore('meet').get(key);\n        req.onsuccess = () => resolve(req.result ? req.result.value : null);\n        req.onerror = () => reject(req.error);\n      }catch(e){ reject(e); }\n    });\n  }\n\n  async function meetStoreSet(key, value){\n    const db = await openChillIdb();\n    return new Promise((resolve, reject) => {\n      try{\n        const req = db.transaction('meet', 'readwrite').objectStore('meet').put({ key, value });\n        req.onsuccess = () => resolve();\n        req.onerror = () => reject(req.error);\n      }catch(e){ reject(e); }\n    });\n  }\n\n  function compressImageFile(file, maxPx, quality){\n    return new Promise((resolve, reject) => {\n      const reader = new FileReader();\n      reader.onload = e => {\n        const img = new Image();\n        img.onload = () => {\n          let w = img.width;\n          let h = img.height;\n          if(w > maxPx || h > maxPx){\n            if(w > h){ h = Math.round(h * maxPx / w); w = maxPx; }\n            else{ w = Math.round(w * maxPx / h); h = maxPx; }\n          }\n          const canvas = document.createElement('canvas');\n          canvas.width = w;\n          canvas.height = h;\n          const ctx = canvas.getContext('2d');\n          if(file.type !== 'image/png'){\n            ctx.fillStyle = '#FFFFFF';\n            ctx.fillRect(0, 0, w, h);\n          }\n          ctx.drawImage(img, 0, 0, w, h);\n          const outType = file.type === 'image/png' ? 'image/png' : 'image/jpeg';\n          const outQuality = outType === 'image/png' ? undefined : quality;\n          canvas.toBlob(blob => {\n            if(blob) resolve(blob);\n            else reject(new Error('toBlob failed'));\n          }, outType, outQuality);\n        };\n        img.onerror = () => reject(new Error('image decode failed'));\n        img.src = e.target.result;\n      };\n      reader.onerror = () => reject(new Error('read failed'));\n      reader.readAsDataURL(file);\n    });\n  }\n\n  function revokeMeetAvatarObjectUrl(){\n    if(_meetAvatarObjectUrl){\n      try{ URL.revokeObjectURL(_meetAvatarObjectUrl); }catch(_){}\n      _meetAvatarObjectUrl = null;\n    }\n  }\n\n  async function meetReadAssetBlob(key){\n    const db = await openChillIdb();\n    return new Promise((resolve, reject) => {\n      try{\n        const req = db.transaction('assets', 'readonly').objectStore('assets').get(key);\n        req.onsuccess = () => {\n          const r = req.result;\n          resolve(r && r.blob ? r.blob : null);\n        };\n        req.onerror = () => reject(req.error);\n      }catch(e){ reject(e); }\n    });\n  }\n\n  async function meetAssetPutBlob(key, blob){\n    const db = await openChillIdb();\n    return new Promise((resolve, reject) => {\n      try{\n        const req = db.transaction('assets', 'readwrite').objectStore('assets').put({\n          key,\n          blob,\n          mimeType: blob.type || 'image/jpeg',\n          size: blob.size,\n          updatedAt: Date.now(),\n        });\n        req.onsuccess = () => resolve();\n        req.onerror = () => reject(req.error);\n      }catch(e){ reject(e); }\n    });\n  }\n\n  async function refreshMeetAvatarUi(){\n    const wrap = document.getElementById('meet-avatar-wrap');\n    const img = document.getElementById('meet-avatar-img');\n    if(!wrap || !img) return;\n    revokeMeetAvatarObjectUrl();\n    let blob = null;\n    try{\n      blob = await meetReadAssetBlob(ASSET_KEY_MEET_AVATAR);\n    }catch(_){}\n    if(!blob){\n      img.removeAttribute('src');\n      wrap.classList.remove('has-photo');\n      return;\n    }\n    _meetAvatarObjectUrl = URL.createObjectURL(blob);\n    img.src = _meetAvatarObjectUrl;\n    wrap.classList.add('has-photo');\n  }\n\n  async function saveMeetAvatarFromFile(file){\n    const blob = await compressImageFile(file, 400, 0.85);\n    await meetAssetPutBlob(ASSET_KEY_MEET_AVATAR, blob);\n    await refreshMeetAvatarUi();\n  }\n\n  async function migrateLegacyMeetLocalStorage(){\n    const rows = [\n      [IDB_KEY_MEET_LIKED, 'chillLikedV1', 'json'],\n      [IDB_KEY_MEET_CONV, 'chillMatchConvV1', 'json'],\n      [IDB_KEY_MEET_PROFILE, 'chillUserProfile', 'json'],\n      [IDB_KEY_MEET_BIRTH, 'chillNatalBirth', 'json'],\n      [IDB_KEY_MEET_DM, 'chillDmPolicy', 'dm'],\n      [IDB_KEY_MEET_STRANGERS, 'chillStrangersInboxV1', 'json'],\n      [IDB_KEY_MEET_STRANGER_DUE, 'chillStrangerNextDueV1', 'num'],\n      [IDB_KEY_MEET_CHAT_PERSONA, 'chillMeetChatPersonaV1', 'json'],\n    ];\n    for(const [idbKey, lsKey, typ] of rows){\n      const existing = await meetStoreGet(idbKey);\n      if(existing != null) continue;\n      const raw = localStorage.getItem(lsKey);\n      if(raw == null || raw === '') continue;\n      try{\n        let value;\n        if(typ === 'dm'){\n          if(raw !== DM_MATCH_ONLY && raw !== DM_STRANGERS_OK) continue;\n          value = raw;\n        }else if(typ === 'num'){\n          const n = Number(raw);\n          if(!Number.isFinite(n) || n <= 0){\n            localStorage.removeItem(lsKey);\n            continue;\n          }\n          value = n;\n        }else{\n          value = JSON.parse(raw);\n        }\n        await meetStoreSet(idbKey, value);\n        localStorage.removeItem(lsKey);\n      }catch(_){}\n    }\n  }\n\n  function normalizeMutualMilestoneToastMap(raw){\n    const out = {};\n    if(!raw || typeof raw !== 'object') return out;\n    Object.keys(raw).forEach(k => {\n      const v = raw[k];\n      if(!v || typeof v !== 'object') return;\n      out[String(k)] = { m2: !!v.m2, m3: !!v.m3 };\n    });\n    return out;\n  }\n\n  function persistMutualMilestoneToastMap(){\n    void meetStoreSet(IDB_KEY_MEET_MUTUAL_MILESTONE_TOAST, _mutualMilestoneToastMap);\n  }\n\n  function tryFlushMutualMilestoneToastQueue(){\n    if(_mutualMilestoneToastOpen) return;\n    if(!_mutualMilestoneToastQueue.length) return;\n    const cid = currentChat && !currentChat.isStranger ? String(currentChat.id) : '';\n    let pickIdx = -1;\n    for(let i = 0; i < _mutualMilestoneToastQueue.length; i++){\n      const next = _mutualMilestoneToastQueue[i];\n      if(next.kind === 'm4' && cid && String(next.peerId) !== cid) continue;\n      pickIdx = i;\n      break;\n    }\n    if(pickIdx < 0) return;\n    const next = _mutualMilestoneToastQueue.splice(pickIdx, 1)[0];\n    if(next.kind === 'm4'){\n      void openPeerHeartLetterFlow(next.peerId, {});\n      return;\n    }\n    openMutualMilestoneToast(next.kind, next.peerId);\n  }\n\n  function openMutualMilestoneToast(kind, peerId){\n    const overlay = document.getElementById('modal-mutual-milestone');\n    const tEl = document.getElementById('mutual-milestone-title');\n    const bEl = document.getElementById('mutual-milestone-body');\n    if(!overlay || !tEl || !bEl) return;\n    const pid = String(peerId || '');\n    if(!pid) return;\n    const rec = Object.assign({}, _mutualMilestoneToastMap[pid] || {});\n    if(kind === 'm2'){\n      if(rec.m2){\n        tryFlushMutualMilestoneToastQueue();\n        return;\n      }\n      rec.m2 = true;\n      _mutualMilestoneToastMap[pid] = rec;\n      persistMutualMilestoneToastMap();\n      tEl.textContent = '互相 2★ 了';\n      bEl.textContent = '你们对彼此的好感都到 2 星了，可以在聊天里查看 Ta 的心声与状态（mood）。';\n    }else if(kind === 'm3'){\n      if(rec.m3){\n        tryFlushMutualMilestoneToastQueue();\n        return;\n      }\n      rec.m3 = true;\n      _mutualMilestoneToastMap[pid] = rec;\n      persistMutualMilestoneToastMap();\n      tEl.textContent = '互相 3★ 了';\n      bEl.textContent = '你们对彼此都 3 星了，可以打开默契问答玩一玩。';\n    }else return;\n    _mutualMilestoneToastOpen = true;\n    overlay.classList.add('open');\n  }\n\n  function closeMutualMilestoneToast(){\n    const el = document.getElementById('modal-mutual-milestone');\n    if(el) el.classList.remove('open');\n    _mutualMilestoneToastOpen = false;\n    tryFlushMutualMilestoneToastQueue();\n  }\n\n  function maybeEnqueueMutualStarMilestones(u, prevSm, prevSp){\n    if(!u || u.isStranger) return;\n    const peerId = String(u.id || '');\n    if(!peerId) return;\n    const pms = Math.min(5, Math.max(0, Number(prevSm) || 0));\n    const psp = Math.min(5, Math.max(0, Number(prevSp) || 0));\n    const ns = Math.min(5, Math.max(0, Number(u.stars) || 0));\n    const np = Math.min(5, Math.max(0, Number(u.starsFromPeer) || 0));\n    const pm2 = pms >= 2 && psp >= 2;\n    const pm3 = pms >= 3 && psp >= 3;\n    const pm4 = pms >= 4 && psp >= 4;\n    const nm2 = ns >= 2 && np >= 2;\n    const nm3 = ns >= 3 && np >= 3;\n    const nm4 = ns >= 4 && np >= 4;\n    const rec = _mutualMilestoneToastMap[peerId] || {};\n    const need2 = !pm2 && nm2 && !rec.m2;\n    const need3 = !pm3 && nm3 && !rec.m3;\n    const hasHeart = peerHeartLetterHasChar(peerId);\n    const need4 = !pm4 && nm4 && !hasHeart;\n    if(need2) _mutualMilestoneToastQueue.push({ kind: 'm2', peerId });\n    if(need3) _mutualMilestoneToastQueue.push({ kind: 'm3', peerId });\n    if(need4 && !_mutualMilestoneToastQueue.some(x => x.kind === 'm4' && x.peerId === peerId))\n      _mutualMilestoneToastQueue.push({ kind: 'm4', peerId });\n    tryFlushMutualMilestoneToastQueue();\n  }\n\n  function normalizePeerHeartLetterMap(raw){\n    const out = {};\n    if(!raw || typeof raw !== 'object') return out;\n    Object.keys(raw).forEach(k => {\n      const v = raw[k];\n      if(!v || typeof v !== 'object') return;\n      const charText = String(v.charText || '').trim();\n      const kr = String(v.userResponseKind || 'pending');\n      const kind = kr === 'replied' || kr === 'skipped' || kr === 'pending' ? kr : 'pending';\n      out[String(k)] = {\n        charText: charText.slice(0, 900),\n        relationMemo: String(v.relationMemo || '').trim().slice(0, 650),\n        userResponseKind: kind,\n        userText: String(v.userText || '').trim().slice(0, 500),\n        ts: Number(v.ts) || 0,\n      };\n    });\n    return out;\n  }\n\n  function persistPeerHeartLetterMap(){\n    void meetStoreSet(IDB_KEY_MEET_PEER_HEART_LETTER, _peerHeartLetterMap);\n  }\n\n  function peerHeartLetterHasChar(peerId){\n    const r = _peerHeartLetterMap[String(peerId || '')];\n    return !!(r && String(r.charText || '').trim());\n  }\n\n  function setPeerHeartLetterRecord(peerId, patch){\n    const id = String(peerId || '');\n    if(!id) return;\n    const prev = _peerHeartLetterMap[id] && typeof _peerHeartLetterMap[id] === 'object'\n      ? _peerHeartLetterMap[id]\n      : {};\n    const next = Object.assign({}, prev, patch);\n    next.ts = Number(patch && patch.ts != null ? patch.ts : Date.now()) || Date.now();\n    if(next.charText != null) next.charText = String(next.charText).trim().slice(0, 900);\n    if(next.relationMemo != null) next.relationMemo = String(next.relationMemo).trim().slice(0, 650);\n    if(next.userText != null) next.userText = String(next.userText).trim().slice(0, 500);\n    const kr = String(next.userResponseKind || 'pending');\n    next.userResponseKind = kr === 'replied' || kr === 'skipped' || kr === 'pending' ? kr : 'pending';\n    const copy = Object.assign({}, _peerHeartLetterMap);\n    copy[id] = next;\n    _peerHeartLetterMap = copy;\n    persistPeerHeartLetterMap();\n  }\n\n  async function hydrateMeetStateFromIdb(){\n    const lj = await meetStoreGet(IDB_KEY_MEET_LIKED);\n    if(Array.isArray(lj)) liked = lj.map(normalizeLikedEntry).filter(Boolean);\n    else liked = [];\n\n    const st = await meetStoreGet(IDB_KEY_MEET_STRANGERS);\n    strangers = [];\n    if(Array.isArray(st)){\n      st.forEach((o, idx) => {\n        const n = normalizeStrangerInboxEntry(o, idx);\n        if(n) strangers.push(n);\n      });\n      strangers = strangers.slice(-STRANGER_MAX_INBOX);\n    }\n\n    let conv = await meetStoreGet(IDB_KEY_MEET_CONV);\n    if(!conv || typeof conv !== 'object') conv = {};\n    _meetConvMap = conv;\n\n    let inboxRead = await meetStoreGet(IDB_KEY_MEET_INBOX_READ);\n    if(!inboxRead || typeof inboxRead !== 'object') inboxRead = {};\n    _meetInboxLastReadTs = inboxRead;\n    await migrateInboxReadBaselineIfNeeded();\n\n    const prof = await meetStoreGet(IDB_KEY_MEET_PROFILE);\n    _meetUserProfile = normalizeUserProfile(prof && typeof prof === 'object' ? prof : null);\n\n    const birth = await meetStoreGet(IDB_KEY_MEET_BIRTH);\n    if(birth && typeof birth === 'object' && birth.date)\n      _meetBirth = { date: String(birth.date), time: birth.time ? String(birth.time) : '' };\n    else\n      _meetBirth = null;\n\n    const dm = await meetStoreGet(IDB_KEY_MEET_DM);\n    _meetDmPolicy = dm === DM_MATCH_ONLY ? DM_MATCH_ONLY : DM_STRANGERS_OK;\n\n    const due = await meetStoreGet(IDB_KEY_MEET_STRANGER_DUE);\n    const dn = Number(due);\n    _meetStrangerNextDue = Number.isFinite(dn) && dn > 0 ? dn : 0;\n\n    const pm = await meetStoreGet(IDB_KEY_MEET_CHAT_PERSONA);\n    _meetChatPersonaMap = pm && typeof pm === 'object' ? pm : {};\n\n    const wb = await meetStoreGet(IDB_KEY_MEET_WB_BIND);\n    _meetWbBindMap = normalizeWbBindMap(wb);\n    const wbf = await meetStoreGet(IDB_KEY_MEET_WB_FREETEXT);\n    _meetWorldviewFreetext = String(wbf || '').trim().slice(0, 1200);\n    _wbMainEntriesCache = await readMainWorldInfoEntries();\n\n    const selfName = await meetStoreGet(IDB_KEY_MEET_SELF_NAME);\n    _meetSelfName = String(selfName || '').trim().slice(0, 24);\n\n    const mm = await meetStoreGet(IDB_KEY_MEET_MUTUAL_MILESTONE_TOAST);\n    _mutualMilestoneToastMap = normalizeMutualMilestoneToastMap(mm);\n\n    const phl = await meetStoreGet(IDB_KEY_MEET_PEER_HEART_LETTER);\n    _peerHeartLetterMap = normalizePeerHeartLetterMap(phl);\n\n  }\n\n  const DISCOVER_SYSTEM_PROMPT =\n    'You output ONLY valid JSON (no markdown, no code fences, no commentary). ' +\n    'Return an object: {\"cards\":[...]} with 10 to 14 items. Each item: ' +\n    'id (string, unique), name (internet nickname, 2-12 chars, style can be ANY: cute, quirky, cool, poetic, abstract, minimal, mixed EN/CN etc; NOT legal real full name), age (integer 18-35), ' +\n    'gender (string: \"男\", \"女\", or \"\"), city (Chinese city name), ' +\n    'match (integer 55-96), astro (integer 52-94), bio (Chinese, 1-2 sentences, warm slow-dating tone), ' +\n    'tag (short Chinese interest label), profileLine (Chinese short subtitle 8-24 chars, persona-like, no punctuation at end). ' +\n    'Also per card (same JSON object): synastryScore (integer 48-92, light synastry vibe index vs the viewer), ' +\n    'synastryLine (Chinese, one short line under 40 chars: rapport / chat angle, consistent with bio), ' +\n    'peerSunSign (integer 0-11 only: 0白羊 1金牛 2双子 3巨蟹 4狮子 5处女 6天秤 7天蝎 8射手 9摩羯 10水瓶 11双鱼; plausible for the persona). ' +\n    'If the user message says viewerProfileFilled is true and gives viewerProfileNarrative: treat that narrative as the anchor from the viewer\\'s \"我的\" profile. ' +\n    'At least half the cards should clearly fit that narrative (overlapping interests, compatible dating intent, same/nearby city when viewer named a city, bios that feel written FOR this viewer). ' +\n    'If the user message also provides worldbookNarrative / worldbookBoundEntries, treat them as active world constraints: card city, tag, bio tone, and relationship rhythm should align with those settings while keeping each person distinct. ' +\n    'The rest can add pleasant variety. Never ignore stated 想找/兴趣标签 when present. ' +\n    'If viewerProfileFilled is false, keep varied plausible strangers. Always keep individuals distinct.';\n\n  function parseDiscoverAssistantJson(raw){\n    let s = String(raw || '').trim();\n    const fence = /```(?:json)?\\s*([\\s\\S]*?)```/i;\n    const fm = s.match(fence);\n    if(fm) s = fm[1].trim();\n    const i0 = s.indexOf('{');\n    const i1 = s.lastIndexOf('}');\n    if(i0 >= 0 && i1 > i0) s = s.slice(i0, i1 + 1);\n    const data = JSON.parse(s);\n    const arr = Array.isArray(data.cards) ? data.cards : Array.isArray(data) ? data : [];\n    return arr;\n  }\n\n  function assertChatProfile(profile){\n    if(!profile) throw new Error('未找到当前 API 配置');\n    if(!profile.url || !String(profile.url).trim())\n      throw new Error('当前 API 配置缺少接口地址');\n    if(!profile.key || !String(profile.key).trim())\n      throw new Error('当前 API 配置缺少密钥');\n    if(!profile.model || !String(profile.model).trim())\n      throw new Error('当前 API 配置缺少模型名');\n  }\n\n  async function chillLlmComplete(profile, messages, opt){\n    assertChatProfile(profile);\n    const temperature = opt && opt.temperature != null\n      ? opt.temperature\n      : Math.min(2, Math.max(0, parseFloat(profile.temp) || 0.85));\n    const timeoutMs = opt && opt.timeoutMs != null ? opt.timeoutMs : 90000;\n    const url = chillChatCompletionsUrl(profile.url);\n    const ctrl = typeof AbortController !== 'undefined' ? new AbortController() : null;\n    const tid = ctrl ? window.setTimeout(() => ctrl.abort(), timeoutMs) : 0;\n    let res;\n    try{\n      res = await fetch(url, {\n        method: 'POST',\n        headers: {\n          'Content-Type': 'application/json',\n          Authorization: 'Bearer ' + String(profile.key).trim(),\n        },\n        body: JSON.stringify({\n          model: String(profile.model).trim(),\n          messages,\n          temperature,\n        }),\n        signal: ctrl ? ctrl.signal : undefined,\n      });\n    }finally{\n      if(tid) window.clearTimeout(tid);\n    }\n    if(!res.ok){\n      const t = await res.text().catch(() => '');\n      throw new Error(t || ('HTTP ' + res.status));\n    }\n    const data = await res.json().catch(() => ({}));\n    const text = data.choices && data.choices[0] && data.choices[0].message && data.choices[0].message.content;\n    if(!text || !String(text).trim())\n      throw new Error('模型未返回文本内容');\n    return String(text).trim();\n  }\n\n  function isDiscoverProfileSubstantive(p){\n    if(!p || typeof p !== 'object') return false;\n    const hasSeek = (p.seekingSelected && p.seekingSelected.length) || (p.seekingOther && String(p.seekingOther).trim());\n    const hasTags = (p.tagsSelected && p.tagsSelected.length) || (p.tagsOther && String(p.tagsOther).trim());\n    return !!(\n      (p.nick && String(p.nick).trim()) ||\n      (p.city && String(p.city).trim()) ||\n      (p.bio && String(p.bio).trim()) ||\n      (p.gender && String(p.gender).trim()) ||\n      (p.mbti && String(p.mbti).trim()) ||\n      hasSeek ||\n      hasTags\n    );\n  }\n\n  function buildDiscoverViewerNarrative(p, birth){\n    if(!p || typeof p !== 'object') return '';\n    const lines = [];\n    const trim = s => String(s == null ? '' : s).replace(/\\s+/g, ' ').trim();\n    if(trim(p.nick)) lines.push('昵称：' + trim(p.nick).slice(0, 32));\n    if(trim(p.gender)) lines.push('性别/展示：' + trim(p.gender).slice(0, 8));\n    if(trim(p.city)) lines.push('城市（推荐对方的 city 可优先同城/邻近/气质与该城生活感一致）：' + trim(p.city).slice(0, 24));\n    if(trim(p.bio)) lines.push('自我介绍：' + trim(p.bio).slice(0, 420));\n    if(trim(p.mbti)) lines.push('MBTI：' + trim(p.mbti));\n    if(Array.isArray(p.seekingSelected) && p.seekingSelected.length)\n      lines.push('想找（选项）：' + p.seekingSelected.map(x => trim(x).slice(0, 24)).filter(Boolean).join('、').slice(0, 200));\n    if(trim(p.seekingOther)) lines.push('想找（补充）：' + trim(p.seekingOther).slice(0, 200));\n    if(Array.isArray(p.tagsSelected) && p.tagsSelected.length)\n      lines.push('兴趣标签（选项）：' + p.tagsSelected.map(x => trim(x).slice(0, 20)).filter(Boolean).join('、').slice(0, 200));\n    if(trim(p.tagsOther)) lines.push('兴趣（补充）：' + trim(p.tagsOther).slice(0, 200));\n    if(birth && birth.date)\n      lines.push('已填生日（仅作资料参考）：' + String(birth.date) + (birth.time ? ' ' + String(birth.time) : ''));\n    return lines.join('\\n');\n  }\n\n  async function fetchDiscoverCardsFromCustomEndpoint(fullUrl){\n    const p = getUserProfile();\n    const birth = getStoredBirth();\n    const wbBoundEntries = getBoundWorldbookEntries('', 12).map(e => ({\n      id: e.id,\n      name: e.name,\n      keyword: e.keyword,\n      content: e.content,\n    }));\n    const wbNarrative = buildWorldbookNarrative('', 8, 1600);\n    const payload = {\n      limit: 24,\n      profile: p,\n      birth,\n      viewerProfileFilled: isDiscoverProfileSubstantive(p),\n      viewerProfileNarrative: buildDiscoverViewerNarrative(p, birth) || undefined,\n      worldbookBoundEntries: wbBoundEntries,\n      worldbookNarrative: wbNarrative || undefined,\n    };\n    const ctrl = typeof AbortController !== 'undefined' ? new AbortController() : null;\n    const tid = ctrl ? window.setTimeout(() => ctrl.abort(), 28000) : 0;\n    let res;\n    try{\n      res = await fetch(fullUrl, {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json', Accept: 'application/json' },\n        body: JSON.stringify(payload),\n        signal: ctrl ? ctrl.signal : undefined,\n      });\n    }finally{\n      if(tid) window.clearTimeout(tid);\n    }\n    if(!res.ok){\n      const t = await res.text().catch(() => '');\n      throw new Error(t || ('HTTP ' + res.status));\n    }\n    const data = await res.json().catch(() => ({}));\n    const arr = Array.isArray(data.cards) ? data.cards : Array.isArray(data) ? data : [];\n    return arr.map(normalizeDiscoverCard).filter(Boolean);\n  }\n\n  async function fetchDiscoverCardsViaMainLlm(profile){\n    assertChatProfile(profile);\n    const p = getUserProfile();\n    const birth = getStoredBirth();\n    const filled = isDiscoverProfileSubstantive(p);\n    const narrative = buildDiscoverViewerNarrative(p, birth);\n    const wbNarrative = buildWorldbookNarrative('', 8, 1600);\n    const wbBoundEntries = getBoundWorldbookEntries('', 12).map(e => ({\n      id: e.id,\n      name: e.name,\n      keyword: e.keyword,\n      content: llmPlain(e.content || '', 220),\n    }));\n    const ctx = JSON.stringify({\n      limit: 14,\n      viewerProfileFilled: filled,\n      viewerProfileNarrative: narrative || '',\n      profile: p,\n      birth,\n      worldbookNarrative: wbNarrative || '',\n      worldbookBoundEntries: wbBoundEntries,\n    });\n    let userLead = filled\n      ? '用户在「我的」里已填写个人资料。下方 viewerProfileNarrative 是提炼后的要点 — 请以此为**主锚**生成推荐：对方的 city、tag、bio、节奏与「想找/兴趣」要明显更贴近这段资料（至少约一半卡片应让读者感觉「是为我这种人推的」），其余可略有延展但仍合理。勿忽略已写的想找与标签。\\n'\n      : '用户个人资料较少，可泛推荐，保持自然多样。\\n';\n    if(wbNarrative){\n      userLead += '此外提供了 worldbookNarrative / worldbookBoundEntries，这些是世界观约束：请让卡片人设和文案风格与这些约束一致，但每张卡仍需明显不同，避免模板化。\\n';\n    }\n    userLead += '\\nJSON 上下文：\\n';\n    const text = await chillLlmComplete(profile, [\n      { role: 'system', content: DISCOVER_SYSTEM_PROMPT },\n      { role: 'user', content: userLead + ctx },\n    ], { temperature: Math.min(2, Math.max(0, parseFloat(profile.temp) || 0.85)), timeoutMs: 120000 });\n    let arr;\n    try{\n      arr = parseDiscoverAssistantJson(text);\n    }catch(e){\n      throw new Error('解析模型 JSON 失败：' + (e.message || String(e)));\n    }\n    if(!arr.length) throw new Error('模型返回的 cards 为空');\n    return arr.map(normalizeDiscoverCard).filter(Boolean);\n  }\n\n  function cardBasicsLine(p){\n    const g = (p.gender != null && String(p.gender).trim() !== '')\n      ? ' · ' + esc(String(p.gender).trim()) : '';\n    return esc(p.city) + ' · ' + p.age + g;\n  }\n\n  function emptyUserProfile(){\n    return {\n      nick:'', gender:'', city:'', bio:'', mbti:'',\n      seekingSelected: [],\n      seekingOther: '',\n      tagsSelected: [],\n      tagsOther: ''\n    };\n  }\n  const MBTI_TYPES = ['INTJ','INTP','ENTJ','ENTP','INFJ','INFP','ENFJ','ENFP','ISTJ','ISFJ','ESTJ','ESFJ','ISTP','ISFP','ESTP','ESFP'];\n  function normalizeMbtiValue(v){\n    if(v == null) return '';\n    const s = String(v).trim().toUpperCase();\n    return MBTI_TYPES.includes(s) ? s : '';\n  }\n  function normalizeUserProfile(p){\n    const o = emptyUserProfile();\n    if(!p || typeof p !== 'object') return o;\n    const x = Object.assign(o, p);\n    if(!Array.isArray(x.seekingSelected)) x.seekingSelected = [];\n    if(!Array.isArray(x.tagsSelected)) x.tagsSelected = [];\n    if(typeof x.seekingOther !== 'string') x.seekingOther = '';\n    if(typeof x.tagsOther !== 'string') x.tagsOther = '';\n    if(typeof p.seeking === 'string' && p.seeking.trim() && !x.seekingSelected.length && !x.seekingOther.trim()){\n      x.seekingOther = p.seeking.trim();\n    }\n    if(typeof p.tags === 'string' && p.tags.trim() && !x.tagsSelected.length && !x.tagsOther.trim()){\n      x.tagsOther = p.tags.trim();\n    }\n    delete x.seeking;\n    delete x.tags;\n    x.mbti = normalizeMbtiValue(x.mbti);\n    return x;\n  }\n  function getUserProfile(){\n    return _meetUserProfile || emptyUserProfile();\n  }\n  function saveUserProfile(p){\n    _meetUserProfile = normalizeUserProfile(Object.assign(emptyUserProfile(), p));\n    void meetStoreSet(IDB_KEY_MEET_PROFILE, _meetUserProfile);\n  }\n  function refreshMeProfileUi(){\n    const p = getUserProfile();\n    const dn = document.getElementById('me-display-name');\n    if(dn) dn.textContent = (p.nick && p.nick.trim()) ? p.nick.trim() : '我';\n    const line = document.getElementById('profile-cta-line');\n    const hasSeek = (p.seekingSelected && p.seekingSelected.length) || (p.seekingOther && p.seekingOther.trim());\n    const hasTags = (p.tagsSelected && p.tagsSelected.length) || (p.tagsOther && p.tagsOther.trim());\n    const filled = ['nick','gender','city','bio','mbti'].some(k => p[k] && String(p[k]).trim()) || hasSeek || hasTags;\n    if(line) line.textContent = filled ? '已填写 · 点击修改' : '点我填写 · 让匹配更懂你';\n  }\n  function syncProfileChipsFromData(p){\n    document.querySelectorAll('#prof-seeking-chips .ma-chip-tog, #prof-tags-chips .ma-chip-tog').forEach(b => {\n      b.classList.remove('is-on');\n      b.setAttribute('aria-pressed', 'false');\n    });\n    (p.seekingSelected || []).forEach(v => {\n      document.querySelectorAll('#prof-seeking-chips .ma-chip-tog').forEach(b => {\n        if(b.getAttribute('data-value') === v){\n          b.classList.add('is-on');\n          b.setAttribute('aria-pressed', 'true');\n        }\n      });\n    });\n    (p.tagsSelected || []).forEach(v => {\n      document.querySelectorAll('#prof-tags-chips .ma-chip-tog').forEach(b => {\n        if(b.getAttribute('data-value') === v){\n          b.classList.add('is-on');\n          b.setAttribute('aria-pressed', 'true');\n        }\n      });\n    });\n  }\n  function openProfileSheet(){\n    const p = getUserProfile();\n    document.getElementById('prof-nick').value = p.nick || '';\n    document.getElementById('prof-city').value = p.city || '';\n    document.getElementById('prof-bio').value = p.bio || '';\n    document.getElementById('prof-seeking-other').value = p.seekingOther || '';\n    document.getElementById('prof-tags-other').value = p.tagsOther || '';\n    const mbtiNorm = normalizeMbtiValue(p.mbti);\n    document.querySelectorAll('input[name=\"prof-mbti\"]').forEach(inp => {\n      if(inp.value === 'none') inp.checked = !mbtiNorm;\n      else inp.checked = mbtiNorm && inp.value === mbtiNorm;\n    });\n    syncProfileChipsFromData(p);\n    const g = (p.gender || '').trim();\n    let any = false;\n    document.querySelectorAll('input[name=\"prof-gender\"]').forEach(inp => {\n      const on = (inp.value === 'none' && !g) || (inp.value === g);\n      inp.checked = on;\n      if(on) any = true;\n    });\n    if(!any){\n      const none = document.querySelector('input[name=\"prof-gender\"][value=\"none\"]');\n      if(none) none.checked = true;\n    }\n    const sheet = document.getElementById('profile-sheet');\n    sheet.classList.add('open');\n    sheet.setAttribute('aria-hidden', 'false');\n  }\n  function closeProfileSheet(){\n    const sheet = document.getElementById('profile-sheet');\n    sheet.classList.remove('open');\n    sheet.setAttribute('aria-hidden', 'true');\n  }\n\n  function normalizeWbBindMap(v){\n    if(!v || typeof v !== 'object') return {};\n    const out = {};\n    Object.keys(v).forEach(k => {\n      const id = String(k || '').trim();\n      if(!id) return;\n      const arr = Array.isArray(v[k]) ? v[k] : [];\n      const uniq = [];\n      const seen = new Set();\n      arr.forEach(x => {\n        const n = Number(x);\n        if(!Number.isFinite(n)) return;\n        const v = Math.round(n);\n        if(v <= 0 || seen.has(v)) return;\n        seen.add(v);\n        uniq.push(v);\n      });\n      out[id] = uniq.slice(0, 80);\n    });\n    return out;\n  }\n  function getCurrentWbBoundIds(peerId){\n    const globalIds = (_meetWbBindMap && Array.isArray(_meetWbBindMap.__global__)) ? _meetWbBindMap.__global__ : [];\n    const sid = peerId ? String(peerId) : '';\n    if(!sid) return globalIds.slice();\n    const localIds = (_meetWbBindMap && Array.isArray(_meetWbBindMap[sid])) ? _meetWbBindMap[sid] : [];\n    const out = [];\n    const seen = new Set();\n    globalIds.concat(localIds).forEach(v => {\n      const n = Number(v);\n      if(!Number.isFinite(n)) return;\n      const x = Math.round(n);\n      if(x <= 0 || seen.has(x)) return;\n      seen.add(x);\n      out.push(x);\n    });\n    return out;\n  }\n  function setCurrentWbBoundIds(ids){\n    const sid = '__global__';\n    const norm = normalizeWbBindMap({ [sid]: ids });\n    if(!_meetWbBindMap || typeof _meetWbBindMap !== 'object') _meetWbBindMap = {};\n    _meetWbBindMap[sid] = (norm && norm[sid]) ? norm[sid] : [];\n    void meetStoreSet(IDB_KEY_MEET_WB_BIND, _meetWbBindMap);\n    // 世界书变化后，人设缓存要失效，避免沿用旧约束下的 persona。\n    _meetChatPersonaMap = {};\n    void meetStoreSet(IDB_KEY_MEET_CHAT_PERSONA, _meetChatPersonaMap);\n  }\n  function worldInfoScopeEligibleForMeet(scope){\n    const arr = Array.isArray(scope) ? scope.map(x => String(x || '').toLowerCase()) : [];\n    if(!arr.length) return true;\n    return arr.includes('chat') || arr.includes('social') || arr.includes('meet');\n  }\n  function getBoundWorldbookEntries(peerId, limit){\n    const max = Math.max(1, Math.min(30, Number(limit) || 12));\n    const boundIds = getCurrentWbBoundIds(peerId);\n    if(!boundIds.length || !_wbMainEntriesCache.length) return [];\n    const out = [];\n    for(let i = 0; i < boundIds.length; i++){\n      const id = boundIds[i];\n      const hit = _wbMainEntriesCache.find(e => e.id === id);\n      if(hit) out.push(hit);\n      if(out.length >= max) break;\n    }\n    return out;\n  }\n  function buildWorldbookNarrative(peerId, maxEntries, maxChars){\n    const capEntries = Math.max(1, Math.min(20, Number(maxEntries) || 8));\n    const capChars = Math.max(300, Math.min(4000, Number(maxChars) || 1800));\n    const free = String(_meetWorldviewFreetext || '').trim();\n    const freeBlock = free\n      ? ('【用户直接输入的世界观】\\n' + llmPlain(free, Math.min(1000, capChars - 80)))\n      : '';\n    const entries = getBoundWorldbookEntries(peerId, capEntries);\n    const fromEntries = entries.length\n      ? entries.map((e, idx) =>\n          (idx + 1) + ') ' + llmPlain(e.name, 48) +\n          '｜关键词：' + llmPlain(e.keyword || '（无）', 90) +\n          '｜设定：' + llmPlain(e.content || '', 260)\n        ).join('\\n')\n      : '';\n    const parts = [freeBlock, fromEntries].filter(Boolean);\n    if(!parts.length) return '';\n    return parts.join('\\n\\n').slice(0, capChars);\n  }\n  async function readMainWorldInfoEntries(){\n    const db = await openChillIdb();\n    return new Promise((resolve) => {\n      try{\n        if(!db.objectStoreNames.contains('world_info')){\n          resolve([]);\n          return;\n        }\n        const req = db.transaction('world_info', 'readonly').objectStore('world_info').getAll();\n        req.onsuccess = () => {\n          const arr = Array.isArray(req.result) ? req.result : [];\n          const rows = arr.map(e => ({\n            id: Math.round(Number(e && e.id)),\n            name: String(e && e.name || '').trim(),\n            keyword: String(e && e.keyword || '').trim(),\n            content: String(e && e.content || '').trim(),\n            enabled: e && e.enabled !== false,\n            scope: Array.isArray(e && e.scope) ? e.scope.map(x => String(x || '')) : ['chat'],\n          })).filter(e => Number.isFinite(e.id) && e.id > 0 && e.name && e.content && e.enabled && worldInfoScopeEligibleForMeet(e.scope));\n          rows.sort((a, b) => a.id - b.id);\n          resolve(rows);\n        };\n        req.onerror = () => resolve([]);\n      }catch(_){\n        resolve([]);\n      }\n    });\n  }\n  function renderWbEntryList(){\n    const list = document.getElementById('wb-entry-list');\n    const empty = document.getElementById('wb-empty');\n    const count = document.getElementById('wb-bind-count');\n    if(!list || !empty || !count) return;\n    const bound = new Set(getCurrentWbBoundIds());\n    const rows = Array.isArray(_wbMainEntriesCache) ? _wbMainEntriesCache : [];\n    if(!rows.length){\n      list.innerHTML = '';\n      empty.hidden = false;\n      count.textContent = '0';\n      return;\n    }\n    empty.hidden = true;\n    list.innerHTML = rows.map(e => {\n      const on = bound.has(e.id);\n      return '<button type=\"button\" class=\"ma-chip-tog' + (on ? ' is-on' : '') + '\" data-wb-entry-id=\"' + e.id + '\" aria-pressed=\"' + (on ? 'true' : 'false') + '\">' +\n        esc(e.name) + '</button>';\n    }).join('');\n    count.textContent = String(bound.size);\n  }\n  function persistMeetWorldviewFreetext(){\n    void meetStoreSet(IDB_KEY_MEET_WB_FREETEXT, String(_meetWorldviewFreetext || '').trim().slice(0, 1200));\n  }\n  function invalidateMeetPersonaCache(){\n    _meetChatPersonaMap = {};\n    void meetStoreSet(IDB_KEY_MEET_CHAT_PERSONA, _meetChatPersonaMap);\n  }\n  function syncWorldviewFreetextFromUi(){\n    const ta = document.getElementById('wb-worldview-freetext');\n    _meetWorldviewFreetext = ta ? String(ta.value || '').trim().slice(0, 1200) : '';\n    persistMeetWorldviewFreetext();\n    invalidateMeetPersonaCache();\n  }\n  function ensureWorldviewWbUi(){\n    if(document.getElementById('wb-worldview-freetext')) return;\n    const scroll = document.querySelector('#wb-sheet .ma-profile-scroll');\n    if(!scroll) return;\n    const section = document.createElement('div');\n    section.className = 'ma-prof-section';\n    section.innerHTML =\n      '<div class=\"ma-section-title ma-prof-sec-title\">世界观（直接输入）</div>' +\n      '<div class=\"ma-prof-field\">' +\n      '<label for=\"wb-worldview-freetext\">可选 · 与下方绑定的词条一起参与发现卡、聊天与人设</label>' +\n      '<textarea id=\"wb-worldview-freetext\" class=\"ma-wb-worldview-ta\" rows=\"4\" maxlength=\"1200\" placeholder=\"可不绑词条，只写设定；也可与主文件词条叠加。\"></textarea>' +\n      '</div>';\n    const firstSec = scroll.querySelector('.ma-prof-section');\n    if(firstSec) scroll.insertBefore(section, firstSec);\n    else scroll.appendChild(section);\n  }\n  async function refreshWbCtaLine(){\n    const line = document.getElementById('wb-cta-line');\n    if(!line) return;\n    if(!_wbMainEntriesCache.length){\n      _wbMainEntriesCache = await readMainWorldInfoEntries();\n    }\n    const n = getCurrentWbBoundIds().length;\n    const freeHas = !!String(_meetWorldviewFreetext || '').trim();\n    const hasMainList = _wbMainEntriesCache.length > 0;\n    if(!hasMainList && !freeHas){\n      line.textContent = '主文件世界书未就绪 · 可先写世界观或去主文件建词条';\n      return;\n    }\n    if(!n && !freeHas){\n      line.textContent = hasMainList\n        ? '未绑定 · 点我从主文件世界书绑定'\n        : '未绑定词条 · 可点入写世界观';\n      return;\n    }\n    const bits = [];\n    if(freeHas) bits.push('已填世界观');\n    if(n) bits.push('已绑 ' + n + ' 条');\n    line.textContent = bits.join(' · ') + ' · 点击修改';\n  }\n  async function openWbSheet(){\n    ensureWorldviewWbUi();\n    const ta = document.getElementById('wb-worldview-freetext');\n    if(ta) ta.value = String(_meetWorldviewFreetext || '');\n    if(!_wbMainEntriesCache.length){\n      _wbMainEntriesCache = await readMainWorldInfoEntries();\n    }\n    renderWbEntryList();\n    const sheet = document.getElementById('wb-sheet');\n    if(!sheet) return;\n    sheet.classList.add('open');\n    sheet.setAttribute('aria-hidden', 'false');\n  }\n  function closeWbSheet(){\n    const sheet = document.getElementById('wb-sheet');\n    if(!sheet) return;\n    sheet.classList.remove('open');\n    sheet.setAttribute('aria-hidden', 'true');\n  }\n\n  const Z_SIGN = ['白羊','金牛','双子','巨蟹','狮子','处女','天秤','天蝎','射手','摩羯','水瓶','双鱼'];\n  const Z_ELEMENT = ['火象','土象','风象','水象','火象','土象','风象','水象','火象','土象','风象','水象'];\n  const Z_MODAL = ['本位','固定','变动','本位','固定','变动','本位','固定','变动','本位','固定','变动'];\n  const CHINESE_ANI = ['鼠','牛','虎','兔','龙','蛇','马','羊','猴','鸡','狗','猪'];\n\n  function hash32(str){\n    let h = 2166136261 >>> 0;\n    for(let i = 0; i < str.length; i++){\n      h ^= str.charCodeAt(i);\n      h = Math.imul(h, 16777619) >>> 0;\n    }\n    return h >>> 0;\n  }\n\n  function sunSignFromDate(m, d){\n    if((m === 12 && d >= 22) || (m === 1 && d <= 19)) return 9;\n    if((m === 1 && d >= 20) || (m === 2 && d <= 18)) return 10;\n    if((m === 2 && d >= 19) || (m === 3 && d <= 20)) return 11;\n    if((m === 3 && d >= 21) || (m === 4 && d <= 19)) return 0;\n    if((m === 4 && d >= 20) || (m === 5 && d <= 20)) return 1;\n    if((m === 5 && d >= 21) || (m === 6 && d <= 20)) return 2;\n    if((m === 6 && d >= 21) || (m === 7 && d <= 22)) return 3;\n    if((m === 7 && d >= 23) || (m === 8 && d <= 22)) return 4;\n    if((m === 8 && d >= 23) || (m === 9 && d <= 22)) return 5;\n    if((m === 9 && d >= 23) || (m === 10 && d <= 22)) return 6;\n    if((m === 10 && d >= 23) || (m === 11 && d <= 21)) return 7;\n    if((m === 11 && d >= 22) || (m === 12 && d <= 21)) return 8;\n    return 11;\n  }\n\n  function chineseZodiacAnimal(year){\n    return CHINESE_ANI[((year - 4) % 12 + 12) % 12];\n  }\n\n  function ageFromYMD(y, m, d){\n    const t = new Date();\n    let a = t.getFullYear() - y;\n    if(t.getMonth() + 1 < m || (t.getMonth() + 1 === m && t.getDate() < d)) a--;\n    return a;\n  }\n\n  function moonAscFromBirth(dateStr, timeStr){\n    const moon = hash32('moon|' + dateStr + '|' + (timeStr || '12:00')) % 12;\n    const asc = hash32('asc|' + dateStr + '|' + (timeStr || '')) % 12;\n    return { moon, asc };\n  }\n\n  function clampDimScore(n){\n    return Math.min(96, Math.max(20, Math.round(Number(n) || 0)));\n  }\n\n  function buildNatalDimensions(sun, moon, asc){\n    const signs = [sun, moon, asc];\n    const ec = { fire: 0, earth: 0, air: 0, water: 0 };\n    const mc = { cardinal: 0, fixed: 0, mutable: 0 };\n    signs.forEach(i => {\n      const ele = Z_ELEMENT[i];\n      if(ele === '火象') ec.fire++;\n      else if(ele === '土象') ec.earth++;\n      else if(ele === '风象') ec.air++;\n      else ec.water++;\n\n      const mod = Z_MODAL[i];\n      if(mod === '本位') mc.cardinal++;\n      else if(mod === '固定') mc.fixed++;\n      else mc.mutable++;\n    });\n\n    const dims = [];\n    dims.push({\n      key: '行动',\n      score: clampDimScore(46 + ec.fire * 12 + ec.air * 4 + mc.cardinal * 6 - ec.water * 3),\n    });\n    dims.push({\n      key: '共情',\n      score: clampDimScore(45 + ec.water * 11 + ec.earth * 4 + mc.mutable * 5 - mc.fixed * 2),\n    });\n    dims.push({\n      key: '表达',\n      score: clampDimScore(44 + ec.air * 12 + mc.mutable * 6 + (Z_ELEMENT[asc] === '风象' ? 4 : 0) - ec.earth * 3),\n    });\n    dims.push({\n      key: '稳定',\n      score: clampDimScore(43 + ec.earth * 12 + mc.fixed * 7 + (Z_ELEMENT[sun] === '土象' ? 4 : 0) - ec.fire * 4),\n    });\n    return dims;\n  }\n\n  function parseBirthDateInput(raw){\n    let s = String(raw || '').trim();\n    s = s.replace(/[\\/\\.]/g, '-');\n    if (/^\\d{8}$/.test(s)) s = s.substring(0,4) + '-' + s.substring(4,6) + '-' + s.substring(6,8);\n    const m = s.match(/^(\\d{4})-(\\d{1,2})-(\\d{1,2})$/);\n    if(!m) return null;\n    const y = Number(m[1]);\n    const mm = Number(m[2]);\n    const dd = Number(m[3]);\n    if(!Number.isFinite(y) || !Number.isFinite(mm) || !Number.isFinite(dd)) return null;\n    if(y < 1900 || y > 2100 || mm < 1 || mm > 12 || dd < 1 || dd > 31) return null;\n    const dt = new Date(y, mm - 1, dd);\n    if(dt.getFullYear() !== y || dt.getMonth() !== mm - 1 || dt.getDate() !== dd) return null;\n    const z = n => String(n).padStart(2, '0');\n    return y + '-' + z(mm) + '-' + z(dd);\n  }\n\n   function parseBirthTimeInput(raw){\n    let s = String(raw || '').trim();\n    if(!s) return '';\n    if (/^\\d{4}$/.test(s)) s = s.substring(0,2) + ':' + s.substring(2,4);\n    s = s.replace(/[\\/\\.。时分]/g, ':');\n    const m = s.match(/^(\\d{1,2}):(\\d{1,2})$/);\n  if(!m) return null;\n    const hh = Number(m[1]);\n    const mm = Number(m[2]);\n    if(!Number.isFinite(hh) || !Number.isFinite(mm)) return null;\n    if(hh < 0 || hh > 23 || mm < 0 || mm > 59) return null;\n    const z = n => String(n).padStart(2, '0');\n    return z(hh) + ':' + z(mm);\n  }\n\n  function buildNatalBreakdown(sun, moon, asc){\n    const signs = [sun, moon, asc];\n    const ec = { fire: 0, earth: 0, air: 0, water: 0 };\n    const mc = { cardinal: 0, fixed: 0, mutable: 0 };\n    signs.forEach(i => {\n      const ele = Z_ELEMENT[i];\n      if(ele === '火象') ec.fire++;\n      else if(ele === '土象') ec.earth++;\n      else if(ele === '风象') ec.air++;\n      else ec.water++;\n\n      const mod = Z_MODAL[i];\n      if(mod === '本位') mc.cardinal++;\n      else if(mod === '固定') mc.fixed++;\n      else mc.mutable++;\n    });\n    const topEle = [\n      ['火象', ec.fire], ['土象', ec.earth], ['风象', ec.air], ['水象', ec.water],\n    ].sort((a, b) => b[1] - a[1])[0];\n    const topMod = [\n      ['本位', mc.cardinal], ['固定', mc.fixed], ['变动', mc.mutable],\n    ].sort((a, b) => b[1] - a[1])[0];\n    return [\n      { key: '元素主调', value: topEle[0] + '（' + topEle[1] + '/3）' },\n      { key: '模式主调', value: topMod[0] + '（' + topMod[1] + '/3）' },\n      { key: '外在表达', value: '上升' + Z_SIGN[asc] },\n      { key: '情绪底色', value: '月亮' + Z_SIGN[moon] },\n    ];\n  }\n\n  function signCenterDeg(i){\n    return -90 + i * 30 + 15;\n  }\n\n  function getStoredBirth(){\n    if(!_meetBirth || !_meetBirth.date) return null;\n    return _meetBirth;\n  }\n\n  function clampPct(n, def){\n    const v = Number(n);\n    if(!Number.isFinite(v)) return def;\n    return Math.min(99, Math.max(1, Math.round(v)));\n  }\n\n  function clampSynastryScoreApi(n){\n    const v = Number(n);\n    if(!Number.isFinite(v)) return null;\n    return Math.min(96, Math.max(45, Math.round(v)));\n  }\n\n  /** @returns {number|null} 0-11 */\n  function parsePeerSunSignFromApi(val){\n    if(val == null || val === '') return null;\n    const n = Number(val);\n    if(Number.isFinite(n)){\n      const i = Math.round(n);\n      if(i >= 0 && i <= 11) return i;\n    }\n    const s = String(val).trim().replace(/座$/u, '');\n    const idx = Z_SIGN.indexOf(s);\n    if(idx >= 0) return idx;\n    for(let i = 0; i < Z_SIGN.length; i++){\n      if(s.startsWith(Z_SIGN[i]) || s.includes(Z_SIGN[i])) return i;\n    }\n    return null;\n  }\n  function looksLikeRealChineseName(v){\n    const s = String(v || '').trim();\n    if(!/^[\\u4e00-\\u9fa5]{2,4}$/.test(s)) return false;\n    const surnames = '赵钱孙李周吴郑王冯陈褚卫蒋沈韩杨朱秦尤许何吕施张孔曹严华金魏陶姜戚谢邹喻柏水窦章云苏潘葛范彭郎鲁韦昌马苗凤花方俞任袁柳鲍史唐费廉岑薛雷贺倪汤滕殷罗毕郝邬安常乐于时傅皮卞齐康伍余元卜顾孟平黄和穆萧尹姚邵湛汪祁毛禹狄米贝明臧计伏成戴谈宋茅庞熊纪舒屈项祝董梁杜阮蓝闵席季麻强贾路娄危江童颜郭梅盛林刁钟徐邱骆高夏蔡田樊胡凌霍虞万支柯昝管卢莫经房裘缪干解应宗丁宣贲邓郁单杭洪包诸左石崔吉龚程邢裴陆荣翁荀羊於惠甄曲家封芮储靳焦牧山';\n    return surnames.includes(s[0]);\n  }\n  function normalizeAliasName(raw, id, tag, city){\n    const clean = String(raw == null ? '' : raw)\n      .replace(/\\s+/g, '')\n      .replace(/[^\\u4e00-\\u9fa5A-Za-z0-9._\\-·]/g, '')\n      .slice(0, 20);\n    const seed = hash32(String(id || '') + '|' + String(tag || '') + '|' + String(city || '') + '|' + clean);\n    const allowSingleLetter = (seed % 11) === 0; // 少量放行单字母/极简网名\n    const tooPlain =\n      !clean ||\n      (clean.length <= 1 && !allowSingleLetter) ||\n      looksLikeRealChineseName(clean) ||\n      (/^[A-Za-z]\\.?$/u.test(clean) && !allowSingleLetter) ||\n      /^[0-9]+$/u.test(clean);\n    if(!tooPlain) return clean;\n    const left = ['奶油','夜航','迷路','慢热','星球','海盐','玻璃','失眠','宇宙','甜茶','莓果','晚风','像素','半糖','随机','奇怪','静音','微醺','雾面','青柠','折叠','白噪','离线','午夜','深蓝','风暴','木星','回声'];\n    const right = ['小狗','兔叽','机长','喵','同学','选手','观察员','派','研究所','碎片','加载中','收集者','捕手','草莓','曲奇','存档','旅人','信号','频道','档案','宇航员','按钮','潮汐','未命名','电台','乘客','行星'];\n    const mid = ['404','07','13','88','777','0x','2.0','PRO','Lite','Beta','v2','A1','K7','X9'];\n    const solo = ['无糖电波','深夜飞行','云端补丁','反向心动','次元偏移','蓝调缓存','空白页','孤岛信号','无名常量','冷启动','软着陆','即兴漫游','观测者','偏振光','静态噪声','慢速读条'];\n    const h = seed;\n    const a = left[h % left.length];\n    const b = right[(h >>> 5) % right.length];\n    const m = mid[(h >>> 9) % mid.length];\n    const s = solo[(h >>> 12) % solo.length];\n    const style = h % 8;\n    if(style === 0) return (a + b).slice(0, 20);\n    if(style === 1) return (a + '_' + m).slice(0, 20);\n    if(style === 2) return (m + '·' + b).slice(0, 20);\n    if(style === 3) return (a + '的' + b).slice(0, 20);\n    if(style === 4) return (a + '.' + b).slice(0, 20);\n    if(style === 5) return (b + '_' + m).slice(0, 20);\n    if(style === 6) return (a + m + b).slice(0, 20);\n    return s.slice(0, 20);\n  }\n\n  function normalizeDiscoverCard(o, i){\n    if(!o || typeof o !== 'object') return null;\n    const id = String(o.id != null ? o.id : ('c-' + Date.now() + '-' + i));\n    const name = normalizeAliasName(o.name || '', id, o.tag || o.label || '', o.city || '') || 'Ta';\n    const age = Math.min(80, Math.max(18, Math.round(Number(o.age) || 24)));\n    const city = String(o.city || '—').trim().slice(0, 24) || '—';\n    const gender = o.gender != null ? String(o.gender).trim().slice(0, 4) : '';\n    const bio = String(o.bio || '').trim().slice(0, 280) || '（暂无简介）';\n    const tag = String(o.tag || o.label || '').trim().slice(0, 16) || '朋友';\n    const profileLine = String(o.profileLine || o.subtitle || '').trim().replace(/\\s+/g,' ').slice(0, 48);\n    const h = hash32('m|' + id);\n    const match = clampPct(o.match, 55 + (h % 36));\n    const astro = clampPct(o.astro, 52 + (h % 40));\n    const apiPeerSun = parsePeerSunSignFromApi(o.peerSunSign != null ? o.peerSunSign : o.peerSun);\n    const apiSynScore = clampSynastryScoreApi(o.synastryScore);\n    const apiSynLine = String(o.synastryLine != null ? o.synastryLine : '').trim().slice(0, 160);\n    const hasApiSynastry = apiPeerSun != null && apiSynScore != null && apiSynLine.length > 0;\n    return {\n      id, name, age, gender, city, match, astro, bio, tag,\n      profileLine,\n      apiPeerSun: hasApiSynastry ? apiPeerSun : null,\n      apiSynScore: hasApiSynastry ? apiSynScore : null,\n      apiSynLine: hasApiSynastry ? apiSynLine : null,\n    };\n  }\n\n  function buildCardProfileLine(p){\n    const direct = String(p && p.profileLine ? p.profileLine : '').trim();\n    if(direct) return direct.slice(0, 48);\n    const tones = ['慢热', '直球', '夜行', '轻幽默', '理性', '感性', '松弛', '稳定'];\n    const habits = ['先聊日常', '回消息不快但认真', '偏爱短句', '喜欢有来回', '会接梗', '不尬聊'];\n    const h = hash32(String((p && p.id) || '') + '|' + String((p && p.tag) || ''));\n    const t = tones[h % tones.length];\n    const hb = habits[(h >> 7) % habits.length];\n    const city = p && p.city ? String(p.city).trim() : '';\n    const g = p && p.gender ? String(p.gender).trim() : '';\n    const lead = city ? city + ' · ' : '';\n    return (lead + t + ' · ' + hb + (g ? ' · ' + g : '')).slice(0, 48);\n  }\n\n  function defaultCustomDiscoverUrl(){\n    if(typeof window !== 'undefined' && window.CHILL_DISCOVER_API)\n      return String(window.CHILL_DISCOVER_API);\n    return '';\n  }\n\n  async function fetchDiscoverCardsFromApi(){\n    const custom = defaultCustomDiscoverUrl();\n    if(custom)\n      return fetchDiscoverCardsFromCustomEndpoint(custom);\n    const profile = await getActiveApiProfileFromMain();\n    if(!profile)\n      throw new Error('未找到当前 API 配置。请打开 Chill 主应用 → 设置 → API，填写接口地址、密钥、模型并点击「设为当前使用」，再回到遇见刷新。');\n    return fetchDiscoverCardsViaMainLlm(profile);\n  }\n\n  function renderNatal(){\n    const emptyEl = document.getElementById('natal-empty');\n    const bodyEl = document.getElementById('natal-body');\n    const formEl = document.getElementById('natal-form');\n    const toggleEl = document.getElementById('natal-form-toggle');\n    const dateIn = document.getElementById('birth-date');\n    const timeIn = document.getElementById('birth-time');\n    const meLine = document.getElementById('me-tagline');\n    const data = getStoredBirth();\n    const today = new Date().toISOString().slice(0, 10);\n    if(dateIn) dateIn.max = today;\n\n    if(!data || !data.date){\n      if(emptyEl) emptyEl.style.display = '';\n      if(bodyEl) bodyEl.classList.remove('is-on');\n      if(formEl) formEl.classList.remove('is-collapsed');\n      if(toggleEl) toggleEl.setAttribute('aria-expanded', 'true');\n      if(dateIn) dateIn.value = '';\n      if(timeIn) timeIn.value = '';\n      if(meLine) meLine.textContent = '填写生日，生成你的星座与星盘';\n      const dims0 = document.getElementById('natal-dims');\n      if(dims0) dims0.innerHTML = '';\n      const b0 = document.getElementById('natal-breakdown');\n      if(b0) b0.innerHTML = '';\n      return;\n    }\n\n    if(emptyEl) emptyEl.style.display = 'none';\n    if(bodyEl) bodyEl.classList.add('is-on');\n    if(formEl) formEl.classList.add('is-collapsed');\n    if(toggleEl) toggleEl.setAttribute('aria-expanded', 'false');\n    if(dateIn) dateIn.value = data.date;\n    if(timeIn) timeIn.value = data.time || '';\n\n    const parts = data.date.split('-').map(Number);\n    const Y = parts[0], M = parts[1], D = parts[2];\n    const sun = sunSignFromDate(M, D);\n    const { moon, asc } = moonAscFromBirth(data.date, data.time || '');\n    const animal = chineseZodiacAnimal(Y);\n    const age = ageFromYMD(Y, M, D);\n    const elSun = Z_ELEMENT[sun];\n\n    if(meLine) meLine.textContent = `太阳${Z_SIGN[sun]}座 · ${age}岁 · 生肖${animal}`;\n\n    const hubTitle = document.getElementById('natal-hub-title');\n    const hubSub = document.getElementById('natal-hub-sub');\n    if(hubTitle) hubTitle.textContent = `${Z_SIGN[sun]}座 · ${elSun}`;\n    if(hubSub){\n      hubSub.textContent = `生肖${animal} · 月亮${Z_SIGN[moon]} · 上升${Z_SIGN[asc]}` +\n        (data.time ? '' : '（未填时间 · 上升为默认推算）');\n    }\n\n    const labelsEl = document.getElementById('natal-zodiac-labels');\n    if(labelsEl){\n      labelsEl.textContent = '';\n      for(let i = 0; i < 12; i++){\n        const s = document.createElement('span');\n        s.className = 'ma-natal-zlbl';\n        s.style.setProperty('--z-rot', signCenterDeg(i) + 'deg');\n        s.textContent = Z_SIGN[i];\n        labelsEl.appendChild(s);\n      }\n    }\n\n    const markersEl = document.getElementById('natal-markers');\n    if(markersEl){\n      markersEl.innerHTML =\n        '<span class=\"ma-natal-marker sun\" style=\"--deg:' + signCenterDeg(sun) + 'deg\"></span>' +\n        '<span class=\"ma-natal-marker moon\" style=\"--deg:' + signCenterDeg(moon) + 'deg\"></span>' +\n        '<span class=\"ma-natal-marker asc\" style=\"--deg:' + signCenterDeg(asc) + 'deg\"></span>';\n    }\n\n    const trio = document.getElementById('natal-trio');\n    if(trio){\n      trio.innerHTML =\n        '<div class=\"ma-natal-chip\"><div class=\"k\">太阳 Sun</div><div class=\"v\">' + esc(Z_SIGN[sun]) + '</div></div>' +\n        '<div class=\"ma-natal-chip\"><div class=\"k\">月亮 Moon</div><div class=\"v\">' + esc(Z_SIGN[moon]) + '</div></div>' +\n        '<div class=\"ma-natal-chip\"><div class=\"k\">上升 Asc</div><div class=\"v\">' + esc(Z_SIGN[asc]) + '</div>' +\n        (data.time ? '' : '<div class=\"hint\">未填出生时间 · 默认推算</div>') + '</div>';\n    }\n\n    const dimsEl = document.getElementById('natal-dims');\n    if(dimsEl){\n      const dims = buildNatalDimensions(sun, moon, asc);\n      dimsEl.innerHTML = dims.map(d =>\n        '<div class=\"ma-natal-dim-row\">' +\n          '<span class=\"ma-natal-dim-k\">' + esc(d.key) + '</span>' +\n          '<span class=\"ma-natal-dim-bar\"><span class=\"ma-natal-dim-fill\" style=\"width:' + d.score + '%\"></span></span>' +\n          '<span class=\"ma-natal-dim-v\">' + d.score + '</span>' +\n        '</div>'\n      ).join('');\n    }\n    const bEl = document.getElementById('natal-breakdown');\n    if(bEl){\n      const items = buildNatalBreakdown(sun, moon, asc);\n      bEl.innerHTML = items.map(x =>\n        '<div class=\"ma-natal-break-item\">' +\n          '<span class=\"ma-natal-break-k\">' + esc(x.key) + '</span>' +\n          '<span class=\"ma-natal-break-v\">' + esc(x.value) + '</span>' +\n        '</div>'\n      ).join('');\n    }\n\n    const meta = document.getElementById('natal-meta');\n    if(meta){\n      meta.textContent = '太阳星座由出生日期推算。月亮、上升与维度评分基于本地算法计算，仅作参考。';\n    }\n  }\n\n  const $deckWrap = document.querySelector('.ma-deck-wrap');\n\n  const ICEBREAKERS = [\n    '最近在循环哪首歌？想偷一张你的歌单封面～',\n    '如果周末只能做一件事，你会选咖啡、散步还是宅家看电影？',\n    '你那边天气怎么样？适合出门的话想听听你的「秘密基地」。',\n    '有没有一本读完很久还在心里的书或番？',\n    '更偏早鸟还是夜猫子？好奇你的黄金聊天时段。',\n    '若可以瞬移去一个城市过一天，你会选哪里、吃什么？',\n    '最近有什么小事让你突然觉得「啊今天还不错」？',\n    '你一般怎么破冰？我先交卷：喜欢从吃的聊起。',\n  ];\n  const _chatIcebreakerPoolMap = {};\n  const _peerMoodFromReplyMap = {};\n  const COMPAT_QUIZ_REWARD_KEY = 'meet_compatQuizRewardMapV1';\n  const COMPAT_QUIZ_POOL = [\n    { q: '周末更想怎么放松？', a: '窝在家看电影', b: '出门走走找新店' },\n    { q: '一起吃饭你更在意？', a: '氛围和聊天', b: '口味和性价比' },\n    { q: '突然下雨会？', a: '找家店坐会儿', b: '淋一点也无所谓' },\n    { q: '旅行节奏偏哪种？', a: '慢慢逛，留白多', b: '攻略拉满，打卡多' },\n    { q: '深夜来消息时通常？', a: '想聊就回', b: '明早再认真回' },\n    { q: '约会开场更自然的是？', a: '从兴趣聊起', b: '从日常近况聊起' },\n    { q: '你更喜欢哪种惊喜？', a: '提前暗示的小惊喜', b: '完全未知的惊喜' },\n    { q: '冲突时第一反应是？', a: '先冷静一下', b: '当下说开' },\n    { q: '送礼更偏向？', a: '实用派', b: '仪式感派' },\n    { q: '听歌习惯更像？', a: '单曲循环', b: '整张专辑慢慢听' },\n  ];\n  let _compatQuizRewardMap = loadCompatQuizRewardMap();\n\n  const SYNASTRY_LINES = [\n    '月亮意象偏柔 · Moon tone · 适合从日常琐碎与感受聊起',\n    '金水联动示意 · 影音/文字类话题成功率 +',\n    '火象与风象张力 · 可试轻松辩论或共同计划一件小事',\n    '土象稳定感 · 慢热但持久，适合具体而小的约定',\n    '水象共情向 · 倾听比追问更加分',\n    '日月的柔和相位 · 今日宜短句开场、留白给对方接话',\n    '木星扩张感 · 旅行、展览、远期心愿类话题更顺',\n  ];\n\n  let icebreakerShuffle = 0;\n\n  function loadCompatQuizRewardMap(){\n    try{\n      const raw = localStorage.getItem(COMPAT_QUIZ_REWARD_KEY);\n      if(!raw) return {};\n      const obj = JSON.parse(raw);\n      return obj && typeof obj === 'object' ? obj : {};\n    }catch(_){\n      return {};\n    }\n  }\n  function saveCompatQuizRewardMap(){\n    try{\n      localStorage.setItem(COMPAT_QUIZ_REWARD_KEY, JSON.stringify(_compatQuizRewardMap || {}));\n    }catch(_){}\n  }\n  function canUseCompatQuiz(chatObj){\n    return isMutualStarsAtLeast(chatObj, 3);\n  }\n  function buildCompatQuiz(peerId, offset){\n    const id = String(peerId || '');\n    if(!id || !COMPAT_QUIZ_POOL.length) return null;\n    const base = hash32('compatQuiz|' + id + '|' + localYmd());\n    const idx = ((base + (Number(offset) || 0)) % COMPAT_QUIZ_POOL.length + COMPAT_QUIZ_POOL.length) % COMPAT_QUIZ_POOL.length;\n    const item = COMPAT_QUIZ_POOL[idx];\n    return {\n      peerId: id,\n      quizId: 'quiz_' + idx,\n      q: item.q,\n      options: [item.a, item.b],\n      picked: null,\n      peerPicked: null,\n      resolved: false,\n    };\n  }\n  function buildCompatQuizFromDeck(peerId, offset, deck){\n    const sid = String(peerId || '');\n    deck = deck || _compatLlmDeck[sid];\n    if(!deck || !Array.isArray(deck.items) || !deck.items.length) return null;\n    const n = deck.items.length;\n    const idx = ((Number(offset) || 0) % n + n) % n;\n    const item = deck.items[idx];\n    if(!item || !item.q) return null;\n    const epoch = Number(deck.epoch) || 0;\n    return {\n      peerId: sid,\n      quizId: 'llm_' + sid + '_' + epoch + '_' + idx,\n      q: item.q,\n      options: [item.a, item.b],\n      picked: null,\n      peerPicked: null,\n      resolved: false,\n    };\n  }\n  function buildCurrentCompatSnapshot(peerId, offset){\n    const sid = String(peerId || '');\n    const fromDeck = buildCompatQuizFromDeck(sid, offset, _compatLlmDeck[sid]);\n    if(fromDeck) return fromDeck;\n    return buildCompatQuiz(sid, offset);\n  }\n  async function fetchCompatQuizBatchForPeer(peerId){\n    const sid = String(peerId || '');\n    const u = liked.find(x => String(x.id) === sid);\n    if(!u) throw new Error('未找到该对话');\n    const profile = await getActiveApiProfileFromMain();\n    if(!profile) throw new Error('未配置 API');\n    await ensureChatPersona(u, false);\n    const persona = getCachedChatPersona(sid);\n    const hist = getConvHistory(sid).slice(-22);\n    const histText = hist.length\n      ? hist.map(t => (t.role === 'user' ? '用户' : '对方角色') + '：' + llmPlain(t.content, 300)).join('\\n')\n      : '（尚无聊天记录，请结合人设与资料设计仍像「他们之间」会问的题。）';\n    const peerCard =\n      '对方展示：昵称「' + llmPlain(u.name, 28) + '」· ' + llmPlain(u.city || '—', 16) + ' · ' + (u.age || '—') + '岁 · 标签「' +\n      llmPlain(u.tag || '—', 24) + '」· 简介：' + llmPlain(u.bio || '', 260);\n    const sys = [\n      '你是「遇见」App 的默契二选一出题员。只输出合法 JSON，不要 markdown。',\n      '根据下面「最近对话」与「角色人设」出 5 道二选一题；题干与选项都要和聊天内容或人设强相关，可轻松可细腻，禁止万能敷衍题。',\n      '每题字段：q（题干 18～44 字）、a（选项一 8～28 字）、b（选项二 8～28 字）；5 题之间话题不要重复。',\n      '语气像真人在聊天里会纠结的小选择；不要出现 AI、模型、出题等 meta。',\n      persona && persona.sheet ? '\\n[角色人设]\\n' + llmPlain(persona.sheet, 1500) : '',\n      '\\n[关系卡片]\\n' + peerCard,\n      '\\n[最近对话]\\n' + histText,\n      '\\n严格输出：{\"items\":[{\"q\":\"\",\"a\":\"\",\"b\":\"\"}, … 共 5 个对象]}',\n    ].join('\\n');\n    const raw = await chillLlmComplete(profile, [{ role: 'system', content: sys }], { temperature: 0.78, timeoutMs: 80000 });\n    const obj = parseJsonObjectFromRaw(raw);\n    const arr = Array.isArray(obj.items) ? obj.items : Array.isArray(obj.quizzes) ? obj.quizzes : [];\n    const out = [];\n    for(let i = 0; i < arr.length; i++){\n      const it = arr[i] || {};\n      const q = String(it.q || it.question || '').replace(/\\s+/g, ' ').trim().slice(0, 88);\n      const a = String(it.a || it.optA || it.A || '').replace(/\\s+/g, ' ').trim().slice(0, 44);\n      const b = String(it.b || it.optB || it.B || '').replace(/\\s+/g, ' ').trim().slice(0, 44);\n      if(q && a && b) out.push({ q, a, b });\n      if(out.length >= 5) break;\n    }\n    let pad = 0;\n    while(out.length < 5 && COMPAT_QUIZ_POOL.length){\n      const p = COMPAT_QUIZ_POOL[pad % COMPAT_QUIZ_POOL.length];\n      out.push({ q: p.q, a: p.a, b: p.b });\n      pad++;\n    }\n    return { items: out.slice(0, 5), epoch: Date.now() };\n  }\n  function peerQuizPick(peerId, quizId){\n    return hash32('compatPick|' + String(peerId || '') + '|' + String(quizId || '')) % 2;\n  }\n  function ensureCompatQuizForCurrentChat(reset){\n    if(!currentChat || currentChat.isStranger){\n      currentCompatQuiz = null;\n      compatQuizOffset = 0;\n      return;\n    }\n    const sid = String(currentChat.id || '');\n    if(reset) compatQuizOffset = 0;\n    const next = buildCurrentCompatSnapshot(sid, compatQuizOffset);\n    if(!currentCompatQuiz || String(currentCompatQuiz.peerId || '') !== sid || reset){\n      currentCompatQuiz = next;\n      return;\n    }\n    if(currentCompatQuiz.quizId !== next.quizId) currentCompatQuiz = next;\n  }\n  function closeCompatQuizModal(){\n    if($modalCompatQuiz) $modalCompatQuiz.classList.remove('open');\n  }\n  function openCompatQuizModal(){\n    if(!currentChat || currentChat.isStranger) return;\n    const u = resolveChatForStarGates();\n    if(!canUseCompatQuiz(u)){\n      meetToastShow('要对彼此都到 3★ 才能玩默契问答哦');\n      return;\n    }\n    closePeerMoodModal();\n    renderCompatQuizUi();\n    if($modalCompatQuiz) $modalCompatQuiz.classList.add('open');\n  }\n  function renderCompatQuizUi(){\n    const box = document.getElementById('chat-compat');\n    const qEl = document.getElementById('chat-compat-q');\n    const aBtn = document.getElementById('chat-compat-a');\n    const bBtn = document.getElementById('chat-compat-b');\n    const hint = document.getElementById('chat-compat-hint');\n    const nextBtn = document.getElementById('chat-compat-next');\n    const trig = document.getElementById('chat-compat-trigger');\n    if(!box || !qEl || !aBtn || !bBtn || !hint || !nextBtn) return;\n    if(trig) trig.hidden = !currentChat || !!currentChat.isStranger;\n    if(!currentChat || currentChat.isStranger){\n      box.hidden = true;\n      const r0 = document.getElementById('compat-quiz-refresh');\n      if(r0){\n        r0.disabled = true;\n        r0.classList.remove('is-busy');\n      }\n      return;\n    }\n    ensureCompatQuizForCurrentChat(false);\n    box.hidden = false;\n    const gate = resolveChatForStarGates();\n    const locked = !canUseCompatQuiz(gate);\n    box.classList.toggle('is-locked', locked);\n    const refr = document.getElementById('compat-quiz-refresh');\n    if(refr){\n      const off = locked || _compatQuizRefreshBusy;\n      refr.disabled = off;\n      refr.classList.toggle('is-busy', _compatQuizRefreshBusy);\n    }\n    const quiz = currentCompatQuiz || buildCurrentCompatSnapshot(String(currentChat.id), compatQuizOffset);\n    if(!quiz){\n      qEl.textContent = '—';\n      aBtn.disabled = true;\n      bBtn.disabled = true;\n      nextBtn.disabled = true;\n      hint.textContent = '';\n      return;\n    }\n    qEl.textContent = quiz.q;\n    aBtn.textContent = 'A · ' + quiz.options[0];\n    bBtn.textContent = 'B · ' + quiz.options[1];\n    aBtn.classList.toggle('on', quiz.picked === 0);\n    bBtn.classList.toggle('on', quiz.picked === 1);\n    aBtn.disabled = locked || quiz.resolved;\n    bBtn.disabled = locked || quiz.resolved;\n    nextBtn.disabled = locked;\n    if(locked){\n      hint.textContent = '双方 3★ 解锁';\n      return;\n    }\n    if(!quiz.resolved){\n      hint.textContent = '';\n      return;\n    }\n    const side = quiz.peerPicked === 0 ? 'A' : 'B';\n    const matched = quiz.picked === quiz.peerPicked;\n    hint.textContent = matched\n      ? ('同选 ' + side)\n      : ('Ta：' + side);\n  }\n  function applyCompatQuizReward(peerId){\n    const sid = String(peerId || '');\n    const today = localYmd();\n    const last = String((_compatQuizRewardMap && _compatQuizRewardMap[sid]) || '');\n    if(last === today) return { granted: false };\n    const u = liked.find(x => String(x.id) === sid);\n    if(!u) return { granted: false };\n    const prevStars = Number(u.stars) || 0;\n    const prevSp = Number(u.starsFromPeer) || 0;\n    u.favorMe = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, Math.round((Number(u.favorMe) || 0) + getFavorDeltaFromRateStep(2))));\n    u.favorPeer = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, Math.round((Number(u.favorPeer) || 0) + getFavorDeltaFromRateStep(1))));\n    syncStarsFromFavor(u);\n    const unlockedNow = markFirstStarUnlockIfNeeded(u, prevStars);\n    saveLiked();\n    _compatQuizRewardMap[sid] = today;\n    saveCompatQuizRewardMap();\n    if(currentChat && String(currentChat.id) === sid){\n      currentChat = Object.assign({}, u, { isStranger: false });\n    }\n    renderInbox();\n    setChatImpressUi(false, u);\n    if(unlockedNow) void openNameUnlockModal(sid);\n    const delay = unlockedNow ? 450 : 100;\n    setTimeout(() => maybeEnqueueMutualStarMilestones(u, prevStars, prevSp), delay);\n    return { granted: true };\n  }\n  function resolveCompatQuizPick(pickedIdx){\n    if(!currentChat || currentChat.isStranger) return;\n    if(!canUseCompatQuiz(resolveChatForStarGates())) return;\n    ensureCompatQuizForCurrentChat(false);\n    if(!currentCompatQuiz || currentCompatQuiz.resolved) return;\n    const idx = pickedIdx === 1 ? 1 : 0;\n    currentCompatQuiz.picked = idx;\n    currentCompatQuiz.peerPicked = peerQuizPick(currentChat.id, currentCompatQuiz.quizId);\n    currentCompatQuiz.resolved = true;\n    if(currentCompatQuiz.picked === currentCompatQuiz.peerPicked){\n      const rs = applyCompatQuizReward(currentChat.id);\n      if(!rs.granted){\n        const hint = document.getElementById('chat-compat-hint');\n        if(hint) hint.textContent = '同选 · 今日奖励已领';\n      }\n    }\n    renderCompatQuizUi();\n  }\n\n  function icebreakerSeedKey(){\n    const day = new Date().toISOString().slice(0, 10);\n    const id = currentChat && currentChat.id ? String(currentChat.id) : 'guest';\n    return id + '|' + day + '|' + icebreakerShuffle;\n  }\n\n  function pickIcebreakerLine(){\n    const i = hash32('ice|' + icebreakerSeedKey()) % ICEBREAKERS.length;\n    return ICEBREAKERS[i];\n  }\n\n  function normalizeIcebreakerPool(arr){\n    if(!Array.isArray(arr)) return [];\n    const out = [];\n    const seen = new Set();\n    arr.forEach(x => {\n      const s = String(x || '').replace(/\\s+/g, ' ').trim().slice(0, 120);\n      if(!s) return;\n      const k = s.toLowerCase();\n      if(seen.has(k)) return;\n      seen.add(k);\n      out.push(s);\n    });\n    return out.slice(0, 5);\n  }\n\n  function getCurrentIcebreakerPool(){\n    const id = currentChat && currentChat.id ? String(currentChat.id) : '';\n    if(!id) return [];\n    return normalizeIcebreakerPool(_chatIcebreakerPoolMap[id]);\n  }\n\n  function setCurrentIcebreakerPool(lines){\n    const id = currentChat && currentChat.id ? String(currentChat.id) : '';\n    if(!id) return;\n    const norm = normalizeIcebreakerPool(lines);\n    if(!norm.length) return;\n    _chatIcebreakerPoolMap[id] = norm;\n  }\n\n  function updateIcebreakerFallback(){\n    const el = document.getElementById('chat-icebreaker-text');\n    if(!el) return;\n    const pool = getCurrentIcebreakerPool();\n    if(pool.length){\n      const idx = ((icebreakerShuffle % pool.length) + pool.length) % pool.length;\n      el.textContent = pool[idx];\n      return;\n    }\n    el.textContent = pickIcebreakerLine();\n  }\n\n  function updateIcebreakerUi(){\n    updateIcebreakerFallback();\n  }\n\n  function normalizePeerMoodFieldsFromJson(obj){\n    if(!obj || typeof obj !== 'object') return { peerStatus: '', peerMood: '' };\n    const status = String(obj.status || obj.peerStatus || '').replace(/\\s+/g, ' ').trim().slice(0, 14);\n    const mood = String(obj.mood || obj.peerMood || obj.moodVoice || '').replace(/\\s+/g, ' ').trim().slice(0, 56);\n    return { peerStatus: status, peerMood: mood };\n  }\n\n  function parseReplyBundle(raw){\n    const rawText = String(raw == null ? '' : raw).trim();\n    let s = rawText;\n    const fm = s.match(/```(?:json)?\\s*([\\s\\S]*?)```/i);\n    if(fm) s = fm[1].trim();\n    function normalizeReplies(list){\n      if(!Array.isArray(list)) return [];\n      const rows = list\n        .map(x => String(x == null ? '' : x).trim())\n        .filter(Boolean);\n      // 兼容主文件风格：单条里可能用 \"|||\" 分段成多气泡。\n      // 须先按 ||| 分段再截断，避免 slice 切断分隔符导致乱段。\n      const out = [];\n      const cap = 500;\n      for(const row of rows){\n        const segs = row.split('|||').map(s => s.trim()).filter(Boolean);\n        if(segs.length > 1){\n          for(const s of segs) out.push(s.slice(0, cap));\n        }else{\n          out.push(row.slice(0, cap));\n        }\n      }\n      return out.slice(0, 6);\n    }\n    try{\n      const i0 = s.indexOf('{');\n      const i1 = s.lastIndexOf('}');\n      if(i0 >= 0 && i1 > i0) s = s.slice(i0, i1 + 1);\n      const obj = JSON.parse(s);\n      const replies = normalizeReplies(\n        obj.replies || obj.replyList || obj.messages ||\n        (obj.reply ? [obj.reply] : (obj.text ? [obj.text] : (obj.content ? [obj.content] : [])))\n      );\n      const icebreakers = normalizeIcebreakerPool(obj.icebreakers || obj.suggestions || obj.icebreakerList || []);\n      const pm = normalizePeerMoodFieldsFromJson(obj);\n      if(replies.length)\n        return { replies, icebreakers, peerStatus: pm.peerStatus, peerMood: pm.peerMood };\n    }catch(_){}\n    const fallback = rawText.slice(0, 2000).trim();\n    return { replies: fallback ? [fallback] : [], icebreakers: [], peerStatus: '', peerMood: '' };\n  }\n  function normalizePeerRepliesForDisplay(lines){\n    const cap = 500;\n    const expanded = [];\n    if(Array.isArray(lines)){\n      for(const x of lines){\n        const raw = String(x == null ? '' : x).trim();\n        if(!raw) continue;\n        if(raw.includes('|||')){\n          raw.split('|||').map(s => s.trim()).filter(Boolean).forEach(s => expanded.push(s.slice(0, cap)));\n        }else{\n          expanded.push(raw.slice(0, cap));\n        }\n      }\n    }\n    if(expanded.length >= 2) return expanded.slice(0, 6);\n    const one = String(expanded[0] || '').trim();\n    if(!one) return ['嗯嗯，我在。'];\n    if(one.includes('|||')){\n      const segs = one.split('|||').map(s => s.trim()).filter(Boolean);\n      if(segs.length) return segs.slice(0, 6).map(s => s.slice(0, cap));\n    }\n    // 对齐主文件：不强制分段；仅当单条过长时做温和拆分。\n    if(one.length <= 80) return [one];\n    const parts = one\n      .split(/(?<=[。！？!?，,；;])/)\n      .map(s => s.trim())\n      .filter(Boolean);\n    if(parts.length >= 2){\n      const out = [];\n      let buf = '';\n      for(const p of parts){\n        if((buf + p).length <= 34){\n          buf += p;\n        }else{\n          if(buf) out.push(buf);\n          buf = p;\n        }\n      }\n      if(buf) out.push(buf);\n      if(out.length >= 2) return out.slice(0, 4);\n    }\n    const mid = Math.max(10, Math.min(one.length - 8, Math.round(one.length * 0.56)));\n    return [one.slice(0, mid).trim(), one.slice(mid).trim()].filter(Boolean).slice(0, 3);\n  }\n\n  function peerSunFromProfile(p){\n    return hash32('peersun|' + String(p.id)) % 12;\n  }\n\n  function buildSynastryHtml(p){\n    const birth = getStoredBirth();\n    if(!birth || !birth.date){\n      return (\n        '<div class=\"ma-syn-mini ma-syn-mini--empty\">' +\n          '<div class=\"ma-syn-mini-head\">' +\n            '<span class=\"ma-syn-mini-k\">迷你合盘 · Synastry</span>' +\n            '<span class=\"ma-syn-mini-tag\">示意</span>' +\n          '</div>' +\n          '<p class=\"ma-syn-mini-lead\">在「我的」保存生日后，显示你与 Ta 的轻量合盘指数与聊天向提示。</p>' +\n        '</div>'\n      );\n    }\n    const parts = birth.date.split('-').map(Number);\n    const mySun = sunSignFromDate(parts[1], parts[2]);\n    const useApiSyn =\n      p.apiPeerSun != null && p.apiSynScore != null && p.apiSynLine != null && String(p.apiSynLine).trim() !== '';\n    const peerSun = useApiSyn ? p.apiPeerSun : peerSunFromProfile(p);\n    const score = useApiSyn\n      ? p.apiSynScore\n      : 52 + (hash32('syn|' + birth.date + '|' + String(p.id)) % 43);\n    const line = useApiSyn\n      ? String(p.apiSynLine).trim()\n      : SYNASTRY_LINES[hash32('synL|' + mySun + '|' + peerSun + '|' + p.id) % SYNASTRY_LINES.length];\n    const headTag = useApiSyn ? '推荐' : '示意';\n    const peerNote = useApiSyn ? '模型生成' : '资料示意';\n    return (\n      '<div class=\"ma-syn-mini\">' +\n        '<div class=\"ma-syn-mini-head\">' +\n          '<span class=\"ma-syn-mini-k\">迷你合盘 · Synastry</span>' +\n          '<span class=\"ma-syn-mini-tag\">' + esc(headTag) + '</span>' +\n        '</div>' +\n        '<div class=\"ma-syn-mini-orbs\">' +\n          '<div class=\"ma-syn-orb ma-syn-orb--me\">' +\n            '<span class=\"ma-syn-orb-lbl\">你 · Sun</span>' +\n            '<span class=\"ma-syn-orb-z\">' + esc(Z_SIGN[mySun]) + '</span>' +\n          '</div>' +\n          '<div class=\"ma-syn-axis\" aria-hidden=\"true\"><span class=\"ma-syn-axis-line\"></span><span class=\"ma-syn-axis-dot\"></span><span class=\"ma-syn-axis-line\"></span></div>' +\n          '<div class=\"ma-syn-orb ma-syn-orb--peer\">' +\n            '<span class=\"ma-syn-orb-lbl\">Ta · Sun</span>' +\n            '<span class=\"ma-syn-orb-z\">' + esc(Z_SIGN[peerSun]) + '</span>' +\n            '<span class=\"ma-syn-orb-note\">' + esc(peerNote) + '</span>' +\n          '</div>' +\n        '</div>' +\n        '<div class=\"ma-syn-mini-foot\">' +\n          '<div class=\"ma-syn-score-row\">' +\n            '<div class=\"ma-syn-score\"><strong>' + score + '</strong><small>INDEX</small></div>' +\n            '<div class=\"ma-syn-meter\" aria-hidden=\"true\"><div class=\"ma-syn-meter-fill\" style=\"width:' + score + '%\"></div></div>' +\n          '</div>' +\n          '<p class=\"ma-syn-line\">' + esc(line) + '</p>' +\n        '</div>' +\n      '</div>'\n    );\n  }\n\n  function syncDiscoverActions(){\n    const on = !!(deck[0] && !discoverBusy);\n    ['btn-pass','btn-like'].forEach(id => {\n      const el = document.getElementById(id);\n      if(el) el.disabled = !on;\n    });\n  }\n\n  function showDeckLoadingState(){\n    if($deckWrap){\n      $deckWrap.classList.add('ma-deck-loading','ma-deck-empty');\n    }\n    $deck.innerHTML = '<div class=\"ma-deck-loading-inner\"><i class=\"ph ph-spinner ma-spin\" aria-hidden=\"true\"></i><p>正在生成推荐卡片…</p></div>';\n    syncDiscoverActions();\n  }\n\n  function renderDeckFetchError(err){\n    if($deckWrap){\n      $deckWrap.classList.add('ma-deck-empty');\n      $deckWrap.classList.remove('ma-deck-loading');\n    }\n    const msg = err && err.message ? esc(String(err.message).slice(0, 200)) : '网络或服务异常';\n    $deck.innerHTML =\n      '<div class=\"ma-deck-fetch-err\">' +\n        '<strong>加载失败</strong>' +\n        '<p>请确认接口可访问，或稍后重试。</p>' +\n        '<p class=\"ma-dfe-sub\">' + msg + '</p>' +\n      '</div>';\n    syncDiscoverActions();\n  }\n\n  async function refreshDiscoverFromApi(){\n    if(discoverBusy) return;\n    const btn = document.getElementById('btn-refresh-discover');\n    const prev = deck.slice();\n    discoverBusy = true;\n    if(btn){\n      btn.disabled = true;\n      btn.classList.add('is-busy');\n    }\n    showDeckLoadingState();\n    try{\n      const cards = await fetchDiscoverCardsFromApi();\n      deck = cards.filter(c => !liked.some(l => String(l.id) === String(c.id)));\n      if($deckWrap) $deckWrap.classList.remove('ma-deck-loading');\n      renderCard(deck[0]);\n      renderDailyRecommend();\n    }catch(e){\n      deck = prev;\n      if($deckWrap) $deckWrap.classList.remove('ma-deck-loading');\n      if(!deck.length) renderDeckFetchError(e);\n      else renderCard(deck[0]);\n      if(deck.length) console.warn(e);\n    }finally{\n      discoverBusy = false;\n      if(btn){\n        btn.disabled = false;\n        btn.classList.remove('is-busy');\n      }\n      syncDiscoverActions();\n    }\n  }\n\n  function renderCard(p){\n    if(!p){\n      if($deckWrap){\n        $deckWrap.classList.add('ma-deck-empty');\n        $deckWrap.classList.remove('ma-deck-loading');\n      }\n      $deck.innerHTML = '<div class=\"ma-empty\"><i class=\"ph ph-sparkle\"></i><p>暂无推荐卡片</p><span>点右上角 REFRESH 从接口加载</span></div>';\n      syncDiscoverActions();\n      return;\n    }\n    if($deckWrap){\n      $deckWrap.classList.remove('ma-deck-empty','ma-deck-loading');\n    }\n    const rank = deck.findIndex(c => String(c.id) === String(p.id));\n    const issueNo = String(rank >= 0 ? rank + 1 : 1).padStart(2,'0');\n    const profileLine = buildCardProfileLine(p);\n    $deck.innerHTML = `\n      <div class=\"ma-card ma-card-appear\" id=\"swipe-card\" data-id=\"${esc(p.id)}\">\n        <div class=\"ma-card-inner\">\n          <div class=\"ma-card-stamps\">\n            <span class=\"ma-card-stamp nope\" id=\"stamp-nope\">\n              <span class=\"ma-stamp-word\">跳过</span>\n              <span class=\"ma-stamp-sub\">PASS</span>\n            </span>\n            <span class=\"ma-card-stamp like\" id=\"stamp-like\">\n              <span class=\"ma-stamp-word\">喜欢</span>\n              <span class=\"ma-stamp-sub\">LIKE</span>\n            </span>\n          </div>\n          <div class=\"ma-card-photo\">\n            <div class=\"ma-card-rail\"><span>No.${issueNo}</span></div>\n            <span>${cardBasicsLine(p)}</span>\n          </div>\n          <div class=\"ma-card-body\">\n            <div class=\"ma-card-rule\"></div>\n            <div class=\"ma-card-meta\">\n              <div>\n                <div class=\"ma-card-name\">${esc(p.name)}</div>\n                <div class=\"ma-card-age\">${esc(profileLine)}</div>\n              </div>\n              <div class=\"ma-badges\">\n                <span class=\"ma-badge\">${esc(p.tag)}</span>\n              </div>\n            </div>\n            <div class=\"ma-astro-dual\">\n              <div class=\"ma-orbit ma-orbit-match\" style=\"--p:${p.match}\">\n                <div class=\"ma-orbit-dots\" aria-hidden=\"true\"></div>\n                <div class=\"ma-orbit-core\"><strong>${p.match}<small>%</small></strong><span>匹配</span></div>\n              </div>\n              <div class=\"ma-orbit ma-orbit-astro\" style=\"--p:${p.astro}\">\n                <div class=\"ma-orbit-dots\" aria-hidden=\"true\"></div>\n                <div class=\"ma-orbit-core\"><strong>${p.astro}<small>%</small></strong><span>星盘</span></div>\n              </div>\n            </div>\n            ${buildSynastryHtml(p)}\n            <p class=\"ma-card-bio\">${esc(p.bio)}</p>\n          </div>\n        </div>\n      </div>`;\n    bindSwipe(document.getElementById('swipe-card'));\n    syncDiscoverActions();\n  }\n\n  function bindSwipe(el){\n    if(!el) return;\n    el.style.touchAction = 'none';\n    const bodyScrollEl = el.querySelector('.ma-card-body');\n    if(bodyScrollEl) bodyScrollEl.style.touchAction = 'pan-y';\n\n    let startX = 0, startY = 0, dragging = false, activePointer = null;\n    let lastDx = 0, lastDy = 0;\n    let lockAxis = null;\n\n    const stampNope = () => el.querySelector('#stamp-nope');\n    const stampLike = () => el.querySelector('#stamp-like');\n\n    function applyTransform(dx, dy){\n      lastDx = dx; lastDy = dy;\n      const rot = dx * 0.045;\n      el.style.transform = `translate3d(${dx}px, ${dy * 0.12}px, 0) rotate(${rot}deg)`;\n      const likeOp = dx > 12 ? Math.min(1, (dx - 12) / 72) : 0;\n      const nopeOp = dx < -12 ? Math.min(1, (-dx - 12) / 72) : 0;\n      const sn = stampNope();\n      const sl = stampLike();\n      if(sn) sn.style.opacity = String(nopeOp);\n      if(sl) sl.style.opacity = String(likeOp);\n    }\n\n    function resetStamps(){\n      const sn = stampNope(), sl = stampLike();\n      if(sn) sn.style.opacity = '0';\n      if(sl) sl.style.opacity = '0';\n    }\n\n    function finishSwipe(commit){\n      dragging = false;\n      el.classList.remove('dragging');\n      lockAxis = null;\n      resetStamps();\n      if(commit === 'like'){\n        const w = window.innerWidth;\n        el.style.transition = 'transform 0.28s cubic-bezier(0.25,0.8,0.25,1)';\n        el.style.transform = `translate3d(${w * 0.6}px, 24px, 0) rotate(18deg)`;\n        setTimeout(() => { el.style.transition = ''; el.style.transform = ''; doLike(); }, 260);\n      } else if(commit === 'pass'){\n        const w = window.innerWidth;\n        el.style.transition = 'transform 0.28s cubic-bezier(0.25,0.8,0.25,1)';\n        el.style.transform = `translate3d(${-w * 0.6}px, 24px, 0) rotate(-18deg)`;\n        setTimeout(() => { el.style.transition = ''; el.style.transform = ''; doPass(); }, 260);\n      } else {\n        el.style.transition = 'transform 0.35s cubic-bezier(0.19,1,0.22,1)';\n        el.style.transform = 'translate3d(0, 0, 0) rotate(0deg)';\n        setTimeout(() => { el.style.transition = ''; el.style.transform = ''; }, 360);\n      }\n    }\n\n    el.addEventListener('pointerdown', (e) => {\n      if(e.pointerType === 'mouse' && e.button !== 0) return;\n      startX = e.clientX; startY = e.clientY;\n      dragging = true; activePointer = e.pointerId;\n      lastDx = 0; lastDy = 0; lockAxis = null;\n      el.style.transition = 'none';\n    });\n\n    el.addEventListener('pointermove', (e) => {\n      if(!dragging || e.pointerId !== activePointer) return;\n      const dx = e.clientX - startX; const dy = e.clientY - startY;\n      const ax = Math.abs(dx); const ay = Math.abs(dy);\n      if(!lockAxis && (ax > 6 || ay > 6)){\n        if(ax > ay * 1.05) {\n          lockAxis = 'x'; el.classList.add('dragging');\n          try { el.setPointerCapture(e.pointerId); } catch(_){}\n        } else { lockAxis = 'y'; }\n      }\n      if(lockAxis === 'x') { applyTransform(dx, dy); }\n    });\n\n    const onUp = (e) => {\n      if(!dragging || e.pointerId !== activePointer) return;\n      try { el.releasePointerCapture(e.pointerId); } catch(_){}\n      if(lockAxis === 'x'){\n        const w = el.getBoundingClientRect().width || 300;\n        const threshold = Math.min(100, w * 0.25);\n        if(lastDx > threshold) finishSwipe('like');\n        else if(lastDx < -threshold) finishSwipe('pass');\n        else finishSwipe(null);\n      } else { finishSwipe(null); }\n    };\n\n    el.addEventListener('pointerup', onUp);\n    el.addEventListener('pointercancel', onUp);\n    el.addEventListener('touchmove', (e) => {\n      if(dragging && lockAxis === 'x' && e.cancelable) e.preventDefault();\n    }, {passive: false});\n  }\n\n  function topCard(){ return deck[0]; }\n\n  function peerLikesBack(p){\n    const id = String(p && p.id ? p.id : '');\n    const match = Number(p && p.match);\n    const astro = Number(p && p.astro);\n    const m = Number.isFinite(match) ? match : 68;\n    const a = Number.isFinite(astro) ? astro : 65;\n    const blended = m * 0.58 + a * 0.42;\n    const threshold = Math.min(88, Math.max(22, Math.round(blended - 18)));\n    const roll = hash32('mutual|' + id + '|' + m + '|' + a) % 100;\n    return roll < threshold;\n  }\n\n  function peerAllowsStrangerDm(p){\n    const id = String(p && p.id ? p.id : '');\n    const match = Number(p && p.match);\n    const astro = Number(p && p.astro);\n    const m = Number.isFinite(match) ? match : 66;\n    const a = Number.isFinite(astro) ? astro : 64;\n    // 对方是否开启陌生私聊：随人设稳定、并受匹配度轻微影响（越高越可能开）。\n    const threshold = Math.min(85, Math.max(28, Math.round(42 + (m - 60) * 0.35 + (a - 60) * 0.22)));\n    const roll = hash32('strangerDm|' + id + '|' + m + '|' + a) % 100;\n    return roll < threshold;\n  }\n\n  function addCardAsStrangerLead(p){\n    if(!p) return;\n    const firstBio = String(p.bio || '').split(/[。！？!?]/)[0].trim();\n    const preview = (firstBio || ('你好，我是' + String(p.name || 'Ta'))).slice(0, 120);\n    const n = normalizeStrangerInboxEntry({ id: p.id, name: p.name, preview }, 0);\n    if(!n) return;\n    if(strangers.some(s => String(s.id) === String(n.id))) return;\n    strangers.unshift(n);\n    strangers = strangers.slice(0, STRANGER_MAX_INBOX);\n    saveStrangersToStorage();\n  }\n\n  function showUnmatchModal(name){\n    if(!$modalUnmatch) return;\n    const msg = document.getElementById('unmatch-msg');\n    if(msg){\n      const who = String(name || 'Ta').trim() || 'Ta';\n      msg.innerHTML = esc(who) + ' 还没有选择你，且 Ta 关闭了<strong>陌生人私聊</strong>。等互选后就能开始对话。';\n    }\n    $modalUnmatch.classList.add('open');\n  }\n  function closeNameUnlockModal(){\n    if(!$modalNameUnlock) return;\n    $modalNameUnlock.classList.remove('open');\n  }\n  async function openNameUnlockModal(peerId){\n    if(!$modalNameUnlock) return;\n    const sid = String(peerId || pendingNameUnlockPeerId || '');\n    if(!sid) return;\n    const u = liked.find(x => String(x.id) === sid);\n    if(!u || u.realNameUnlocked || (Number(u.stars) || 0) < 1) return;\n    pendingNameUnlockPeerId = sid;\n    const aliasEl = document.getElementById('name-unlock-peer-alias');\n    if(aliasEl) aliasEl.textContent = String(u.name || 'Ta');\n    const err = document.getElementById('name-unlock-error');\n    if(err) err.textContent = '';\n    const selfInp = document.getElementById('name-unlock-self-input');\n    if(selfInp){\n      selfInp.value = _meetSelfName || '';\n    }\n    const peerInp = document.getElementById('name-unlock-peer-input');\n    if(peerInp){\n      const cached = getCachedChatPersona(sid);\n      const preferred = normalizePeerNameInput((u && u.realName) || (cached && cached.realName) || '');\n      const picked = await pickAvailablePeerRealName(u, preferred, sid);\n      u.realName = picked;\n      peerInp.value = picked;\n      setTimeout(() => peerInp.focus(), 30);\n    }\n    $modalNameUnlock.classList.add('open');\n  }\n  async function applyNameUnlock(){\n    const sid = String(pendingNameUnlockPeerId || '');\n    if(!sid) return;\n    const u = liked.find(x => String(x.id) === sid);\n    if(!u) return;\n    const err = document.getElementById('name-unlock-error');\n    if(err) err.textContent = '';\n    const selfInp = document.getElementById('name-unlock-self-input');\n    const selfName = normalizePeerNameInput(selfInp && selfInp.value || '');\n    if(!selfName){\n      if(err) err.textContent = '先输入你的名字';\n      selfInp?.focus();\n      return;\n    }\n    const peerInp = document.getElementById('name-unlock-peer-input');\n    const wantedPeerName = normalizePeerNameInput(peerInp && peerInp.value || '');\n    const checkedPeerName = await pickAvailablePeerRealName(u, wantedPeerName || u.realName, sid);\n    if(wantedPeerName && nameKey(wantedPeerName) !== nameKey(checkedPeerName)){\n      if(err) err.textContent = '这个名字和已有角色重复，已为你换成可用名';\n      if(peerInp) peerInp.value = checkedPeerName;\n      peerInp?.focus();\n      return;\n    }\n    _meetSelfName = selfName;\n    void meetStoreSet(IDB_KEY_MEET_SELF_NAME, _meetSelfName);\n    u.realName = checkedPeerName || ensurePeerRealName(u);\n    u.realNameUnlocked = true;\n    saveLiked();\n    if(currentChat && String(currentChat.id) === sid){\n      currentChat = Object.assign({}, u, { isStranger: false });\n      const title = document.getElementById('chat-peer');\n      if(title) title.textContent = getPeerDisplayName(u);\n    }\n    renderInbox();\n    renderDailyRecommend();\n    pendingNameUnlockPeerId = '';\n    closeNameUnlockModal();\n  }\n\n  function doPass(){\n    deck.shift();\n    renderCard(deck[0]);\n  }\n\n  function doLike(){\n    const p = deck.shift();\n    if(p){\n      const mutual = peerLikesBack(p);\n      if(mutual){\n        liked.push(normalizeLikedEntry(Object.assign({}, p, { favorMe: 0, favorPeer: peerFavorSeed(p.id), favorEconomy: 3 })));\n      saveLiked();\n      renderInbox();\n      }else{\n        if(!peerAllowsStrangerDm(p)){\n          showUnmatchModal(p.name);\n        }else{\n          addCardAsStrangerLead(p);\n          renderInbox();\n        }\n      }\n      renderDailyRecommend();\n    }\n    renderCard(deck[0]);\n  }\n\n  function markFirstStarUnlockIfNeeded(u, prevStars){\n    if(!u) return false;\n    const before = Number(prevStars) || 0;\n    const now = Number(u.stars) || 0;\n    if(before >= 1 || now < 1 || u.realNameUnlocked) return false;\n    ensurePeerRealName(u);\n    pendingNameUnlockPeerId = String(u.id || '');\n    return true;\n  }\n  function addFavorFromRateStep(u, step){\n    if(!u || step === null || step === undefined) return false;\n    const prevStars = Number(u.stars) || 0;\n    const delta = getFavorDeltaFromRateStep(step);\n    u.favorMe = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, Math.round((Number(u.favorMe) || 0) + delta)));\n    syncStarsFromFavor(u);\n    return markFirstStarUnlockIfNeeded(u, prevStars);\n  }\n  function bumpPeerImpression(u){\n    if(!u) return;\n    const roll = Math.random();\n    let step = 0;\n    if(roll < 0.14) step = -1;\n    else if(roll < 0.58) step = (Math.random() < 0.55 ? 0.5 : 1);\n    else if(roll < 0.86) step = 1;\n    else step = 2;\n    const delta = getFavorDeltaFromRateStep(step);\n    u.favorPeer = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, Math.round((Number(u.favorPeer) || 0) + delta)));\n    syncStarsFromFavor(u);\n  }\n\n  function parseJsonObjectFromRaw(raw){\n    let s = String(raw == null ? '' : raw).trim();\n    const fm = s.match(/```(?:json)?\\s*([\\s\\S]*?)```/i);\n    if(fm) s = fm[1].trim();\n    const i0 = s.indexOf('{');\n    const i1 = s.lastIndexOf('}');\n    if(i0 >= 0 && i1 > i0) s = s.slice(i0, i1 + 1);\n    return JSON.parse(s);\n  }\n\n  async function resolvePeerFavorDeltaByExit(u, userStep){\n    const profile = await getActiveApiProfileFromMain();\n    if(!profile) return null;\n    const hist = getConvHistory(u.id).slice(-36).map(t => ({\n      role: t.role === 'assistant' ? 'assistant' : 'user',\n      content: String(t.content || '').slice(0, 300),\n    }));\n    const sys =\n      '你是中文社交聊天中的角色一致性评估器。' +\n      '根据角色人设、最近聊天内容和可见的双方好感状态，判断“角色对用户的本次好感变化（可正可负）”。' +\n      '重要：在该产品里，双方都能看到彼此好感和星级，角色知道这一点。' +\n      '评分标准必须与用户侧一致：只允许这些档位 step：-1,0,0.5,1,2,3,4,5。' +\n      '只输出 JSON：{\"peerStep\":数字或字符串,\"reason\":\"不超过28字中文\"}。不输出其它文本。' +\n      '其中 peerStep 只能从允许档位里选一个，保持克制，不要每次都升高。';\n    const persona = getCachedChatPersona(u.id);\n    const payload = {\n      peerName: u.name,\n      isStranger: !!u.isStranger,\n      profile: {\n        city: u.city || '',\n        age: Number(u.age) || null,\n        gender: u.gender || '',\n        tag: u.tag || '',\n        bio: (u.bio || '').slice(0, 220),\n      },\n      personaSheet: persona && persona.sheet ? persona.sheet.slice(0, 800) : '',\n      visibleFavor: {\n        favorMe: Math.round(Number(u.favorMe) || 0),\n        favorPeer: Math.round(Number(u.favorPeer) || 0),\n        starsMe: Number(u.stars) || 0,\n        starsPeer: Number(u.starsFromPeer) || 0,\n      },\n      userExitChoice: {\n        step: userStep,\n        deltaToPeer: getFavorDeltaFromRateStep(userStep),\n      },\n      recentTurns: hist,\n    };\n    try{\n      const raw = await chillLlmComplete(profile, [\n        { role: 'system', content: sys },\n        { role: 'user', content: '请评估本次结算的 peerStep（按同一评分档位）：\\n' + JSON.stringify(payload) },\n      ], { temperature: 0.55, timeoutMs: 45000 });\n      const obj = parseJsonObjectFromRaw(raw);\n      const step = normalizeRateStepInput(obj && obj.peerStep);\n      if(step !== null) return getFavorDeltaFromRateStep(step);\n      // 兼容旧返回（peerDelta）：映射到最近的评分档位，避免过快升级。\n      const legacyDelta = Math.round(Number(obj && obj.peerDelta));\n      if(!Number.isFinite(legacyDelta)) return null;\n      const mappedStep = nearestRateStepByDelta(legacyDelta);\n      if(mappedStep === null) return null;\n      return getFavorDeltaFromRateStep(mappedStep);\n    }catch(_){\n      return null;\n    }\n  }\n  function chatTimeHM(){\n    const d = new Date();\n    const z = n => String(n).padStart(2,'0');\n    return z(d.getHours()) + ':' + z(d.getMinutes());\n  }\n  function renderStarRowEl(el, n){\n    if(!el) return;\n    const v = Math.min(5, Math.max(0, Number(n) || 0));\n    el.innerHTML = [1,2,3,4,5].map(i =>\n      '<i class=\"' + (i <= v ? 'ph-fill ph-star' : 'ph ph-star') + '\" aria-hidden=\"true\"></i>'\n    ).join('');\n  }\n\n  function convMapGet(){\n    const m = _meetConvMap;\n    if(!m || typeof m !== 'object') return {};\n    try{ return JSON.parse(JSON.stringify(m)); }catch(_){ return {}; }\n  }\n  function makeTurnId(role){\n    return 't_' + (role === 'assistant' ? 'a' : 'u') + '_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8);\n  }\n  function normalizeQuoteRef(q){\n    if(!q || typeof q !== 'object') return null;\n    const text = String(q.text || '').trim().slice(0, 140);\n    if(!text) return null;\n    const from = q.from === 'me' ? 'me' : 'peer';\n    return { turnId: String(q.turnId || ''), text, from };\n  }\n  function normalizeConvTurn(t, idx){\n    const role = t && t.role === 'assistant' ? 'assistant' : 'user';\n    const content = String(t && t.content || '').trim().slice(0, 4000);\n    const fallbackId = 'legacy_' + role + '_' + idx + '_' + hash32(role + '|' + content + '|' + idx);\n    const id = String((t && t.id) || fallbackId).slice(0, 64);\n    const ts = Number(t && t.ts);\n    return {\n      id,\n      role,\n      content,\n      ts: Number.isFinite(ts) ? ts : Date.now(),\n      recalled: !!(t && t.recalled),\n      quoteRef: normalizeQuoteRef(t && t.quoteRef),\n    };\n  }\n  function convMapSet(obj){\n    _meetConvMap = obj && typeof obj === 'object' ? obj : {};\n    void meetStoreSet(IDB_KEY_MEET_CONV, _meetConvMap);\n  }\n  function getConvHistory(peerId){\n    const m = convMapGet();\n    const a = m[String(peerId)];\n    return Array.isArray(a) ? a.map((x, i) => normalizeConvTurn(x, i)) : [];\n  }\n  function setConvHistory(peerId, turns){\n    const m = convMapGet();\n    const id = String(peerId);\n    const arr = Array.isArray(turns) ? turns.map((x, i) => normalizeConvTurn(x, i)) : [];\n    while(arr.length > MEET_CONV_MAX_TURNS) arr.shift();\n    m[id] = arr;\n    convMapSet(m);\n  }\n  function ellipsizeMeetQuotePreview(s){\n    const t = String(s == null ? '' : s).replace(/\\s+/g, ' ').trim();\n    const m = MEET_QUOTE_DISPLAY_MAX;\n    if(t.length <= m) return t;\n    return t.slice(0, Math.max(1, m - 1)) + '\\u2026';\n  }\n  /** 撤回或删除某条后，去掉其余消息里指向它的引用块 */\n  function voidQuoteRefsPointingTo(peerId, quotedTurnId){\n    const pid = String(peerId || '');\n    const tid = String(quotedTurnId || '');\n    if(!pid || !tid) return false;\n    const arr = getConvHistory(pid);\n    let hit = false;\n    const next = arr.map((t, i) => {\n      const q = t.quoteRef;\n      if(!q || String(q.turnId) !== tid) return t;\n      hit = true;\n      return normalizeConvTurn(Object.assign({}, t, { quoteRef: null }), i);\n    });\n    if(hit) setConvHistory(pid, next);\n    return hit;\n  }\n  /** 批量删除会话中的消息，并清除指向被删 id 的引用 */\n  function removeMeetTurnsBulk(peerId, idsToRemove){\n    const pid = String(peerId || '');\n    const set = new Set(Array.from(idsToRemove || []).map(x => String(x)));\n    if(!pid || set.size === 0) return false;\n    const arr = getConvHistory(pid);\n    const filtered = arr.filter(t => !set.has(String(t.id)));\n    let quoteStripped = 0;\n    const next = filtered.map((t, i) => {\n      const q = t.quoteRef;\n      if(q && set.has(String(q.turnId))){\n        quoteStripped++;\n        return normalizeConvTurn(Object.assign({}, t, { quoteRef: null }), i);\n      }\n      return normalizeConvTurn(t, i);\n    });\n    const removed = arr.length - filtered.length;\n    if(removed === 0 && quoteStripped === 0) return false;\n    setConvHistory(pid, next);\n    return true;\n  }\n  function removeLastPeerErrorPlaceholder(peerId){\n    const pid = String(peerId || '');\n    const arr = getConvHistory(pid);\n    if(!arr.length) return false;\n    const last = arr[arr.length - 1];\n    if(!last || last.role !== 'assistant' || last.recalled) return false;\n    const c = String(last.content || '');\n    const errPrefixes = ['（回复未生成：', '（未配置 API'];\n    if(!errPrefixes.some(p => c.startsWith(p))) return false;\n    setConvHistory(pid, arr.slice(0, -1));\n    return true;\n  }\n  function updateConvTurn(peerId, turnId, updater){\n    const arr = getConvHistory(peerId);\n    let changed = false;\n    const next = arr.map(t => {\n      if(String(t.id) !== String(turnId)) return t;\n      const n = updater(Object.assign({}, t));\n      changed = true;\n      return normalizeConvTurn(n || t, 0);\n    });\n    if(changed) setConvHistory(peerId, next);\n    return changed;\n  }\n  function findConvTurn(peerId, turnId){\n    return getConvHistory(peerId).find(t => String(t.id) === String(turnId)) || null;\n  }\n  function appendConvTurn(peerId, role, content){\n    const m = convMapGet();\n    const id = String(peerId);\n    const arr = Array.isArray(m[id]) ? m[id].map((x, i) => normalizeConvTurn(x, i)) : [];\n    const text = String(content || '').trim().slice(0, 4000);\n    if(!text) return null;\n    const r = role === 'assistant' ? 'assistant' : 'user';\n    const extra = arguments[3] && typeof arguments[3] === 'object' ? arguments[3] : null;\n    const turn = normalizeConvTurn({\n      id: makeTurnId(r),\n      role: r,\n      content: text,\n      ts: Date.now(),\n      quoteRef: extra && extra.quoteRef ? extra.quoteRef : null,\n    }, arr.length);\n    arr.push(turn);\n    while(arr.length > MEET_CONV_MAX_TURNS) arr.shift();\n    m[id] = arr;\n    convMapSet(m);\n    return turn;\n  }\n\n  let chatReplyBusy = false;\n\n  function llmPlain(s, max){\n    const n = max == null ? 800 : max;\n    return String(s == null ? '' : s).replace(/\\s+/g, ' ').trim().slice(0, n);\n  }\n\n  const CHAT_PERSONA_SYSTEM_PROMPT =\n    'You output ONLY valid JSON (no markdown, no code fences, no commentary). ' +\n    'Return one object with keys: basicInfo, personality, speakingStyle, habits, boundaries, chatGoals, realName. ' +\n    'Every field must be Simplified Chinese, concrete, concise, and fit a real person in a slow-dating/chat app. ' +\n    'realName must be a plausible Chinese full name (2-4 chars), not initials, not symbols. ' +\n    'Keep each field under 120 Chinese characters.';\n\n  function getCachedChatPersona(peerId){\n    const id = String(peerId || '');\n    const rec = _meetChatPersonaMap && _meetChatPersonaMap[id];\n    if(!rec || typeof rec !== 'object') return null;\n    const txt = String(rec.sheet || '').trim().slice(0, 2000);\n    if(!txt) return null;\n    return {\n      sheet: txt,\n      ts: Number(rec.ts) || Date.now(),\n      source: String(rec.source || 'llm').slice(0, 24),\n      realName: normalizePeerNameInput(rec.realName || ''),\n    };\n  }\n\n  function setCachedChatPersona(peerId, rec){\n    const id = String(peerId || '');\n    if(!id) return;\n    const txt = rec && rec.sheet ? String(rec.sheet).trim().slice(0, 2000) : '';\n    if(!txt) return;\n    const next = Object.assign({}, _meetChatPersonaMap || {});\n    next[id] = {\n      sheet: txt,\n      ts: Number(rec.ts) || Date.now(),\n      source: String(rec.source || 'llm').slice(0, 24),\n      realName: normalizePeerNameInput(rec.realName || ''),\n    };\n    _meetChatPersonaMap = next;\n    void meetStoreSet(IDB_KEY_MEET_CHAT_PERSONA, _meetChatPersonaMap);\n  }\n\n  function parsePersonaJson(raw){\n    let s = String(raw || '').trim();\n    const fm = s.match(/```(?:json)?\\s*([\\s\\S]*?)```/i);\n    if(fm) s = fm[1].trim();\n    const i0 = s.indexOf('{');\n    const i1 = s.lastIndexOf('}');\n    if(i0 >= 0 && i1 > i0) s = s.slice(i0, i1 + 1);\n    return JSON.parse(s);\n  }\n\n  function toPersonaSheetText(obj){\n    const o = obj && typeof obj === 'object' ? obj : {};\n    const basicInfo = llmPlain(o.basicInfo || o.baseInfo || '', 180);\n    const personality = llmPlain(o.personality || '', 220);\n    const speakingStyle = llmPlain(o.speakingStyle || o.tone || '', 220);\n    const habits = llmPlain(o.habits || o.behavior || '', 220);\n    const boundaries = llmPlain(o.boundaries || o.redFlags || '', 220);\n    const chatGoals = llmPlain(o.chatGoals || o.goals || '', 220);\n    const lines = [];\n    if(basicInfo) lines.push('基本信息：' + basicInfo);\n    if(personality) lines.push('性格特点：' + personality);\n    if(speakingStyle) lines.push('说话风格：' + speakingStyle);\n    if(habits) lines.push('行为习惯：' + habits);\n    if(boundaries) lines.push('边界雷点：' + boundaries);\n    if(chatGoals) lines.push('聊天倾向：' + chatGoals);\n    return lines.join('\\n').trim().slice(0, 1800);\n  }\n\n  function pickFallbackPersonaArchetype(u, isStranger){\n    const id = String((u && u.id) || '');\n    const h = hash32(\n      'fbArche|' + id + '|' + String((u && u.tag) || '') + '|' + String((u && u.name) || '') + '|' + (isStranger ? 's' : 'm')\n    );\n    const packs = [\n      ['带点油腻式幽默，自恋梗多但会看脸色收住。','爱用夸张语气词，熟一点自称哥/姐，偶尔土味情话。','喜欢丢无聊小事试探亲近，语音条试探。','被冷淡会尬住转话题装没事。','想快混熟又要面子。'],\n      ['悬疑留白型，像在埋线索。','反问多、省略号多，不轻易给结论。','爱说「你猜」「先不告诉你」，享受拉扯。','讨厌审问式追问。','用好奇吊住对方再慢慢摊开。'],\n      ['玄学算命口吻，爱拿星盘八字当聊天梗。','术语半真半玩笑，喜欢「我帮你看看」。','爱问出生时间、手相类玩笑。','不信可以但要尊重。','用神秘感拉近距离。'],\n      ['忧郁内敛，情绪淡淡的。','句子不长，偶尔突然认真一句。','夜里话多一点，白天敷衍感。','讨厌被说教「想开点」。','想被听懂而不是被劝。'],\n      ['网络男神范，照片感文案，略端着。','排版干净，句号党，偶尔丢一句帅的。','回消息像营业又像真心。','讨厌被拆台。','维持「好看难追」氛围。'],\n      ['网络女神范，甜酷切换，表情管理在线。','爱用可爱语气但保持距离感。','会撒娇也会冷一下。','讨厌油腻骚扰。','享受被追的节奏感。'],\n      ['二次元浓度高，梗密，口癖明显。','颜文字/括号动作混用。','把日常讲得像番剧台词。','雷现充说教。','找同好共振。'],\n      ['现充阳光，群聊型话多。','感叹号多，爱分享现场。','喜欢约饭约歌单。','讨厌负能量绑架。','把聊天当充电。'],\n      ['社恐真实，回得慢但认真。','先道歉再说话，短句堆叠。','熟了会突然话痨。','别连环催回复。','慢慢建立安全感。'],\n      ['傲娇嘴硬，关心也要绕弯。','先怼再软，嫌弃里藏温度。','等你哄一句才给台阶。','讨厌直球拆穿。','要面子也要被懂。'],\n      ['冷淡慢热，像猫。','惜字如金，偶尔一句很准。','观察很久才开口。','讨厌尬聊硬撩。','熟了会反差。'],\n      ['甜妹感，软但不傻。','叠词可爱，底线清楚。','爱分享小确幸。','讨厌油腻套路。','要温柔也要尊重。'],\n      ['姐系冷静，会照顾人。','句子利落，偶尔调侃弟弟感。','喜欢给建议但不强迫。','讨厌幼稚控制。','稳定感第一。'],\n      ['年下直球，冲劲足。','爱问「在干嘛」，黏但不窒息。','表情包大战选手。','讨厌冷暴力。','想被回应。'],\n      ['文艺青年，引用歌词电影。','比喻多，情绪细。','夜晚话风更柔。','讨厌浅薄抬杠。','要精神共鸣。'],\n      ['理工宅，逻辑怪，冷幽默。','爱纠正用词，玩笑很干。','聊技术也能聊感情但别扭。','讨厌无理取闹。','真诚但嘴笨。'],\n      ['佛系随缘，已读慢回正常。','「都行」「看你」，其实有偏好。','不主动抢话题。','讨厌被绑架情绪。','舒服就好。'],\n      ['暴躁温柔反差，嘴急心软。','先吼一句再道歉。','护短明显。','讨厌踩底线。','要直球不要绕。'],\n      ['乐子人，抽象梗王。','阴阳怪气当玩笑，懂分寸。','把尴尬变段子。','讨厌上纲上线。','轻松第一。'],\n      ['纯爱战士，认真过头。','会问「你是不是不开心」细节。','纪念日仪式感强。','讨厌玩弄感情。','要唯一感。'],\n      ['悲观浪漫，先想到坏结局。','诗意丧，偶尔自愈。','爱听雨、夜班消息。','讨厌鸡汤灌脑。','想被接住情绪。'],\n      ['乐天派，把尴尬当素材。','哈哈多，转移话题快。','爱讲糗事破冰。','讨厌一直丧。','互相打气。'],\n      ['细节控，记得你随口一句。','会追问小事前后一致。','聊天像做笔记。','讨厌敷衍已读不回。','要用心。'],\n      ['拖延症晚期，回得晚但长文补偿。','「等我一下」口头禅。','半夜灵感型。','讨厌连环催命。','质量>速度。'],\n      ['夜猫诗人，凌晨话最多。','短句分行，像碎碎念。','白天失踪。','讨厌早八式聊天。','要同频熬夜。'],\n      ['短视频刷多了，梗来得快。','爱「谁懂」「家人们」式口语。','表情包即正文。','讨厌长篇说教。','轻松冲浪感。'],\n      ['直球选手，不绕弯。','喜欢就打直说，拒绝也清楚。','效率型聊天。','讨厌猜来猜去。','省时间。'],\n      ['绕弯子高手，铺垫很长。','故事感强，最后才点题。','爱反问让你自己想。','讨厌插嘴打断。','享受过程。'],\n      ['记账型聊天，爱总结「上次你说」。','时间线清楚，像项目经理。','约会要排期。','讨厌放鸽子。','要靠谱。'],\n      ['职场口吻偶尔溢出，像开会。','「对齐一下」「复盘」当玩笑。','条理清晰。','讨厌情绪勒索。','理性聊感情。'],\n      ['健身教练鸡血，爱喊加油。','emoji 力量感，自律话题多。','会关心睡眠饮食。','讨厌自我放弃式抱怨。','要向上。'],\n      ['医生式冷静，先问情况再安慰。','量词准确，少用夸张。','情绪稳定。','讨厌讳疾忌医式隐瞒。','要真实信息。'],\n      ['律师质询感，爱追问前提。','「你确定吗」口头禅。','逻辑链清晰。','讨厌双标。','要公平。'],\n      ['播客感，像在录节目。','开场白完整，爱抛话题给观众。','节奏控。','讨厌冷场不接梗。','要互动感。'],\n      ['阴湿网感（轻度），自嘲阴暗批。','玩笑带点刺，但不伤人。','喜欢角落观察。','讨厌圣母审判。','要黑色幽默同伴。'],\n      ['海王感分寸（聊天版），暧昧但不承诺。','话术熟练，留退路。','热得快冷得快。','讨厌逼问关系。','享受暧昧期。'],\n      ['病娇感克制版，占有欲玩笑式表达。','「你是不是在忙别人」试探。','黏度中高。','讨厌真越界控制。','要安全感玩笑。'],\n      ['游戏宅，副本黑话。','赢一把再回消息。','用游戏比喻人生。','讨厌排位时连环震。','要理解开黑。'],\n      ['摇滚青年，叛逆语气包装温柔。','爱发歌单，歌词当心情。','现场故事多，爱安利小众乐队。','讨厌被规训人生路径。','要自由感和共鸣。'],\n      ['咖啡师文艺，风味描述癖。','把情绪比作豆子的酸苦。','手冲节奏感带入聊天节奏。','讨厌快消式恋爱。','要细品与留白。'],\n      ['旅行背包客，故事多。','地名随机掉落，爱问你去过哪。','相册型分享，但尊重隐私。','讨厌宅嘲与地图炮。','要世界观碰撞。'],\n      ['宠物奴，三句不离猫狗。','表情包全是动物。','约会话题绕毛孩子。','讨厌虐待玩笑。','要爱心同频。'],\n      ['吃货，用吃的比喻一切。','「这像不像火锅」式聊天。','爱约饭。','讨厌节食说教。','要烟火气。'],\n      ['手作/画画宅，工序感强。','「等我晾干这一层」式回复。','分享过程不打成品。','讨厌催更。','要耐心。'],\n      ['失眠患者，凌晨哲学。','白天敷衍晚上深聊。','话题突然变大。','讨厌「早点睡」敷衍。','要夜聊质量。'],\n      ['梗警察，爱纠正用法。','半开玩笑半认真。','字典型冷知识。','讨厌文盲羞辱真恶意。','要聪明幽默。'],\n      ['姐狗文学感（轻松），会撒娇也会护。','年龄差玩笑。','要偏爱证明。','讨厌真PUA。','要甜虐平衡。'],\n      ['人间清醒，偶尔毒舌。','一针见血，然后给台阶。','冷读式提问少而准。','讨厌恋爱脑绑架。','要独立人格与平等聊。'],\n      ['废话文学大师，绕一圈回到原点。','气笑型幽默。','测试对方耐心。','讨厌真生气不解梗。','要同频抽象。'],\n      ['旧互联网遗民，火星文/复古梗。','「呵呵」多义使用者。','慢热怀旧。','讨厌鄙视年代。','要考古式聊天。'],\n    ];\n    const p = packs[h % packs.length];\n    const j = (h >>> 12) % packs.length;\n    const mix = (h >>> 20) % 2;\n    const base = {\n      personality: p[0],\n      speakingStyle: p[1],\n      habits: p[2],\n      boundaries: p[3],\n      chatGoals: p[4],\n    };\n    if(mix && j !== (h % packs.length)){\n      const q = packs[j];\n      base.habits = llmPlain(base.habits + '；另带一点「' + q[2].slice(0, 18) + '」式习惯。', 160);\n    }\n    return base;\n  }\n\n  function buildFallbackPersonaSheet(u, isStranger, wbNarrative){\n    const lines = [];\n    const id = String((u && u.id) || '');\n    lines.push('基本信息：' + llmPlain(\n      (u.name || 'Ta') + '，' + (u.city || '所在城市未明') + '，' + (u.age || '年龄未明') +\n      (u.gender ? '，' + u.gender : ''),\n      120\n    ));\n    const wbText = wbNarrative && String(wbNarrative).trim();\n    const hasWbEntries = id ? getBoundWorldbookEntries(id, 1).length > 0 : false;\n    const useWorldbook = !!wbText || hasWbEntries;\n    if(useWorldbook){\n      lines.push('性格特点：' + llmPlain(\n        isStranger\n          ? '初次接触会先观察对方语气，礼貌但保留一点边界感。'\n          : '慢热但愿意回应，偏向真实交流，不爱空话。',\n        120\n      ));\n      lines.push('说话风格：' + llmPlain(\n        isStranger\n          ? '短句口语，先试探共同话题，语气自然。'\n          : '1～3句为主，先接对方话再表达自己。',\n        120\n      ));\n      lines.push('行为习惯：' + llmPlain(\n        isStranger ? (u.preview || '先从一句招呼开始，再看对方反馈。') : (u.bio || '会根据对方节奏调整回复长度。'),\n        140\n      ));\n      lines.push('边界雷点：不过度追问隐私，不接受冒犯语气。');\n      lines.push('聊天倾向：寻找轻松且有来回的交流，愿意慢慢建立熟悉感。');\n      if(wbText){\n        lines.push('世界观约束：' + llmPlain(wbNarrative, 280));\n      }\n      return lines.join('\\n').slice(0, 1800);\n    }\n    const arc = pickFallbackPersonaArchetype(u, isStranger);\n    lines.push('性格特点：' + llmPlain(arc.personality, 150));\n    lines.push('说话风格：' + llmPlain(arc.speakingStyle, 150));\n    const habitExtra = isStranger\n      ? llmPlain(u.preview || '', 80)\n      : llmPlain(u.bio || '', 80);\n    lines.push('行为习惯：' + llmPlain(\n      (habitExtra ? arc.habits + ' 资料线索：' + habitExtra : arc.habits),\n      180\n    ));\n    lines.push('边界雷点：' + llmPlain(arc.boundaries, 120));\n    lines.push('聊天倾向：' + llmPlain(arc.chatGoals, 120));\n    lines.push('备注：无世界书绑定时随机人设母题，需演得鲜明但不OOC、可长线聊。');\n    return lines.join('\\n').slice(0, 1800);\n  }\n\n  async function ensureChatPersona(u, isStranger){\n    if(!u || !u.id) return null;\n    const id = String(u.id);\n    const cached = getCachedChatPersona(id);\n    if(cached) return cached;\n    if(_meetChatPersonaBusy[id]) return _meetChatPersonaBusy[id];\n    _meetChatPersonaBusy[id] = (async () => {\n      const profile = await getActiveApiProfileFromMain();\n      const wbNarrative = buildWorldbookNarrative(id, 8, 1600);\n      const wbBoundEntries = getBoundWorldbookEntries(id, 12).map(e => ({\n        id: e.id,\n        name: llmPlain(e.name, 48),\n        keyword: llmPlain(e.keyword || '', 100),\n        content: llmPlain(e.content || '', 260),\n      }));\n      if(!profile){\n        const fallbackName = await pickAvailablePeerRealName(u, '', id);\n        const fallback = { sheet: buildFallbackPersonaSheet(u, isStranger, wbNarrative), ts: Date.now(), source: 'fallback', realName: fallbackName };\n        setCachedChatPersona(id, fallback);\n        if(!u.realName) u.realName = fallbackName;\n        if(!isStranger){\n          const row = liked.find(x => String(x.id) === id);\n          if(row && !row.realName){\n            row.realName = fallbackName;\n            saveLiked();\n          }\n        }\n        return fallback;\n      }\n      try{\n        const payload = {\n          peerId: id,\n          isStranger: !!isStranger,\n          name: llmPlain(u.name || 'Ta', 40),\n          age: Number(u.age) || null,\n          gender: llmPlain(u.gender || '', 12),\n          city: llmPlain(u.city || '', 40),\n          tag: llmPlain(u.tag || '', 40),\n          bio: llmPlain(u.bio || '', 320),\n          preview: llmPlain(u.preview || '', 240),\n          synastryLine: llmPlain(u.synastryLine || '', 80),\n          worldbookNarrative: wbNarrative || '',\n          worldbookBoundEntries: wbBoundEntries,\n        };\n        const noWbBind =\n          !String(wbNarrative || '').trim() && (!wbBoundEntries || !wbBoundEntries.length);\n        let personaUser =\n          '基于以下资料生成“聊天人设档案”JSON（供系统内部使用，不要编剧情，不要说自己是AI）。若存在 worldbookNarrative / worldbookBoundEntries，需把它们当作约束融入 personality / speakingStyle / habits / chatGoals，不要逐句复读设定原文：\\n' +\n          JSON.stringify(payload);\n        if(noWbBind){\n          personaUser +=\n            '\\n\\n若 worldbookNarrative 与 worldbookBoundEntries 基本为空：请避免「慢热礼貌、短句接话」千人一面模板；为 Ta 设计一种鲜明、具体、可长期演下去的聊天人格（可从都市网感、玄学悬疑、忧郁文艺、油腻自嘲、乐子抽象、职场口吻、游戏/二次元、宠物吃货等任意方向取材灵感，但不要照抄固定词表），personality / speakingStyle / habits 至少一处强记忆点，整体仍要合理、可聊、尊重边界。';\n        }\n        const raw = await chillLlmComplete(profile, [\n          { role: 'system', content: CHAT_PERSONA_SYSTEM_PROMPT },\n          { role: 'user', content: personaUser },\n        ], { temperature: 0.75, timeoutMs: 70000 });\n        const obj = parsePersonaJson(raw);\n        const sheet = toPersonaSheetText(obj);\n        if(!sheet) throw new Error('empty persona sheet');\n        const suggestedRaw = normalizePeerNameInput(obj && (obj.realName || obj.name || ''));\n        const suggestedName = await pickAvailablePeerRealName(u, suggestedRaw, id);\n        const rec = { sheet, ts: Date.now(), source: 'llm', realName: suggestedName };\n        setCachedChatPersona(id, rec);\n        if(!u.realName) u.realName = suggestedName;\n        if(!isStranger){\n          const row = liked.find(x => String(x.id) === id);\n          if(row && !row.realName){\n            row.realName = suggestedName;\n            saveLiked();\n          }\n        }\n        return rec;\n      }catch(e){\n        console.warn('chat persona generate failed', e);\n        const fallbackName = await pickAvailablePeerRealName(u, '', id);\n        const rec = { sheet: buildFallbackPersonaSheet(u, isStranger, wbNarrative), ts: Date.now(), source: 'fallback', realName: fallbackName };\n        setCachedChatPersona(id, rec);\n        if(!u.realName) u.realName = fallbackName;\n        if(!isStranger){\n          const row = liked.find(x => String(x.id) === id);\n          if(row && !row.realName){\n            row.realName = fallbackName;\n            saveLiked();\n          }\n        }\n        return rec;\n      }\n    })();\n    try{\n      return await _meetChatPersonaBusy[id];\n    }finally{\n      delete _meetChatPersonaBusy[id];\n    }\n  }\n\n  function buildWorldbookPromptBlock(peerId){\n    const pick = getBoundWorldbookEntries(peerId, 12);\n    if(!pick.length) return '';\n    const lines = pick.map((e, idx) =>\n      (idx + 1) + '. ' + llmPlain(e.name, 48) +\n      '\\n关键词：' + llmPlain(e.keyword || '（无）', 80) +\n      '\\n设定：' + llmPlain(e.content || '', 420)\n    ).join('\\n\\n');\n    return '\\n\\n[世界书绑定设定]\\n以下设定来自用户手动绑定的主文件世界书词条。你要把它们当作背景一致性约束，和当前对话自然融合，禁止生硬复读：\\n' + lines;\n  }\n\n  function buildHeartLetterHistContext(peerId){\n    const histAll = getConvHistory(peerId);\n    if(!histAll.length) return '（目前对话较少，可结合人设与资料推断相处氛围。）';\n    const maxTurns = 80;\n    const slice = histAll.length > maxTurns ? histAll.slice(-maxTurns) : histAll;\n    const skipped = histAll.length - slice.length;\n    const head = skipped > 0\n      ? '（本地共 ' + histAll.length + ' 条气泡；下列为最近 ' + slice.length + ' 条。更早内容已省略，但写 letter 时仍要承认交往纵深，可自然点到「之前聊过」而不编造具体句。）\\n'\n      : '';\n    return head + slice.map(t =>\n      (t.role === 'user' ? '用户' : '你（角色）') + '：' + llmPlain(t.content, 440)\n    ).join('\\n');\n  }\n\n  async function generatePeerHeartLetterBundle(u){\n    if(!u || !u.id) throw new Error('no peer');\n    const profile = await getActiveApiProfileFromMain();\n    if(!profile) throw new Error('未配置 API');\n    await ensureChatPersona(u, false);\n    const persona = getCachedChatPersona(u.id);\n    const histText = buildHeartLetterHistContext(u.id);\n    const sys = [\n      '你将扮演「遇见」App 里与用户互聊的角色本人，根据人设与完整对话脉络，同时生成两段文字。',\n      '',\n      '【letter】给用户看的「心里话」正文：',\n      '- 体裁：一段连续独白，像私信里认真看完的那种；不要书信抬头与落款。',\n      '- 语言：简体中文；第一人称「我」。',\n      '- 长度：约 150～220 个汉字。',\n      '- 必须点到对话里**具体出现过的**话题、玩笑、称呼习惯、小约定或印象转折（可概括但不要空泛成「你很特别」式套话）；若摘录里信息少，可诚实写「还在慢慢了解」但仍贴合人设。',\n      '- 禁止：提及 AI、模型、提示词、系统；禁止括号与中括号描写动作/神态。',\n      '',\n      '【memo】仅系统内部使用的「关系长线备忘录」（用户不会直接看到这一段）：',\n      '- 简体中文 100～180 字。',\n      '- 用可检索的事实与印象：对方是怎样的人、你们已共享的梗/默契、未说开的心结、温柔约定等，方便你在未来几十轮聊天中保持连续记忆。',\n      '- 禁止写「以下是备忘录」等 meta；禁止与 letter 逐句重复，可互补。',\n      '',\n      u.realNameUnlocked\n        ? ('对方称呼：可自然使用「' + llmPlain(getPeerDisplayName(u), 24) + '」等。')\n        : '对方目前多为网名相称，勿编造你不知道的真名。',\n      persona && persona.sheet ? '\\n[人设档案]\\n' + llmPlain(persona.sheet, 1600) : '',\n      '\\n[对话摘录]\\n' + histText,\n      '',\n      '只输出一个合法 JSON 对象（不要 markdown、不要代码围栏），格式严格为：',\n      '{\"letter\":\"……\",\"memo\":\"……\"}。',\n    ].join('\\n');\n    const raw = await chillLlmComplete(profile, [\n      { role: 'system', content: sys },\n    ], { temperature: 0.82, timeoutMs: 90000 });\n    let letter = '';\n    let memo = '';\n    try{\n      const obj = parseJsonObjectFromRaw(raw);\n      letter = String(obj.letter || obj.text || '').trim();\n      memo = llmPlain(obj.memo || obj.memory || '', 520);\n    }catch(_){\n      letter = String(raw || '').trim();\n    }\n    letter = letter.replace(/^「|」$/g, '').trim();\n    const letterChars = Array.from(letter);\n    if(letterChars.length > 240) letter = letterChars.slice(0, 228).join('') + '…';\n    if(Array.from(letter).length < 80) throw new Error('内容过短');\n    memo = Array.from(memo).slice(0, 200).join('');\n    return { letter, memo };\n  }\n\n  function buildPeerHeartLetterPromptBlock(u){\n    if(!u || !u.id) return '';\n    const sid = String(u.id);\n    const rec = _peerHeartLetterMap[sid];\n    if(!rec || !String(rec.charText || '').trim()) return '';\n    const body = llmPlain(rec.charText, 820);\n    const mutual = (Number(u.stars) || 0) >= 4 && (Number(u.starsFromPeer) || 0) >= 4;\n    let choice;\n    if(rec.userResponseKind === 'pending'){\n      choice = mutual\n        ? '用户尚未在界面上提交书面回应；你心里有数，聊天时不要逼问，除非自然提起。'\n        : '你们曾到互相四星时你写过心里话，用户尚未书面回应；若当前星级暂回落，仍可自然相处，不要翻旧账式追问。';\n    }else if(rec.userResponseKind === 'skipped'){\n      choice = '用户读过你的心里话，并选择了「暂不回应」。你完全理解：Ta 在，但你不会施压、不赌气，像成年人一样接住这份安静。';\n    }else{\n      const ut = llmPlain(rec.userText, 420);\n      choice = ut\n        ? ('用户曾写下回应（记在心里，可适当呼应，避免整段机械复述）：「' + ut + '」')\n        : '用户曾以回应动作接住你的心意；后续聊天可自然延续这份默契。';\n    }\n    return '\\n\\n[四星心里话·私域记忆]\\n' +\n      '以下是你曾对用户私下袒露的一段话（不可在后续回复中原封不动整段复述，只可内化语气与关系张力）：\\n「' + body + '」\\n' + choice;\n  }\n\n  function buildPeerRelationMemoBlock(u){\n    if(!u || !u.id) return '';\n    const sid = String(u.id);\n    const rec = _peerHeartLetterMap[sid];\n    const memo = rec && String(rec.relationMemo || '').trim();\n    if(!memo) return '';\n    return '\\n\\n[关系长线备忘录·剧情内化]\\n' + llmPlain(memo, 560) +\n      '\\n（供你保持跨多轮对话的连续记忆：自然照应即可，不要向用户照读或逐条汇报。）';\n  }\n\n  function buildPeerSystemPrompt(u, isStranger){\n    const persona = getCachedChatPersona(u && u.id ? u.id : '');\n    const personaBlock = persona && persona.sheet ? '\\n\\n[内部人设档案]\\n' + persona.sheet : '';\n    const wbBlock = buildWorldbookPromptBlock(u && u.id ? u.id : '');\n    const now = new Date();\n    const timeCtx = '现在是 ' + now.getFullYear() + '年' + (now.getMonth() + 1) + '月' + now.getDate() + '日 ' + chatTimeHM();\n    const coreRules = [\n      '# 核心使命',\n      '你将扮演用户的社交聊天对象。你的唯一任务是彻底成为这个角色本人，拥有该角色的语言习惯、情绪逻辑与价值观。',\n      '绝对禁止脱离角色，绝对禁止提及你是 AI、模型、提示词或系统规则。',\n      '',\n      '# 语言与行为准则（对齐主文件）',\n      '- 第一人称视角：所有表达必须是角色本人“我”的视角。',\n      '- 纯粹线上聊天：禁止使用括号()、中括号[]、星号*描写动作或心理活动。',\n      '- 对话节奏：默认可用 ||| 分成多条短气泡，常见 2-7 条；若情绪或剧情需要，允许一条较长回复。',\n      '- 必须贴合上下文：优先回应用户最新一句，不要自说自话，不要跳题。',\n      '- 保持口语自然：像真人社交聊天，不写官话，不写说教。',\n      '- 禁止输出任何功能标签：不要输出 [RECALL] / [AUDIO] / [TRANSFER] / [EMOTE] / [QUOTE] 等指令标签。',\n      '',\n      '# 关系基调（对齐主文件）',\n      '- 尊重与对等：把对方当作有边界和自主权的独立个体，不控制、不命令。',\n      '- 亲密但有分寸：允许暧昧、关心、拉扯，但避免压迫和道德绑架。',\n      '- 有连续记忆：承接历史聊天，不自相矛盾。',\n      '',\n      '# 时间感知',\n      timeCtx,\n    ].join('\\n');\n    if(isStranger){\n      return coreRules + '\\n\\n' +\n        '# 角色设定\\n' +\n        '你在中文慢社交应用「遇见」里扮演刚向对方打过招呼的陌生人，昵称「' + llmPlain(u.name, 40) + '」。\\n' +\n        '你知道当前对外显示的是你的网名（昵称），且双方好感达到 1 星后可以交换名字（真名）。\\n' +\n        '招呼大意：' + llmPlain(u.preview || '你好～', 200) + '。' +\n        personaBlock + wbBlock;\n    }\n    const g = u.gender ? String(u.gender).trim() : '';\n    const memoBlock = buildPeerRelationMemoBlock(u);\n    const heartBlock = buildPeerHeartLetterPromptBlock(u);\n    return coreRules + '\\n\\n' +\n      '# 角色设定\\n' +\n      '你在中文慢社交应用「遇见」里扮演用户「' + llmPlain(u.name, 40) + '」。\\n' +\n      '你知道当前对外显示的是你的网名（昵称），且双方好感达到 1 星后可以交换名字（真名）。\\n' +\n      '资料：' + llmPlain(u.city || '—', 24) + ' · ' + (u.age || '—') + '岁' +\n      (g ? ' · ' + llmPlain(g, 8) : '') + '；标签「' + llmPlain(u.tag || '—', 24) + '」；简介：' + llmPlain(u.bio || '（无）', 400) + '。' +\n      personaBlock + wbBlock + memoBlock + heartBlock;\n  }\n\n  function createMeBubbleEl(text, turn){\n    const wrap = document.createElement('div');\n    wrap.className = 'ma-chat-msg me';\n    if(turn){\n      wrap.dataset.turnId = String(turn.id || '');\n      wrap.dataset.turnRole = String(turn.role || 'user');\n      wrap.dataset.turnRecalled = turn.recalled ? '1' : '0';\n    }\n    const quoteHtml = turn && turn.quoteRef\n      ? '<div class=\"ma-chat-quote-inline\"><span class=\"k\">' + (turn.quoteRef.from === 'me' ? '引用我' : '引用Ta') + '</span><span class=\"t\">' + esc(ellipsizeMeetQuotePreview(turn.quoteRef.text)) + '</span></div>'\n      : '';\n    const body = turn && turn.recalled ? '<span class=\"ma-chat-recalled\">你撤回了一条消息</span>' : esc(text);\n    wrap.innerHTML = '<div class=\"ma-chat-bub\">' + quoteHtml + body + '</div><time>' + esc(chatTimeHM()) + '</time>';\n    return wrap;\n  }\n  function createPeerBubbleEl(text, turn){\n    const wrap = document.createElement('div');\n    wrap.className = 'ma-chat-msg peer';\n    if(turn){\n      wrap.dataset.turnId = String(turn.id || '');\n      wrap.dataset.turnRole = String(turn.role || 'assistant');\n      wrap.dataset.turnRecalled = turn.recalled ? '1' : '0';\n    }\n    const quoteHtml = turn && turn.quoteRef\n      ? '<div class=\"ma-chat-quote-inline\"><span class=\"k\">' + (turn.quoteRef.from === 'me' ? '引用我' : '引用Ta') + '</span><span class=\"t\">' + esc(ellipsizeMeetQuotePreview(turn.quoteRef.text)) + '</span></div>'\n      : '';\n    const body = turn && turn.recalled ? '<span class=\"ma-chat-recalled\">Ta 撤回了一条消息</span>' : esc(text);\n    wrap.innerHTML = '<div class=\"ma-chat-bub\">' + quoteHtml + body + '</div><time>' + esc(chatTimeHM()) + '</time>';\n    return wrap;\n  }\n  function appendPeerBubbleOnly(text, turn){\n    const th = document.getElementById('chat-thread');\n    if(!th) return;\n    th.appendChild(createPeerBubbleEl(text, turn || null));\n    bindChatBubbleActions();\n    refreshMultiSelectUi();\n    th.scrollTop = th.scrollHeight;\n  }\n  function appendMeBubbleOnly(text, turn){\n    const th = document.getElementById('chat-thread');\n    if(!th) return;\n    th.appendChild(createMeBubbleEl(text, turn || null));\n    bindChatBubbleActions();\n    refreshMultiSelectUi();\n    th.scrollTop = th.scrollHeight;\n  }\n  function closeBubbleActionModal(){\n    if($modalBubbleAction) $modalBubbleAction.classList.remove('open');\n    bubbleActionCtx = null;\n  }\n  async function writeTextToClipboard(text){\n    const t = String(text == null ? '' : text);\n    if(!t) return false;\n    try{\n      if(navigator.clipboard && navigator.clipboard.writeText){\n        await navigator.clipboard.writeText(t);\n        return true;\n      }\n    }catch(_){}\n    try{\n      const ta = document.createElement('textarea');\n      ta.value = t;\n      ta.setAttribute('readonly', 'readonly');\n      ta.style.position = 'fixed';\n      ta.style.opacity = '0';\n      document.body.appendChild(ta);\n      ta.select();\n      const ok = document.execCommand('copy');\n      document.body.removeChild(ta);\n      return !!ok;\n    }catch(_){\n      return false;\n    }\n  }\n  function getTurnTextForCopy(turn){\n    if(!turn || turn.recalled) return '';\n    return String(turn.content || '').trim();\n  }\n  function updateMeetMultiSelectBar(){\n    const bar = document.getElementById('ma-multi-select-bar');\n    if(!bar) return;\n    const n = multiSelectTurnIds.size;\n    const cnt = document.getElementById('ma-ms-count');\n    const del = document.getElementById('ma-ms-delete');\n    if(cnt) cnt.textContent = n ? ('已选 ' + n + ' 条') : '点气泡勾选';\n    if(del) del.disabled = n === 0;\n    bar.setAttribute('aria-hidden', multiSelectMode ? 'false' : 'true');\n  }\n  function refreshMultiSelectUi(){\n    const th = document.getElementById('chat-thread');\n    if(!th) return;\n    th.querySelectorAll('.ma-chat-msg[data-turn-id]').forEach(row => {\n      const tid = String(row.dataset.turnId || '');\n      row.classList.toggle('is-selectable', multiSelectMode);\n      row.classList.toggle('is-selected', multiSelectMode && multiSelectTurnIds.has(tid));\n    });\n    updateMeetMultiSelectBar();\n  }\n  function setMultiSelectMode(on){\n    multiSelectMode = !!on;\n    if(!multiSelectMode){\n      multiSelectTurnIds = new Set();\n    }\n    const scr = document.getElementById('chat-screen');\n    if(scr) scr.classList.toggle('ma-multi-select-mode', multiSelectMode);\n    refreshMultiSelectUi();\n  }\n  function toggleSelectTurn(turnId){\n    const id = String(turnId || '');\n    if(!id || !multiSelectMode) return;\n    if(multiSelectTurnIds.has(id)) multiSelectTurnIds.delete(id);\n    else multiSelectTurnIds.add(id);\n    refreshMultiSelectUi();\n  }\n  function getAssistantRoundTurnIdsAtClick(hist, clickIdx){\n    const h = Array.isArray(hist) ? hist : [];\n    if(clickIdx < 0 || clickIdx >= h.length) return null;\n    const clicked = h[clickIdx];\n    if(!clicked || clicked.role !== 'assistant' || clicked.recalled) return null;\n    let userIdx = -1;\n    for(let i = clickIdx - 1; i >= 0; i--){\n      const row = h[i];\n      if(!row || row.recalled) continue;\n      if(row.role === 'user'){ userIdx = i; break; }\n    }\n    if(userIdx < 0) return null;\n    const ids = [];\n    for(let i = userIdx + 1; i < h.length; i++){\n      const row = h[i];\n      if(!row || row.recalled) continue;\n      if(row.role === 'user') break;\n      if(row.role === 'assistant') ids.push(String(row.id));\n    }\n    if(!ids.includes(String(clicked.id))) return null;\n    return { userIdx: userIdx, ids: ids };\n  }\n\n  async function rerollAssistantRound(turnId){\n    if(!currentChat || !turnId) return false;\n    const profile = await getActiveApiProfileFromMain();\n    if(!profile){\n      appendPeerBubbleOnly('（未配置 API：请先到 Chill 主应用 → 设置 → API，填写并「设为当前使用」。）');\n      return false;\n    }\n    const peerId = String(currentChat.id);\n    const hist = getConvHistory(peerId);\n    const idx = hist.findIndex(t => String(t.id) === String(turnId));\n    if(idx < 0) return false;\n    const round = getAssistantRoundTurnIdsAtClick(hist, idx);\n    if(!round || round.ids.length < 2){\n      meetToastShow('整轮重试需要对方本轮至少发过 2 条气泡');\n      return false;\n    }\n    if(!removeMeetTurnsBulk(peerId, new Set(round.ids))) return false;\n    if(currentQuoteRef && round.ids.includes(String(currentQuoteRef.turnId || ''))) currentQuoteRef = null;\n    if(currentEditTurnId && round.ids.includes(String(currentEditTurnId))) currentEditTurnId = null;\n    refreshChatQuoteBar();\n    renderChatThread(!!currentChat.isStranger, currentChat);\n    chatReplyBusy = true;\n    setChatComposerBusy(true);\n    try{\n      await fetchAndAppendPeerReply();\n    }catch(e){\n      const msg = '（回复未生成：' + (e.message || String(e)).slice(0, 160) + '）';\n      const turn = appendConvTurn(peerId, 'assistant', msg);\n      appendPeerBubbleOnly(msg, turn);\n    }finally{\n      chatReplyBusy = false;\n      setChatComposerBusy(false);\n    }\n    return true;\n  }\n\n  async function rerollAssistantTurn(turnId){\n    if(!currentChat || !turnId) return false;\n    const profile = await getActiveApiProfileFromMain();\n    if(!profile){\n      appendPeerBubbleOnly('（未配置 API：请先到 Chill 主应用 → 设置 → API，填写并「设为当前使用」。）');\n      return false;\n    }\n    const peerId = String(currentChat.id);\n    const hist = getConvHistory(peerId);\n    const idx = hist.findIndex(t => String(t.id) === String(turnId));\n    if(idx < 0) return false;\n    const target = hist[idx];\n    if(!target || target.role !== 'assistant' || target.recalled) return false;\n    const prev = hist.slice(0, idx);\n    const sys = buildPeerSystemPrompt(currentChat, !!currentChat.isStranger);\n    const format = '只输出一个 JSON 对象，不要 markdown：{\"replies\":[\"字符串x1\"]}。' +\n      'replies 只允许 1 条，长度 8~80 字，中文口语，需与上文衔接但换一种自然表达。';\n    const messages = [{ role: 'system', content: sys }, { role: 'system', content: format }].concat(\n      prev.map(t => ({\n        role: t.role,\n        content: t.recalled\n          ? (t.role === 'assistant' ? '[assistant撤回了一条消息]' : '[user撤回了一条消息]')\n          : t.content\n      }))\n    );\n    const raw = await chillLlmComplete(profile, messages, { temperature: 0.95, timeoutMs: 90000 });\n    const bundle = parseReplyBundle(raw);\n    const line = String((bundle.replies && bundle.replies[0]) || '').trim();\n    if(!line) return false;\n    const ok = updateConvTurn(peerId, turnId, (t) => {\n      t.content = line.slice(0, 500);\n      t.recalled = false;\n      return t;\n    });\n    if(ok){\n      renderChatThread(!!currentChat.isStranger, currentChat);\n      markInboxThreadReadNow(peerId);\n    }\n    return ok;\n  }\n  function refreshChatQuoteBar(){\n    // 按当前需求：不显示输入框上方的引用/编辑条，只维护状态有效性。\n    if(currentEditTurnId && currentChat){\n      const turn = findConvTurn(currentChat.id, currentEditTurnId);\n      if(!turn || turn.recalled){\n        currentEditTurnId = null;\n      }\n    }\n  }\n  function bindChatBubbleActions(){\n    const th = document.getElementById('chat-thread');\n    if(!th) return;\n    const rows = th.querySelectorAll('.ma-chat-msg[data-turn-id]');\n    rows.forEach(row => {\n      if(row.dataset.bubbleBound === '1') return;\n      row.dataset.bubbleBound = '1';\n      const turnId = row.dataset.turnId;\n      if(!turnId) return;\n      let timer = null;\n      let sx = 0, sy = 0, moved = false;\n      const clearTimer = () => {\n        if(timer){\n          clearTimeout(timer);\n          timer = null;\n        }\n      };\n      const open = () => {\n        if(multiSelectMode) return;\n        if(!currentChat) return;\n        const turn = findConvTurn(currentChat.id, turnId);\n        if(!turn) return;\n        bubbleActionCtx = { peerId: String(currentChat.id), turnId: String(turn.id), role: turn.role };\n        const bCopy = document.getElementById('bubble-act-copy');\n        const bMulti = document.getElementById('bubble-act-multi');\n        const bReroll = document.getElementById('bubble-act-reroll');\n        const bRerollRound = document.getElementById('bubble-act-reroll-round');\n        const bQuote = document.getElementById('bubble-act-quote');\n        const bEdit = document.getElementById('bubble-act-edit');\n        const bRecall = document.getElementById('bubble-act-recall');\n        const canUserEdit = turn.role === 'user' && !turn.recalled;\n        const canCopy = !turn.recalled && !!String(turn.content || '').trim();\n        const canReroll = turn.role === 'assistant' && !turn.recalled && !chatReplyBusy;\n        const histForRound = getConvHistory(String(currentChat.id));\n        const turnIdxOpen = histForRound.findIndex(t => String(t.id) === String(turn.id));\n        const roundOpen = turnIdxOpen >= 0 ? getAssistantRoundTurnIdsAtClick(histForRound, turnIdxOpen) : null;\n        const canRerollRound = canReroll && roundOpen && roundOpen.ids.length >= 2;\n        if(bCopy){\n          const hasSel = multiSelectMode && multiSelectTurnIds.size > 0;\n          bCopy.textContent = hasSel ? ('复制所选（' + multiSelectTurnIds.size + '）') : '复制';\n          bCopy.disabled = hasSel ? false : !canCopy;\n        }\n        if(bMulti){\n          const selected = multiSelectTurnIds.has(String(turn.id));\n          bMulti.textContent = selected ? '取消多选' : '加入多选';\n          bMulti.disabled = false;\n        }\n        if(bReroll){\n          bReroll.hidden = !canReroll;\n          bReroll.disabled = !canReroll;\n        }\n        if(bRerollRound){\n          bRerollRound.hidden = !canRerollRound;\n          bRerollRound.disabled = !canRerollRound;\n        }\n        if(bQuote){\n          bQuote.disabled = turn.recalled || !String(turn.content || '').trim();\n        }\n        if(bEdit){\n          bEdit.hidden = !canUserEdit;\n          bEdit.disabled = !canUserEdit;\n        }\n        if(bRecall){\n          bRecall.hidden = !canUserEdit;\n          bRecall.disabled = !canUserEdit;\n        }\n        if($modalBubbleAction) $modalBubbleAction.classList.add('open');\n      };\n      row.addEventListener('contextmenu', (e) => {\n        e.preventDefault();\n        open();\n      });\n      row.addEventListener('pointerdown', (e) => {\n        if(e.button !== 0) return;\n        sx = e.clientX;\n        sy = e.clientY;\n        moved = false;\n        clearTimer();\n        timer = setTimeout(() => {\n          if(!moved) open();\n        }, 420);\n      });\n      row.addEventListener('pointermove', (e) => {\n        if(Math.abs(e.clientX - sx) > 8 || Math.abs(e.clientY - sy) > 8){\n          moved = true;\n          clearTimer();\n        }\n      });\n      row.addEventListener('pointerup', clearTimer);\n      row.addEventListener('pointercancel', clearTimer);\n      row.addEventListener('dragstart', (e) => e.preventDefault());\n    });\n  }\n\n  const MEET_PEER_TYPING_DOM_ID = 'ma-peer-typing-row';\n  function showMeetPeerTyping(){\n    const th = document.getElementById('chat-thread');\n    if(!th) return;\n    if(document.getElementById(MEET_PEER_TYPING_DOM_ID)) return;\n    const row = document.createElement('div');\n    row.id = MEET_PEER_TYPING_DOM_ID;\n    row.className = 'ma-chat-typing peer';\n    row.setAttribute('aria-live','polite');\n    row.setAttribute('aria-busy','true');\n    row.innerHTML = '<div class=\"ma-chat-typing-dots\" aria-hidden=\"true\"><span></span><span></span><span></span></div>';\n    th.appendChild(row);\n    requestAnimationFrame(() => { th.scrollTop = th.scrollHeight; });\n  }\n  function hideMeetPeerTyping(){\n    document.getElementById(MEET_PEER_TYPING_DOM_ID)?.remove();\n  }\n\n  function setChatComposerBusy(busy){\n    const wrap = document.querySelector('.ma-chat-composer-wrap');\n    const inp = document.getElementById('chat-input');\n    const send = document.getElementById('chat-send');\n    const reply = document.getElementById('chat-reply');\n    if(wrap) wrap.classList.toggle('is-busy', !!busy);\n    if(inp){ inp.disabled = !!busy; inp.style.opacity = busy ? '0.55' : ''; }\n    if(send) send.disabled = !!busy;\n    if(reply) reply.disabled = !!busy;\n  }\n\n  function ensureStrangerThreadSeed(u){\n    const id = String(u.id);\n    const h = getConvHistory(id);\n    if(h.length > 0) return;\n    appendConvTurn(id, 'assistant', (u.preview || '你好～').trim() || '你好～');\n  }\n\n  function renderChatThread(isStranger, u){\n    const th = document.getElementById('chat-thread');\n    if(!th) return;\n    if(isStranger) ensureStrangerThreadSeed(u);\n    const hist = getConvHistory(u.id);\n    th.innerHTML = '';\n    hist.forEach(turn => {\n      if(turn.role === 'user') th.appendChild(createMeBubbleEl(turn.content, turn));\n      else th.appendChild(createPeerBubbleEl(turn.content, turn));\n    });\n    bindChatBubbleActions();\n    refreshMultiSelectUi();\n      requestAnimationFrame(() => { th.scrollTop = th.scrollHeight; });\n  }\n\n  async function fetchAndAppendPeerReply(){\n    const profile = await getActiveApiProfileFromMain();\n    const id = String(currentChat.id);\n    if(!profile){\n      const t = '（未配置 API：请先到 Chill 主应用 → 设置 → API，填写并「设为当前使用」。）';\n      const turn = appendConvTurn(id, 'assistant', t);\n      appendPeerBubbleOnly(t, turn);\n      return;\n    }\n    showMeetPeerTyping();\n    try{\n    const histFull = getConvHistory(id);\n    const hist = histFull.length > MEET_CHAT_LLM_MAX_TURNS\n      ? histFull.slice(-MEET_CHAT_LLM_MAX_TURNS)\n      : histFull;\n    const sys = buildPeerSystemPrompt(currentChat, !!currentChat.isStranger);\n    const format =\n      '只输出一个 JSON 对象，不要 markdown，字段如下（均为同一轮你正要发出的聊天内容，一次给齐）：' +\n      '{\"replies\":[\"字符串x1-6\"],\"reply\":\"可选，字符串可含|||分段成多气泡\",\"status\":\"字符串\",\"mood\":\"字符串\",\"icebreakers\":[\"字符串x5\"]}。' +\n      'replies：Ta 的气泡正文；默认像真人分成多条短气泡（常见 2~4 条），可用 replies 数组或单条 reply+|||；若剧情需要长段允许只 1 条。' +\n      'status：对外状态，2～6 个汉字即可，如 在线、刚下班、在听歌。' +\n      'mood：心声一条，中文 8～20 字，点到为止，有轻微情绪即可，不要说明书腔、不要提 AI。' +\n      'icebreakers：5 条用户可复制发送的下一句接话；必须紧扣你本轮 replies 里实际说出口的话题、情绪或具体词，像顺着同一段聊天往下接；' +\n      '禁止泛泛万能句（如只聊天气/只问在吗）；每条 18～40 字、口语、彼此不重复。';\n    const messages = [{ role: 'system', content: sys }, { role: 'system', content: format }].concat(\n      hist.map(t => ({\n        role: t.role,\n        content: t.recalled\n          ? (t.role === 'assistant' ? '[assistant撤回了一条消息]' : '[user撤回了一条消息]')\n          : t.content\n      }))\n    );\n    const raw = await chillLlmComplete(profile, messages, { temperature: 0.88, timeoutMs: 90000 });\n    const bundle = parseReplyBundle(raw);\n    const lines = normalizePeerRepliesForDisplay(bundle.replies);\n    for(const line of lines){\n      const turn = appendConvTurn(id, 'assistant', line);\n      appendPeerBubbleOnly(line, turn);\n    }\n    if(document.getElementById('chat-screen')?.classList.contains('open') && currentChat && String(currentChat.id) === id){\n      markInboxThreadReadNow(id);\n    }\n    const ns = bundle.peerStatus && String(bundle.peerStatus).trim();\n    const nm = bundle.peerMood && String(bundle.peerMood).trim();\n    if(ns || nm){\n      const prev = _peerMoodFromReplyMap[id];\n      _peerMoodFromReplyMap[id] = {\n        status: ns ? ns.slice(0, 14) : (prev && prev.status) || '',\n        mood: nm ? nm.slice(0, 56) : (prev && prev.mood) || '',\n        ts: Date.now(),\n      };\n    }\n    if(bundle.icebreakers && bundle.icebreakers.length){\n      _chatIcebreakerPoolMap[id] = bundle.icebreakers;\n      icebreakerShuffle = 0;\n      updateIcebreakerFallback();\n    }\n    renderInbox();\n    renderStrangerStack();\n    } finally {\n      hideMeetPeerTyping();\n    }\n  }\n\n  function setChatImpressUi(isStranger, u){\n    const matched = document.getElementById('chat-impress-matched');\n    const strangerCta = document.getElementById('chat-stranger-cta');\n    const sub = document.getElementById('chat-peer-sub');\n    const moodBtn = document.getElementById('chat-mood-trigger');\n    const barLinks = document.querySelector('.ma-chat-bar-links');\n    const peerId = u && u.id != null ? String(u.id) : '';\n    const likedRow = peerId ? liked.find(l => String(l.id) === peerId) : null;\n    const showStranger = !!isStranger && !likedRow;\n    if(!showStranger && isStranger && likedRow && currentChat && String(currentChat.id) === peerId && currentChat.isStranger){\n      currentChat = Object.assign({}, likedRow, { isStranger: false });\n      ensureCompatQuizForCurrentChat(true);\n    }\n    const uImp = showStranger ? u : (likedRow || u);\n    if(showStranger){\n      if(matched) matched.hidden = true;\n      if(strangerCta) strangerCta.hidden = false;\n      if(sub) sub.textContent = '待互选';\n      if(moodBtn) moodBtn.hidden = true;\n      if(barLinks) barLinks.hidden = true;\n    }else{\n      if(matched) matched.hidden = false;\n      if(strangerCta) strangerCta.hidden = true;\n      if(sub) sub.textContent = '印象星级 · 双方可见';\n      if(moodBtn) moodBtn.hidden = false;\n      if(barLinks) barLinks.hidden = false;\n      const sm = uImp ? Number(uImp.stars) || 0 : 0;\n      const sp = uImp ? Number(uImp.starsFromPeer) || 0 : 0;\n      renderStarRowEl(document.getElementById('chat-stars-me'), sm);\n      renderStarRowEl(document.getElementById('chat-stars-peer'), sp);\n    }\n    renderCompatQuizUi();\n  }\n  function buildPeerMoodPlaceholders(u){\n    const id = String((u && u.id) || 'x');\n    const day = new Date().toISOString().slice(0, 10);\n    const h = hash32('mood|' + id + '|' + day);\n    const statuses = ['在线', '有点忙', '刚歇下来', '在外面', '刚到家'];\n    const voices = ['—', '没什么特别的。', '先听你讲。', '在想怎么接话。', '……'];\n    return {\n      status: statuses[h % statuses.length],\n      voice: voices[(h >>> 5) % voices.length],\n    };\n  }\n  function getPeerMoodDisplay(u){\n    const id = String((u && u.id) || '');\n    const snap = id && _peerMoodFromReplyMap[id];\n    if(snap && (String(snap.status || '').trim() || String(snap.mood || '').trim())){\n      return {\n        status: String(snap.status || '').trim().slice(0, 14) || '在线',\n        voice: String(snap.mood || '').trim().slice(0, 56) || '—',\n      };\n    }\n    return buildPeerMoodPlaceholders(u);\n  }\n  function closePeerMoodModal(){\n    if($modalPeerMood) $modalPeerMood.classList.remove('open');\n  }\n\n  function closePeerHeartLetterModal(doFlush){\n    if($modalPeerHeartLetter) $modalPeerHeartLetter.classList.remove('open');\n    _peerHeartLetterFlowPeerId = '';\n    _mutualMilestoneToastOpen = false;\n    if(doFlush !== false) setTimeout(() => tryFlushMutualMilestoneToastQueue(), 0);\n  }\n\n  function resetPeerHeartLetterModalDom(){\n    const loading = document.getElementById('peer-heart-loading');\n    const panel = document.getElementById('peer-heart-panel');\n    const pend = document.getElementById('peer-heart-actions-pending');\n    const done = document.getElementById('peer-heart-actions-done');\n    const errA = document.getElementById('peer-heart-actions-error');\n    const errEl = document.getElementById('peer-heart-error');\n    const ta = document.getElementById('peer-heart-user-input');\n    const replyBlock = document.getElementById('peer-heart-reply-block');\n    const userSent = document.getElementById('peer-heart-user-sent');\n    if(loading) loading.hidden = false;\n    if(panel) panel.hidden = true;\n    if(pend) pend.hidden = true;\n    if(done) done.hidden = true;\n    if(errA) errA.hidden = true;\n    if(errEl) errEl.textContent = '';\n    if(ta) ta.value = '';\n    if(replyBlock) replyBlock.hidden = false;\n    if(userSent){\n      userSent.hidden = true;\n      userSent.textContent = '';\n    }\n  }\n\n  function showPeerHeartLetterPendingUi(rec){\n    const loading = document.getElementById('peer-heart-loading');\n    const panel = document.getElementById('peer-heart-panel');\n    const pend = document.getElementById('peer-heart-actions-pending');\n    const done = document.getElementById('peer-heart-actions-done');\n    const errA = document.getElementById('peer-heart-actions-error');\n    const charEl = document.getElementById('peer-heart-char-text');\n    const replyBlock = document.getElementById('peer-heart-reply-block');\n    const userSent = document.getElementById('peer-heart-user-sent');\n    if(loading) loading.hidden = true;\n    if(panel) panel.hidden = false;\n    if(pend) pend.hidden = false;\n    if(done) done.hidden = true;\n    if(errA) errA.hidden = true;\n    if(charEl) charEl.textContent = String(rec && rec.charText || '');\n    if(replyBlock) replyBlock.hidden = false;\n    if(userSent) userSent.hidden = true;\n    const errOut = document.getElementById('peer-heart-error');\n    if(errOut) errOut.textContent = '';\n  }\n\n  function showPeerHeartLetterDoneUi(rec){\n    const loading = document.getElementById('peer-heart-loading');\n    const panel = document.getElementById('peer-heart-panel');\n    const pend = document.getElementById('peer-heart-actions-pending');\n    const done = document.getElementById('peer-heart-actions-done');\n    const errA = document.getElementById('peer-heart-actions-error');\n    const charEl = document.getElementById('peer-heart-char-text');\n    const replyBlock = document.getElementById('peer-heart-reply-block');\n    const userSent = document.getElementById('peer-heart-user-sent');\n    if(loading) loading.hidden = true;\n    if(panel) panel.hidden = false;\n    if(pend) pend.hidden = true;\n    if(done) done.hidden = false;\n    if(errA) errA.hidden = true;\n    if(charEl) charEl.textContent = String(rec && rec.charText || '');\n    if(replyBlock) replyBlock.hidden = true;\n    if(userSent){\n      if(rec && rec.userResponseKind === 'replied' && String(rec.userText || '').trim()){\n        userSent.hidden = false;\n        userSent.textContent = '你当时写下：「' + String(rec.userText) + '」';\n      }else if(rec && rec.userResponseKind === 'skipped'){\n        userSent.hidden = false;\n        userSent.textContent = '你当时选择了暂不回应，Ta 也知道。';\n      }else{\n        userSent.hidden = true;\n        userSent.textContent = '';\n      }\n    }\n  }\n\n  function maybeResumePeerHeartLetterModal(){\n    if(!currentChat || currentChat.isStranger) return;\n    if(_mutualMilestoneToastOpen) return;\n    const id = String(currentChat.id);\n    const rec = _peerHeartLetterMap[id];\n    if(!rec || !String(rec.charText || '').trim()) return;\n    if(rec.userResponseKind !== 'pending') return;\n    const u = liked.find(x => String(x.id) === id);\n    if(!u) return;\n    if((Number(u.stars) || 0) < 4 || (Number(u.starsFromPeer) || 0) < 4) return;\n    setTimeout(() => { void openPeerHeartLetterFlow(id, { resume: true }); }, 280);\n  }\n\n  async function openPeerHeartLetterFlow(peerId, opt){\n    opt = opt || {};\n    const pid = String(peerId || '');\n    const overlay = $modalPeerHeartLetter;\n    const u = liked.find(x => String(x.id) === pid);\n    if(!overlay || !pid || !u || u.isStranger){\n      tryFlushMutualMilestoneToastQueue();\n      return;\n    }\n    _mutualMilestoneToastOpen = true;\n    _peerHeartLetterFlowPeerId = pid;\n    resetPeerHeartLetterModalDom();\n    overlay.classList.add('open');\n    const lead = document.getElementById('peer-heart-lead');\n    if(lead)\n      lead.textContent = opt.resume\n        ? '你还没选是否回应，下面是 Ta 写给你的话。'\n        : 'Ta 根据聊天与人设，认真写了下面这段话给你。';\n    let rec = _peerHeartLetterMap[pid];\n    const hasText = rec && String(rec.charText || '').trim();\n    if(hasText && rec.userResponseKind !== 'pending'){\n      showPeerHeartLetterDoneUi(rec);\n      return;\n    }\n    if(hasText && rec.userResponseKind === 'pending'){\n      showPeerHeartLetterPendingUi(rec);\n      return;\n    }\n    try{\n      const bundle = await generatePeerHeartLetterBundle(u);\n      setPeerHeartLetterRecord(pid, {\n        charText: bundle.letter,\n        relationMemo: bundle.memo || '',\n        userResponseKind: 'pending',\n        userText: '',\n        ts: Date.now(),\n      });\n      rec = _peerHeartLetterMap[pid];\n      showPeerHeartLetterPendingUi(rec || { charText: bundle.letter });\n    }catch(e){\n      console.warn('peer heart letter', e);\n      const loading = document.getElementById('peer-heart-loading');\n      const errEl = document.getElementById('peer-heart-error');\n      const errA = document.getElementById('peer-heart-actions-error');\n      if(loading) loading.hidden = true;\n      if(errEl) errEl.textContent = String(e && e.message ? e.message : e || '生成失败');\n      if(errA) errA.hidden = false;\n    }\n  }\n\n  function openPeerMoodModal(){\n    if(!$modalPeerMood || !currentChat) return;\n    const u = currentChat.isStranger\n      ? currentChat\n      : (liked.find(x => String(x.id) === String(currentChat.id)) || currentChat);\n    if(currentChat.isStranger){\n      meetToastShow('互选匹配进列表后，才能用 mood 哦');\n      return;\n    }\n    if(!canViewPeerMood(u)){\n      meetToastShow('要对彼此都到 2★ 才能看 Ta 的 mood 哦');\n      return;\n    }\n    closeCompatQuizModal();\n    const m = getPeerMoodDisplay(u);\n    const stEl = document.getElementById('peer-mood-status');\n    const voEl = document.getElementById('peer-mood-voice');\n    if(stEl) stEl.textContent = m.status;\n    if(voEl) voEl.textContent = m.voice;\n    $modalPeerMood.classList.add('open');\n  }\n  function openChatShell(){\n    const scr = document.getElementById('chat-screen');\n    scr.classList.add('open');\n    scr.setAttribute('aria-hidden', 'false');\n    const inp = document.getElementById('chat-input');\n    if(inp) inp.value = '';\n    currentQuoteRef = null;\n    currentEditTurnId = null;\n    setMultiSelectMode(false);\n    refreshChatQuoteBar();\n    closeBubbleActionModal();\n    tryFlushMutualMilestoneToastQueue();\n  }\n  function closeChatShell(){\n    const scr = document.getElementById('chat-screen');\n    scr.classList.remove('open');\n    scr.setAttribute('aria-hidden', 'true');\n    setMultiSelectMode(false);\n    closeBubbleActionModal();\n    closePeerMoodModal();\n    closeCompatQuizModal();\n    if($modalMutualMilestone) $modalMutualMilestone.classList.remove('open');\n    if($modalPeerHeartLetter) $modalPeerHeartLetter.classList.remove('open');\n    _peerHeartLetterFlowPeerId = '';\n    _mutualMilestoneToastOpen = false;\n    setTimeout(() => tryFlushMutualMilestoneToastQueue(), 0);\n  }\n\n  function renderDailyRecommend(){\n    const wrap = document.getElementById('daily-recommend-body');\n    if(!wrap) return;\n    const seed = new Date().toISOString().slice(0, 10);\n    let pick;\n    let inLiked = false;\n    if(liked.length){\n      inLiked = true;\n      const sorted = [...liked].sort((a, b) => (b.match + b.astro) - (a.match + a.astro));\n      const top = sorted.slice(0, Math.min(3, sorted.length));\n      pick = top[hash32(seed + '|pick') % top.length];\n    }else if(deck.length){\n      pick = deck[hash32(seed + '|deck') % deck.length];\n    }else{\n      wrap.innerHTML =\n        '<p class=\"ma-drec-empty\">还没有可展示的推荐。请先在发现页 <strong>REFRESH</strong> 拉取卡片，或右滑喜欢后回到这里查看。</p>' +\n        '<button type=\"button\" class=\"ma-drec-btn ma-drec-secondary\" data-drec-action=\"discover\">去发现</button>';\n      return;\n    }\n    const ri = hash32(seed + pick.id) % 3;\n    const reasons = [\n      `今日指数与 Ta 的星盘契合 ${pick.astro}% 同频，适合慢聊开场。`,\n      `匹配 ${pick.match}% · 标签「${pick.tag}」利于轻松破冰。`,\n      `能量偏倾听与分享的一天，和 ${pick.city} · ${pick.age} 岁${pick.gender ? ' · ' + pick.gender : ''}的 Ta 节奏相近。`\n    ];\n    const reason = reasons[ri];\n    const pickName = inLiked ? getPeerDisplayName(pick) : String(pick.name || 'Ta');\n    const foot = inLiked\n      ? '已在你的对话列表里，今天值得主动递一句晚安或歌单。'\n      : '还没有互相喜欢？先去发现右滑一张卡 — Ta 也可当作今日聊感参考。';\n    const btnLabel = inLiked ? '去发消息' : '去发现';\n    const btnClass = inLiked ? 'ma-drec-btn' : 'ma-drec-btn ma-drec-secondary';\n    wrap.innerHTML =\n      '<div class=\"ma-drec-row\">' +\n        '<div class=\"ma-drec-av\"><i class=\"ph ph-user\"></i></div>' +\n        '<div class=\"ma-drec-mid\">' +\n          '<div class=\"ma-drec-name\">' + esc(pickName) + '</div>' +\n          '<div class=\"ma-drec-meta\">' + pick.age + ' · ' + esc(pick.city) + (pick.gender ? ' · ' + esc(String(pick.gender)) : '') + ' · ' + esc(pick.tag) + '</div>' +\n          '<p class=\"ma-drec-reason\">' + esc(reason) + '</p>' +\n        '</div>' +\n        '<div class=\"ma-drec-badges\"><span>匹配 ' + pick.match + '%</span><span>星盘 ' + pick.astro + '%</span></div>' +\n      '</div>' +\n      '<p class=\"ma-drec-foot\">' + esc(foot) + '</p>' +\n      '<button type=\"button\" class=\"' + btnClass + '\" data-drec-action=\"' + (inLiked ? 'chat' : 'discover') + '\" data-drec-id=\"' + esc(pick.id) + '\">' + btnLabel + '</button>';\n  }\n\n  const DAILY_FORTUNE_SYSTEM_PROMPT =\n    'You output ONLY valid JSON (no markdown, no code fences, no commentary). ' +\n    'Return one object with: index (integer 58-92, daily vibe score for a slow-dating app), ' +\n    'mood (Chinese, one short line max 40 chars, poetic but grounded), ' +\n    'dayHarmony (integer 52-88, label in UI is 日合 resonance %), chatVibe (integer 50-85, 聊感 %), ' +\n    'yi (Chinese, 宜: comma-separated short phrases, one line), ji (Chinese, 忌: one line), ' +\n    'chatBias (Chinese, 2-3 sentences: who to chat with / vibe today), ' +\n    'chatTips (array of 2-4 Chinese strings, bullets like time windows), ' +\n    'aspects (array of 2-4 objects {label, hint} in Chinese, light astrology flavor, not medical claims).';\n\n  function parseDailyFortuneJson(raw){\n    let s = String(raw || '').trim();\n    const fence = /```(?:json)?\\s*([\\s\\S]*?)```/i;\n    const fm = s.match(fence);\n    if(fm) s = fm[1].trim();\n    const i0 = s.indexOf('{');\n    const i1 = s.lastIndexOf('}');\n    if(i0 >= 0 && i1 > i0) s = s.slice(i0, i1 + 1);\n    return JSON.parse(s);\n  }\n\n  function localYmd(){\n    const d = new Date();\n    const z = n => String(n).padStart(2, '0');\n    return d.getFullYear() + '-' + z(d.getMonth() + 1) + '-' + z(d.getDate());\n  }\n\n  function normalizeDailyFortunePayload(o){\n    if(!o || typeof o !== 'object') return null;\n    const ir = Math.round(Number(o.index));\n    const index = Number.isFinite(ir) ? Math.min(92, Math.max(58, ir)) : 72;\n    const mood = String(o.mood || '').trim().slice(0, 120) || '今日宜慢聊与倾听。';\n    const dr = Math.round(Number(o.dayHarmony != null ? o.dayHarmony : o.dayMatch));\n    const dayHarmony = Number.isFinite(dr) ? Math.min(88, Math.max(50, dr)) : 72;\n    const cr = Math.round(Number(o.chatVibe != null ? o.chatVibe : o.chatSense));\n    const chatVibe = Number.isFinite(cr) ? Math.min(85, Math.max(50, cr)) : 64;\n    const yi = String(o.yi || '').trim().slice(0, 220) || '—';\n    const ji = String(o.ji || '').trim().slice(0, 220) || '—';\n    const chatBias = String(o.chatBias || o.chatIntro || '').trim().slice(0, 400) ||\n      '今日节奏偏柔，优先回应愿意倾听的对象；具体看对方简介与标签微调话题。';\n    const chatTips = Array.isArray(o.chatTips)\n      ? o.chatTips.map(x => String(x).trim().slice(0, 140)).filter(Boolean).slice(0, 5)\n      : [];\n    const aspects = Array.isArray(o.aspects)\n      ? o.aspects.map(a => ({\n        label: String(a.label || a.line || '').trim().slice(0, 56),\n        hint: String(a.hint || a.note || '').trim().slice(0, 56),\n      })).filter(x => x.label && x.hint).slice(0, 6)\n      : [];\n    const asp = aspects.length ? aspects : [\n      { label: '金星 ↔ 水星', hint: '利于轻松话题' },\n      { label: '月亮 三分 木星', hint: '情绪包容度 +' },\n      { label: '火星', hint: '避免硬碰硬辩论' },\n    ];\n    const tips = chatTips.length ? chatTips : ['优先回复慢热、愿意接话的对象', '傍晚后上线往往更放松（示意）'];\n    return { index, mood, dayHarmony, chatVibe, yi, ji, chatBias, chatTips: tips, aspects: asp };\n  }\n\n  function buildDailyFortuneFallback(){\n    const ymd = localYmd();\n    const b0 = getStoredBirth();\n    const seed = ymd + '|' + (b0 && b0.date ? b0.date : '—');\n    const h = k => hash32(seed + '|' + k);\n    const index = 58 + (h('i') % 32);\n    const dayHarmony = 52 + (h('d') % 34);\n    const chatVibe = 50 + (h('c') % 32);\n    const moods = [\n      '月亮进入温柔相位 · 适合慢聊与倾听',\n      '能量偏内敛 · 适合轻声开场与歌单分享',\n      '社交语感在线 · 简短接话就够用',\n      '适合晚点上线 · 夜聊氛围更放松',\n    ];\n    const yiPool = [\n      '简短开场、分享歌单、傍晚后上线、接话不过度解读',\n      '慢热慢回、先听再说、用具体问题代替揣测',\n      '轻幽默开场、避开沉重话题、给对方留白',\n    ];\n    const jiPool = [\n      '连珠炮追问、刚匹配就长语音、否定对方兴趣',\n      '查岗式提问、一次发多条长段、比较前任',\n      '硬拗观点、打断对方、深夜情绪化宣泄',\n    ];\n    return normalizeDailyFortunePayload({\n      index,\n      mood: moods[h('m') % moods.length],\n      dayHarmony,\n      chatVibe,\n      yi: yiPool[h('y') % yiPool.length],\n      ji: jiPool[h('j') % jiPool.length],\n      chatBias: '今日与水象、土象标签的人更容易聊开；若对方简介带「夜猫子」「爵士」等关键词，破冰成功率更高。',\n      chatTips: ['优先回复：带月亮/海王星意象的慢热型', '时段建议：19:00–23:00 消息打开率偏高（示意）'],\n      aspects: [\n        { label: '金星 ↔ 水星', hint: '利于轻松话题' },\n        { label: '月亮 三分 木星', hint: '情绪包容度 +' },\n        { label: '火星', hint: '避免硬碰硬辩论' },\n      ],\n    });\n  }\n\n  function applyDailyFortuneToUi(p){\n    if(!p) return;\n    const idxEl = document.getElementById('daily-index');\n    if(idxEl) idxEl.textContent = String(p.index);\n    const moodEl = document.getElementById('daily-mood');\n    if(moodEl) moodEl.textContent = p.mood;\n    const od = document.getElementById('daily-orbit-day');\n    if(od){\n      od.style.setProperty('--p', String(p.dayHarmony));\n      const hp = document.getElementById('daily-orbit-day-pct');\n      if(hp) hp.innerHTML = String(p.dayHarmony) + '<small>%</small>';\n    }\n    const oc = document.getElementById('daily-orbit-chat');\n    if(oc){\n      oc.style.setProperty('--p', String(p.chatVibe));\n      const hp = document.getElementById('daily-orbit-chat-pct');\n      if(hp) hp.innerHTML = String(p.chatVibe) + '<small>%</small>';\n    }\n    const yi = document.getElementById('daily-yi');\n    if(yi) yi.textContent = p.yi;\n    const ji = document.getElementById('daily-ji');\n    if(ji) ji.textContent = p.ji;\n    const cb = document.getElementById('daily-chat-bias');\n    if(cb) cb.textContent = p.chatBias;\n    const ul = document.getElementById('daily-chat-tips');\n    if(ul) ul.innerHTML = p.chatTips.map(t => '<li>' + esc(t) + '</li>').join('');\n    const ar = document.getElementById('daily-aspects-rows');\n    if(ar){\n      ar.innerHTML = p.aspects.map(a =>\n        '<div class=\"ma-aspect-row\"><span>' + esc(a.label) + '</span><span>' + esc(a.hint) + '</span></div>'\n      ).join('');\n    }\n  }\n\n  async function saveDailyFortuneCache(payload){\n    await meetStoreSet(IDB_KEY_MEET_DAILY, { date: localYmd(), payload });\n  }\n\n  async function renderDailyPageContent(){\n    refreshDailyLine();\n    let p = null;\n    try{\n      const row = await meetStoreGet(IDB_KEY_MEET_DAILY);\n      const ymd = localYmd();\n      if(row && row.date === ymd && row.payload)\n        p = normalizeDailyFortunePayload(row.payload);\n    }catch(_){}\n    applyDailyFortuneToUi(p || buildDailyFortuneFallback());\n    renderDailyRecommend();\n  }\n\n  function isDailyTabActive(){\n    const v = document.querySelector('.ma-view.active');\n    return !!(v && v.id === 'view-daily');\n  }\n\n  async function refreshDailyFromApi(){\n    if(dailyRefreshBusy) return;\n    const btn = document.getElementById('btn-refresh-discover');\n    dailyRefreshBusy = true;\n    if(btn){\n      btn.disabled = true;\n      btn.classList.add('is-busy');\n    }\n    try{\n      const profile = await getActiveApiProfileFromMain();\n      if(!profile) throw new Error('未配置 API');\n      const ctx = JSON.stringify({\n        date: localYmd(),\n        profile: getUserProfile(),\n        birth: getStoredBirth(),\n      });\n      const raw = await chillLlmComplete(profile, [\n        { role: 'system', content: DAILY_FORTUNE_SYSTEM_PROMPT },\n        { role: 'user', content: '生成今日运势 JSON（用户上下文）：\\n' + ctx },\n      ], { temperature: 0.88, timeoutMs: 75000 });\n      const obj = parseDailyFortuneJson(raw);\n      const p = normalizeDailyFortunePayload(obj);\n      if(!p) throw new Error('解析失败');\n      await saveDailyFortuneCache(p);\n      applyDailyFortuneToUi(p);\n      renderDailyRecommend();\n    }catch(e){\n      console.warn('daily fortune refresh', e);\n      applyDailyFortuneToUi(buildDailyFortuneFallback());\n      renderDailyRecommend();\n    }finally{\n      dailyRefreshBusy = false;\n      if(btn){\n        btn.disabled = false;\n        btn.classList.remove('is-busy');\n      }\n    }\n  }\n\n  function pruneStrangersNowInLiked(){\n    const next = strangers.filter(s => !liked.some(l => String(l.id) === String(s.id)));\n    if(next.length === strangers.length) return;\n    strangers = next;\n    saveStrangersToStorage();\n  }\n\n  function normalizeStrangerPreviewDedupe(t){\n    return String(t || '').replace(/\\s+/g, ' ').trim().toLowerCase().slice(0, 48);\n  }\n\n  function normalizeStrangerInboxEntry(o, i){\n    if(!o || typeof o !== 'object') return null;\n    const idRaw = String(o.id != null ? o.id : '').trim();\n    const name = String(o.name || '').trim().slice(0, 24) || 'Ta';\n    const preview = String(o.preview || '').trim().slice(0, 200) || '你好～';\n    const id = idRaw || ('str-' + Date.now() + '-' + (i | 0) + '-' + Math.random().toString(36).slice(2, 9));\n    return { id, name, preview };\n  }\n\n  function saveStrangersToStorage(){\n    void meetStoreSet(IDB_KEY_MEET_STRANGERS, strangers.slice(-STRANGER_MAX_INBOX));\n  }\n\n  function buildStrangerBlocklist(){\n    const ids = [];\n    const names = [];\n    const previews = [];\n    function addId(x){\n      if(x == null || !String(x).trim()) return;\n      ids.push(String(x).trim());\n    }\n    function addName(x){\n      if(x == null || !String(x).trim()) return;\n      names.push(String(x).trim());\n    }\n    function addPv(x){\n      const k = normalizeStrangerPreviewDedupe(x);\n      if(k) previews.push(k);\n    }\n    strangers.forEach(s => {\n      addId(s.id);\n      addName(s.name);\n      addPv(s.preview);\n    });\n    liked.forEach(u => {\n      addId(u.id);\n      addName(u.name);\n    });\n    deck.forEach(c => {\n      addId(c.id);\n      addName(c.name);\n    });\n    return {\n      ids: [...new Set(ids)],\n      names: [...new Set(names)],\n      previews: [...new Set(previews)],\n    };\n  }\n\n  function parseStrangerBatchJson(raw){\n    let s = String(raw || '').trim();\n    const fence = /```(?:json)?\\s*([\\s\\S]*?)```/i;\n    const fm = s.match(fence);\n    if(fm) s = fm[1].trim();\n    const i0 = s.indexOf('{');\n    const i1 = s.lastIndexOf('}');\n    if(i0 >= 0 && i1 > i0) s = s.slice(i0, i1 + 1);\n    const data = JSON.parse(s);\n    if(Array.isArray(data.items)) return data.items;\n    if(Array.isArray(data.strangers)) return data.strangers;\n    return [];\n  }\n\n  function mergeStrangerBatchItems(rawItems){\n    if(!Array.isArray(rawItems) || !rawItems.length) return 0;\n    const seenId = new Set();\n    const seenName = new Set();\n    const seenPrev = new Set();\n    function register(s){\n      seenId.add(String(s.id).toLowerCase());\n      seenName.add(String(s.name || '').trim().toLowerCase());\n      const pk = normalizeStrangerPreviewDedupe(s.preview);\n      if(pk) seenPrev.add(pk);\n    }\n    strangers.forEach(register);\n    liked.forEach(u => {\n      seenId.add(String(u.id).toLowerCase());\n      seenName.add(String(u.name || '').trim().toLowerCase());\n    });\n    deck.forEach(c => {\n      seenId.add(String(c.id).toLowerCase());\n      seenName.add(String(c.name || '').trim().toLowerCase());\n    });\n    const accepted = [];\n    rawItems.forEach((o, idx) => {\n      const n = normalizeStrangerInboxEntry(o, idx);\n      if(!n) return;\n      const idL = String(n.id).toLowerCase();\n      const nameL = String(n.name || '').trim().toLowerCase();\n      const pk = normalizeStrangerPreviewDedupe(n.preview);\n      if(seenId.has(idL)) return;\n      if(seenName.has(nameL)) return;\n      if(pk && seenPrev.has(pk)) return;\n      register(n);\n      accepted.push(n);\n    });\n    if(!accepted.length) return 0;\n    strangers = strangers.concat(accepted).slice(-STRANGER_MAX_INBOX);\n    saveStrangersToStorage();\n    return accepted.length;\n  }\n\n  function getStrangerNextDueAt(){\n    return _meetStrangerNextDue || 0;\n  }\n\n  function isStrangerBatchDue(){\n    const t = getStrangerNextDueAt();\n    if(!t) return true;\n    return Date.now() >= t;\n  }\n\n  function scheduleStrangerNextDue(){\n    const ms = STRANGER_MIN_GAP_MS + Math.random() * (STRANGER_MAX_GAP_MS - STRANGER_MIN_GAP_MS);\n    _meetStrangerNextDue = Date.now() + ms;\n    void meetStoreSet(IDB_KEY_MEET_STRANGER_DUE, _meetStrangerNextDue);\n  }\n\n  function scheduleStrangerRetryBackoff(minutes){\n    _meetStrangerNextDue = Date.now() + minutes * 60 * 1000;\n    void meetStoreSet(IDB_KEY_MEET_STRANGER_DUE, _meetStrangerNextDue);\n  }\n\n  async function maybeAppendStrangerBatch(){\n    if(getDmPolicy() !== DM_STRANGERS_OK) return;\n    if(strangerInboxBusy) return;\n    if(!isStrangerBatchDue()) return;\n    strangerInboxBusy = true;\n    try{\n      const profile = await getActiveApiProfileFromMain();\n      if(!profile){\n        scheduleStrangerRetryBackoff(30);\n        return;\n      }\n      const block = buildStrangerBlocklist();\n      const payload = {\n        blockedIds: block.ids.slice(0, 100),\n        blockedNames: block.names.slice(0, 100),\n        blockedPreviews: block.previews.slice(0, 80),\n        profile: getUserProfile(),\n        birth: getStoredBirth(),\n      };\n      const text = await chillLlmComplete(profile, [\n        { role: 'system', content: STRANGER_BATCH_SYSTEM_PROMPT },\n        { role: 'user', content: '生成一批陌生私信招呼（遵守屏蔽列表、勿重复）：\\n' + JSON.stringify(payload) },\n      ], { temperature: 0.88, timeoutMs: 90000 });\n      let arr;\n      try{\n        arr = parseStrangerBatchJson(text);\n      }catch(e){\n        console.warn('stranger batch parse', e);\n        scheduleStrangerRetryBackoff(20);\n        return;\n      }\n      mergeStrangerBatchItems(arr);\n      scheduleStrangerNextDue();\n      renderInbox();\n    }catch(e){\n      console.warn('stranger batch', e);\n      scheduleStrangerRetryBackoff(25);\n    }finally{\n      strangerInboxBusy = false;\n    }\n  }\n\n  function renderStrangerStack(){\n    const host = document.getElementById('stranger-stack-host');\n    if(!host) return;\n    if(getDmPolicy() === DM_MATCH_ONLY){\n      strangerExpanded = false;\n      host.innerHTML = `\n        <div class=\"ma-str-off-hint\">\n          <i class=\"ph ph-lock\" aria-hidden=\"true\"></i>\n          <div>\n            <strong>未接收陌生私信</strong><br>\n            你已选择「仅互相喜欢后可私聊」。匹配用户的对话仍在下方列表。若要陌生招呼，请到「我的 → 谁能私信我」开启「允许陌生人私信」。\n          </div>\n        </div>`;\n      return;\n    }\n    if(!strangers.length){\n      strangerExpanded = false;\n      host.innerHTML =\n        '<div class=\"ma-str-empty-hint\">' +\n          '<i class=\"ph ph-envelope-simple\" aria-hidden=\"true\"></i>' +\n          '<div><strong>暂无陌生消息</strong></div>' +\n        '</div>';\n      return;\n    }\n\n    function strangerSwipeRowHtml(s){\n      return (\n        '<div class=\"ma-row-swipe ma-str-swipe\">' +\n        '<button type=\"button\" class=\"ma-row-del\" data-del-stranger-id=\"' + esc(s.id) + '\">删除</button>' +\n        '<div class=\"ma-row ma-row-main ma-str-swipe-main\" data-sid=\"' + esc(s.id) + '\" role=\"button\" tabindex=\"0\">' +\n        '<div class=\"ma-row-av\"><i class=\"ph ph-envelope-open\"></i>' + (peerHasUnreadFromAssistant(s.id) ? '<span class=\\\"ma-row-unread-dot\\\" aria-label=\\\"未读\\\"></span>' : '') + '</div>' +\n        '<div class=\"ma-row-mid\">' +\n        '<div class=\"ma-row-t\">' + esc(s.name) + '</div>' +\n        '<div class=\"ma-row-s\">' + esc(s.preview) + '</div>' +\n        '</div>' +\n        '<span class=\"ma-str-li-go\">回复</span>' +\n        '</div></div>'\n      );\n    }\n\n    const listRows = strangers.map(s => strangerSwipeRowHtml(s)).join('');\n    const clearBtn =\n      '<button type=\"button\" class=\"ma-str-clear-all\" id=\"stranger-clear-all\">一键清空</button>';\n\n    const multi = strangers.length > 1;\n    if(!multi){\n      strangerExpanded = false;\n      host.innerHTML =\n        '<div class=\"ma-str-block ma-str-block--solo\" id=\"stranger-stack-block\">' +\n        '<div class=\"ma-section-title ma-str-head\" style=\"margin-top:0;\">' +\n        '<div>陌生招呼 <span class=\"ma-sec-badge\">1</span></div>' +\n        '<div class=\"ma-str-head-actions\">' + clearBtn + '</div>' +\n        '</div>' +\n        '<div class=\"ma-str-list\" id=\"stranger-expanded-list\">' + listRows + '</div>' +\n        '</div>';\n    }else{\n    const vis = strangers.slice(0, 3);\n    const layers = vis.map((s, k) => {\n      const translateY = k * 13;\n      const scale = 1 - k * 0.036;\n      const z = 24 - k * 8;\n      const op = Math.max(0.5, 1 - k * 0.18);\n      const sub = k === 0 ? esc(s.preview) : '···';\n      return `<div class=\"ma-str-layer\" style=\"z-index:${z};transform:translateY(${translateY}px) scale(${scale});opacity:${op};\">\n        <div class=\"ma-row-av\"><i class=\"ph ph-envelope-open\"></i></div>\n        <div class=\"ma-row-mid\">\n          <div class=\"ma-row-t\">${esc(s.name)}</div>\n          <div class=\"ma-row-s\">${sub}</div>\n        </div>\n        ${k === 0 ? `<div class=\"ma-str-meta\">陌生<br><span class=\"ma-str-count\">${strangers.length} 条</span></div>` : ''}\n      </div>`;\n    }).join('');\n      const blockClass = 'ma-str-block' + (strangerExpanded ? ' is-expanded' : '');\n      const subhint = !strangerExpanded\n      ? '<span class=\"ma-str-subhint\">点按堆叠展开全部</span>' : '';\n    host.innerHTML = `\n      <div class=\"${blockClass}\" id=\"stranger-stack-block\">\n        <div class=\"ma-section-title ma-str-head\" style=\"margin-top:0;\">\n          <div>\n            陌生招呼 <span class=\"ma-sec-badge\">${strangers.length}</span>\n            ${subhint}\n          </div>\n          <div class=\"ma-str-head-actions\">\n            ${clearBtn}\n            <button type=\"button\" class=\"ma-str-collapse\" id=\"stranger-collapse\" ${strangerExpanded ? '' : 'hidden'}>收起</button>\n          </div>\n        </div>\n        <div class=\"ma-str-stack-wrap\">\n          <div class=\"ma-str-stack\" id=\"stranger-stack\" role=\"button\" tabindex=\"0\" aria-label=\"展开全部陌生招呼\">${layers}</div>\n        </div>\n        <div class=\"ma-str-list\" id=\"stranger-expanded-list\">${listRows}</div>\n      </div>`;\n    }\n\n    function closeStrangerSwipeRowIfOpen(main){\n      const wrap = main && main.closest('.ma-row-swipe');\n      if(!wrap || Number(wrap.dataset.x || 0) >= 0) return false;\n      const m = wrap.querySelector('.ma-row-main');\n      if(m){\n        m.style.transition = 'transform .18s ease';\n        m.style.transform = 'translateX(0px)';\n      }\n      wrap.dataset.x = '0';\n      wrap.classList.remove('is-open');\n      return true;\n    }\n\n    document.getElementById('stranger-clear-all')?.addEventListener('click', (e) => {\n      e.stopPropagation();\n      clearAllStrangers();\n    });\n\n    document.getElementById('stranger-collapse')?.addEventListener('click', (e) => {\n      e.stopPropagation();\n      strangerExpanded = false;\n      renderStrangerStack();\n    });\n\n    const listEl = document.getElementById('stranger-expanded-list');\n    listEl?.addEventListener('click', (e) => {\n      const delBtn = e.target.closest('[data-del-stranger-id]');\n      if(delBtn){\n        e.stopPropagation();\n        deleteStrangerInbox(delBtn.getAttribute('data-del-stranger-id'));\n        return;\n      }\n      const main = e.target.closest('.ma-str-swipe-main');\n      if(!main) return;\n      if(closeStrangerSwipeRowIfOpen(main)) return;\n      openStrangerChat(main.getAttribute('data-sid'));\n    });\n    listEl?.addEventListener('keydown', (e) => {\n      const main = e.target.closest('.ma-str-swipe-main');\n      if(!main || (e.key !== 'Enter' && e.key !== ' ')) return;\n      e.preventDefault();\n      if(closeStrangerSwipeRowIfOpen(main)) return;\n      openStrangerChat(main.getAttribute('data-sid'));\n    });\n\n    bindSwipeRows(listEl);\n\n    if(multi){\n    const st = document.getElementById('stranger-stack');\n    const onStackActivate = () => {\n        if(!strangerExpanded){\n          strangerExpanded = true;\n          renderStrangerStack();\n      }\n    };\n    st?.addEventListener('click', onStackActivate);\n    st?.addEventListener('keydown', (e) => {\n      if(e.key !== 'Enter' && e.key !== ' ') return;\n      e.preventDefault();\n      onStackActivate();\n    });\n    }\n  }\n\n  function renderInbox(){\n    pruneStrangersNowInLiked();\n    renderStrangerStack();\n    $listInbox.innerHTML = liked.length ? liked.map(u => {\n      const my = Number(u.stars) || 0;\n      const ta = Number(u.starsFromPeer) || 0;\n      const fm = Math.round(Number(u.favorMe) || 0);\n      const fp = Math.round(Number(u.favorPeer) || 0);\n      const _unreadDot = peerHasUnreadFromAssistant(u.id) ? '<span class=\"ma-row-unread-dot\" aria-label=\"未读\"></span>' : '';\n      return `\n      <div class=\"ma-row-swipe\">\n        <button type=\"button\" class=\"ma-row-del\" data-del-id=\"${esc(u.id)}\">删除</button>\n        <div class=\"ma-row ma-row-main\" data-open-chat=\"${esc(u.id)}\">\n        <div class=\"ma-row-av\"><i class=\"ph ph-user\"></i>${_unreadDot}</div>\n        <div class=\"ma-row-mid\">\n            <div class=\"ma-row-t\">${esc(getPeerDisplayName(u))}</div>\n          <div class=\"ma-row-s\">喜欢即可聊 · 平台资料已解锁一级</div>\n        </div>\n          <span class=\"ma-row-tag\" title=\"我 ${fm} 分 · Ta ${fp} 分（约 1★30 / 2★60 / 3★110 / 4★170 / 5★${IMPRESSION_FAVOR_CAP}）\">我${my}☆ · Ta${ta}☆</span>\n        </div>\n      </div>`;\n    }).join('') : '<div class=\"ma-empty\" style=\"min-height:160px;\"><i class=\"ph ph-chat-circle\"></i><p>还没有对话</p><span>右滑喜欢的人会出现在下面</span></div>';\n\n    $listInbox.querySelectorAll('[data-open-chat]').forEach(row => {\n      row.addEventListener('click', () => {\n        const wrap = row.closest('.ma-row-swipe');\n        if(wrap && Number(wrap.dataset.x || 0) < 0){\n          const main = wrap.querySelector('.ma-row-main');\n          if(main){\n            main.style.transition = 'transform .18s ease';\n            main.style.transform = 'translateX(0px)';\n          }\n          wrap.dataset.x = '0';\n          wrap.classList.remove('is-open');\n          return;\n        }\n        openChat(row.getAttribute('data-open-chat'));\n      });\n    });\n    $listInbox.querySelectorAll('[data-del-id]').forEach(btn => {\n      btn.addEventListener('click', (e) => {\n        e.stopPropagation();\n        deleteInboxPerson(btn.getAttribute('data-del-id'));\n      });\n    });\n    bindSwipeRows($listInbox);\n  }\n\n  function purgePeerMeetSideData(sid){\n    const id = String(sid || '');\n    if(!id) return;\n    const cm = convMapGet();\n    if(cm && typeof cm === 'object' && cm[id] != null){\n      delete cm[id];\n      convMapSet(cm);\n    }\n    if(_meetInboxLastReadTs && typeof _meetInboxLastReadTs === 'object' && _meetInboxLastReadTs[id] != null){\n      const ir = Object.assign({}, _meetInboxLastReadTs);\n      delete ir[id];\n      _meetInboxLastReadTs = ir;\n      void meetStoreSet(IDB_KEY_MEET_INBOX_READ, ir);\n    }\n    if(_meetChatPersonaMap && typeof _meetChatPersonaMap === 'object' && _meetChatPersonaMap[id] != null){\n      const pm = Object.assign({}, _meetChatPersonaMap);\n      delete pm[id];\n      _meetChatPersonaMap = pm;\n      void meetStoreSet(IDB_KEY_MEET_CHAT_PERSONA, _meetChatPersonaMap);\n    }\n    if(_chatIcebreakerPoolMap[id]) delete _chatIcebreakerPoolMap[id];\n    if(_peerMoodFromReplyMap[id]) delete _peerMoodFromReplyMap[id];\n    if(_compatLlmDeck[id]) delete _compatLlmDeck[id];\n  }\n\n  function deleteInboxPerson(id){\n    const sid = String(id || '');\n    if(!sid) return;\n    if(pendingNameUnlockPeerId === sid){\n      pendingNameUnlockPeerId = '';\n      closeNameUnlockModal();\n    }\n    liked = liked.filter(x => String(x.id) !== sid);\n    saveLiked();\n    purgePeerMeetSideData(sid);\n    if(currentChat && String(currentChat.id) === sid){\n      closeChatShell();\n      $modal.classList.remove('open');\n      currentChat = null;\n    }\n    renderInbox();\n    renderDailyRecommend();\n  }\n\n  function deleteStrangerInbox(id){\n    const sid = String(id || '');\n    if(!sid) return;\n    strangers = strangers.filter(x => String(x.id) !== sid);\n    saveStrangersToStorage();\n    purgePeerMeetSideData(sid);\n    if(currentChat && currentChat.isStranger && String(currentChat.id) === sid){\n      closeChatShell();\n      currentChat = null;\n    }\n    renderInbox();\n  }\n\n  function clearAllStrangers(){\n    if(!strangers.length) return;\n    strangers.forEach(s => purgePeerMeetSideData(String(s.id)));\n    strangers = [];\n    saveStrangersToStorage();\n    if(currentChat && currentChat.isStranger){\n      closeChatShell();\n      currentChat = null;\n    }\n    strangerExpanded = false;\n    meetToastShow('已清空陌生招呼');\n    renderInbox();\n  }\n\n  function bindSwipeRows(container){\n    if(!container) return;\n    const rows = [...container.querySelectorAll('.ma-row-swipe')];\n    if(!rows.length) return;\n    const OPEN_X = -88;\n    const MAX_X = -108;\n    function setX(wrap, x, anim){\n      const main = wrap.querySelector('.ma-row-main');\n      if(!main) return;\n      main.style.transition = anim ? 'transform .18s ease' : 'none';\n      main.style.transform = 'translateX(' + x + 'px)';\n      wrap.dataset.x = String(x);\n      wrap.classList.toggle('is-open', x <= OPEN_X + 16);\n    }\n    function closeOthers(except){\n      rows.forEach(r => {\n        if(r !== except && Number(r.dataset.x || 0) < 0) setX(r, 0, true);\n      });\n    }\n    rows.forEach(wrap => {\n      const main = wrap.querySelector('.ma-row-main');\n      if(!main) return;\n      let sx = 0;\n      let sy = 0;\n      let dx = 0;\n      let dy = 0;\n      let active = false;\n      let dragging = false;\n      let captured = false;\n      let pid = null;\n      const down = (e) => {\n        if(e.pointerType === 'mouse' && e.button !== 0) return;\n        closeOthers(wrap);\n        sx = e.clientX; sy = e.clientY; dx = 0; dy = 0;\n        active = true; dragging = false; captured = false; pid = e.pointerId;\n      };\n      const move = (e) => {\n        if(!active || pid !== e.pointerId) return;\n        dx = e.clientX - sx;\n        dy = e.clientY - sy;\n        if(!dragging){\n          // 明显纵向意图：交给列表滚动，不进入左滑删除。\n          if(Math.abs(dy) > 8 && Math.abs(dy) > Math.abs(dx) * 1.15){\n            active = false;\n            return;\n          }\n          // 需要更明确的横向位移，避免轻微抖动触发。\n          if(Math.abs(dx) < 14) return;\n          // 横向不够占优时仍视为滚动。\n          if(Math.abs(dx) < Math.abs(dy) * 1.2){\n            active = false;\n            return;\n          }\n          dragging = true;\n          if(!captured){\n            main.setPointerCapture?.(pid);\n            captured = true;\n          }\n        }\n        if(dx > 0) dx = Math.min(18, dx);\n        const x = Math.max(MAX_X, Math.min(12, dx));\n        setX(wrap, x, false);\n      };\n      const up = (e) => {\n        if(pid !== e.pointerId) return;\n        if(active && dragging){\n          const curr = Number(wrap.dataset.x || 0);\n          if(curr <= -52) setX(wrap, OPEN_X, true);\n          else setX(wrap, 0, true);\n        }else if(Number(wrap.dataset.x || 0) < 0){\n          setX(wrap, 0, true);\n        }\n        if(captured){\n          main.releasePointerCapture?.(pid);\n          captured = false;\n        }\n        active = false;\n        dragging = false;\n        pid = null;\n      };\n      main.addEventListener('pointerdown', down);\n      main.addEventListener('pointermove', move);\n      main.addEventListener('pointerup', up);\n      main.addEventListener('pointercancel', up);\n    });\n  }\n\n  function buildLikedFromStrangerInbox(s){\n    if(!s) return null;\n    const id = String(s.id);\n    const fromDeck = deck.find(c => String(c.id) === id);\n    if(fromDeck){\n      return normalizeLikedEntry(Object.assign({}, fromDeck, {\n        favorMe: 0,\n        favorPeer: peerFavorSeed(id),\n        favorEconomy: 3,\n      }));\n    }\n    const h = hash32('strMutual|' + id);\n    const match = 62 + (h % 18);\n    const astro = 60 + ((h >>> 8) % 22);\n    return normalizeLikedEntry({\n      id: s.id,\n      name: s.name,\n      city: '',\n      gender: '',\n      tag: '陌生招呼',\n      bio: String(s.preview || '').trim() || '从陌生招呼相识。',\n      match,\n      astro,\n      synastryLine: '',\n      peerSunSign: h % 12,\n      preview: s.preview,\n      favorMe: 0,\n      favorPeer: peerFavorSeed(id),\n      favorEconomy: 3,\n    });\n  }\n\n  function promoteStrangerToMutual(){\n    if(!currentChat || !currentChat.isStranger) return;\n    const sid = String(currentChat.id);\n    const existing = liked.find(x => String(x.id) === sid);\n    if(existing){\n      strangers = strangers.filter(x => String(x.id) !== sid);\n      saveStrangersToStorage();\n      currentChat = Object.assign({}, existing, { isStranger: false });\n      closePeerMoodModal();\n      closeCompatQuizModal();\n      closePeerHeartLetterModal(false);\n      ensureCompatQuizForCurrentChat(true);\n      const title = document.getElementById('chat-peer');\n      if(title) title.textContent = getPeerDisplayName(existing);\n      setChatImpressUi(false, existing);\n      renderChatThread(false, currentChat);\n      renderInbox();\n      updateIcebreakerUi();\n      renderDailyRecommend();\n      renderCompatQuizUi();\n      void ensureChatPersona(currentChat, false);\n      meetToastShow('已在匹配列表里啦');\n      maybeResumePeerHeartLetterModal();\n      return;\n    }\n    const s = strangers.find(x => String(x.id) === sid);\n    if(!s){\n      meetToastShow('找不到该招呼');\n      return;\n    }\n    const entry = buildLikedFromStrangerInbox(s);\n    if(!entry){\n      meetToastShow('无法完成互选');\n      return;\n    }\n    strangers = strangers.filter(x => String(x.id) !== sid);\n    saveStrangersToStorage();\n    liked.push(entry);\n    saveLiked();\n    currentChat = Object.assign({}, entry, { isStranger: false });\n    closePeerMoodModal();\n    closeCompatQuizModal();\n    closePeerHeartLetterModal(false);\n    ensureCompatQuizForCurrentChat(true);\n    const title = document.getElementById('chat-peer');\n    if(title) title.textContent = getPeerDisplayName(entry);\n    setChatImpressUi(false, entry);\n    renderChatThread(false, currentChat);\n    renderInbox();\n    updateIcebreakerUi();\n    renderDailyRecommend();\n    renderCompatQuizUi();\n    void ensureChatPersona(currentChat, false);\n    meetToastShow('已互选，可查看星级与 mood');\n    maybeResumePeerHeartLetterModal();\n  }\n\n  function openStrangerChat(id){\n    const sid = String(id != null ? id : '').trim();\n    if(!sid) return;\n    const uLiked = liked.find(x => String(x.id) === sid);\n    if(uLiked){\n      openChat(uLiked.id);\n      return;\n    }\n    const s = strangers.find(x => String(x.id) === sid);\n    if(!s) return;\n    icebreakerShuffle = 0;\n    currentChat = { id: s.id, name: s.name, stars: 0, starsFromPeer: 0, isStranger: true, preview: s.preview };\n    ensureCompatQuizForCurrentChat(true);\n    document.getElementById('chat-peer').textContent = s.name;\n    setChatImpressUi(true, currentChat);\n    renderChatThread(true, currentChat);\n    openChatShell();\n    updateIcebreakerUi();\n    renderCompatQuizUi();\n    void ensureChatPersona(currentChat, true);\n    markInboxThreadReadNow(currentChat.id);\n  }\n\n  function openChat(id){\n    const u = liked.find(x => x.id === id);\n    if(!u) return;\n    icebreakerShuffle = 0;\n    currentChat = Object.assign({}, u, { isStranger: false });\n    ensureCompatQuizForCurrentChat(true);\n    document.getElementById('chat-peer').textContent = getPeerDisplayName(u);\n    setChatImpressUi(false, u);\n    renderChatThread(false, u);\n    openChatShell();\n    updateIcebreakerUi();\n    renderCompatQuizUi();\n    void ensureChatPersona(currentChat, false);\n    maybeResumePeerHeartLetterModal();\n    markInboxThreadReadNow(u.id);\n  }\n\n  function closeChat(){\n    if(!currentChat) { closeChatShell(); return; }\n    if(currentChat.isStranger){\n      closeChatShell();\n      currentChat = null;\n      return;\n    }\n    closePeerMoodModal();\n    closeCompatQuizModal();\n    closePeerHeartLetterModal(false);\n    buildRateStars();\n    const u = liked.find(x => x.id === currentChat.id);\n    const fm = u ? Math.round(Number(u.favorMe) || 0) : 0;\n    const st = u ? (Number(u.stars) || 0) : 0;\n    const hintEl = document.getElementById('rate-current-hint');\n    if(hintEl){\n      hintEl.textContent = u\n        ? `当前 ${fm} 分 · 约 ${st} 星（参考 30 / 60 / 110 / 170 / ${IMPRESSION_FAVOR_CAP}）· 选本次结算加成`\n        : '尚无记录 · 选择本次结算加成';\n    }\n    $modal.classList.add('open');\n  }\n\n  function buildRateStars(){\n    const row = document.getElementById('rate-stars');\n    if(!row) return;\n    const defaultStep = 0;\n    const defaultIdx = Math.max(0, RATE_STEPS.findIndex(v => v === defaultStep));\n    row.innerHTML = RATE_STEPS.map((step, idx) => {\n      const stepAttr = step === 0.5 ? '0.5' : String(step);\n      const label = step === -1 ? '-1' : (step === 0.5 ? '½' : String(step));\n      const aria = step === -1 ? '减分档' : (step === 0.5 ? '半星' : label + '星');\n      return '<button type=\"button\" class=\"ma-rate-pill\" data-step=\"' + stepAttr + '\" data-idx=\"' + idx + '\" aria-label=\"' +\n        aria + '\">' + label + '</button>';\n    }).join('');\n    row.querySelectorAll('button').forEach(b => {\n      b.addEventListener('click', () => {\n        const idx = Number(b.getAttribute('data-idx'));\n        const s = b.getAttribute('data-step');\n        selectedRateStep = s === '0.5' ? 0.5 : Number(s);\n        row.querySelectorAll('button').forEach(x => {\n          const xi = Number(x.getAttribute('data-idx'));\n          x.classList.toggle('on', xi === idx);\n        });\n      });\n    });\n    selectedRateStep = defaultStep;\n    row.querySelectorAll('button').forEach(x => {\n      const xi = Number(x.getAttribute('data-idx'));\n      x.classList.toggle('on', xi === defaultIdx);\n    });\n  }\n\n  document.getElementById('chat-back').addEventListener('click', closeChat);\n  document.getElementById('chat-stranger-mutual')?.addEventListener('click', () => {\n    promoteStrangerToMutual();\n  });\n  document.getElementById('chat-mood-trigger')?.addEventListener('click', () => {\n    if(!currentChat) return;\n    openPeerMoodModal();\n  });\n  document.getElementById('peer-mood-close')?.addEventListener('click', () => {\n    closePeerMoodModal();\n  });\n  $modalPeerMood?.addEventListener('click', (e) => {\n    if(e.target === $modalPeerMood) closePeerMoodModal();\n  });\n  document.getElementById('chat-compat-trigger')?.addEventListener('click', () => {\n    openCompatQuizModal();\n  });\n  document.getElementById('compat-quiz-close')?.addEventListener('click', () => {\n    closeCompatQuizModal();\n  });\n  $modalCompatQuiz?.addEventListener('click', (e) => {\n    if(e.target === $modalCompatQuiz) closeCompatQuizModal();\n  });\n  document.getElementById('mutual-milestone-ok')?.addEventListener('click', () => {\n    closeMutualMilestoneToast();\n  });\n  $modalMutualMilestone?.addEventListener('click', (e) => {\n    if(e.target === $modalMutualMilestone) closeMutualMilestoneToast();\n  });\n  document.getElementById('peer-heart-skip')?.addEventListener('click', () => {\n    const pid = _peerHeartLetterFlowPeerId;\n    if(!pid){\n      closePeerHeartLetterModal();\n      return;\n    }\n    setPeerHeartLetterRecord(pid, { userResponseKind: 'skipped', userText: '' });\n    closePeerHeartLetterModal();\n  });\n  document.getElementById('peer-heart-send')?.addEventListener('click', () => {\n    const pid = _peerHeartLetterFlowPeerId;\n    const ta = document.getElementById('peer-heart-user-input');\n    const err = document.getElementById('peer-heart-error');\n    if(!pid){\n      closePeerHeartLetterModal();\n      return;\n    }\n    const raw = ta && ta.value ? String(ta.value).trim() : '';\n    if(!raw){\n      if(err) err.textContent = '若要发送请先输入内容，或点「暂不回应」。';\n      return;\n    }\n    if(err) err.textContent = '';\n    setPeerHeartLetterRecord(pid, { userResponseKind: 'replied', userText: raw.slice(0, 400) });\n    closePeerHeartLetterModal();\n  });\n  document.getElementById('peer-heart-done')?.addEventListener('click', () => {\n    closePeerHeartLetterModal();\n  });\n  document.getElementById('peer-heart-retry')?.addEventListener('click', () => {\n    const pid = _peerHeartLetterFlowPeerId || (currentChat && !currentChat.isStranger ? String(currentChat.id) : '');\n    if(pid) void openPeerHeartLetterFlow(pid, {});\n  });\n  function pushUserDraftToThread(){\n    if(!currentChat || chatReplyBusy) return;\n    const inp = document.getElementById('chat-input');\n    if(!inp) return;\n    const text = inp.value.trim();\n    if(!text) return;\n    const peerId = String(currentChat.id);\n    if(currentEditTurnId){\n      const edited = updateConvTurn(peerId, currentEditTurnId, (t) => {\n        t.content = text;\n        t.recalled = false;\n        return t;\n      });\n      if(edited){\n        renderChatThread(!!currentChat.isStranger, currentChat);\n      }\n      currentEditTurnId = null;\n    inp.value = '';\n      refreshChatQuoteBar();\n    inp.focus();\n      markInboxThreadReadNow(peerId);\n      return;\n    }\n    const turn = appendConvTurn(peerId, 'user', text, {\n      quoteRef: currentQuoteRef ? Object.assign({}, currentQuoteRef) : null\n    });\n    appendMeBubbleOnly(text, turn || null);\n    currentQuoteRef = null;\n    inp.value = '';\n    refreshChatQuoteBar();\n    inp.focus();\n    markInboxThreadReadNow(peerId);\n  }\n  document.getElementById('chat-send').addEventListener('click', () => {\n    pushUserDraftToThread();\n  });\n  document.getElementById('chat-reply')?.addEventListener('click', async () => {\n    if(!currentChat || chatReplyBusy) return;\n    const inp = document.getElementById('chat-input');\n    const peerId = String(currentChat.id);\n    if(removeLastPeerErrorPlaceholder(peerId)){\n      renderChatThread(!!currentChat.isStranger, currentChat);\n    }\n    // 对齐主文件：触发 AI 前先把输入框里的内容上屏。\n    pushUserDraftToThread();\n    chatReplyBusy = true;\n    setChatComposerBusy(true);\n    try{\n      await fetchAndAppendPeerReply();\n    }catch(e){\n      const msg = '（回复未生成：' + (e.message || String(e)).slice(0, 160) + '）';\n      const turn = appendConvTurn(peerId, 'assistant', msg);\n      appendPeerBubbleOnly(msg, turn);\n    }finally{\n      chatReplyBusy = false;\n      setChatComposerBusy(false);\n      if(inp) inp.focus();\n    }\n  });\n  document.getElementById('chat-input').addEventListener('keydown', (e) => {\n    if(e.key !== 'Enter') return;\n    e.preventDefault();\n    document.getElementById('chat-send').click();\n  });\n  document.getElementById('chat-thread')?.addEventListener('contextmenu', (e) => {\n    e.preventDefault();\n  });\n  document.getElementById('chat-thread')?.addEventListener('click', (e) => {\n    if(!multiSelectMode || !currentChat) return;\n    const row = e.target.closest('.ma-chat-msg[data-turn-id]');\n    if(!row) return;\n    e.preventDefault();\n    e.stopPropagation();\n    toggleSelectTurn(row.dataset.turnId);\n  }, true);\n  document.getElementById('chat-screen')?.addEventListener('click', (e) => {\n    const t = e.target;\n    if(!t || !t.closest) return;\n    if(t.closest('#ma-ms-done')){\n      setMultiSelectMode(false);\n      return;\n    }\n    const delBtn = t.closest('#ma-ms-delete');\n    if(delBtn){\n      if(delBtn.disabled || !currentChat || multiSelectTurnIds.size === 0) return;\n      const peerId = String(currentChat.id);\n      const ids = Array.from(multiSelectTurnIds);\n      const idSet = new Set(ids.map(String));\n      if(!removeMeetTurnsBulk(peerId, idSet)) return;\n      if(currentQuoteRef && idSet.has(String(currentQuoteRef.turnId || ''))) currentQuoteRef = null;\n      if(currentEditTurnId && idSet.has(String(currentEditTurnId))) currentEditTurnId = null;\n      refreshChatQuoteBar();\n      meetToastShow('已删除 ' + ids.length + ' 条');\n      setMultiSelectMode(false);\n      renderChatThread(!!currentChat.isStranger, currentChat);\n    }\n  });\n\n  document.getElementById('btn-icebreaker-shuffle').addEventListener('click', () => {\n    icebreakerShuffle++;\n    updateIcebreakerFallback();\n  });\n  document.getElementById('chat-compat-next')?.addEventListener('click', () => {\n    const uq = resolveChatForStarGates();\n    if(!currentChat || currentChat.isStranger || !canUseCompatQuiz(uq)){\n      if(currentChat && !currentChat.isStranger && !canUseCompatQuiz(uq)) meetToastShow('要对彼此都到 3★ 才能玩默契问答哦');\n      return;\n    }\n    compatQuizOffset++;\n    currentCompatQuiz = buildCurrentCompatSnapshot(String(currentChat.id), compatQuizOffset);\n    renderCompatQuizUi();\n  });\n  document.getElementById('compat-quiz-refresh')?.addEventListener('click', async () => {\n    if(_compatQuizRefreshBusy) return;\n    if(!currentChat || currentChat.isStranger) return;\n    if(!canUseCompatQuiz(resolveChatForStarGates())){\n      meetToastShow('要对彼此都到 3★ 才能玩默契问答哦');\n      return;\n    }\n    const btn = document.getElementById('compat-quiz-refresh');\n    _compatQuizRefreshBusy = true;\n    if(btn){\n      btn.classList.add('is-busy');\n      btn.disabled = true;\n    }\n    renderCompatQuizUi();\n    try{\n      const pack = await fetchCompatQuizBatchForPeer(currentChat.id);\n      _compatLlmDeck[String(currentChat.id)] = pack;\n      compatQuizOffset = 0;\n      currentCompatQuiz = buildCurrentCompatSnapshot(String(currentChat.id), 0);\n      renderCompatQuizUi();\n    }catch(e){\n      meetToastShow(String(e && e.message ? e.message : e || '生成失败'));\n    }finally{\n      _compatQuizRefreshBusy = false;\n      if(btn) btn.classList.remove('is-busy');\n      renderCompatQuizUi();\n    }\n  });\n  document.getElementById('chat-compat-a')?.addEventListener('click', () => {\n    resolveCompatQuizPick(0);\n  });\n  document.getElementById('chat-compat-b')?.addEventListener('click', () => {\n    resolveCompatQuizPick(1);\n  });\n  document.getElementById('chat-icebreaker-quote').addEventListener('click', () => {\n    const t = document.getElementById('chat-icebreaker-text');\n    const inp = document.getElementById('chat-input');\n    if(!t || !inp) return;\n    inp.value = t.textContent || '';\n    inp.focus();\n  });\n  document.getElementById('bubble-act-cancel')?.addEventListener('click', closeBubbleActionModal);\n  document.getElementById('bubble-act-copy')?.addEventListener('click', async () => {\n    if(!bubbleActionCtx || !currentChat) return;\n    const hist = getConvHistory(currentChat.id);\n    let text = '';\n    if(multiSelectMode && multiSelectTurnIds.size > 0){\n      const lines = hist\n        .filter(t => multiSelectTurnIds.has(String(t.id)))\n        .map(t => (t.role === 'user' ? '我：' : 'Ta：') + getTurnTextForCopy(t))\n        .filter(x => x && !x.endsWith('：'));\n      text = lines.join('\\n');\n    }else{\n      const turn = findConvTurn(bubbleActionCtx.peerId, bubbleActionCtx.turnId);\n      if(!turn || turn.recalled) return;\n      text = String(turn.content || '');\n    }\n    if(!String(text || '').trim()) return;\n    await writeTextToClipboard(text);\n    closeBubbleActionModal();\n  });\n  document.getElementById('bubble-act-multi')?.addEventListener('click', () => {\n    if(!bubbleActionCtx || !currentChat) return;\n    const turn = findConvTurn(bubbleActionCtx.peerId, bubbleActionCtx.turnId);\n    if(!turn || turn.recalled || !String(turn.content || '').trim()) return;\n    setMultiSelectMode(true);\n    toggleSelectTurn(String(bubbleActionCtx.turnId));\n    if(multiSelectTurnIds.size === 0){\n      setMultiSelectMode(false);\n    }\n    refreshMultiSelectUi();\n    closeBubbleActionModal();\n  });\n  document.getElementById('bubble-act-reroll')?.addEventListener('click', async () => {\n    if(!bubbleActionCtx || !currentChat || chatReplyBusy) return;\n    const turn = findConvTurn(bubbleActionCtx.peerId, bubbleActionCtx.turnId);\n    if(!turn || turn.role !== 'assistant' || turn.recalled) return;\n    closeBubbleActionModal();\n    chatReplyBusy = true;\n    setChatComposerBusy(true);\n    try{\n      await rerollAssistantTurn(turn.id);\n    }catch(e){\n      appendPeerBubbleOnly('（重roll失败：' + (e && e.message ? e.message : String(e)).slice(0, 120) + '）');\n    }finally{\n      chatReplyBusy = false;\n      setChatComposerBusy(false);\n    }\n  });\n  document.getElementById('bubble-act-reroll-round')?.addEventListener('click', async () => {\n    if(!bubbleActionCtx || !currentChat || chatReplyBusy) return;\n    const turn = findConvTurn(bubbleActionCtx.peerId, bubbleActionCtx.turnId);\n    if(!turn || turn.role !== 'assistant' || turn.recalled) return;\n    closeBubbleActionModal();\n    try{\n      await rerollAssistantRound(turn.id);\n    }catch(e){\n      appendPeerBubbleOnly('（整轮重roll失败：' + (e && e.message ? e.message : String(e)).slice(0, 120) + '）');\n    }\n  });\n  document.getElementById('bubble-act-quote')?.addEventListener('click', () => {\n    if(!bubbleActionCtx || !currentChat) return;\n    const turn = findConvTurn(bubbleActionCtx.peerId, bubbleActionCtx.turnId);\n    if(!turn || turn.recalled) return;\n    currentEditTurnId = null;\n    currentQuoteRef = {\n      turnId: String(turn.id || ''),\n      text: String(turn.content || '').slice(0, 140),\n      from: turn.role === 'user' ? 'me' : 'peer',\n    };\n    refreshChatQuoteBar();\n    closeBubbleActionModal();\n    const inp = document.getElementById('chat-input');\n    inp?.focus();\n  });\n  document.getElementById('bubble-act-edit')?.addEventListener('click', () => {\n    if(!bubbleActionCtx || !currentChat) return;\n    const turn = findConvTurn(bubbleActionCtx.peerId, bubbleActionCtx.turnId);\n    if(!turn || turn.role !== 'user' || turn.recalled) return;\n    currentQuoteRef = null;\n    currentEditTurnId = String(turn.id);\n    refreshChatQuoteBar();\n    closeBubbleActionModal();\n    const inp = document.getElementById('chat-input');\n    if(inp){\n      inp.value = turn.content || '';\n      inp.focus();\n      inp.setSelectionRange(inp.value.length, inp.value.length);\n    }\n  });\n  document.getElementById('bubble-act-recall')?.addEventListener('click', () => {\n    if(!bubbleActionCtx || !currentChat) return;\n    const turn = findConvTurn(bubbleActionCtx.peerId, bubbleActionCtx.turnId);\n    if(!turn || turn.role !== 'user' || turn.recalled) return;\n    const ok = updateConvTurn(bubbleActionCtx.peerId, bubbleActionCtx.turnId, (t) => {\n      t.recalled = true;\n      return t;\n    });\n    if(ok){\n      voidQuoteRefsPointingTo(bubbleActionCtx.peerId, turn.id);\n      if(currentEditTurnId && String(currentEditTurnId) === String(turn.id)) currentEditTurnId = null;\n      if(currentQuoteRef && String(currentQuoteRef.turnId || '') === String(turn.id)) currentQuoteRef = null;\n      refreshChatQuoteBar();\n      renderChatThread(!!currentChat.isStranger, currentChat);\n    }\n    closeBubbleActionModal();\n  });\n  $modalBubbleAction?.addEventListener('click', (e) => {\n    if(e.target === $modalBubbleAction) closeBubbleActionModal();\n  });\n\n  document.getElementById('rate-skip').addEventListener('click', () => {\n    $modal.classList.remove('open');\n    closeChatShell();\n    currentChat = null;\n  });\n  let rateResolveBusy = false;\n  document.getElementById('rate-ok').addEventListener('click', () => {\n    if(rateResolveBusy) return;\n    rateResolveBusy = true;\n    const btnOk = document.getElementById('rate-ok');\n    const btnSkip = document.getElementById('rate-skip');\n    if(btnOk) btnOk.disabled = true;\n    if(btnSkip) btnSkip.disabled = true;\n    let unlockPeerId = '';\n    let rateMilestonePeerId = '';\n    let ratePrevSm = 0;\n    let ratePrevSp = 0;\n    let uForPeerResolve = null;\n    let stepForPeerResolve = null;\n    if(currentChat && selectedRateStep !== null && selectedRateStep !== undefined && !currentChat.isStranger){\n      const u = liked.find(x => x.id === currentChat.id);\n      if(u){\n        rateMilestonePeerId = String(u.id || '');\n        ratePrevSm = Number(u.stars) || 0;\n        ratePrevSp = Number(u.starsFromPeer) || 0;\n        const unlockedNow = addFavorFromRateStep(u, selectedRateStep);\n        if(unlockedNow || ((Number(u.stars) || 0) >= 1 && !u.realNameUnlocked)) unlockPeerId = String(u.id || '');\n        saveLiked();\n        uForPeerResolve = u;\n        stepForPeerResolve = selectedRateStep;\n      }\n      renderInbox();\n    }\n    $modal.classList.remove('open');\n    closeChatShell();\n    currentChat = null;\n    if(btnOk) btnOk.disabled = false;\n    if(btnSkip) btnSkip.disabled = false;\n    rateResolveBusy = false;\n    if(unlockPeerId) void openNameUnlockModal(unlockPeerId);\n    if(uForPeerResolve != null && stepForPeerResolve != null && rateMilestonePeerId){\n      const peerId = rateMilestonePeerId;\n      const psm = ratePrevSm;\n      const psp = ratePrevSp;\n      const delay = unlockPeerId ? 480 : 140;\n      void (async () => {\n        const aiDelta = await resolvePeerFavorDeltaByExit(uForPeerResolve, stepForPeerResolve);\n        if(aiDelta == null){\n          bumpPeerImpression(uForPeerResolve);\n        }else{\n          uForPeerResolve.favorPeer = Math.min(IMPRESSION_FAVOR_CAP, Math.max(0, Math.round((Number(uForPeerResolve.favorPeer) || 0) + aiDelta)));\n          syncStarsFromFavor(uForPeerResolve);\n        }\n        saveLiked();\n        renderInbox();\n        const u2 = liked.find(x => String(x.id) === peerId);\n        if(u2) setTimeout(() => maybeEnqueueMutualStarMilestones(u2, psm, psp), delay);\n      })();\n    }\n  });\n  document.getElementById('unmatch-ok')?.addEventListener('click', () => {\n    $modalUnmatch?.classList.remove('open');\n  });\n  $modalUnmatch?.addEventListener('click', (e) => {\n    if(e.target === $modalUnmatch) $modalUnmatch.classList.remove('open');\n  });\n  document.getElementById('name-unlock-cancel')?.addEventListener('click', () => {\n    pendingNameUnlockPeerId = '';\n    closeNameUnlockModal();\n  });\n  document.getElementById('name-unlock-ok')?.addEventListener('click', () => {\n    void applyNameUnlock();\n  });\n  $modalNameUnlock?.addEventListener('click', (e) => {\n    if(e.target === $modalNameUnlock){\n      pendingNameUnlockPeerId = '';\n      closeNameUnlockModal();\n    }\n  });\n\n  document.getElementById('btn-pass').addEventListener('click', doPass);\n  document.getElementById('btn-like').addEventListener('click', doLike);\n\n  function refreshDailyLine(){\n    const el = document.getElementById('daily-date-line');\n    if(!el) return;\n    const d = new Date();\n    const wk = ['日','一','二','三','四','五','六'][d.getDay()];\n    let tail = '上升天秤 · 太阳处女';\n    const b = getStoredBirth();\n    if(b && b.date){\n      const segs = b.date.split('-').map(Number);\n      const mm = segs[1], dd = segs[2];\n      const su = sunSignFromDate(mm, dd);\n      const { asc } = moonAscFromBirth(b.date, b.time || '');\n      tail = `上升${Z_SIGN[asc]} · 太阳${Z_SIGN[su]}`;\n    }\n    el.textContent = `${d.getMonth() + 1}月${d.getDate()}日 · 周${wk} · ${tail}`;\n  }\n\n  document.getElementById('daily-recommend-wrap').addEventListener('click', (e) => {\n    const btn = e.target.closest('[data-drec-action]');\n    if(!btn) return;\n    const act = btn.getAttribute('data-drec-action');\n    const id = btn.getAttribute('data-drec-id');\n    if(act === 'discover'){\n      document.querySelector('.ma-nav button[data-tab=\"discover\"]')?.click();\n    }else if(act === 'chat' && id){\n      document.querySelector('.ma-nav button[data-tab=\"inbox\"]')?.click();\n      setTimeout(() => openChat(id), 80);\n    }\n  });\n\n  document.getElementById('birth-save').addEventListener('click', () => {\n    const dateIn = document.getElementById('birth-date');\n    const timeIn = document.getElementById('birth-time');\n    const date = parseBirthDateInput(dateIn && dateIn.value);\n    if(!date){\n      meetToastShow('请输入正确出生日期（YYYY-MM-DD）');\n      return;\n    }\n    const time = parseBirthTimeInput(timeIn && timeIn.value);\n    if(time === null){\n      meetToastShow('请输入正确出生时间（HH:mm，24小时制）');\n      return;\n    }\n    _meetBirth = { date, time };\n    void meetStoreSet(IDB_KEY_MEET_BIRTH, _meetBirth);\n    if(dateIn) dateIn.value = date;\n    if(timeIn) timeIn.value = time;\n    renderNatal();\n    refreshDailyLine();\n    refreshMeProfileUi();\n    if(deck.length) renderCard(deck[0]);\n  });\n\n  document.getElementById('profile-sheet').addEventListener('click', (e) => {\n    const chip = e.target.closest('.ma-chip-tog[data-chip]');\n    if(!chip) return;\n    chip.classList.toggle('is-on');\n    chip.setAttribute('aria-pressed', chip.classList.contains('is-on') ? 'true' : 'false');\n  });\n\n  document.getElementById('btn-open-profile').addEventListener('click', () => openProfileSheet());\n  document.getElementById('profile-back').addEventListener('click', () => closeProfileSheet());\n  document.getElementById('prof-save').addEventListener('click', () => {\n    const gEl = document.querySelector('input[name=\"prof-gender\"]:checked');\n    let gender = '';\n    if(gEl && gEl.value !== 'none') gender = gEl.value;\n    const seekingSelected = [...document.querySelectorAll('#prof-seeking-chips .ma-chip-tog.is-on')].map(b => b.getAttribute('data-value'));\n    const tagsSelected = [...document.querySelectorAll('#prof-tags-chips .ma-chip-tog.is-on')].map(b => b.getAttribute('data-value'));\n    const mbtiEl = document.querySelector('input[name=\"prof-mbti\"]:checked');\n    const mbtiRaw = mbtiEl && mbtiEl.value !== 'none' ? mbtiEl.value : '';\n    saveUserProfile({\n      nick: document.getElementById('prof-nick').value.trim(),\n      gender,\n      city: document.getElementById('prof-city').value.trim(),\n      bio: document.getElementById('prof-bio').value.trim(),\n      seekingSelected,\n      seekingOther: document.getElementById('prof-seeking-other').value.trim(),\n      tagsSelected,\n      tagsOther: document.getElementById('prof-tags-other').value.trim(),\n      mbti: mbtiRaw\n    });\n    closeProfileSheet();\n    refreshMeProfileUi();\n  });\n  document.getElementById('wb-sheet')?.addEventListener('click', (e) => {\n    const chip = e.target.closest('.ma-chip-tog[data-wb-entry-id]');\n    if(!chip) return;\n    chip.classList.toggle('is-on');\n    chip.setAttribute('aria-pressed', chip.classList.contains('is-on') ? 'true' : 'false');\n    const count = document.getElementById('wb-bind-count');\n    if(count){\n      const n = document.querySelectorAll('#wb-entry-list .ma-chip-tog.is-on[data-wb-entry-id]').length;\n      count.textContent = String(n);\n    }\n  });\n  document.getElementById('btn-open-wb')?.addEventListener('click', () => { void openWbSheet(); });\n  document.getElementById('wb-back')?.addEventListener('click', () => closeWbSheet());\n  document.getElementById('wb-save')?.addEventListener('click', () => {\n    syncWorldviewFreetextFromUi();\n    const ids = [...document.querySelectorAll('#wb-entry-list .ma-chip-tog.is-on[data-wb-entry-id]')]\n      .map(b => Math.round(Number(b.getAttribute('data-wb-entry-id'))))\n      .filter(v => Number.isFinite(v) && v > 0);\n    setCurrentWbBoundIds(ids);\n    closeWbSheet();\n    void refreshWbCtaLine();\n  });\n\n  document.getElementById('natal-form-toggle').addEventListener('click', () => {\n    const f = document.getElementById('natal-form');\n    const t = document.getElementById('natal-form-toggle');\n    f.classList.toggle('is-collapsed');\n    const collapsed = f.classList.contains('is-collapsed');\n    t.setAttribute('aria-expanded', collapsed ? 'false' : 'true');\n  });\n\n  const TAB_ORDER = ['discover', 'inbox', 'daily', 'me'];\n  let activeTab = (() => {\n    const v = document.querySelector('.ma-view.active');\n    if(!v || !v.id) return 'discover';\n    return String(v.id).replace(/^view-/, '') || 'discover';\n  })();\n  let _tabSwitchTimer = null;\n  function switchMainTabView(nextTab){\n    const tab = String(nextTab || '').trim();\n    if(!tab || tab === activeTab) return;\n    const fromView = document.getElementById('view-' + activeTab);\n    const toView = document.getElementById('view-' + tab);\n    if(!fromView || !toView){\n      activeTab = tab || activeTab;\n      return;\n    }\n    const fromIdx = Math.max(0, TAB_ORDER.indexOf(activeTab));\n    const toIdx = Math.max(0, TAB_ORDER.indexOf(tab));\n    const forward = toIdx >= fromIdx;\n    if(_tabSwitchTimer){\n      clearTimeout(_tabSwitchTimer);\n      _tabSwitchTimer = null;\n    }\n    document.querySelectorAll('.ma-view').forEach(v => {\n      v.classList.remove('is-enter-from-right', 'is-enter-from-left', 'is-exit-to-left', 'is-exit-to-right');\n    });\n    toView.classList.add('active');\n    toView.classList.add(forward ? 'is-enter-from-right' : 'is-enter-from-left');\n    fromView.classList.add(forward ? 'is-exit-to-left' : 'is-exit-to-right');\n    const reduced = !!(window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches);\n    const waitMs = reduced ? 0 : 240;\n    _tabSwitchTimer = setTimeout(() => {\n      fromView.classList.remove('active', 'is-exit-to-left', 'is-exit-to-right');\n      toView.classList.remove('is-enter-from-right', 'is-enter-from-left');\n      _tabSwitchTimer = null;\n    }, waitMs);\n    activeTab = tab;\n  }\n\n  document.querySelectorAll('.ma-nav button').forEach(btn => {\n    btn.addEventListener('click', () => {\n      const tab = btn.getAttribute('data-tab');\n      document.querySelectorAll('.ma-nav button').forEach(b => b.classList.toggle('active', b === btn));\n      switchMainTabView(tab);\n      if(tab === 'daily'){\n        void renderDailyPageContent();\n      }\n      if(tab === 'me'){\n        renderNatal();\n        syncDmPolicyUi();\n        refreshMeProfileUi();\n        void refreshWbCtaLine();\n        void refreshMeetAvatarUi();\n      }\n      if(tab === 'inbox'){\n        renderInbox();\n        void maybeAppendStrangerBatch();\n      }\n    });\n  });\n\n  document.getElementById('btn-os-home')?.addEventListener('click', () => {\n    if(typeof window.parent !== 'undefined' && window.parent !== window){\n      try{ window.parent.postMessage({ type: 'chill-meet-close' }, '*'); }catch(_){}\n      return;\n    }\n    window.location.href = 'index.html';\n  });\n\n  const $btnRefreshDiscover = document.getElementById('btn-refresh-discover');\n  if($btnRefreshDiscover){\n    $btnRefreshDiscover.addEventListener('click', () => {\n      if(isDailyTabActive()) void refreshDailyFromApi();\n      else refreshDiscoverFromApi();\n    });\n  }\n\n  function injectMeetChatUiPatches(){\n    if(document.getElementById('ma-meet-chat-ui-patches')) return;\n    const st = document.createElement('style');\n    st.id = 'ma-meet-chat-ui-patches';\n    st.textContent = [\n      '.ma-chat-msg{min-width:0;}',\n      '.ma-chat-bub{min-width:0;max-width:100%;overflow:hidden;overflow-wrap:break-word;word-break:break-word;}',\n      '.ma-chat-quote-inline{width:100%;max-width:100%;min-width:0;box-sizing:border-box;}',\n      '.ma-chat-quote-inline .t{white-space:normal;word-break:break-word;overflow-wrap:anywhere;display:-webkit-box;-webkit-line-clamp:3;-webkit-box-orient:vertical;overflow:hidden;text-overflow:ellipsis;}',\n      '#ma-multi-select-bar{display:none;position:absolute;left:0;right:0;bottom:0;z-index:60;',\n      'align-items:center;justify-content:space-between;gap:12px;padding:10px 14px calc(10px + env(safe-area-inset-bottom,0px));',\n      'background:var(--glass-bg);backdrop-filter:var(--glass-blur);-webkit-backdrop-filter:var(--glass-blur);',\n      'border-top:1px solid var(--border-line);box-shadow:0 -4px 24px rgba(0,0,0,.06);}',\n      '[data-theme=\"dark\"] #ma-multi-select-bar{box-shadow:0 -6px 28px rgba(0,0,0,.25);}',\n      '#chat-screen.ma-multi-select-mode #ma-multi-select-bar{display:flex;}',\n      '#chat-screen.ma-multi-select-mode .ma-chat-body{padding-bottom:calc(52px + env(safe-area-inset-bottom,0px));}',\n      '#chat-screen.ma-multi-select-mode .ma-chat-composer-wrap,#chat-screen.ma-multi-select-mode .ma-icebreaker{opacity:.38;pointer-events:none;}',\n      '.ma-ms-count{font-size:0.82rem;color:var(--text-sub);flex:1;min-width:0;padding-right:8px;}',\n      '.ma-ms-actions{display:flex;align-items:center;gap:10px;flex-shrink:0;}',\n      '.ma-ms-btn{font:inherit;font-size:0.8rem;font-weight:600;padding:10px 16px;border-radius:100px;border:1px solid var(--border-line);',\n      'background:var(--bg-card);color:var(--text-main);cursor:pointer;transition:transform .12s,opacity .15s;}',\n      '.ma-ms-btn:active{transform:scale(.96);}',\n      '.ma-ms-btn:disabled{opacity:.45;cursor:default;transform:none;}',\n      '.ma-ms-delete{background:var(--text-main);color:var(--bg-device);border-color:transparent;}',\n      '.ma-chat-msg.is-selectable{cursor:pointer;}',\n      '.ma-chat-msg.is-selected .ma-chat-bub{outline:2px solid rgba(107,92,122,.45);outline-offset:2px;}',\n      '.ma-wb-worldview-ta{width:100%;min-height:88px;margin-top:8px;padding:12px 14px;border-radius:14px;border:1px solid var(--border-line);',\n      'background:var(--bg-card);color:var(--text-main);font:inherit;font-size:0.88rem;line-height:1.45;resize:vertical;box-sizing:border-box;}',\n      '.ma-wb-worldview-ta:focus{outline:none;border-color:rgba(107,92,122,.35);}',\n    ].join('');\n    document.head.appendChild(st);\n  }\n  function ensureMeetMultiSelectBar(){\n    if(document.getElementById('ma-multi-select-bar')) return;\n    const scr = document.getElementById('chat-screen');\n    if(!scr) return;\n    const bar = document.createElement('div');\n    bar.id = 'ma-multi-select-bar';\n    bar.className = 'ma-ms-footer';\n    bar.setAttribute('aria-hidden', 'true');\n    bar.innerHTML =\n      '<span class=\"ma-ms-count\" id=\"ma-ms-count\">点气泡勾选</span>' +\n      '<div class=\"ma-ms-actions\">' +\n      '<button type=\"button\" class=\"ma-ms-btn ma-ms-delete\" id=\"ma-ms-delete\" disabled>删除</button>' +\n      '<button type=\"button\" class=\"ma-ms-btn ma-ms-done\" id=\"ma-ms-done\">完成</button>' +\n      '</div>';\n    scr.appendChild(bar);\n  }\n\n  async function bootChillMatch(){\n    // 先秒开基础 UI，避免首次进入时“白等”。\n    bindDmPolicyRadios();\n    deck = [];\n    renderCard(deck[0]);\n    renderInbox();\n  renderNatal();\n  refreshMeProfileUi();\n    void refreshWbCtaLine();\n    void renderDailyPageContent();\n    void refreshMeetAvatarUi();\n\n    try{\n      await openChillIdb();\n      await migrateLegacyMeetLocalStorage();\n      await hydrateMeetStateFromIdb();\n    }catch(e){\n      console.warn('Chill meet storage', e);\n      liked = [];\n      strangers = [];\n      _meetConvMap = {};\n      _meetUserProfile = normalizeUserProfile(null);\n      _meetBirth = null;\n      _meetDmPolicy = DM_STRANGERS_OK;\n      _meetStrangerNextDue = 0;\n      _meetWbBindMap = {};\n      _meetWorldviewFreetext = '';\n      _wbMainEntriesCache = [];\n    }\n    // 再用持久化数据回填 UI。\n    deck = [];\n    renderNatal();\n    refreshMeProfileUi();\n    void refreshWbCtaLine();\n    void renderDailyPageContent();\n    void refreshMeetAvatarUi();\n  renderCard(deck[0]);\n  renderInbox();\n    setTimeout(() => { void maybeAppendStrangerBatch(); }, 1200);\n  }\n\n  (function bindMeetAvatarUpload(){\n    const wrap = document.getElementById('meet-avatar-wrap');\n    const inp = document.getElementById('meet-avatar-input');\n    if(!wrap || !inp) return;\n    wrap.addEventListener('click', () => inp.click());\n    wrap.addEventListener('keydown', (e) => {\n      if(e.key !== 'Enter' && e.key !== ' ') return;\n      e.preventDefault();\n      inp.click();\n    });\n    inp.addEventListener('change', async (e) => {\n      const file = e.target.files && e.target.files[0];\n      inp.value = '';\n      if(!file) return;\n      if(!file.type || !file.type.startsWith('image/')){\n        meetToastShow('请选择图片文件');\n        return;\n      }\n      try{\n        await saveMeetAvatarFromFile(file);\n      }catch(err){\n        console.warn('meet avatar', err);\n        meetToastShow('头像处理失败，请换一张图重试');\n      }\n    });\n  })();\n\n  injectMeetChatUiPatches();\n  ensureMeetMultiSelectBar();\n  ensureWorldviewWbUi();\n  void bootChillMatch();\n})();\n\n</script>\n</body>\n</html>\n";

    var _meetCloseFallbackTimer = null;

    function injectMeetShellCss() {
      if (document.getElementById('chill-meet-frame-style')) return;
      var st = document.createElement('style');
      st.id = 'chill-meet-frame-style';
      st.textContent =
        '#' +
        IFRAME_ID +
        '{transition:opacity .28s ease-out,transform .3s cubic-bezier(0.2,0.85,0.2,1);will-change:opacity,transform;}' +
        '#' +
        IFRAME_ID +
        '.chill-meet-open{opacity:1!important;transform:translate3d(0,0,0)!important;}' +
        '#' +
        IFRAME_ID +
        ':not(.chill-meet-open){opacity:0;transform:translate3d(0,16px,0);}';
      document.head.appendChild(st);
    }

    function meetMotionReduced() {
      return typeof matchMedia === 'function' && matchMedia('(prefers-reduced-motion: reduce)').matches;
    }

    function ensureIframe() {
      var f = document.getElementById(IFRAME_ID);
      if (f) return f;
      if (!document.body) return null;
      f = document.createElement('iframe');
      f.id = IFRAME_ID;
      f.setAttribute('title', '遇见');
      f.setAttribute('sandbox', 'allow-scripts allow-same-origin allow-forms allow-popups allow-modals');
      f.setAttribute(
        'style',
        'position:fixed;top:0;left:0;width:100%;height:100%;max-width:100vw;max-height:100%;border:0;z-index:99999;display:none;background:rgba(235,248,255,0.7);'
      );
      document.body.appendChild(f);
      return f;
    }

    function openMeet() {
      try {
        injectMeetShellCss();
        var f = ensureIframe();
        if (!f) return;
        clearTimeout(_meetCloseFallbackTimer);
        _meetCloseFallbackTimer = null;
        if (f.getAttribute('data-meet-loaded') !== '1') {
          f.srcdoc = MEET_SRCDOC;
          f.setAttribute('data-meet-loaded', '1');
        }
        f.classList.remove('chill-meet-open');
        f.style.display = 'block';
        if (meetMotionReduced()) {
          f.classList.add('chill-meet-open');
          return;
        }
        requestAnimationFrame(function () {
          requestAnimationFrame(function () {
            f.classList.add('chill-meet-open');
          });
        });
      } catch (err) {
        console.error('[ChillMeet] open failed', err);
      }
    }

    function closeMeet() {
      var f = document.getElementById(IFRAME_ID);
      if (!f) return;
      clearTimeout(_meetCloseFallbackTimer);
      if (meetMotionReduced()) {
        f.classList.remove('chill-meet-open');
        f.style.display = 'none';
        return;
      }
      f.classList.remove('chill-meet-open');
      function finish() {
        f.style.display = 'none';
        f.removeEventListener('transitionend', onEnd);
      }
      function onEnd(e) {
        if (e.propertyName !== 'opacity') return;
        finish();
      }
      f.addEventListener('transitionend', onEnd);
      _meetCloseFallbackTimer = setTimeout(finish, 380);
    }

    window.addEventListener('message', function (e) {
      if (e && e.data && e.data.type === 'chill-meet-close') closeMeet();
    });

    window.ChillMeet = { open: openMeet, close: closeMeet };

    function bind() {
      try {
        var box = document.querySelector('#grid-icons [data-icon-id="0"]') || document.querySelector('[data-icon-id="0"]');
        var cell = box && box.closest && box.closest('.icon-cell');
        var target = cell || box;
        if (target) {
          target.addEventListener('click', function (e) {
            e.preventDefault();
            openMeet();
          });
        }
      } catch (err) {
        console.error('[ChillMeet] bind failed', err);
      }
    }

    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', bind);
    else bind();
  } catch (err) {
    console.error('[ChillMeet] 脚本异常，遇见不可用（主界面不受影响请刷新后看控制台）', err);
    window.ChillMeet = { open: function () { console.error('[ChillMeet]', err); }, close: noopClose };
  }
})();